							  to vw_ows_ProtectionProductSummary where SummaryID on view is a negative
18-5-18		S Inglis		  Addition of QRM Name
14-1-19		S Inglis		  Addition of Owl Panel as an option
21-1-19		S Inglis		  Change to include OSPA Transalator cases
18-2-19		S Inglis		  Addition of Partner contact numbers and missing third party details
21-2-19		S Inglis		  Change to policies to mark as translator if client cant speak english 
							  and has excepted offer of help
29-3-19		S Inglis		  Update to translator filter
24-6-19		S Inglis		  Update to panel filter as left advisers were coming through as Owl Panel
18-10-19	S Inglis		  Update to main SQL statement to join to PolicyOneLink additional features 
							  column to bring back fracture cover on Openwork cases
30-9-20		S Inglis		  Scan falling over due to truncated data so I have increased the size of 
							  all the columns in the temp table #TTMC_WIDE
28-1-21		S Inglis		  Addition of Client and Partner Email Addresses and marker if they've accepted
							  Special Care. And Product Term (Years)
15-2-21		S Inglis		  Widening of address columns as large address is making the scan fall over
***********************************************************************************************/

BEGIN TRY


declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;



set	@ReportName			= 'TTMC - Protection'
set @StoredProcName		= object_name(@@procid)
set @StoredProcParams	= '@DateSubmitted=' + isnull(convert(varchar,@DateSubmitted,102),'NULL')
set @StoredProcParams	= @StoredProcParams + '; @Source=' + isnull(@Source,'NULL')

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                               @StoredProcParams, @LastAuditID output


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/

Begin

Select
pol.saleID,
sum (case when pot.TypeName = 'Client' then 1 else 0 end) as ClientPolicies,
case when (ffocd.SpeakEnglishId = 20 or ffocd.appropriateforspecialcarenonowlid in (10155,10156)) and isnull(ffosc.UseTranslatorID,ffosc.ThirdPartyPresentAllMeetingsID) = 19 then 'No' else 'Yes' end as ClientEnglish, --updated 21.2.19
sum (case when pot.TypeName = 'Partner' then 1 else 0 end) as PartnerPolicies,
case when (ffocd1.SpeakEnglishId = 20 or ffocd1.appropriateforspecialcarenonowlid in (10155,10156)) and isnull(ffosc.UseTranslatorID,ffosc.ThirdPartyPresentAllMeetingsID) = 19 then 'No' else 'Yes' end as PartnerEnglish, --updated 21.2.19
sum (case when pot.TypeName = 'Joint' then 1 else 0 end) as JointPolicies,
case when ffosc.ThirdPartyPOAName is null then 'No' else 'Yes' end as ThirdParty,
inv.ValueName as CompletedFor
into #Policies
from sa_ows_Policies pol
join sa_ows_Sale sale on sale.SaleID = pol.SaleID
join policy.sa_ows_ProtectionProvider prov on prov.InternalProviderID = pol.InternalProviderID
join StaticData.sa_ows_PolicyOwnerTypes pot on pot.PolicyOwnerTypeID = pol.PolicyOwnerType
left join sa_ows_FactFindOverviewClientDetails ffocd on ffocd.SaleID = pol.SaleID and ffocd.PersonTypeID = 1
left join sa_ows_FactFindOverviewClientDetails ffocd1 on ffocd1.SaleID = pol.SaleID and ffocd1.PersonTypeID = 2
left join sa_ows_FactFindOverviewSpecialCare ffosc on ffosc.SaleID = pol.SaleID
left join sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = sale.SaleID
left join StaticData.sa_ows_InputValues inv on inv.InputID = ffog.CompletedFor
where convert(date,sale.DateSubmitted) between @DateSubmitted and @DateSubmittedTo
and pol.Status in (0,1,2,3)
Group by pol.SaleID, 
case when (ffocd.SpeakEnglishId = 20 or ffocd.appropriateforspecialcarenonowlid in (10155,10156)) and isnull(ffosc.UseTranslatorID,ffosc.ThirdPartyPresentAllMeetingsID) = 19 then 'No' else 'Yes' end, --updated 21.2.19
case when (ffocd1.SpeakEnglishId = 20 or ffocd1.appropriateforspecialcarenonowlid in (10155,10156)) and isnull(ffosc.UseTranslatorID,ffosc.ThirdPartyPresentAllMeetingsID) = 19 then 'No' else 'Yes' end, --updated 21.2.19
		 case when ffosc.ThirdPartyPOAName is null then 'No' else 'Yes' end,
		 inv.ValueName


Select
SaleID,
case when ClientEnglish = 'Yes' and ClientPolicies > 0 and PartnerPolicies = 0 and JointPolicies = 0 then 'Client'
	 when PartnerEnglish = 'Yes' and ClientPolicies = 0 and PartnerPolicies > 0 and JointPolicies = 0 then 'Partner'
	 when ClientEnglish = 'Yes' and PartnerEnglish = 'Yes' and ((PartnerPolicies > 0 and ClientPolicies > 0) or JointPolicies > 0) then 'Client/Partner'
	 when ClientEnglish = 'Yes' and PartnerEnglish = 'No' and (ClientPolicies > 0 or JointPolicies > 0) then 'Client'
	 when ClientEnglish = 'No' and PartnerEnglish = 'Yes' and (PartnerPolicies > 0 or JointPolicies > 0) then 'Partner'
	 when ClientEnglish = 'No' and PartnerEnglish = 'No' and ThirdParty = 'Yes' then 'Translator'
	 when ClientEnglish = 'No' and PartnerEnglish = 'Yes' and ClientPolicies > 0 and PartnerPolicies = 0 and JointPolicies = 0 and CompletedFor = 'Joint' then 'Partner'
	 when ClientEnglish = 'Yes' and PartnerEnglish = 'No' and ThirdParty = 'No' and PartnerPolicies > 0 and CompletedFor = 'Joint' then 'Client'
	 when ThirdParty = 'Yes' and PartnerEnglish = 'No' and PartnerPolicies > 0 and ClientPolicies = 0 and JointPolicies = 0 and CompletedFor = 'Partner' then 'Translator'
	 when ThirdParty = 'Yes' and ClientEnglish = 'No' and PartnerPolicies = 0 and ClientPolicies > 0 and JointPolicies = 0 and CompletedFor = 'Client' then 'Translator'
	 Else 'Query'
	 END as ClientType
into #ClientType
from #Policies

IF @DateSubmitted != ''
	BEGIN
