		insert into #TTMC_WIDE
		(      row_position 
			  ,Contact
			  ,SellerType
			  ,SaleID
			  ,MeetingVenue
			  ,DateSubmitted
			  ,AdviserUID
			  ,UserName
			  ,FirmName
			  ,ClientName
			  ,ClientLastName
			  ,ClientDOB
			  ,ClientEnglishSpeaker
			  ,PartnerName
			  ,PartnerDOB
			  ,PartnerEnglishSpeaker
			  ,FormattedAddress
			  ,PostCode
			  ,TelephoneHome
			  ,TelephoneMobile
			  ,ThirdPartyName
			  ,ThirdPartyContactDetails
			  ,ThirdPartyPhoneNumber
			  ,ThirdPartyRelationship
			  ,ThirdPartyPOAAddress -- need the addresses table TR'd over as well
			  ,PolicyID_1
			  ,PolicyCover_1                                         
			  ,ClientTypeName_1
			  ,ProviderName_1
			  ,ProductName_1
			  ,PremiumAmount_1
			  ,HasCICCover_1
			  ,DeferredPeriod_1
			  ,HasAccidentHealthChildCover_1
			  ,HasAccidentHealthBenefitCover_1
			  ,HasAccidentActiveLifeStyleCover_1
			  ,SumAssuredForCI_1
			  ,SumAssuredForDeath_1
			  ,IncomeProtectionBenefit_1
			  ,IsShortTermIncomeProtection_1
			  ,FractureCover_1
			  ,GlobalTreatment_1
			  ,FirmUID
			  ,QRMName
			  ,PartnerHome --added 18/02/19 SI
			  ,PartnerMobile --added 18/02/19 SI
			  ,ClientAppropriateForSpecialCare
			  ,PartnerAppropriateForSpecialCare
			  ,HasClientAcceptedSpecialCare
			  ,ClientEmail
			  ,PartnerEmail
			  ,ProductTermYears_1) 
		SELECT ROW_NUMBER() over (partition by sale.SaleID order by poli.PolicyId)
			  ,ct.ClientType
			  ,case when miuh.ADUID = '4019902' or miuh.BusinessUID = '2016789' then 'Owl AR'
					when sale.CondorNeedsAnalysisCompletedBy is null and miuh.UserJobTitleCodeSeller not in (61,62,63) then 'Openwork' 
					when sale.CondorNeedsAnalysisCompletedBy is not null then 'Owl' else 'Owl Panel' end as SellerType --updated 24.6.19 SI
			  ,sale.SaleID
			  ,case when mtgv.ValueName = 'Other' then ffog.MeetingVenueOtherDetails else mtgv.ValueName end as MeetingVenue
			  ,sale.DateSubmitted
			  ,sale.AdviserUID
			  ,miuh.UserName
			  ,miuh.BusinessCompanyName
			  ,cliPers.FirstName + ' ' + cliPers.LastName as ClientName
			  ,clipers.LastName as ClientLastName
			  ,cliPers.DateOfBirth as ClientDOB
			  ,case isnull(ffocd_cli.SpeakEnglishId,19) when 20 Then 'No' else 'Yes' end as ClientEnglishSpeaker
			  ,parPers.FirstName + ' ' + parPers.LastName as PartnerName
			  ,parPers.DateOfBirth as PartnerDOB
			  ,case isnull(ffocd_par.SpeakEnglishId,19) when 20 Then 'No' else 'Yes' end as PartnerEnglishSpeaker
			  ,replace(isnull(cliPers.Address1,' ') + ' ' +
					isnull(cliPers.Address2,' ') + ' ' +
					isnull(cliPers.Address3,' ') + ' ' +
					isnull(cliPers.Address4,' ') + ' ' +
					isnull(cliPers.Address5,' ') + ' ' + 
					isnull(cliPers.PostCode,' '),'  ',' ') as FormattedAddress
			  ,cliPers.PostCode as PostCode
			  ,cliPers.TelephoneHome
			  ,cliPers.TelephoneMobile
			  ,case ct.ClientType when 'Translator' then ffosp.ThirdPartyPOAName   --Updated 18/02/19 SI
													 else '' end 
													  as ThirdPartyName
			  ,case ct.ClientType when 'Translator' then ffosp.ThirdPartyContactDetails   --Updated 18/02/19 SI
													 else '' end as ThirdPartyContactDetails  
			  ,case ct.ClientType when 'Translator' then ffosp.ThirdPartyPhoneNumber  --Updated 18/02/19 SI
													 else '' end as ThirdPartyPhoneNumber
			  ,case ct.ClientType when 'Translator' then isnull(ffosp.ThirdPartyRelationship,relt.ValueName)  --Updated 18/02/19 SI
													 else '' end as ThirdPartyRelationship
	          ,case ct.ClientType when 'Translator' then replace(isnull(addr.HouseNameNumber,' ')  + ' ' + --Updated 18/02/19 SI
																			isnull(addr.AddressLine1,' ') + ' ' +
																			isnull(addr.AddressLine2,' ') + ' ' +
																			isnull(addr.AddressLine3,' ') + ' ' +
																			isnull(addr.AddressLine4,' ') + ' ' +
																			isnull(addr.AddressLine5,' ') + ' ' + 
																			isnull(addr.PostCode,' '),'  ',' ') 
	                                         else '' end as ThirdPartyPOAAddress -- need the addresses table TR'd over as well
			  ,poli.PolicyID	      
			  ,case when isnull(ppbd2.ProtectionProductBenefitId,ppbd1.ProtectionProductID) is null or isnull(ppbd1.BenefitTypeID,ppbd2.BenefitTypeID) = 4 then 'N/A' when isnull(ppbd1.HasLifeCoverType,ppbd2.IsLife) = 1 and isnull(ppbd1.LifeAssured,ppbd2.LifeAssuredId) not in (10112,9005) then 'Yes' else 'No' end as PolicyCover	--Updated SI 3.5.18		                                     
			  ,poty.TypeName
			  ,prov.DisplayName as ProviderName
			  ,prpr.DisplayName as ProductName
			  ,ppsu.PremiumAmount
			  ,case isnull(isnull(ppbd1.HasCiCCoverType,ppbd2.IsCriticalIllness),0) when 1 then 'Yes' else 'No' end as HasCICCover --Updated SI 1.5.18	
			  ,isnull(ppbd1.DeferredPeriod,ppbd2.DeferredPeriod) as DeferredPeriod --Updated SI 1.5.18	
			  ,case when ppsu.HasAccidentHealthChildCover = 19 then 'Yes' else 'No' end as HasAccidentHealthChildCover 
			  ,case when ppsu.HasAccidentHealthBenefitCover = 19 then 'Yes' else 'No' end as HasAccidentHealthBenefitCover
			  ,case when ppsu.HasAccidentActiveLifeStyleCover = 19 then 'Yes' else 'No' end as HasAccidentActiveLifeStyleCover
			  ,isnull(ppbd1.SumAssuredForCI,ppbd2.SumAssuredForCriticalIllness) as SumAssuredForCI --Updated SI 1.5.18	
			  ,isnull(ppbd1.SumAssuredForDeath,ppbd2.SumAssuredForDeath) as SumAssuredForDeath --Updated SI 1.5.18	
			  ,isnull(ppbd1.IncomeProtectionBenefit,ppbd2.IncomeProtectionBenefit) as IncomeProtectionBenefit --Updated SI 1.5.18	
 			  ,case when isnull(ppbd1.IsShortTermIncomeProtection,ppbd2.IsShortTermIncomeProtection) = 1 then 'Yes' else 'No' end as IsShortTermIncomeProtection --Updated SI 1.5.18	
			  ,case when isnull(ppaf1.Client,isnull(ppaf3.Client,0)) = 1 or isnull(ppaf1.Partner,isnull(ppaf3.Partner,0)) = 1 then 'Yes' else 'No' end as FractureCover --Updated SI 1.5.18	
			  ,case when isnull(ppaf2.Client,isnull(ppaf4.Client,0)) = 1 or isnull(ppaf2.Partner,isnull(ppaf4.Partner,0)) = 1 then 'Yes' else 'No' end as GlobalTreatment --Updated SI 1.5.18	
			  ,sale.BusinessUid
			  ,miuh.BQMName
			  ,parpers.TelephoneHome as PartnerHome --added 18/02/19 SI
			  ,parpers.TelephoneMobile as PartnerMobile --added 18/02/19 SI
			  ,inpcl.ValueName as ClientAppropriateForSpecialCare
			  ,inppt.ValueName as PartnerAppropriateForSpecialCare
			  ,inpclac.ValueName as HasClientAcceptedSpecialCare
			  ,cliPers.EmailAddress
			  ,parPers.EmailAddress
			  ,isnull(ppbd1.ProductTermYears, ppbd2.ProductTermYears) as ProductTermYears
			  FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Sale] sale
				  join prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person cliPers on cliPers.PersonID = sale.PersonID
				  left join prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person parPers on parPers.PersonID = cliPers.PartnerPersonID
				  join prod_zurich_openwork_datawarehouse.dbo.mi_insight_UserHierarchy miuh on miuh.UserUID = sale.AdviserUID
				  join prod_zurich_openwork_datawarehouse.dbo.sa_ows_Policies poli on poli.SaleID = sale.SaleID
				  join prod_zurich_openwork_datawarehouse.StaticData.sa_ows_PolicyOwnerTypes poty on poty.PolicyOwnerTypeId = poli.PolicyOwnerType
				  join vw_ows_ProtectionProductSummary ppsu on ppsu.PolicyID = poli.PolicyID
				  left join PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd2 on ppbd2.ProtectionProductSummaryId = -ppsu.ProtectionProductID --Updated SI 4.5.18	
																										and ppbd2.IsComplete = 1 --Updated SI 1.5.18	
--				  left join vw_ows_ProtectionProductBenefitDetail ppbd on ppbd.ProtectionProductID = ppsu.ProtectionProductID --Updated SI 1.5.18	
	--																											and ppbd.IsBenefitCompleted = 1 --Updated SI 1.5.18	
				  join prod_zurich_openwork_datawarehouse.Policy.sa_ows_ProtectionProduct prpr on prpr.InternalProductID = poli.InternalProductID
				  LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_FactFindOverviewClientDetails] ffocd_cli on sale.SaleID = ffocd_cli.SaleID
																													  and ffocd_cli.PersonTypeID = 1
				  LEFT JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_FactFindOverviewSpecialCare ffosp on ffosp.SaleID = sale.SaleID																									  
				  LEFT JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_FactFindOverviewClientDetails] ffocd_par on sale.SaleID = ffocd_par.SaleID
																													  and ffocd_par.PersonTypeID = 2
				  JOIN prod_zurich_openwork_datawarehouse.Policy.sa_ows_ProtectionProvider Prov on Prov.InternalProviderID = poli.InternalProviderID                                                                                                     
				                                                                                                      

				  LEFT JOIN prod_zurich_openwork_datawarehouse.staticData.sa_ows_inputvalues pay_freq on pay_freq.inputId = ppsu.PremiumFrequencyID
																								and pay_freq.InputType = 'ProtectionPremiumFrequency'
				  LEFT JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_addresses addr on addr.AddressID = ffosp.ThirdPartyPOAAddressID
				  LEFT JOIN sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = sale.SaleID
				  LEFT JOIN StaticData.sa_ows_InputValues mtgv on mtgv.InputID = ffog.MeetingVenueID
				  LEFT JOIN policy.sa_ows_ProtectionProductBenefitDetail ppbd1 on ppbd1.ProtectionProductID = ppsu.ProtectionProductID
				  Left JOIN policy.sa_ows_ProtectionProductAdditionalFeatures ppaf1 on ppaf1.ProtectionProductBenefitDetailId = ppbd1.ProtectionProductBenefitDetailID and ppaf1.FeatureId = 1 --Updated SI 1.5.18	
				  Left JOIN policy.sa_ows_ProtectionProductAdditionalFeatures ppaf2 on ppaf2.ProtectionProductBenefitDetailId = ppbd1.ProtectionProductBenefitDetailID and ppaf2.FeatureId = 2 --Updated SI 1.5.18	
				  Left JOIN policyonelink.sa_ows_ProtectionProductAdditionalFeatures ppaf3 on ppaf3.ProtectionProductBenefitID = ppbd2.ProtectionProductBenefitID and ppaf3.FeatureId = 1 --Updated SI 18.10.18	
				  Left JOIN policyonelink.sa_ows_ProtectionProductAdditionalFeatures ppaf4 on ppaf4.ProtectionProductBenefitID = ppbd2.ProtectionProductBenefitID and ppaf4.FeatureId = 2 --Updated SI 18.10.18			  
				  JOIN #ClientType ct on ct.SaleID = sale.SaleID
				  left join staticdata.sa_ows_InputValues relt on relt.InputID = ffosp.ThirdPartyRelationshipID
				  Left join StaticData.sa_ows_InputValues inpcl on inpcl.InputID = isnull(ffocd_cli.AppropriateForSpecialCareNonOwlID,ffocd_cli.AppropriateForSpecialCareID)
				  Left join StaticData.sa_ows_InputValues inppt on inppt.InputID = isnull(ffocd_par.AppropriateForSpecialCareNonOwlID,ffocd_par.AppropriateForSpecialCareID)
				  Left join StaticData.sa_ows_InputValues inpclac on inpclac.InputID = isnull(ffosp.HasClientAcceptedOfferID,UseTranslatorID)
				  WHERE sale.SaleStatusID  = 2 -- means submitted
		  				  and   poli.Status       = 2
				  and   sale.DateSubmitted between  @DateSubmitted and @DateSubmittedTo
				  --and	(((case when sale.CondorNeedsAnalysisCompletedBy is null then 'Openwork' else 'Owl' end) = @Source or @Source = 'View All')
				  --or    (sale.AdviserUID = @AdviserUID or @AdviserUID = 'View All'))
				  and ((((case when miuh.ADUID = '4019902' or miuh.BusinessUID = '2016789' then 'Owl AR'
					when sale.CondorNeedsAnalysisCompletedBy is null and miuh.UserJobTitleCodeSeller not in (61,62,63) then 'Openwork' 
					when sale.CondorNeedsAnalysisCompletedBy is not null then 'Owl' else 'Owl Panel' end) = @Source or @Source = 'View All') and @AdviserUID is null ) --updated 14.1.19 SI
				  or (sale.AdviserUID = @AdviserUID and @Source = 'View All'))
				  and   isnull(ffocd_cli.OverviewClientDetailsID,-1) = isnull((select MAX(ffocd_cli1.OverviewClientDetailsID)
															 from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_FactFindOverviewClientDetails] ffocd_cli1
															 where  ffocd_cli1.SaleID = sale.SaleID
															 and    ffocd_cli1.PersonTypeID = 1),-1)
				  and   isnull(ffocd_par.OverviewClientDetailsID,-1) = isnull((select MAX(ffocd_par1.OverviewClientDetailsID)
															 from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_FactFindOverviewClientDetails] ffocd_par1
															 where  ffocd_par1.SaleID = sale.SaleID
															 and    ffocd_par1.PersonTypeID = 2),-1);


