			  ,IsShortTermIncomeProtection_12 varchar(200)
			  ,FractureCover_12 varchar(200)
			  ,GlobalTreatment_12 varchar(200)
			  ,FirmUID varchar(7)
			  ,QRMName varchar(200)
			  ,PartnerHome varchar(30) --added 18/02/19 SI
			  ,PartnerMobile varchar(30) --added 18/02/19 SI
			  ,ClientAppropriateForSpecialCare varchar(50)
			  ,PartnerAppropriateForSpecialCare varchar(50)
			  ,HasClientAcceptedSpecialCare varchar(50)
			  ,ProductTermYears_1 varchar(10)
			  ,ProductTermYears_2 varchar(10)
			  ,ProductTermYears_3 varchar(10)
			  ,ProductTermYears_4 varchar(10)
			  ,ProductTermYears_5 varchar(10)
			  ,ProductTermYears_6 varchar(10)
			  ,ProductTermYears_7 varchar(10)
			  ,ProductTermYears_8 varchar(10)
			  ,ProductTermYears_9 varchar(10)
			  ,ProductTermYears_10 varchar(10)
			  ,ProductTermYears_11 varchar(10)
			  ,ProductTermYears_12 varchar(10)
			  ,ClientEmail varchar(200)
			  ,PartnerEmail varchar(200)
			  ,ImpactandStepsTaken varchar(1000)
			  ,CauseofVulnerabilityOther varchar(1000)
			  ,WhenBecameAwareOther varchar(1000)
