CREATE PROCEDURE [logi].[pr_logi_TTMC_Wealth]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
		@DateSubmitted	  datetime,
		@DateSubmittedTo  datetime,
		@Source			  varchar(20),
		@AdviserUID		  varchar(10) = Null


AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_logi_TTMC_Wealth]
Author      : S Inglis
Date  : 08/05/2018

Purpose     : This report is used for Client Contact team who make client calls. The recipients are:
                  1) Client Contact Team

              The report name is "TTMC - Wealth" and is found on the "Client Contact MI" 
              menu. This report displays: 
              - Details of all wealth policies submitted in the selected period



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_logi_TTMC_Wealth] 'ptl91371', Logi,'01-Nov_2017','30-Nov-2017','Openwork'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
15-05-2018	S Inglis		  Updated to show client and partner ATR
07-03-2019	S Inglis		  Update to include missing translator cases
29-3-19		S Inglis		  Update to translator filter
24-6-19		S Inglis		  Update to panel filter as left advisers were coming through as Owl Panel
27-09-2019	S Inglis		  Update to QRM field to say 'No QRM' if one isn't present
08-11-19	S Inglis		  Addition of "appropriateforspecialcareid = 19" added to case
							  statements to cope with move to D365 where appropriateforspecialcarenonOwlid
							  will no longer be populated
22-1-21		S Inglis		  Addition of Client and Partner Email Addresses and marker if they've accepted
							  Special Care
28-1-21		S Inglis		  Addition of flag for Owl AR firms
21-6-21		S Inglis		  Firm name updated to use trading name and where null business name
***********************************************************************************************/

BEGIN TRY


declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;



set	@ReportName			= 'TTMC - Wealth'
set @StoredProcName		= object_name(@@procid)
set @StoredProcParams	= '@DateSubmitted=' + isnull(convert(varchar,@DateSubmitted,102),'NULL')
set @StoredProcParams	= @StoredProcParams + ';@DateSubmittedTo=' + ISNULL(convert(varchar,@DateSubmittedTo,102),'NULL')
set @StoredProcParams	= @StoredProcParams + '; @Source=' + isnull(@Source,'NULL')

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                               @StoredProcParams, @LastAuditID output


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/




Begin

Select
pol.saleID,
sum (case when pot.TypeName = 'Client' then 1 else 0 end) as ClientPolicies,
case when (ffocd.SpeakEnglishId = 20 or ffocd.appropriateforspecialcarenonowlid in (10155,10156) or ffocd.appropriateforspecialcareid = 19) and isnull (ffosc.UseTranslatorID,ffosc.ThirdPartyPresentAllMeetingsID) = 19 then 'No' else 'Yes' end as ClientEnglish, --updated 8.11.19
sum (case when pot.TypeName = 'Partner' then 1 else 0 end) as PartnerPolicies,
case when (ffocd1.SpeakEnglishId = 20 or ffocd1.appropriateforspecialcarenonowlid in (10155,10156)or ffocd1.appropriateforspecialcareid = 19) and isnull(ffosc.UseTranslatorID,ffosc.ThirdPartyPresentAllMeetingsID) = 19 then 'No' else 'Yes' end as PartnerEnglish, --updated 8.11.19
sum (case when pot.TypeName = 'Joint' then 1 else 0 end) as JointPolicies,
case when ffosc.ThirdPartyPOAName is null then 'No' else 'Yes' end as ThirdParty,
inv.ValueName as CompletedFor
into #Policies
from sa_ows_Policies pol
join sa_ows_Sale sale on sale.SaleID = pol.SaleID
join staticdata.sa_ows_provider prov on prov.InternalProviderID = pol.InternalProviderID
join StaticData.sa_ows_PolicyOwnerTypes pot on pot.PolicyOwnerTypeID = pol.PolicyOwnerType
left join sa_ows_FactFindOverviewClientDetails ffocd on ffocd.SaleID = pol.SaleID and ffocd.PersonTypeID = 1
left join sa_ows_FactFindOverviewClientDetails ffocd1 on ffocd1.SaleID = pol.SaleID and ffocd1.PersonTypeID = 2
left join sa_ows_FactFindOverviewSpecialCare ffosc on ffosc.SaleID = pol.SaleID
left join sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = sale.SaleID
left join StaticData.sa_ows_InputValues inv on inv.InputID = ffog.CompletedFor
where convert(date,sale.DateSubmitted) between @DateSubmitted and @DateSubmittedTo
and pol.Status in (0,1,2,3)
Group by pol.SaleID, 
case when (ffocd.SpeakEnglishId = 20 or ffocd.appropriateforspecialcarenonowlid in (10155,10156) or ffocd.appropriateforspecialcareid = 19) and isnull(ffosc.UseTranslatorID,ffosc.ThirdPartyPresentAllMeetingsID) = 19 then 'No' else 'Yes' end, --updated 8.11.19
case when (ffocd1.SpeakEnglishId = 20 or ffocd1.appropriateforspecialcarenonowlid in (10155,10156) or ffocd1.appropriateforspecialcareid = 19) and isnull(ffosc.UseTranslatorID,ffosc.ThirdPartyPresentAllMeetingsID) = 19 then 'No' else 'Yes' end, --updated 8.11.19
		 case when ffosc.ThirdPartyPOAName is null then 'No' else 'Yes' end,
		 inv.ValueName


Select
SaleID,
case when ClientEnglish = 'Yes' and ClientPolicies > 0 and PartnerPolicies = 0 and JointPolicies = 0 then 'Client'
	 when PartnerEnglish = 'Yes' and ClientPolicies = 0 and PartnerPolicies > 0 and JointPolicies = 0 then 'Partner'
	 when ClientEnglish = 'Yes' and PartnerEnglish = 'Yes' and ((PartnerPolicies > 0 and ClientPolicies > 0) or JointPolicies > 0) then 'Client/Partner'
	 when ClientEnglish = 'Yes' and PartnerEnglish = 'No' and (ClientPolicies > 0 or JointPolicies > 0) then 'Client'
	 when ClientEnglish = 'No' and PartnerEnglish = 'Yes' and (PartnerPolicies > 0 or JointPolicies > 0) then 'Partner'
	 when ClientEnglish = 'No' and PartnerEnglish = 'No' and ThirdParty = 'Yes' then 'Third Party'
	 when ClientEnglish = 'No' and PartnerEnglish = 'Yes' and ClientPolicies > 0 and PartnerPolicies = 0 and JointPolicies = 0 and CompletedFor = 'Joint' then 'Partner'
	 when ClientEnglish = 'Yes' and PartnerEnglish = 'No' and ThirdParty = 'No' and PartnerPolicies > 0 and CompletedFor = 'Joint' then 'Client'
	 when ThirdParty = 'Yes' and PartnerEnglish = 'No' and PartnerPolicies > 0 and ClientPolicies = 0 and JointPolicies = 0 and CompletedFor = 'Partner' then 'Third Party'
	 when ThirdParty = 'Yes' and ClientEnglish = 'No' and PartnerPolicies = 0 and ClientPolicies > 0 and JointPolicies = 0 and CompletedFor = 'Client' then 'Third Party'
	 Else 'Query'
	 END as ClientType
into #ClientType
from #Policies

Select distinct
PersonID,
case when InternalProductID = -2 then 3 else OwnerID end as OwnerID,
InternalProductID,
OngoingServiceFee,
CreatedDate as LatestDate
into #OngoingFee
from  submission.sa_ows_SubmittedProductCurrentOngoingServiceFee ogs
where CreatedDate = (select max(ogs1.CreatedDate)
					 from Submission.sa_ows_SubmittedProductCurrentOngoingServiceFee ogs1
					 where ogs1.InternalProductID = ogs.InternalProductID and ogs.PersonID = ogs1.PersonID)


Select Distinct
	--			ROW_NUMBER() over (partition by sale.SaleID order by poli.PolicyId) as RowNu
	--		  ,ct.ClientType
			  case when miuh.ADUID = '4019902' or miuh.BusinessUID = '2016789' then 'Owl AR'
					when sale.CondorNeedsAnalysisCompletedBy is null and miuh.UserJobTitleCodeSeller not in (61,62,63) then 'Openwork' 
					when sale.CondorNeedsAnalysisCompletedBy is not null then 'Owl' else 'Owl Panel' end as SellerType --updated 24.6.19 SI
			   ,ct.ClientType
			  ,sale.SaleID
			  ,case when mtgv.ValueName = 'Other' then ffog.MeetingVenueOtherDetails else mtgv.ValueName end as MeetingVenue
			  ,sale.DateSubmitted
			  ,sale.AdviserUID
			  ,miuh.UserName
			  ,isnull(miuh.businesstradingname,miuh.BusinessCompanyName) as BusinessCompanyName
			  ,cltitle.valuename + ' ' + cliPers.FirstName + ' ' + cliPers.LastName as ClientName
			  ,clipers.LastName as ClientLastName
			  ,cliPers.DateOfBirth as ClientDOB
			  ,case isnull(ffocd_cli.SpeakEnglishId,19) when 20 Then 'No' else 'Yes' end as ClientEnglishSpeaker
			  ,partitle.ValueName + ' ' + parPers.FirstName + ' ' + parPers.LastName as PartnerName
			  ,parPers.DateOfBirth as PartnerDOB
			  ,case isnull(ffocd_par.SpeakEnglishId,19) when 20 Then 'No' else 'Yes' end as PartnerEnglishSpeaker
			,replace(isnull(cliPers.Address1,' ') + ' ' +
					isnull(cliPers.Address2,' ') + ' ' +
					isnull(cliPers.Address3,' ') + ' ' +
					isnull(cliPers.Address4,' ') + ' ' +
					isnull(cliPers.Address5,' ') + ' ' + 
					isnull(cliPers.PostCode,' '),'  ',' ') as FormattedAddress
			  ,cliPers.PostCode as PostCode
			  ,cliPers.TelephoneHome
			  ,cliPers.TelephoneMobile
			  ,ffosp.ThirdPartyPOAName as ThirdPartyName
			  ,ffosp.ThirdPartyContactDetails as ThirdPartyContactDetails
			  ,ffosp.ThirdPartyPhoneNumber as ThirdPartyPhoneNumber
			  ,ffosp.ThirdPartyRelationship as ThirdPartyRelationship
	          , isnull(addr.HouseNameNumber,' ')  + ' ' +
				isnull(addr.AddressLine1,' ') + ' ' +
				isnull(addr.AddressLine2,' ') + ' ' +
				isnull(addr.AddressLine3,' ') + ' ' +
				isnull(addr.AddressLine4,' ') + ' ' +
				isnull(addr.AddressLine5,' ') + ' ' + 
				isnull(addr.PostCode,' ') as ThirdPartyPOAAddress, -- need the addresses table TR'd over as well
poli.PolicyID,
poty.TypeName,
prov.DisplayName as ProviderName,
prod.DisplayName as ProductName,
atrr.ValueName as ClientAttitudeToRisk,
atrr1.ValueName as PartnerAttitudeToRisk, --added 150518 SI
qr.AnswerText as InitialFee,
qr1.AnswerText as Amount,
case when qb.questiontext like '%new money%' then 'New Money' 
	 when qb.QuestionText like '%legacy%' then 'Legacy' 
	 when qb.QuestionText like '%regular%' then 'Regular' 
	 when qb.questiontext like '%employer%' then 'Regular Employer' else 'Investment' end as PaymentType,
--qr2.AnswerText as NewAmount, 
--qr5.AnswerText as RegularAmount,
case when qr3.AnswerText = 2 then 'No' when qr3.AnswerText = 1 then 'Yes' else 'N/A' end as InTrust,
case when qb.QuestionText like '%legacy%' then 'Yes' else 'No' end as Replacement,
ogs.OngoingServiceFee,
ab.AnswerText as FundChoice,
case when uanda.FeeType = 65 then uanda.FeeAmount else uanda.FeeAmount*uanda.Hours end as UandAAmount,
sale.BusinessUid,
isnull(miuh.BQMName,'No QRM') as BQMName, -- updated 27/09/19 SI
parpers.TelephoneHome as PartnerHome --added 12/03/19 SI
,parpers.TelephoneMobile as PartnerMobile --added 12/03/19 SI
,cliPers.EmailAddress as ClientEmailAddress
,parPers.EmailAddress as PartnerEmailAddress
,inpcl.ValueName as ClientAppropriateForSpecialCare
,inppt.ValueName as PartnerAppropriateForSpecialCare
,inpclac.ValueName as HasClientAcceptedSpecialCare
--uanda.HaveYouChargedUnderstandingAnalysisFee
--qr1.*
into #COBTable
from sa_ows_Policies poli
join sa_ows_Sale sale on sale.SaleID = poli.SaleID
JOIN #ClientType ct on ct.SaleID = poli.SaleID
join prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person cliPers on cliPers.PersonID = sale.PersonID
left join prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person parPers on parPers.PersonID = cliPers.PartnerPersonID
join prod_zurich_openwork_datawarehouse.dbo.mi_insight_UserHierarchy miuh on miuh.UserUID = sale.AdviserUID
--join prod_zurich_openwork_datawarehouse.dbo.sa_ows_Policies poli on poli.SaleID = sale.SaleID
join prod_zurich_openwork_datawarehouse.StaticData.sa_ows_PolicyOwnerTypes poty on poty.PolicyOwnerTypeId = poli.PolicyOwnerType
join StaticData.sa_ows_Provider prov on prov.InternalProviderID = poli.InternalProviderID
join StaticData.sa_ows_Product prod on prod.InternalProductID = poli.InternalProductID
left join sa_ows_FactFindATRInvestorExperiences atr on atr.SaleID = poli.SaleID and atr.PersonTypeID = 1
left join sa_ows_ClientDetailATRInvestorExperiences catr on catr.PersonID = sale.PersonID and catr.PersonTypeID = 1
left join StaticData.sa_ows_InputValues atrr on atrr.InputID = isnull(atr.AgreedAttitudeToRiskID,catr.AgreedAttitudeToRiskID)
left join sa_ows_FactFindATRInvestorExperiences atr1 on atr1.SaleID = poli.SaleID and atr1.PersonTypeID = 2
left join sa_ows_ClientDetailATRInvestorExperiences catr1 on catr1.PersonID = sale.PersonID and catr1.PersonTypeID = 2
left join StaticData.sa_ows_InputValues atrr1 on atrr1.InputID = isnull(atr1.AgreedAttitudeToRiskID,catr1.AgreedAttitudeToRiskID)
join sa_ows_HDRUI_QuestionnaireResponses qr on qr.PolicyID = poli.PolicyID and qr.QuestionID in (select QuestionID 
																								from StaticData.sa_ows_HDRUI_QuestionBank 
																								where QuestionText like '%Enter%Advice &%')
join sa_ows_HDRUI_QuestionnaireResponses qr1 on qr1.PolicyID = poli.PolicyID and qr1.QuestionID in (select QuestionID 
																								from StaticData.sa_ows_HDRUI_QuestionBank 
																								where (QuestionText like '%Amount%' or QuestionText like '%Employer Contribution%')
																								and (qr1.ParentQuestionID = qr.ParentQuestionID or qr1.QuestionID = 497 or qr1.QuestionID = 34)
																								)
join StaticData.sa_ows_HDRUI_QuestionBank qb on qb.QuestionID = qr1.QuestionID
left join sa_ows_HDRUI_QuestionnaireResponses qr3 on qr3.PolicyID = poli.PolicyID and qr3.QuestionID in (select QuestionID 
																								from StaticData.sa_ows_HDRUI_QuestionBank 
																								where QuestionText like '%Trust?'
																								)
--left join sa_ows_HDRUI_QuestionnaireResponses qr4 on qr4.PolicyID = poli.PolicyID and qr4.QuestionID in (select QuestionID 
--																								from StaticData.sa_ows_HDRUI_QuestionBank 
--																								where QuestionText like '%Replacement%?'
--																								)
left join #OngoingFee ogs on ogs.PersonID = sale.PersonID and ogs.InternalProductID = (case when prod.ProductCodeSwift like 'OZ%' or ProductCodeSwift like 'OW%' then -2 else poli.InternalProductID end) and (ogs.OwnerID = poli.PolicyOwnerType or (ogs.OwnerID = 3 and poli.PolicyOwnerType in (1,2)))
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_FactFindOverviewClientDetails] ffocd_cli on sale.SaleID = ffocd_cli.SaleID
																									and ffocd_cli.PersonTypeID = 1
																			and ffocd_cli.DateUpdated = (Select max(ffocd1.DateUpdated)
																			from sa_ows_FactFindOverviewClientDetails ffocd1
																			where ffocd1.SaleID = ffocd_cli.SaleID and ffocd1.PersonTypeID = ffocd_cli.PersonTypeID)
LEFT JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_FactFindOverviewSpecialCare ffosp on ffosp.SaleID = sale.SaleID																									  
LEFT JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_FactFindOverviewClientDetails] ffocd_par on sale.SaleID = ffocd_par.SaleID
																									and ffocd_par.PersonTypeID = 2
																				and ffocd_par.DateUpdated = (Select max(ffocd2.DateUpdated)
																											from sa_ows_FactFindOverviewClientDetails ffocd2
																											where ffocd2.SaleID = ffocd_par.SaleID and ffocd2.PersonTypeID = ffocd_par.PersonTypeID)
LEFT JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_addresses addr on addr.AddressID = ffosp.ThirdPartyPOAAddressID
LEFT JOIN sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = sale.SaleID
LEFT JOIN StaticData.sa_ows_InputValues mtgv on mtgv.InputID = ffog.MeetingVenueID
Left Join sa_ows_HDRUI_QuestionnaireResponses Fund on fund.PolicyID = poli.PolicyID and fund.QuestionID = 2630
Left join StaticData.sa_ows_HDRUI_AnswerBank ab on ab.AnswerID = fund.AnswerText
left join sa_ows_HDRUI_SubmissionFeeUnderstandingDetails uanda on uanda.SaleID = poli.SaleID --and HaveYouChargedUnderstandingAnalysisFee = 19
Left join StaticData.sa_ows_InputValues inpcl on inpcl.InputID = ffocd_cli.AppropriateForSpecialCareNonOwlID
Left join StaticData.sa_ows_InputValues inppt on inppt.InputID = ffocd_par.AppropriateForSpecialCareNonOwlID
Left join StaticData.sa_ows_InputValues inpclac on inpclac.InputID = ffosp.HasClientAcceptedOfferID
left join StaticData.sa_ows_InputValues cltitle on cltitle.InputID = clipers.TitleID
left join StaticData.sa_ows_InputValues partitle on partitle.InputID = parPers.TitleID
where poli.Status in (0,1,2,3)
and   sale.DateSubmitted between  @DateSubmitted and @DateSubmittedTo
and ((((case when miuh.ADUID = '4019902' or miuh.BusinessUID = '2016789' then 'Owl AR'
when sale.CondorNeedsAnalysisCompletedBy is null and miuh.UserJobTitleCodeSeller not in (61,62,63) then 'Openwork' 
when sale.CondorNeedsAnalysisCompletedBy is not null then 'Owl' else 'Owl Panel' end) = @Source or @Source = 'View All') and @AdviserUID is null )) --updated 14.1.19 SI
Order by SaleID, PolicyID;

