			  ,Replacement_10
			  ,OngoingServiceFee_10 
			  ,FundChoice_10
			  ,PolicyID_11                                    
			  ,ClientTypeName_11
			  ,ProviderName_11
			  ,ProductName_11
			  ,InitialFee_11
			  ,Amount_11 
			  ,PaymentType_11 
			  ,InTrust_11 
			  ,Replacement_11
			  ,OngoingServiceFee_11
			  ,FundChoice_11
			  ,PolicyID_12                                  
			  ,ClientTypeName_12
			  ,ProviderName_12
			  ,ProductName_12
			  ,InitialFee_12
			  ,Amount_12
			  ,PaymentType_12
			  ,InTrust_12
			  ,Replacement_12
			  ,OngoingServiceFee_12
			  ,FundChoice_12
			  ,FirmUID
			  ,QRMName
			  ,PartnerHome --added 12/03/19 SI
			  ,PartnerMobile --added 12/03/19 SI
from #TTMC_WIDE
where row_position = 1

END
End

END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH



