			  ,InTrust_7 varchar(200)
			  ,Replacement_7 varchar(200)
			  ,OngoingServiceFee_7 decimal(10,2)
			  ,FundChoice_7 varchar(200)
			  ,PolicyID_8	int                                     
			  ,ClientTypeName_8 varchar(10)
			  ,ProviderName_8 varchar(200)
