AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
11/07/2017	A Groves	Changed to select via category rather than agent type as per 
						Leah Gough's wishes.
17/07/2017	A Groves	Exclude enterprises where they have an agent category code
						normally assigned to people rather than to enterprises.
***********************************************************************************************/

CREATE PROCEDURE [logi].[pr_logi_UTILGetAllOpenworkAdvisers] --@FirstTime varchar(10)

AS

select	Code as AdviserUID, ltrim(rtrim(DESCN)) + ' (' + Code + ')'as AdviserNameAndUID
from	mstt_Agents a
where	a.AgentCategory in ('SHRHLDR','SQMNS','SQMSL','DIRNS','DIRSL','MBRNS','MBRSL',
							'NASPDIR','NASPMBR','NASPPRN','NASPSOLE','PTNRNS','PTNRSL',
							'PFA','PRINNS','PRINSL','SOLE')
and		a.Manager2Code <> '1011671'
and		a.AgentType <> 2	--Exclude enterprises AG 17/07/2017
and		(a.CompetentStatus = 1													-- Active
		or a.CompetentStatus = 2 and DateLeaving >= DATEADD(yy,-2,getdate()))	-- or left in last couple of years
order	by a.Descn







