/****** Object:  StoredProcedure [logi].[pr_logi_UTILOpSysCommandExecution]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
Program:		[logi].[pr_logi_UTILOpSysCommandExecution]
				(Based on UTIL_OpSysCommandExecution of 05/01/2011 
					(based on spReplaceXp_Cmd_Shell by Liam North))		
Author:			A Groves
Date created:	16/06/2015
											
 Description:   This stored proc takes an operating system command as a parameter and dynamically
				creates a job and a job step into which it places the operating system command
				and then runs the job to execute the operating system command.

				The main point of this proc is to avoid the need for enabling the xp_cmd_shell 
				system stored proc which is seen as a security risk amongst the DBA community.

				Two key features of this proc are:
				1) The job is created using a name that incorporates the time down to a third
					of a second to avoid duplicate job names
				2) The job will auto-delete itself on completion - so it completely tidies up
					after itself.
				
				The stored proc is called as follows:

						exec [logi].[pr_logi_UTILOpSysCommandExecution] @Cmd

Amendment History
=================

Date		Author		Description
----------	----------	-----------
07/06/2018	A Groves	Changed text to: xp_cmd_shell replacement -
						so that the xp proc does not get identified in searches.
************************************************************************************************/
CREATE PROCEDURE [logi].[pr_logi_UTILOpSysCommandExecution]
	@JobCommand varchar(8000)

AS

DECLARE @job NVARCHAR(100) ; 
        SET @job = 'xp_cmd_shell replacement - ' + CONVERT(NVARCHAR, GETDATE(), 121) ;  

EXEC msdb..sp_add_job @job_name = @job, 
            @description = 'Automated job to execute command shell script', 
            @owner_login_name = 'SERV\SVC_SQL_MIDB_AGT', @delete_level = 1 ;  

EXEC msdb..sp_add_jobstep @job_name = @job, @step_id = 1, 
            @step_name = 'Command Shell Execution', @subsystem = 'CMDEXEC', 
            @command = @JobCommand, @on_success_action = 1 ;  

EXEC msdb..sp_add_jobserver @job_name = @job ;  

EXEC msdb..sp_start_job @job_name = @job ;

GO
/****** Object:  StoredProcedure [logi].[pr_owl_ClawbackAudit]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/**********************************************************************************************
Author	: S Inglis
Date	: 13/04/2016

Purpose	: This report is used by Payment Services to display any policy that has successfully
		  passed through the Owl CLawback process. 

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
10.5.17		S Inglis	Update to allow null value to pass through as StatementID
17.7.17		S Inglis	Update to allow for payments that have generated a £0 fee
13-11-17	S Inglis	Update to include all payments that have gone through audit log
***********************************************************************************************/
CREATE PROCEDURE [logi].[pr_owl_ClawbackAudit]
		 @StatementID	varchar(10) = null, --updated 10.5.17 SI
		 @PolicyNumber	varchar(20) = 'View All',
		 @PtlCode		varchar(255),
		 @ReportFormat	varchar(200)


AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 


set @ReportName               = 'pr_owl_ClawbackAudit';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@StatementID = ' + @StatementID;
set @StoredProcParams		  = @StoredProcParams + '; @PolicyNumber = ' + @PolicyNumber;

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output


/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/

Select
edih.StatementID,
isnull(edic.PolicyNumber,ocal.PolicyNumber) as PolicyNumber,
case when edih.LifeOfficeCode = 'METLIFEOWL' then edic.FullName else edic.SurName end as Name,
isnull(edic.AmountReceived,0) as NewAmount,
ocal.AmountReceived as OriginalAmount
from sa_SwiftLogging_OwlClawbackAuditLog ocal 
left join sa_swift_EDIFACTCommissionStatementContents edic on ocal.EdifactLineID = edic.ID --updated 17.7.17
join sa_swift_EDIFACTCommissionStatementHeader edih on edih.ID = isnull(ocal.EdifactID,edic.StatementHeaderID)
Where (StatementID = @StatementID or isnull(edic.PolicyNumber,ocal.PolicyNumber) = @PolicyNumber) or (@StatementID is null and @PolicyNumber = 'View All') -- updated 13.11.17 SI



END TRY



BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH

exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     

GO
