21-02-17	S Inglis		  Addition of statement number to report
17-07-17	S Inglis		  Update to code to include Aviva Owl data
20-12-17	S Inglis		  Addition of link to confirm if case is automatched
25-09-18	S Campbell		  Added to where clause to exclude any EDI files which are not converted
							  to a statement (usually due to duplicate EDI file being loaded) Ticket #516045
*************************************************************************************************************/

CREATE PROCEDURE [logi].[pr_Owl_ClawbackProcessExceptions]
        @PtlCode		  varchar(255),
		@ReportFormat	  varchar(255)


AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;


print 'setting parameters';
set @ReportName               = 'Owl Clawback Process Exceptions';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams		  = '(None)'


exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/


Begin

SELECT edih.StatementID -- added 21.2.17 SI
      ,EdifactLineID
      ,case when ocel.LifeOfficeCode = 'METLIFEOWL' THEN 'MetlifeOwl' 
			when ocel.LifeOfficeCode = 'BN295EL' then 'ZurichOwl' 
			when ocel.LifeOfficeCode = 'Aviva Owl' then 'Aviva Owl' 
			else 'LVOwl' end as Provider
      ,ocel.PolicyNumber
      ,ocel.AmountReceived
      ,ocel.PremiumAmount
      ,CommInitialPeriod
      ,CalcClawbackPct
      ,CreationDate
	  ,case when expt.UnallocatedReasonCode is null and expt.AMOUNT_REC != edic.AmountReceived then 'Automatched' else 'Suspense' end as PaymentStatus -- added 20.12.17 SI
  FROM dbo.sa_SwiftLogging_OwlClawbackExceptionLog ocel
  join sa_swift_EDIFACTCommissionStatementContents edic on edic.ID = EdifactLineID -- added 21.2.17 SI
  join sa_swift_EDIFACTCommissionStatementHeader edih on edih.ID = edic.StatementHeaderID -- added 21.2.17 SI
  left join mstt_Expectation expt on expt.ID = edic.Pacc_ID -- added 20.12.17 SI
  where CreationDate >= dateadd(week,-1,getdate())
  and edih.StatementID is not null -- SC 25.09.18 - Prevents unconverted statements being picked up
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
