INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('CINV','COBI');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('TIP','COBI');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('TIPR','COBI');

INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('PENS','COBP');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('PNSW','COBP');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('PNRP','COBP');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('SIPP','COBP');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('METG','COBP');

INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('ICOB','ICOB');

INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('MORT','MCOB');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('BTL','MCOB');

INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('ANNS','RPB');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('ANN','RPB');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('ANNC','RPB');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('DTOD','RPB');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('DRAW','RPB');

INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('VCT','SI');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('VCTR','SI');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('EIS','SI');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('EISR','SI');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('BPRL','SI');
INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('BPRR','SI');


IF OBJECT_ID('tempdb..#AQT_OUTCOMES') IS NOT NULL
DROP TABLE #AQT_OUTCOMES;

CREATE TABLE #AQT_OUTCOMES 
      (
            Advice                    VARCHAR(200),
            AdviserGUID               uniqueidentifier,
            ClientName                VARCHAR(200),
            CaseSubmitDate            DATETIME,
            CaseOutcome               VARCHAR(200),
            ProdShortName             VARCHAR(200),
            InitialCode               INT,
            InitialStatus             VARCHAR(200),
            FinalCode                 INT,
            FinalStatus               VARCHAR(200),
            InitialWorkFlowStatus     VARCHAR(200),
            FinalWorkFlowStatus       VARCHAR(200),
            InitialCheckDate          DATETIME,
            FinalCheckDate            DATETIME,
		    AssessorUID               VARCHAR(200),
		    Assessor                  VARCHAR(200)
      );


insert into #AQT_OUTCOMES (Advice,ClientName,AdviserGUID,CaseSubmitDate,CaseOutcome,ProdShortName,InitialCode,InitialStatus,
                           InitialWorkFlowStatus,InitialCheckDate,AssessorUID,Assessor)
select substring(saca.CASE_CaseReference,4,len(saca.CASE_CaseReference)) as CaseReference
      ,FirstNameATT.ATTL_AttributeValue + ' ' + LastNameATT.ATTL_AttributeValue
      ,saca.CASE_AdviserID
      ,saca.CASE_SubmitDate
      ,cofs.CFS_Description
      ,prty.PROD_ShortName 
      ,bqre.BQR_Code     
      ,bqco.BQC_Description as outcome
      ,CaseStatus.Code_Description as WorkFlowStatus
      ,buqu.BQ_CompletedDate
	  ,miuh.UserUID AS AssessorUID
      ,miuh.UserName AS Assessor

FROM mi_aqt_ReportingHierarchy marh
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca on marh.AdviserGUID = saca.CASE_AdviserID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status --updated 29/7/20 SH

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 

JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[mi_insight_UserHierarchy] miuh on miuh.UserGUID = buqu.BQ_CheckedBy
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_AttributeLink] LastNameATT on LastNameATT.ATTL_ParentID = Saca.CASE_ID 
                                                                                           and LastNameATT.ATTL_AttributeID = 'A95C20A2-B67E-4099-AA57-C8FB37781AFF'
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_AttributeLink] FirstNameATT on FirstNameATT.ATTL_ParentID = Saca.CASE_ID
                                                                                            and FirstNameATT.ATTL_AttributeID = '966F042A-0407-4CC3-8B5F-EA2C37A103E3'
WHERE (marh.AdviserUID = @AdviserUid or marh.BusinessUID = @AdviserUid)  
and   saca.CASE_SubmitDate >= '01-DEC-2013'
AND   saca.CASE_SubmitDate >= DATEADD(mm,-12,dateadd(dd,0,datediff(dd,0,GETDATE())))
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362) --updated 29/7/20 SH
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select min(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) 
AND   LastNameATT.ATTL_CreatedDate = (select max(LastNameATT1.ATTL_CreatedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_AttributeLink] LastNameATT1 
                             where  LastNameATT1.ATTL_ParentID    = Saca.CASE_ID 
                             and    LastNameATT1.ATTL_AttributeID = 'A95C20A2-B67E-4099-AA57-C8FB37781AFF' )                            
AND   FirstNameATT.ATTL_CreatedDate = (select max(FirstNameATT1.ATTL_CreatedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_AttributeLink] FirstNameATT1 
                             where  FirstNameATT1.ATTL_ParentID    = Saca.CASE_ID 
                             and    FirstNameATT1.ATTL_AttributeID = '966F042A-0407-4CC3-8B5F-EA2C37A103E3' )                            
                             ;                            

create index CTE_OUTCOME1 on #AQT_OUTCOMES (Advice,CaseOutcome,ProdShortName);


WITH CTE_OUTCOME
AS (select substring(saca.CASE_CaseReference,4,len(saca.CASE_CaseReference)) as Advice
      ,cofs.CFS_Description as CaseOutcome
      ,prty.PROD_ShortName  as ProdShortName 
      ,bqre.BQR_Code   
      ,bqco.BQC_Description as FinalStatus
      ,CaseStatus.Code_Description as FinalWorkFlowStatus
      ,buqu.BQ_CompletedDate FinalCheckDate
FROM mi_aqt_ReportingHierarchy marh
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca on marh.AdviserGUID = saca.CASE_AdviserID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status --updated 29/7/20 SH
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
WHERE (marh.AdviserUID = @AdviserUid or marh.BusinessUID = @AdviserUid)  
and   saca.CASE_SubmitDate >= '01-DEC-2013'
AND   saca.CASE_SubmitDate >= DATEADD(mm,-12,dateadd(dd,0,datediff(dd,0,GETDATE())))
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362) --updated 29/7/20 SH
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10,14)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) )
UPDATE #AQT_OUTCOMES                             
 set    FinalStatus             = CTE_OUTCOME.FinalStatus,
        FinalCode               = CTE_OUTCOME.BQR_Code,
        FinalWorkFlowStatus     = CTE_OUTCOME.FinalWorkFlowStatus,
        FinalCheckDate          = CTE_OUTCOME.FinalCheckDate
FROM   #AQT_OUTCOMES aqou1
JOIN   CTE_OUTCOME on CTE_OUTCOME.Advice        = aqou1.Advice
                           and CTE_OUTCOME.CaseOutcome   = aqou1.CaseOutCome
                           and CTE_OUTCOME.ProdShortName = aqou1.ProdShortName;

select  AQTO.AssessorUID
       ,AQTO.ClientName
       ,AQTO.Assessor
       ,AQTH.AdviserUID
       ,AQTH.Adviser
       ,AQTO.Advice
       ,AQTO.InitialCheckDate as BQ_CheckDate
		,LOB
--		,ProdShortName  -- for testing
		,AQTO.InitialStatus as Status
--		,AQTO.FinalStatus as FinStatus  -- for testing
--		,AQTO.InitialWorkFlowStatus as Initial_Status -- for testing
--		,AQTO.FinalWorkFlowStatus as Final_Status  -- for testing
       ,AQTO.CaseSubmitDate as CASE_SubmitDate
       ,AQTH.BusinessUID
       ,AQTH.FirmName
       ,AQTH.SupervisorUID
       ,AQTH.SupervisorName
       ,AQTH.BQMUID
       ,AQTH.BQMName
       ,AQTH.AQMUID
       ,AQTH.AQMName
       ,CASE  AQTO.InitialStatus WHEN 'A1 Suitable and Complete' THEN 'Passed'
								WHEN 'A2 Suitable and Acceptable' THEN 'Passed'
								WHEN 'First time pass' THEN 'Passed'
								WHEN 'First time pass with feedback' THEN 'Passed'
										   ELSE CASE  WHEN AQTO.FinalWorkFlowStatus in ('Reject','Unsuitable advice') THEN 
															    CASE AQTO.FinalCode WHEN 752 THEN 'Unsuitable advice'
																				WHEN 753 THEN 'Unsuitable advice'
																				WHEN 757 THEN 'Unsuitable advice'
																				WHEN 352 THEN 'Unsuitable advice'
																				WHEN 362 THEN 'Unsuitable advice'
																	ELSE 'Queried' END  
                     							ELSE 'Queried' END END AS Result  --updated 29/7/20 SH
  
from      #AQT_OUTCOMES AQTO
left join dbo.mi_aqt_ReportingHierarchy AQTH on AQTH.AdviserGUID = AQTO.AdviserGUID
JOIN #LOBCODES lob on lob.ShortCode = AQTO.ProdShortName
where   AQTH.AdviserUID is not null;

END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

