CREATE PROCEDURE [logi].[pr_Ringo_AdviserAQTChkdCasesNew_Backup20210827SC]
                @AdviserUID      varchar(7)
               ,@PtlCode         varchar(10)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

