	    or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

--IF @AdviserUID != ''
--BEGIN

--SELECT @AdviserGuid = marh.AdviserGUID
--FROM   mi_aqt_ReportingHierarchy marh
--WHERE  marh.AdviserUID = @AdviserUID;


SELECT distinct
		 case when  CFQ.[CFQ_QuestionCode] = 3274 then 'Wealth'
			  when CFQ.[CFQ_QuestionCode] = 3288 then 'Mortgage'	
			  when CFQ.[CFQ_QuestionCode] = 3304 and saca.CASE_CaseReference not like 'H%' then 'Protection'	
			  when CFQ.[CFQ_QuestionCode] = 3304 and saca.CASE_CaseReference like 'H%' then 'Owl Panel'
			  when CFQ.[CFQ_QuestionCode] = 3314 then 'Owl Single-Tie'
			  else NULL end as LOB
	  ,saca.CASE_CaseReference Advice
	  ,BQR.[BQR_ID]
      ,BQR.[BQR_ParentID]
      ,BQR.[BQR_BusinessQualityID]
	  ,CFQ.[CFQ_QuestionCode] Code
	  ,CFQ.[CFQ_Description] Question
	  ,BQC.BQC_Description as Answer
      ,BQR.[BQR_CreatedDate] as [Check Date]
      ,BQR.[BQR_UpdatedDate] as [Answer Date]
  into #DocCheck  
  FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_Insight_BusinessQualityResult] BQR
  left join [dbo].[sa_Insight_SalesCase] saca on saca.[CASE_ID] = BQR.BQR_CaseID
  left join [dbo].[sa_Insight_ComplianceFormQuestion] CFQ on CFQ.[CFQ_ID] = BQR.[BQR_QuestionID]
  left join [dbo].[sa_Insight_ComplianceFormSection] CFS on CFS.[CFS_ID] = CFQ.[CFQ_SectionID]
  left join [dbo].[sa_Insight_BusinessQualityCode] BQC on BQC.BQC_Code = BQR.BQR_Code
	where	CFQ.[CFQ_QuestionCode] in ('3274','3288','3304','3314') and 
			BQC.BQC_Description in ('Yes','No') 

Select	
cco.AssessorUID
       ,FirstNameATT.ATTL_AttributeValue +' ' + LastNameATT.ATTL_AttributeValue 
	   ,CaseID
       ,cco.Assessor
       ,AQTH.AdviserUID
       ,AQTH.Adviser
       ,cco.Advice
       ,cco.InitialCheck as BQ_CheckDate
	   ,ProdConfig.RegulationCategory 
	   ,cco.InitialResult as Status
       ,cco.Submitted as CASE_SubmitDate
       ,AQTH.BusinessUID
       ,AQTH.FirmName
       ,AQTH.SupervisorUID
       ,AQTH.SupervisorName
       ,AQTH.BQMUID
       ,AQTH.BQMName
       ,AQTH.AQMUID
       ,AQTH.AQMName
--	   ,FinalWorkflow AS Result --17/5/17 SI
--	   ,case when cco.FinalResult like 'C%' then 'Reject' else cco.FinalResult end as Result -- Added 20/4/18
	   ,case when cco.FinalWorkflow = 'Action Required' then 'TBC'  -- added 24/05/18 SI
			 when cco.FinalWorkflow = 'Not Proceeded With' then cco.FinalWorkflow else 
	   (case when cco.InitialResult like 'A1%' or cco.initialResult like 'A2%' or cco.initialResult like 'First time pass%' then 'Pass'
			 when (cco.FinalResult like 'A3%' or cco.FinalResult like 'B%' or cco.FinalResult like 'C%' or 
				   cco.FinalResult like 'Unclear action%' or cco.FinalResult like 'Unsuitable%') and cco.FinalWorkflow in ('Reject','Unsuitable advice') then 'Unsuitable advice'
			 else 'Suitable post clarification' end) end as Result
		,dc.Answer
from mi_insight_CaseCheckOutcomes cco
join sa_insight_SalesCase saca on cco.Advice = saca.CASE_CaseReference 
join (Select distinct ATTL_ParentID, ATTl_AttributeID, ATTL_AttributeValue
		from sa_insight_AttributeLink atl
		inner join sa_insight_Attribute att on att.ATT_ID = atl.ATTL_AttributeID
		where ATT_Name = 'CASE.CLIENTFIRSTNAME') FirstNameATT
		on FirstNameATT.ATTL_ParentID = saca.CASE_ID
join (Select distinct ATTL_ParentID, ATTl_AttributeID, ATTL_AttributeValue
		from sa_insight_AttributeLink atl
		inner join sa_insight_Attribute att on att.ATT_ID = atl.ATTL_AttributeID
		where ATT_Name = 'CASE.CLIENTSURNAME') LastNameATT
		on LastNameATT.ATTL_ParentID = saca.CASE_ID
join (select distinct ProductShortName, RegulationCategory
			from dbo.mi_insight_ConfigProductTypeReplacement) ProdConfig
			on ProdConfig.ProductShortName = cco.Product
left join dbo.mi_aqt_ReportingHierarchy AQTH on AQTH.AdviserUID = cco.AdviserUID
left join #DocCheck dc on dc.Advice = cco.Advice
where cco.AdviserUID is not null
and   cco.Submitted >= '01-DEC-2013'
AND   cco.InitialCheck>= DATEADD(mm,-12,dateadd(dd,0,datediff(dd,0,GETDATE()))) --update 28.1.19 SI
AND   saca.CASE_CaseReference != '0'
AND	  aqth.AdviserUID is not null
--And   CaseID = '551012248'
AND   (AQTH.AdviserUID = @AdviserUID or AQTH.BusinessUID = @AdviserUID) --updated 14.3.17 SI
Order by FirstNameATT.ATTL_AttributeValue +' ' + LastNameATT.ATTL_AttributeValue 

END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
