*/ --Above code replaced with below in order to better categorise products

Select distinct ProductShortName as ShortCode, case when RegulationCategory = 'SpInv' then 'SI' else RegulationCategory end as 'LOB' 
into #LOBCodes
From dbo.mi_insight_ConfigProductTypeReplacement order by ProductShortName;


WITH CTE_AQTCHECK As (
	select saca.CASE_CaseReference as Advice
		  ,CASE_AdviserID as AdviserGUID
		  ,'Not Checked' as CaseOutcome
		  ,prty.PROD_ShortName     as Product  
