/******************************************************************************************
Name  : [logi].[pr_ringo_AdviserCOBReplacements]
Author      : S Inglis
Date  : 09/12/2016

Purpose     : This report is used for Project Ringo - Enhancements. The recipients are:
                  1) T&C Team

              The report name is "Adviser COB Replacements" and is found on the "BQM MI" 
              menu. This report displays: 
              - Client and Policy details of COB Replacements



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_AdviserCOBReplacements] '1000190', 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author		Description
----        ------		-----------		
7-11-17		S Inglis	Update to look at OWS for Provider and Client details
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_ringo_AdviserCOBReplacements]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(15)
AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016


EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
												   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
	    or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID;
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
	BEGIN
		IF @AdviserUID != ''
		BEGIN
						select	miuh.UserUID as AdviserUID,
								miuh.UserName,
								miuh.BusinessUID,
								miuh.BusinessCompanyName,
								bpol.BPOL_BackOfficeID,
								MAX(attlsw.ATTL_AttributeValue) as IsSwitch, 
								max(attlrep.ATTL_AttributeValue) as IsReplacement,
								prov.DisplayName as CompanyName,
								pers.FirstName +' '+pers.LastName as ClientName
						from	dbo.mi_insight_KPIPopulation pop
						join dbo.sa_insight_SalesCase sc on sc.CASE_AdviserID = pop.UserID
						JOIN dbo.mi_insight_UserHierarchy miuh ON  sc.CASE_AdviserID = miuh.UserGUID
						join dbo.sa_insight_BasicPolicy as bpol on bpol.BPOL_ParentID = sc.CASE_ID 
						join (select	distinct ProductType, RegulationCode
							  from	dbo.mi_insight_ConfigProductTypeReplacement
							  where   RegulationCode = 'COB') RegGrp on RegGrp.ProductType = bpol.BPOL_ProductType
						join sa_insight_KPI kpi on kpi.KPI_Code = 'COBREP' and kpi.KPI_Type = 1	-- COB Replacement & Adviser KPI
						left join dbo.sa_insight_Attribute AS attrsw ON attrsw.ATT_Name = 'PRODUCT.SWITCH'
						left JOIN dbo.sa_insight_AttributeLink AS attlsw ON attlsw.ATTL_ParentID = bpol.BPOL_ID and attlsw.ATTL_AttributeID = attrsw.ATT_ID
						left join dbo.sa_insight_Attribute AS attrrep ON attrrep.ATT_Name = 'CASE.REPLACEMENT'
						left JOIN dbo.sa_insight_AttributeLink AS attlrep ON attlrep.ATTL_ParentID = sc.CASE_ID and attlrep.ATTL_AttributeID = attrrep.ATT_ID
						left join sa_ows_Policies pol on pol.PolicyID = bpol_BackOfficeID
						left join StaticData.sa_ows_Provider prov on prov.InternalProviderID = pol.InternalProviderID
						left join sa_ows_Sale sale on sale.SaleID = pol.SaleID --Update 7.11.17
						left join sa_ows_Person pers on pers.PersonID = sALE.PersonID -- Update 7.11.17
						WHERE	sc.CASE_SubmitDate	between DATEADD(year,-1,GETDATE())and		getdate()
						and		RegGrp.RegulationCode = 'COB'			--A COB case
						and		ISNUMERIC(bpol.BPOL_BackOfficeID) = 1	--CaseID is valid
						and		bpol.BPOL_BackOfficeID <> '0'			--Unwanted DUPLICATE setting
						and		bpol.BPOL_ProductType <> 25				--Ignore DUPLICATEs
						and		pop.UserJobTitleCode in (4,42)			--4=Adviser;42=Schedule E Seller 
						and		pop.COBCompetencyCode = 3				--Fully Competent
						and     (attlrep.ATTL_AttributeValue in ('Yes','yes') or attlsw.ATTL_AttributeValue in ('Yes','yes'))
						and     miuh.UserUID = @AdviserUID
						group	by bpol.BPOL_BackOfficeID,miuh.UserUID,
        								miuh.username,
								miuh.BusinessUID,
								miuh.BusinessCompanyName,prov.DisplayName,
								pers.FirstName +' '+pers.LastName

		END

	END

END



GO
