CREATE PROCEDURE [logi].[pr_ringo_AdviserCompetencyAndAssessment]
      @PtlCode		  varchar(255),
	  @AdviserUID	  varchar (7),
	  @FirmName		  varchar (7)
AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'AdviserCPDHours';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + cast (@AdviserUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @AdviserUID
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin
With CTE_Competence as(
select      Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            case when ab.ASB_RESULT = 2 then count (ab.ASB_RESULT) end as Failed, 
            case when ab.ASB_RESULT = 1 then count (ab.ASB_RESULT) end as Passed,
            ab.ASB_CompletedDate
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
where 1=1
  and Attendee.UserUID = @AdviserUID
  and ASB_Status = 4 
--and       ass.ASS_Description = 'Competence Assessment ICOB'
--and         trk.TCT_Description = 'DT14 - Full Competence'
and ASS_Description like 'Competence%'
and ASB_CompletedDate > DATEADD(year,-1,getdate())
Group by	Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            ab.ASB_Result, 
            ab.ASB_CompletedDate
),
CTE_Comp as
(select
ASS_Description
,ASB_AttendeeID
,COUNT(Failed) as Failed
,COUNT(passed) as Passed
from CTE_Competence
Group by ASS_Description,ASB_AttendeeID),

CTE_FandB as
(Select
ASB_AttendeeID,
ASS_description,
case when Failed = 1 and Passed = 1 then 'Yes' else 'N/A' end as 'Fail and Subsequent Pass'
from CTE_Comp),

CTE_CompAss as
			(select      
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            case when ab.ASB_RESULT = 2 then 'Fail' when ab.ASB_Result = 1 then 'Pass' end as Result,
            ab.ASB_CompletedDate,
            fandb.[Fail and Subsequent Pass]
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
            left  JOIN CTE_FandB fandb on fandb.ASS_Description = ass.ASS_Description 
where 1=1
--			and Attendee.UserUID = @AdviserUID
			and ASB_Status = 4 
			and ass.ASS_Description like 'Competence%'
			and ASB_CompletedDate > DATEADD(year,-1,getdate())
Group by	ab.ASB_AttendeeID,
            ass.ASS_Description,
            ab.ASB_Result, 
            ab.ASB_CompletedDate,
            fandb.[Fail and Subsequent Pass])

Select	 1 as QueryNumber,
		 'COB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate,
		 case when ca.ASB_CompletedDate is null then 'N/A' else convert(varchar(11),ca.ASB_CompletedDate) end as 'Competency Date Check',
		 case when ca.Result is null then 'N/A' else ca.Result end as 'Outcome',
		 case when ca.[Fail and Subsequent Pass] is null then 'N/A' else ca.[Fail and Subsequent Pass] end as 'Fail and Subsequent Pass',
		 marh.AdviserUID
		-- 'COMPETENCY DATE CHECK'
		-- 'COMPETENCY OUTCOME'
		-- 'FAIL AND SUB PASS'
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                      And cobcomp.UC_BusinessArea = 3
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                                        And cobcode.Code_CodeType = 55
left join CTE_CompAss ca on ca.ASB_AttendeeID = marh.AdviserGUID and ca.ASS_Description = 'Competence Assessment COBS'                                                       
where 1=1
And	  marh.AdviserUID  = @AdviserUID 
And   marh.BusinessUID = @FirmName 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') = 
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
                  From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
And	  ISNULL(ca.ASB_CompletedDate, '01-JAN-1900') =
	  ISNULL((Select Max (ca1.ASB_CompletedDate)
				From CTE_CompAss ca1
				Where ca1.ASB_AttendeeID = ca.ASB_AttendeeID
				and ca1.ASS_Description = 'Competence Assessment COBS'), '01-JAN-1900')

Union

Select 2 as QueryNumber,
		'MCOB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate,
		 case when ca.ASB_CompletedDate is null then 'N/A' else convert(varchar(11),ca.ASB_CompletedDate) end as 'Competency Date Check',
		 case when ca.Result is null then 'N/A' else ca.Result end as 'Outcome',
		 case when ca.[Fail and Subsequent Pass] is null then 'N/A' else ca.[Fail and Subsequent Pass] end as 'Fail and Subsequent Pass',
		 marh.AdviserUID
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                                        And cobcomp.UC_BusinessArea = 2
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                                        And cobcode.Code_CodeType = 55
left join CTE_CompAss ca on ca.ASB_AttendeeID = marh.AdviserGUID and ca.ASS_Description = 'Competence Assessment MCOB'
where 1=1
and   marh.AdviserUID  = @AdviserUID 
And   marh.BusinessUID = @FirmName 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
              From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
And	  ISNULL(ca.ASB_CompletedDate, '01-JAN-1900') =
	  ISNULL((Select Max (ca1.ASB_CompletedDate)
				From CTE_CompAss ca1
				Where ca1.ASB_AttendeeID = ca.ASB_AttendeeID
				and ca1.ASS_Description = 'Competence Assessment MCOB'), '01-JAN-1900')
Union
Select   3 as QueryNumber,
		 'ICOB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate,
		 case when ca.ASB_CompletedDate is null then 'N/A' else convert(varchar(11),ca.ASB_CompletedDate) end as 'Competency Date Check',
		 case when ca.Result is null then 'N/A' else ca.Result end as 'Outcome',
		 case when ca.[Fail and Subsequent Pass] is null then 'N/A' else ca.[Fail and Subsequent Pass] end as 'Fail and Subsequent Pass',
	     marh.AdviserUID
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                                        And cobcomp.UC_BusinessArea = 1
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                      And cobcode.Code_CodeType = 55
left join CTE_CompAss ca on ca.ASB_AttendeeID = marh.AdviserGUID and ca.ASS_Description = 'Competence Assessment ICOBS'
Where marh.AdviserUID  = @AdviserUID 
And   marh.BusinessUID = @FirmName 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
                    From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
And	  ISNULL(ca.ASB_CompletedDate, '01-JAN-1900') =
	  ISNULL((Select Max (ca1.ASB_CompletedDate)
				From CTE_CompAss ca1
				Where ca1.ASB_AttendeeID = ca.ASB_AttendeeID
				and ca1.ASS_Description = 'Competence Assessment ICOBS'), '01-JAN-1900')
UNION
Select   4 as QueryNumber,
		'SI' As Licence,
		 case when uh.UserUID is not null then 'Yes' end as Competency,
		 'N/A' as CompetencyDate,
		 'N/A' as 'Competency Date Check',
		 'N/A' as 'Outcome',
		 'N/A' as 'Fail and Subsequent Pass',
		 uh.UserUID as AdviserUID
FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_UserLicence ul
join mi_insight_UserHierarchy uh on uh.UserGUID = ul.ULIC_UserID
join sa_insight_Licence lic on lic.LIC_ID = ul.ULIC_LicenceID
			and lic.LIC_Code in ('LIC78', 'LIC70', 'LIC69')
Where uh.UserUID  = @AdviserUID
and ul.ULIC_Status = 2
GROUP BY uh.UserUID
UNION
Select   5 as QueryNumber,
		'APS' As Licence,
		 case when uh.UserUID is not null then 'Yes' end as Competency,
		 'N/A' as CompetencyDate,
		 'N/A' as 'Competency Date Check',
		 'N/A' as 'Outcome',
		 'N/A' as 'Fail and Subsequent Pass',
		 uh.userUID as AdviserUID
FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_UserLicence ul
join mi_insight_UserHierarchy uh on uh.UserGUID = ul.ULIC_UserID
join sa_insight_Licence lic on lic.LIC_ID = ul.ULIC_LicenceID
			and lic.LIC_Code in ('LIC110', 'LIC107', 'LIC63', 'LIC104')
Where uh.UserUID  = @AdviserUID
and ul.ULIC_Status = 2
GROUP BY uh.UserUID
order by QueryNumber
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


