GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/06/2016	A Groves	Temporary hardcoded access for JMD supervisors (one level up):
						Antony Lark, Duncan Jones and Philip Potter.
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.	
15/02/2017  S Campbell  Added logic to exclude cancelled SPS entries	SR #464410
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.
07/11/2017  S Inglis	Additon of Business Name
10.10.2018	S Campbell	updated CPD CTE due to Insight schema change - SPS hours no longer
						identified by CPD Award Log table category - now join to			
						Statement of Professional Standing table to identify SPS hours
19.8.2021	S Inglis	Addition of Enhanced Monitoring CTE as per request from Kev Bird
27.8.2021	S Inglis	Addition of AIT and CPDIDD to stored proc
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_ringo_AdviserData]
      @PtlCode		  varchar(255),
	  @AdviserUID	  varchar (7)

AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/



DECLARE @return_value int;
DECLARE @lc_UserUid varchar(7);
DECLARE @lc_UserName varchar(50);
DECLARE @lc_UserJobTitleCodeHO int;
DECLARE @lc_UserJobTitleCodePartner int;
DECLARE @lc_UserJobTitleCodeSupervisor int;
DECLARE @lc_UserJobTitleCodeBQM int;
Declare @LC_SupervisorPermission int;
DECLARE	@lc_EnhancedPAAccess int;		--AG 12/09/2016
DECLARE	@lc_UserBusinessUID	varchar(7);	--AG 13/09/2016


--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
                                                   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
	    or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

WITH CTE_RA as
(SELECT
	   uh.UserUID
	  ,cd.Code_Description
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_RiskAssessment ra
  join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
  join mi_insight_UserHierarchy uh on uh.UserGUID = RA_USR_ID
  where RA_Date = (select max(risk.RA_Date) from sa_insight_RiskAssessment risk where risk.RA_USR_ID = ra.RA_USR_ID)
  and RA_USR_Type = 1
  ),

 CTE_CPD as  --  Updated due to Insight db schema changed - original code below
 (SELECT
uh.UserUID
   ,sum(CPDL_Awarded)/60 as TotalCPDHours
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_CPDAwardLog cpdal
  join mi_insight_UserHierarchy uh on uh.UserGUID = cpdal.CPDL_UserID
  join mi_insight_KPIPopulation pop on pop.UserID = uh.UserGUID and pop.UserJobTitleCode = 4
  join dbo.sa_insight_StatementOfProfessionalStanding sps on sps.SPS_UserID = pop.UserID
  where 1=1
  and CPDL_Status = 1
  and pop.COBCompetencyCode is not null
  and CPDL_PlannedDate between dateadd(year,-1,getdate()) and getdate()
  -- and CPDL_Category = 1  Removed due to Insight db schema change
  and sps.SPS_Status = 2
  and sps.SPS_RenewalDate > DATEADD(ss, -1, DATEADD(month, DATEDIFF(month, 0, getdate()), 0)) --  added 06.11.18 to remove links to expired but active SPS records	
  --and uh.UserUID = @AdviserUID
  group by CPDL_UserID,
 -- CPDL_Structure,
  uh.UserUID),

 CTE_MP as
(select
cl.AgentCode
,agt.DESCN
,agt.Firm
,convert(varchar,DATE_,103) as DateOfBreach
,cac.Description
,Convert(varchar,ExpiryDate,103) as ExpirtyDate
from sa_swift_S_ENQURY enq
join sa_swift_CodeAreaOfConcern cac on cac.Code = enq.AreaOfConcernCode
join sa_swift_S_CLIENT cl on cl.CLIENT_NUM = enq.CLIENT_NUM
join sa_swift_S_AGENTS agt on agt.CODE = cl.AgentCode
where ExpiryDate > getdate()),

 CTE_Tests as
(SELECT TOP 1000
 uh.UserUID as AdviserUID
,count(tst.TST_Description) as 'Test Name'
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_TestBooking tb
  join dbo.sa_insight_TestEvent te on te.TSE_ID = tb.TSB_EventID
  join dbo.sa_insight_CodeDescription cd on cd.Code_Code = tb.TSB_Result and cd.Code_CodeType = 29
  join dbo.sa_insight_CodeDescription cd1 on cd1.Code_Code = tb.TSB_Status and cd1.Code_CodeType = 27
  join dbo.sa_insight_Test tst on tst.TST_ID = te.TSE_TypeID
  join mi_insight_UserHierarchy uh on uh.UserGUID = tb.TSB_AttendeeID
  left join sa_insight_TestProperties tp on tp.TP_TestID = tst.TST_ID
  left join dbo.sa_insight_CodeDescription cd2 on cd2.Code_Code = tp.TP_Mode and cd2.Code_CodeType = 157
  where 1=1
  and cd2.Code_Description != 'Practice'
  --and uh.UserUID = @AdviserUID
  and ((TSE_EndDate between getdate() and dateadd(month,6,getdate()) and cd.Code_Description = 'pending') 
		or (tb.TSB_CompletedDate > dateadd(year,-1,getdate()) and cd.Code_Description in ('Passed','Not Taken','Failed')))
 group by uh.UserUID),

 CTE_SPS as
(Select 
  SPS_AccreditedBodyID
 ,SPS_RenewalDate
 ,SPS_UserID
 ,SPS_Status
 ,Case when SPS_Status = 3 then 'Expired' else convert(varchar(10),SPS_RenewalDate,112) end as Status
 FROM sa_insight_StatementOfProfessionalStanding sps
 WHERE SPS_RenewalDate = (select max(SPS_RenewalDate) 
						  from sa_insight_StatementOfProfessionalStanding sps1 
						  where sps1.SPS_UserID = sps.SPS_UserID
						  and SPS_Status <> 4) or SPS_RenewalDate is null),  --  SC Exclude status 4 (cancelled) when selecting max renewal date

 CTE_Checking as
 (Select 
 up.UPS_UserID
,USPS_Description
,cd.Code_Description
,USPS_Percentage
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_UserPositionSampling ups
  join dbo.sa_insight_CodeDescription cd on cd.Code_Code = ups.USPS_Type and cd.Code_CodeType = 546
  join dbo.sa_insight_UserPosition up on up.UPS_ID = ups.USPS_UserPositionID
  join mi_insight_KPIPopulation uh on uh.UserID = up.UPS_UserID
  where USPS_Percentage = 100
  and (ups.USPS_DateTo > getdate() or ups.USPS_DateTo is null)
  --and usps_type = 0
  and USPS_Description not in ('SPINV', 'RPB')
  --and (COBCompetencyCode = 2 or ICOBCompetencyCode = 2 or MCOBCompetencyCode = 2)
  group by USPS_Description,
       up.UPS_UserID
      ,USPS_Type
	  ,cd.Code_Description
      ,USPS_Percentage),
 
 CTE_EM as
 (Select pop.UserUID,
	   pop.UserName

From  dbo.mi_insight_KPIPopulation pop 
			inner join 	 dbo.sa_Insight_UserTandCTrack		 usertct
								  ON pop.UserID = usertct.USRT_UserID
WHERE USRT_TrackID='00703DA4-855C-41D7-8A95-B768335FF08A'
AND USRT_STATUS=1),	 -- 1 = Open


CTE_CPDIDD as
(SELECT case when isnull(aduid,'1111') in ('4021409','4005013') then 'Owl' else 'Openwork' end as Panel
	  ,UserUID --added 31.7.20 SI
	  ,UserName
	  ,agt.DateStarted --added 31.7.20 SI
	  ,agt.DateLeaving --added 31.7.20 SI
	  ,agt.EMAIL --added 31.7.20 SI
	  ,OwlASMName1 --added 31.7.20 SI
	  ,asm.EMAIL as ASMEmail --added 31.7.20 SI
	  ,BusinessCompanyName
	  ,UserContractStatus
	  ,uh.SupervisorName
	  ,CD_email as FSQOEmail --added 31.7.20 SI
	  ,uh.BQMName
	  ,uh.AQMName
      ,[CPDP_Description]
      ,[CPDP_StartDate]
      ,cd.Code_Description
-- ,al.CPDL_CategoryAuditList
	  ,sum(case when al.CPDL_Status = 1 and (al.CPDL_CategoryAuditList like '%7%' or al.CPDL_CategoryAuditList like '%5%') then CPDL_Awarded else 0 end)/60 as IDDHoursCompleted
  	  ,sum(case when al.CPDL_Status = 1 and (al.CPDL_CategoryAuditList not like '%7%' and al.CPDL_CategoryAuditList not like '%5%') then CPDL_Awarded else 0 end)/60 as NonIDDHoursCompleted
	,Datediff(month,CPDP_StartDate,convert(date,'01-Sep-'+convert(varchar(4),case when datepart(month,CPDP_StartDate)>8 then datepart(year,CPDP_StartDate)+1 else datepart(year,CPDP_StartDate) end)))*1.25 as HoursAllocated
	,(Datediff(month,CPDP_StartDate,convert(date,'01-Sep-'+convert(varchar(4),case when datepart(month,CPDP_StartDate)>8 then datepart(year,CPDP_StartDate)+1 else datepart(year,CPDP_StartDate) end)))*1.25) - (sum(case when al.CPDL_Status = 1 and (al.CPDL_CategoryAuditList like '%7%' or al.CPDL_CategoryAuditList like '%5%') then CPDL_Awarded else 0 end)/60) as HoursRemaining
  FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CPDPlan] p
  join mi_insight_userhierarchy uh on uh.UserGUID = cpdp_userid
  left join sa_insight_CPDAWardlog al on al.CPDL_PlanID = p.CPDP_ID
  left join sa_insight_codedescription cd on cd.Code_Code = p.CPDP_Status and code_codetype = 704
  left join mstt_agents agt on agt.CODE = UserUID --added 31.7.20 SI
  left join mstt_agents asm on asm.CODE = OwlASMUID1 --added 31.7.20 SI
  left join sa_Insight_Staff fsqo on fsqo.STAF_UserID = uh.BQMGUID --added 31.7.20 SI
  left join sa_Insight_ContactDetails on CD_ParentID = fsqo.STAF_ID --added 31.7.20 SI
  where cpdp_targetsapplysps = 0-- and al.CPDL_Status = 1
  and isnull(userjobtitlecodeseller,isnull(userjobtitlecodesupervisor,isnull(userjobtitlecodeBQM,userjobtitlecodesalesmgr))) in (4, 7, 8, 42, 52, 54, 55, 61, 63) and Code_Description = 'Open'
  group by
case when isnull(aduid,'1111')  in ('4021409','4005013') then 'Owl' else 'Openwork' end
	  ,UserUID --added 31.7.20 SI
	  ,UserName
	  ,agt.DateStarted --added 31.7.20 SI
	  ,agt.DateLeaving --added 31.7.20 SI
	  ,agt.EMAIL --added 31.7.20 SI
	  ,OwlASMName1 --added 31.7.20 SI
	  ,asm.EMAIL --added 31.7.20 SI
	  ,BusinessCompanyName
	  ,UserContractStatus
	  ,uh.SupervisorName 
	  ,CD_email --added 31.7.20 SI
	  ,uh.BQMName
	  ,uh.AQMName
      ,[CPDP_Description]
      ,[CPDP_StartDate]
      ,cd.Code_Description
	  ,Datediff(month,CPDP_StartDate,convert(date,'01-Sep-'+convert(varchar(4),case when datepart(month,CPDP_StartDate)>8 then datepart(year,CPDP_StartDate)+1 else datepart(year,CPDP_StartDate) end)))*1.25
  ),

  CTE_Final AS (
 Select 
  kpip.UserUID
 ,kpip.UserName
 ,kpip.BusinessName -- Updated 7.11.17 SI
 ,case when kpip.COBCompetencyCode is null then 0 else cpd.TotalCPDHours end as CPDHours
 ,case when kpip.COBCompetencyCode is null then 'N/A'  else SPS.Status end as SPSDate
 ,ra.Code_Description as RiskAssessment
 ,case when checking.Code_Description is null then 'N/A' else 'Yes' end as '100%Checking'
 ,case when mp.DateOfBreach is null then 'No' else 'Yes' end as MatrixPoints
 ,case when crg.AdviserUID is null then 'No' else 'Yes' end as CrgReferral
 ,case when uls.AdviserUID is null then 'No' else 'Yes' end as UnlicencedSales
 ,case when tests.[Test Name] is null then 0 else tests.[Test Name] end as 'No.OfTests'
 ,case when ub.UID is null then 'No' else 'Yes' end as UnsubmittedBusiness
 ,case when ms.PartnerUID is null then 'No' else 'Yes' end as MysteryShops
 ,case when qc.UID is null then 'No' else 'Yes' end as QualityCalls
 ,case when em.UserUID is null then 'No'else 'Yes' end as EnhancedMonitoring
 ,case when ait.AdviserUID is null then 'No' else 'Yes' end as AIT
 ,idd.IDDHoursCompleted as CPDIDDHours
 from mi_insight_KPIPopulation kpip
 left join CTE_CPD cpd on cpd.UserUID = kpip.UserUID
 left join CTE_MP mp on mp.AgentCode = kpip.UserUID
 left join CTE_RA ra on ra.UserUID = kpip.UserUID
 left join CTE_Tests tests on tests.AdviserUID = kpip.UserUID
 left join CTE_SPS sps on sps.SPS_UserID = kpip.UserID
 left join CTE_Checking checking on checking.UPS_UserID = kpip.UserID
 left join TandC.CRG crg on crg.AdviserUID = kpip.UserUID and Formal = 'Y' and crg.CRGMeetingDate >= dateadd(year,-1,getdate())
 left join TandC.UnlicensedSales uls on uls.AdviserUID = kpip.UserUID and uls.DateofULS >= dateadd(year,-1,getdate())
 left join TandC.UnsubmittedBusiness ub on ub.UID = kpip.UserUID and ub.DateofBreach >= dateadd(year,-1,getdate())
 left join TandC.MysteryShop ms on ms.PartnerUID = kpip.UserUID and convert(date,ms.DateFinalReportIssued) >= dateadd(year,-1,getdate())
 left join tandc.Quality_Calls qc on qc.UID = kpip.UserUID and qc.OutcomeDate >= dateadd(year,-1,getdate())
 left join CTE_EM em on em.UserUID = kpip.UserUID
 left join TandC.AIT ait on ait.AdviserUID = kpip.UserUID
 left join CTE_CPDIDD idd on idd.UserUID = kpip.UserUID
 where kpip.UserUID = @AdviserUID)

 Select top 1 * From CTE_Final
 order by SPSDate


