or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin
select distinct
KPI_ID,
KPI_Name
into #KPIName
from sa_insight_KPI
where KPI_Type in (1,2,3)

select 
UserGUID,
UserUid,
UserName
into #UserDetails
from mi_insight_UserHierarchy
where UserUID = @AdviserUID
 select
 kpi.KPID_KPI_ID,
 kpi.KPID_UserID,
 case when kpimi.ReasonDesc IS NOT NULL THEN cd.Code_Description + ' - ' + kpimi.ReasonDesc ELSE CD.Code_Description END as RedReason
 into #KPI1
 from sa_insight_KPIResult KPI
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 left join mi_insight_KPIResult kpimi on kpimi.KPID_KPI_ID = kpi.KPID_KPI_ID and kpimi.KPID_UserID = kpi.KPID_UserID
 where KPI.KPID_Date >= dateadd(month,-1,convert(date,getdate()))

select 
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
 into #KPI2
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date >= dateadd(month,-2,convert(date,getdate())) and KPID_Date < dateadd(month,-1,convert(date,getdate()))

select
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
  into #KPI3
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date between dateadd(month,-3,convert(date,getdate())) and dateadd(month,-2,convert(date,getdate()))

select
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
  into #KPI4
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date between dateadd(month,-4,convert(date,getdate())) and dateadd(month,-3,convert(date,getdate()))

select
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
  into #KPI5
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date between dateadd(month,-5,convert(date,getdate())) and dateadd(month,-4,convert(date,getdate()))

 select
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
  into #KPI6
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date between dateadd(month,-6,convert(date,getdate())) and dateadd(month,-5,convert(date,getdate()))

 select
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
  into #KPI7
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date between dateadd(month,-7,convert(date,getdate())) and dateadd(month,-6,convert(date,getdate()))

select
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
 into #KPI8
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date between dateadd(month,-8,convert(date,getdate())) and dateadd(month,-7,convert(date,getdate()))

select
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
 into #KPI9
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date between dateadd(month,-9,convert(date,getdate())) and dateadd(month,-8,convert(date,getdate()))
  
select
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
  into #KPI10
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date between dateadd(month,-10,convert(date,getdate())) and dateadd(month,-9,convert(date,getdate()))

select
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
 into #KPI11
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date between dateadd(month,-11,convert(date,getdate())) and dateadd(month,-10,convert(date,getdate()))

select
 KPID_KPI_ID,
 KPID_UserID,
 cd.Code_Description
 into #KPI12
 from sa_insight_KPIResult
 join #UserDetails uh on uh.UserGUID = KPID_UserID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 where KPID_Date between dateadd(month,-12,convert(date,getdate())) and dateadd(month,-11,convert(date,getdate()))

Select distinct
  2 as QueryNo
 ,kpin.KPI_Name
 ,kpi.RedReason as CurrentMonth
 ,case when kpir.ReasonDesc is null then 'N/A' else kpir.ReasonDesc end as ReasonDesc
-- ,kpi.KPID_KPI_ID
 ,kpi1.Code_Description as '1MonthAgo'
 ,kpi2.Code_Description as '2MonthsAgo'
 ,kpi3.Code_Description as '3MonthsAgo'
 ,kpi4.Code_Description as '4MonthsAgo'
 ,kpi5.Code_Description as '5MonthsAgo'
 ,kpi6.Code_Description as '6MonthsAgo'
 ,kpi7.Code_Description as '7MonthsAgo'
 ,kpi8.Code_Description as '8MonthsAgo'
 ,kpi9.Code_Description as '9MonthsAgo'
 ,kpi10.Code_Description as '10MonthsAgo'
 ,kpi11.Code_Description as '11MonthsAgo'
-- ,kpi1.KPID_KPI_ID
 from #KPIName kpin
 left join  #KPI1 kpi on kpi.KPID_KPI_ID = kpin.KPI_ID
 left join #KPI2 kpi1 on kpi1.KPID_KPI_ID = kpin.KPI_ID
 left join #KPI3 kpi2 on kpi2.KPID_KPI_ID = kpin.KPI_ID
 left join #KPI4 kpi3 on kpi3.KPID_KPI_ID = kpin.KPI_ID
 left join #KPI5 kpi4 on kpi4.KPID_KPI_ID = kpin.KPI_ID
 left join #KPI6 kpi5 on kpi5.KPID_KPI_ID = kpin.KPI_ID
 left join #KPI7 kpi6 on kpi6.KPID_KPI_ID = kpin.KPI_ID
 left join #KPI8 kpi7 on kpi7.KPID_KPI_ID = kpin.KPI_ID
 left join #KPI9 kpi8 on kpi8.KPID_KPI_ID = kpin.KPI_ID
 left join #KPI10 kpi9 on kpi9.KPID_KPI_ID = kpin.KPI_ID 
 left join #KPI11 kpi10 on kpi10.KPID_KPI_ID = kpin.KPI_ID
 left join #KPI12 kpi11 on kpi11.KPID_KPI_ID = kpin.KPI_ID
 left join mi_insight_KPIResult kpir on kpir.KPID_KPI_ID = kpi.KPID_KPI_ID and kpir.KPID_UserID = kpi.KPID_UserID
 where kpi.RedReason is not null or kpi1.Code_Description is not null 
    or kpi2.Code_Description is not null or kpi3.Code_Description is not null
	or kpi4.Code_Description is not null or kpi5.Code_Description is not null
	or kpi7.Code_Description is not null or kpi6.Code_Description is not null
	or kpi8.Code_Description is not null or kpi9.Code_Description is not null
	or kpi11.Code_Description is not null or kpi10.Code_Description is not null
 group by   kpin.KPI_Name
 ,kpi.RedReason
 ,kpir.ReasonDesc
 --,kpi.KPID_KPI_ID
 ,kpi1.Code_Description
 ,kpi2.Code_Description
 ,kpi3.Code_Description
 ,kpi4.Code_Description
 ,kpi5.Code_Description 
 ,kpi6.Code_Description
 ,kpi7.Code_Description 
 ,kpi8.Code_Description
 ,kpi9.Code_Description
 ,kpi10.Code_Description
 ,kpi11.Code_Description
 UNION ALL
 select 1 as QueryNo
 --     ,'' as UserUID
 --	  ,'' as UserName
  	  ,'KPI Name' as KPI_Name
 --	  ,'' as KPI_Type
      ,substring(DATENAME(month,dateadd(month,-1,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-1,getdate())) as CurrentMonth
	  ,'Reason' as Reason
      ,substring(DATENAME(month,dateadd(month,-2,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-2,getdate())) as '1MonthAgo'
      ,substring(DATENAME(month,dateadd(month,-3,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-3,getdate())) as '2MonthsAgo'
      ,substring(DATENAME(month,dateadd(month,-4,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-4,getdate())) as '3MonthsAgo'
      ,substring(DATENAME(month,dateadd(month,-5,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-5,getdate())) as '4MonthsAgo'
      ,substring(DATENAME(month,dateadd(month,-6,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-6,getdate())) as '5MonthsAgo'
      ,substring(DATENAME(month,dateadd(month,-7,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-7,getdate())) as '6MonthsAgo'
      ,substring(DATENAME(month,dateadd(month,-8,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-8,getdate())) as '7MonthsAgo'
      ,substring(DATENAME(month,dateadd(month,-9,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-9,getdate())) as '8MonthsAgo'
      ,substring(DATENAME(month,dateadd(month,-10,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-10,getdate())) as '9MonthsAgo'
      ,substring(DATENAME(month,dateadd(month,-11,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-11,getdate())) as '10MonthsAgo'
      ,substring(DATENAME(month,dateadd(month,-12,getdate())),1,3) + ' ' + DATENAME(year,dateadd(month,-12,getdate())) as '11MonthsAgo'
  order by QueryNo
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_AdviserLicences]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/06/2016	A Groves	Temporary hardcoded access for JMD supervisors (one level up):
						Antony Lark, Duncan Jones and Philip Potter
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.						
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_AdviserLicences]
                 @FirmName [varchar](200),
                 @AdviserUID [varchar](50),
                 @PtlCode varchar(8)

AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

print 'setting parameters';
set @ReportName               = 'AdviserCPDHours';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + cast (@AdviserUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
                                                   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
	    or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin
Select 3 as QueryNumber,
       'COB' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
	   IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                      And cobcomp.UC_BusinessArea = 3
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
									  And cobcode.Code_CodeType = 55
Where marh.AdviserUID  = @AdviserUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') = 
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
		      From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
Union
Select 2 as QueryNumber,
       'MCOB' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
	   IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
									  And cobcomp.UC_BusinessArea = 2
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
									  And cobcode.Code_CodeType = 55
Where marh.AdviserUID  = @AdviserUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
              From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
Union
Select 1 as QueryNumber,
       'ICOB' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
       IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
									  And cobcomp.UC_BusinessArea = 1
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                      And cobcode.Code_CodeType = 55
Where marh.AdviserUID = @AdviserUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
			  From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
union
Select 4 as QueryNumber,
       'SI' As Licence,
	   'Competency: N/A' As Competency,
	   'Competency Date: N/A' As CompetencyDate
FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_UserLicence ul
join mi_insight_UserHierarchy uh on uh.UserGUID = ul.ULIC_UserID
join sa_insight_Licence lic on lic.LIC_ID = ul.ULIC_LicenceID
			and lic.LIC_Code in ('LIC78', 'LIC70', 'LIC69')
Where uh.UserUID  = @AdviserUID
and ul.ULIC_Status = 2
--GROUP BY uh.UserUID
UNION
Select 5 as QueryNumber,'APS' As Licence,
	   'Competency: N/A' As Competency,
	   'Competency Date: N/A' As CompetencyDate
FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_UserLicence ul
join mi_insight_UserHierarchy uh on uh.UserGUID = ul.ULIC_UserID
join sa_insight_Licence lic on lic.LIC_ID = ul.ULIC_LicenceID
			and lic.LIC_Code in ('LIC110', 'LIC107', 'LIC63', 'LIC104')
Where uh.UserUID  = @AdviserUID
and ul.ULIC_Status = 2
--GROUP BY uh.UserUID
order by QueryNumber;
			  
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
		  
GO
