GO

/******************************************************************************************
Program:		pr_Ringo_AdviserList
Author:			T Cummings
Date:			23/11/2015

Description:	Given an enterprise, this proc pulls back all the advisers and partners
				within the user's span. The user is identified by their PTL code which is
				a parameter to this proc.

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.		
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
09/02/2018	S Inglis	SR500846 Update to allow people in config with only PA access to
						view data
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_AdviserList]
                 @BusinessUID [varchar](200),
                 @PtlCode varchar(8)

AS 

BEGIN

DECLARE	@return_value int;
DECLARE @lc_UserUid varchar(7);
DECLARE @lc_UserName varchar(50);
DECLARE @lc_UserJobTitleCodeHO int;
DECLARE @lc_UserJobTitleCodePartner int;
DECLARE @lc_UserJobTitleCodeSupervisor int;
DECLARE @lc_UserJobTitleCodeBQM int;
DECLARE	@lc_EnhancedPAAccess int;		--AG 12/09/2016
DECLARE	@lc_UserBusinessUID	varchar(7);	--AG 13/09/2016

EXEC	@return_value = logi.pr_Ringo_UserSecurity	@PtlCode, 
													@UserUid=@lc_UserUid OUTPUT,
													@UserName=@lc_UserName OUTPUT,
													@UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
													@UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
													@UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
													@UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
													@EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
													@UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0)
BEGIN 
	SELECT	marh.AdviserUID,
			marh.Adviser
	FROM	mi_aqt_ReportingHierarchy marh
			inner join dbo.mi_insight_UserHierarchy miuh on miuh.UserUID = marh.AdviserUID
	WHERE	(miuh.UserJobTitleCodeSeller = 4 or miuh.UserJobTitleCodePartner = 5)
	and		marh.BusinessUID = @BusinessUID
	order	by marh.Adviser;
END
ELSE IF @lc_UserJobTitleCodeSupervisor > 0 OR @lc_EnhancedPAAccess = 1 -- SI 09/02/2018
BEGIN
	/*****************************************
	SR473819. AG 25/04/2017. Removed JMD hardcoding	SELECT	marh.AdviserUID,
			marh.Adviser
	FROM	mi_aqt_ReportingHierarchy marh
			inner join dbo.mi_insight_UserHierarchy miuh on miuh.UserUID = marh.AdviserUID
			inner join dbo.mi_insight_UserHierarchy miuh2 on miuh.SupervisorUID = miuh2.UserUID --SI Added 10/6/16
	WHERE	(miuh.UserJobTitleCodeSeller = 4 or miuh.UserJobTitleCodePartner = 5)
	and		marh.BusinessUID   = @BusinessUID
	--and     miuh.SupervisorUID = @lc_UserUid --SI Removed 10/6/16
	and		((miuh.SupervisorUID = @lc_UserUid or miuh2.SupervisorUID = @lc_UserUid)	--SI Added 10/6/16
	or		(@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = miuh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
	or		(@lc_UserUid in ('4007621','4007612','4007578') and miuh.BusinessUID = '2005309'))	--AG 12/09/2016
	order	by marh.Adviser;
	******************************************/
	
	SELECT	marh.AdviserUID,
			marh.Adviser
	FROM	mi_aqt_ReportingHierarchy marh
			inner join dbo.mi_insight_UserHierarchy miuh on miuh.UserUID = marh.AdviserUID
	WHERE	(miuh.UserJobTitleCodeSeller = 4 or miuh.UserJobTitleCodePartner = 5)
	and		marh.BusinessUID   = @BusinessUID
	and		marh.AdviserUID <> '4008514'			--Exclude JMD Test User
	and		(@lc_EnhancedPAAccess = 1				--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser
	or		 @lc_UserUid in (miuh.SupervisorUID,miuh.SupervisorUID2,miuh.SupervisorUID3,miuh.SupervisorUID4,miuh.SupervisorUID5,miuh.SupervisorUID6))	--supervises this adviser or supervisor of supervisor (SOS)
	order	by marh.Adviser;
	
END

END
GO
