CREATE PROCEDURE [logi].[pr_Ringo_AdviserReplacements]
                @AdviserUid      varchar(7)
               ,@PtlCode      varchar(15)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

set @ReportName               = 'Adviser Replacements';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
                                                   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding                                                  
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
		or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--4007578=Elizabeth Yates; 4007612=Paul Coggins; 4007621=Antony Lark	AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

select	miuh.UserUID as AdviserUID,
            miuh.BusinessUID,
            bpol.BPOL_BackOfficeID,
            MAX(attlcic.ATTL_AttributeValue) as IsCIC, 
            max(attlrep.ATTL_AttributeValue) as IsReplacement
  INTO #CICREP
  from	    dbo.mi_insight_KPIPopulation pop
  join dbo.sa_insight_SalesCase sc on sc.CASE_AdviserID = pop.UserID
  JOIN dbo.mi_insight_UserHierarchy miuh ON  sc.CASE_AdviserID = miuh.UserGUID
  join dbo.sa_insight_BasicPolicy as bpol on bpol.BPOL_ParentID = sc.CASE_ID 
  join (select	distinct ProductType, RegulationCode
			from	dbo.mi_insight_ConfigProductTypeReplacement
			where   RegulationCode = 'ICOB'
			) RegGrp on RegGrp.ProductType = bpol.BPOL_ProductType
  join sa_insight_KPI kpi on kpi.KPI_Code = 'CICREP' 
                         and kpi.KPI_Type = 1	-- CIC Replacement & Adviser KPI
  join dbo.sa_insight_Attribute AS attrcic ON attrcic.ATT_Name = 'PRODUCT.RFC'
  JOIN dbo.sa_insight_AttributeLink AS attlcic ON attlcic.ATTL_ParentID = bpol.BPOL_ID 
                                              and attlcic.ATTL_AttributeID = attrcic.ATT_ID
  join dbo.sa_insight_Attribute AS attrrep ON attrrep.ATT_Name = 'CASE.REPLACEMENT'
  JOIN dbo.sa_insight_AttributeLink AS attlrep ON attlrep.ATTL_ParentID = sc.CASE_ID 
                                              and attlrep.ATTL_AttributeID = attrrep.ATT_ID
  WHERE	sc.CASE_SubmitDate	>= DATEADD(year,-1,GETDATE())
  and		RegGrp.RegulationCode = 'ICOB'			--A ICOB case
  and		ISNUMERIC(bpol.BPOL_BackOfficeID) = 1	--CaseID is valid
  and		bpol.BPOL_BackOfficeID <> '0'			--Unwanted DUPLICATE setting
  and		bpol.BPOL_ProductType <> 25				--Ignore DUPLICATEs
  and		pop.UserJobTitleCode in (4,42)			--4=Adviser;42=Schedule E Seller 
  and		pop.ICOBCompetencyCode = 3				--Fully Competent (ICOB/protection)
  and		patindex('%CICR,%',attlcic.ATTL_AttributeValue) > 0	--CICR replacement
  and       miuh.UserUID = @AdviserUID
  and       (attlrep.ATTL_AttributeValue in ('Yes','yes') or attlcic.ATTL_AttributeValue in ('Yes','yes'))
group	by sc.CASE_ID, bpol.BPOL_ID,bpol.BPOL_BackOfficeID,miuh.UserUID,miuh.BusinessUID

select	miuh.UserUID as AdviserUID,
        miuh.BusinessUID,
        bpol.BPOL_BackOfficeID,
        MAX(attlsw.ATTL_AttributeValue) as IsSwitch, 
        max(attlrep.ATTL_AttributeValue) as IsReplacement
into   #COBREP
from	dbo.mi_insight_KPIPopulation pop
join dbo.sa_insight_SalesCase sc on sc.CASE_AdviserID = pop.UserID
JOIN dbo.mi_insight_UserHierarchy miuh ON  sc.CASE_AdviserID = miuh.UserGUID
join dbo.sa_insight_BasicPolicy as bpol on bpol.BPOL_ParentID = sc.CASE_ID 
join (select	distinct ProductType, RegulationCode
	  from	dbo.mi_insight_ConfigProductTypeReplacement
	  where   RegulationCode = 'COB') RegGrp on RegGrp.ProductType = bpol.BPOL_ProductType
join sa_insight_KPI kpi on kpi.KPI_Code = 'COBREP' and kpi.KPI_Type = 1	-- COB Replacement & Adviser KPI
left join dbo.sa_insight_Attribute AS attrsw ON attrsw.ATT_Name = 'PRODUCT.SWITCH'
left JOIN dbo.sa_insight_AttributeLink AS attlsw ON attlsw.ATTL_ParentID = bpol.BPOL_ID and attlsw.ATTL_AttributeID = attrsw.ATT_ID
left join dbo.sa_insight_Attribute AS attrrep ON attrrep.ATT_Name = 'CASE.REPLACEMENT'
left JOIN dbo.sa_insight_AttributeLink AS attlrep ON attlrep.ATTL_ParentID = sc.CASE_ID and attlrep.ATTL_AttributeID = attrrep.ATT_ID
WHERE	sc.CASE_SubmitDate	between DATEADD(year,-1,GETDATE())and		getdate()
and		RegGrp.RegulationCode = 'COB'			--A COB case
and		ISNUMERIC(bpol.BPOL_BackOfficeID) = 1	--CaseID is valid
and		bpol.BPOL_BackOfficeID <> '0'			--Unwanted DUPLICATE setting
and		bpol.BPOL_ProductType <> 25				--Ignore DUPLICATEs
and		pop.UserJobTitleCode in (4,42)			--4=Adviser;42=Schedule E Seller 
and		pop.COBCompetencyCode = 3				--Fully Competent
and     (attlrep.ATTL_AttributeValue in ('Yes','yes') or attlsw.ATTL_AttributeValue in ('Yes','yes'))
and     miuh.UserUID = @AdviserUID
group	by bpol.BPOL_BackOfficeID,miuh.UserUID,
        miuh.BusinessUID


select AdviserUID
      ,'ICOB CIC' as ReplacementType 
      ,COUNT(*) as NoOfReplacements
into #CICCount
from #CICREP
group by AdviserUID      

select AdviserUID
      ,'COB' as ReplacementType 
      ,COUNT(*)   as NoOfReplacements  
into   #COBCount
from   #COBREP
group by AdviserUID  

Select
ISNULL(cobc.AdviserUID,cicc.AdviserUID) as Adviser,
isnull(cicc.NoOfReplacements,0) as CIC,
isnull(cobc.NoOfReplacements,0) as COB
from #CICCount cicc
full outer join #COBCount cobc on cobc.AdviserUID = cicc.AdviserUID
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_ringo_AdviserRiskAssessment]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.				
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_ringo_AdviserRiskAssessment]
      @PtlCode		  varchar(255),
	  @AdviserUID	  varchar (7)

AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 25/04/2017
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 25/04/2017

print 'setting parameters';
set @ReportName               = 'AdviserCPDHours';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + cast (@AdviserUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
												   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 25/04/2017
												   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 25/04/2017
												   
/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
	    or (@lc_UserUid in ('4007621','4007612','4007578','4007848') and uh.BusinessUID = '2005309')
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin

SELECT
	   uh.UserUID
	  ,uh.UserName
	  ,cd.Code_Description
      ,RA_Date
	  ,RA_USR_Type
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_RiskAssessment ra
  join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
  join mi_insight_UserHierarchy uh on uh.UserGUID = RA_USR_ID
  where RA_Date > DATEADD(year,-1,getdate())
  and uh.UserUID = @AdviserUID
  and RA_USR_Type = 1
  order by RA_Date desc
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_AdviserSalesCob]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/06/2016	A Groves	Temporary hardcoded access for JMD supervisors (one level up):
						Antony Lark, Duncan Jones and Philip Potter.
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.	
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.				
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_AdviserSalesCob]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

set @ReportName               = 'pr_Ringo_AdviserSalesTotal';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
												   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
	    or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

with cte_PrdSum as 
(select plans.PlanCategory
       ,polm.CONT_NUM
       ,mphi.ProductGroupName
       ,mphi.ProductSubGroupName
       ,Case when MONTH(agmf.TransactionDate) = MONTH(getdate()) then 12
             when MONTH(agmf.TransactionDate) < MONTH(getdate()) then 12 - (MONTH(getdate()) - MONTH(agmf.TransactionDate))
             when MONTH(agmf.TransactionDate) > MONTH(getdate()) then MONTH(agmf.TransactionDate) - MONTH(getdate())   end as AdjustedMonthNo 
       ,MONTH(agmf.TransactionDate) as MonthNo 
       ,YEAR(agmf.TransactionDate) as YearNo 
       ,substring(DATENAME(MONTH,agmf.TransactionDate),1,3) +  ' ' + DATENAME(YEAR,agmf.TransactionDate)  as AdjustedMonthName
       ,case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                      ,'1006886','1011542','1011587','1011623','1011629'
                                      ,'1011630','1011631','1011632','1011633','1011634','1011635') then 'Openwork'
        else 'Adviser' end  as AgentDistribution
       ,sum(agmf.AMOUNT_PAID) AMOUNT_PAID
from   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_PolicyTransactions] potr
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_Policies] polm on polm.POL_NUM = potr.PolicyID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_expectation] pacc on pacc.TransactionID = potr.ID
left join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_PolicyAgentsB30] pb30 on pb30.PolicyID         = polm.POL_NUM
                                                                                 and pb30.SellingAgentCode = potr.AgentCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_paymentsPending] agmf on agmf.PACC_ID = pacc.ID
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_PLANS] plans on plans.CODE = polm.PLAN_CODE
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodePlanCategories] cpca on cpca.Code = plans.PlanCategory
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodeProducts] copr on copr.Code = polm.ProductCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_ProductHierarchy] mphi on mphi.ProductCode = polm.ProductCode
Where  potr.AgentCode = @AdviserUid
--and    agmf.CreateDateTime >= DATEADD(mm,-12,GETDATE())
and    agmf.CommissionType = 1
and    mphi.ProductCategoryCode = 1 
and    potr.AdminMethod != 'X'
and    agmf.TransactionDate >= DATEADD(mm,-12,GETDATE()) 
--and    potr.CreateDateTime    >= DATEADD(mm,-12,GETDATE()) 
--and    potr.CreateDateTime  = (select MAX (potr1.CreateDateTime)
--                                from   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_PolicyTransactions] potr1
--                                join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_policies] polm1 on polm1.POL_NUM = potr1.PolicyID
--                                where  polm1.POL_NUM = polm.POL_NUM
--                                and    potr1.AdminMethod != 'X'
--                                and    potr1.AgentCode = @UserUid)
group by plans.PlanCategory
       ,polm.CONT_NUM
       ,YEAR(agmf.TransactionDate)  
       ,substring(DATENAME(MONTH,agmf.TransactionDate),1,3) +  ' ' + DATENAME(YEAR,agmf.TransactionDate)
       ,MONTH(agmf.TransactionDate)
       ,mphi.ProductGroupName
       ,mphi.ProductSubGroupName
       ,case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                      ,'1006886','1011542','1011587','1011623','1011629'
                                      ,'1011630','1011631','1011632','1011633','1011634','1011635') then 'Openwork'
        else 'Adviser' end                                
)-- select * from cte_PrdSum order by PlanCategory, CONT_NUM --,PolicyID
select dumo.MonthNo,
       cte_PrdSum.AdjustedMonthName,
       cte_PrdSum.MonthNo,
       cte_PrdSum.YearNo,
       sum(CASE cte_PrdSum.ProductGroupName WHEN 'Pensions'    
           THEN CASE WHEN cte_prdSum.ProductSubGroupName like '%Annuity%' THEN 0 ELSE case cte_PrdSum.AgentDistribution when 'Adviser' then  1 else 0 end END ELSE 0 END) as PensionCount,
       sum(CASE cte_PrdSum.ProductGroupName WHEN 'Pensions'    
           THEN CASE WHEN cte_prdSum.ProductSubGroupName like '%Annuity%' THEN 0 ELSE case cte_PrdSum.AgentDistribution when 'Adviser' then  cte_PrdSum.AMOUNT_PAID else 0 end END ELSE 0 END) as PensionAdviserTotal,
       sum(CASE cte_PrdSum.ProductGroupName WHEN 'Pensions'    
           THEN CASE WHEN cte_prdSum.ProductSubGroupName like '%Annuity%' THEN 0 ELSE case cte_PrdSum.AgentDistribution when 'Adviser' then  0 else cte_PrdSum.AMOUNT_PAID end END ELSE 0 END) as PensionOpenworkTotal,
	   sum(CASE cte_PrdSum.ProductGroupName WHEN 'Pensions'    
           THEN CASE WHEN cte_prdSum.ProductSubGroupName like '%Annuity%' THEN case cte_PrdSum.AgentDistribution when 'Adviser' then  1 else 0 end ELSE 0 END ELSE 0 END) as AnnuityCount,
	   sum(CASE cte_PrdSum.ProductGroupName WHEN 'Pensions'    
           THEN CASE WHEN cte_prdSum.ProductSubGroupName like '%Annuity%' THEN case cte_PrdSum.AgentDistribution when 'Adviser' then  cte_PrdSum.AMOUNT_PAID else 0 end ELSE 0 END ELSE 0 END) as AnnuityAdviserTotal,
	   sum(CASE cte_PrdSum.ProductGroupName WHEN 'Pensions'    
           THEN CASE WHEN cte_prdSum.ProductSubGroupName like '%Annuity%' THEN case cte_PrdSum.AgentDistribution when 'Adviser' then  0 else cte_PrdSum.AMOUNT_PAID  end ELSE 0 END ELSE 0 END) as AnnuityOpenworkTotal,
       sum(CASE cte_PrdSum.ProductGroupName WHEN 'Investment' THEN case cte_PrdSum.AgentDistribution when 'Adviser' then  1 else 0 end ELSE 0 END) as InvestmentCount, 
       sum(CASE cte_PrdSum.ProductGroupName WHEN 'Investment' THEN case cte_PrdSum.AgentDistribution when 'Adviser' then  cte_PrdSum.AMOUNT_PAID else 0 end ELSE 0 END) as InvestmentAdviserTotal, 
       sum(CASE cte_PrdSum.ProductGroupName WHEN 'Investment' THEN case cte_PrdSum.AgentDistribution when 'Adviser' then  0 else cte_PrdSum.AMOUNT_PAID end ELSE 0 END) as InvestmentOpenworkTotal 
from TandC.Ringo_DummyMonths dumo
left join cte_PrdSum on cte_PrdSum.AdjustedMonthNo = dumo.MonthNo
group by dumo.MonthNo,
       cte_PrdSum.AdjustedMonthName,
       cte_PrdSum.MonthNo,
       cte_PrdSum.YearNo order by cte_PrdSum.YearNo,cte_PrdSum.MonthNo;


END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_AdviserSalesCobPlat]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/06/2016	A Groves	Temporary hardcoded access for JMD supervisors (one level up):
						Antony Lark, Duncan Jones and Philip Potter.
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_AdviserSalesCobPlat]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

set @ReportName               = 'pr_Ringo_AdviserSalesTotal';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
												   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding												   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
	    or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

with cte_PrdSum as 
(select polm.CONT_NUM
       ,mphi.RDRType
       ,case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                      ,'1006886','1011542','1011587','1011623','1011629'
                                      ,'1011630','1011631','1011632','1011633','1011634','1011635') then 'Openwork'
        else 'Adviser' end  as AgentDistribution
       ,Case when MONTH(agmf.TransactionDate) = MONTH(getdate()) then 12
             when MONTH(agmf.TransactionDate) < MONTH(getdate()) then 12 - (MONTH(getdate()) - MONTH(agmf.TransactionDate))
             when MONTH(agmf.TransactionDate) > MONTH(getdate()) then MONTH(agmf.TransactionDate) - MONTH(getdate())   end as AdjustedMonthNo 
       ,MONTH(agmf.TransactionDate) as MonthNo 
       ,YEAR(agmf.TransactionDate) as YearNo 
       ,substring(DATENAME(MONTH,agmf.TransactionDate),1,3) +  ' ' + DATENAME(YEAR,agmf.TransactionDate)  as AdjustedMonthName
       ,sum(agmf.AMOUNT_PAID) AMOUNT_PAID
from   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_PolicyTransactions] potr
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_policies] polm on polm.POL_NUM = potr.PolicyID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_expectation] pacc on pacc.TransactionID = potr.ID
left join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_PolicyAgentsB30] pb30 on pb30.PolicyID         = polm.POL_NUM
                                                                                 and pb30.SellingAgentCode = potr.AgentCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_PaymentsPending] agmf on agmf.PACC_ID = pacc.ID
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_PLANS] plans on plans.CODE = polm.PLAN_CODE
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodePlanCategories] cpca on cpca.Code = plans.PlanCategory
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodeProducts] copr on copr.Code = polm.ProductCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_ProductHierarchy] mphi on mphi.ProductCode = polm.ProductCode
Where  potr.AgentCode = @AdviserUid
--and    agmf.CreateDateTime >= DATEADD(mm,-12,GETDATE())
and    mphi.ProductCategoryCode = 1 
and   (mphi.RDRType             = 'ONPLAT' 
or     mphi.ProductProviderCode = 'METLIFE' 
or     mphi.ProductCode         = 'OFPRUFND')
and    agmf.CommissionType = 1
and    potr.AdminMethod != 'X'
and    agmf.TransactionDate >= DATEADD(mm,-12,GETDATE()) 
--and    potr.CreateDateTime    >= DATEADD(mm,-12,GETDATE()) 
group by polm.CONT_NUM
       ,YEAR(agmf.TransactionDate)  
       ,substring(DATENAME(MONTH,agmf.TransactionDate),1,3) +  ' ' + DATENAME(YEAR,agmf.TransactionDate)
        ,MONTH(agmf.TransactionDate)
        ,mphi.RDRType
        ,case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                       ,'1006886','1011542','1011587','1011623','1011629'
                                       ,'1011630','1011631','1011632','1011633','1011634','1011635') then 'Openwork'
         else 'Adviser' end                                
)
select dumo.MonthNo,
       cte_PrdSum.AdjustedMonthName,
       cte_PrdSum.MonthNo,
       cte_PrdSum.YearNo,
       sum(CASE isnull(cte_PrdSum.RDRType,'OFFPLAT') WHEN 'ONPLAT' THEN case cte_PrdSum.AgentDistribution when 'Adviser' then  1 else 0 end ELSE 0 END ) as OnPlatformCount,  
       sum(CASE isnull(cte_PrdSum.RDRType,'OFFPLAT') WHEN 'ONPLAT' THEN case cte_PrdSum.AgentDistribution when 'Adviser' then  cte_PrdSum.AMOUNT_PAID else 0 end ELSE 0 END ) as OnPlatformAdviserTotal,
       sum(CASE isnull(cte_PrdSum.RDRType,'OFFPLAT') WHEN 'ONPLAT' THEN case cte_PrdSum.AgentDistribution when 'Adviser' then  0 else cte_PrdSum.AMOUNT_PAID end ELSE 0 END ) as OnPlatformOpenworkTotal,
       SUM(CASE isnull(cte_PrdSum.RDRType,'OFFPLAT') WHEN 'ONPLAT' THEN 0 ELSE case cte_PrdSum.AgentDistribution when 'Adviser' then  1 else 0 end END ) as OffPlatformCount,
       SUM(CASE isnull(cte_PrdSum.RDRType,'OFFPLAT') WHEN 'ONPLAT' THEN 0 ELSE case cte_PrdSum.AgentDistribution when 'Adviser' then  cte_PrdSum.AMOUNT_PAID else 0 end END ) as OffPlatformAdviserTotal,
       SUM(CASE isnull(cte_PrdSum.RDRType,'OFFPLAT') WHEN 'ONPLAT' THEN 0 ELSE case cte_PrdSum.AgentDistribution when 'Adviser' then  0 else cte_PrdSum.AMOUNT_PAID end END ) as OffPlatformOpenworkTotal
from TandC.Ringo_DummyMonths dumo
left join cte_PrdSum on cte_PrdSum.AdjustedMonthNo = dumo.MonthNo
group by dumo.MonthNo,
       cte_PrdSum.AdjustedMonthName,
       cte_PrdSum.MonthNo,
       cte_PrdSum.YearNo order by cte_PrdSum.YearNo,cte_PrdSum.MonthNo;
       
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_AdviserSalesList]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/06/2016	A Groves	Temporary hardcoded access for JMD supervisors (one level up):
						Antony Lark, Duncan Jones and Philip Potter.
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.	
25/04/2017	A Groves	Removed JMD hardcoding to give Tommy Taylor supervisor of supervisor
						(SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.
22/10/2018	A Groves	SR517189. Cases for Marc Sullivan were not being listed because
						his UID on Insight is 0132 and on Swift it is 0000132 which meant
						that any search for cases using UID 0132 would never link. The fix
						was to add leading zeros where the UID passed into this proc is 
						less than 7 digits.
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_AdviserSalesList]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

set @AdviserUID				  = right('0000000'+@AdviserUID,7)	--AG 22/10/2018

set @ReportName               = 'pr_Ringo_AdviserSalesTotal';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
												   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
	    or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

select polm.START_DATE as DateSubmitted
      ,poli.SaleID as AdviceID
      ,case potr.AdminMethod     when 'A' Then 'Advised'
                                 when 'V' Then 'Advised'
                                 when 'F' Then 'Advised'
                                 when 'G' Then 'Advised'
                                 else 'Non Advised' end as AdminMethod
      ,case plans.PlanCategory WHEN 'MORT' Then 'Mortgages'
                               WHEN 'PROTECT' THEN 'Protection'
                               WHEN 'PEN&INV' THEN 'Cob' end as PlanCategory
      ,polm.PLAN_CODE
      ,polm.PolicyRef
      ,plans.DESCN             
      ,case isnull(mphi.RDRType,'OFPLAT') when 'ONPLAT' then 'On Platform'
                                                        else 'Off Platform' end as RDRType
      ,clie.FIRSTNAMES + ' ' + clie.NAME as ClientName
      ,replace(replace(copr.Description,'RDR On -',''),'RDR Off -','') + 
       case isnull(mpsu.MortgageCategoryID,8865) when 8866 then ' - Buy To Let'
                                                           else '' end as ProdDescr
      ,copr.CompanyCode
      ,case when poli.IsLATWrapper = 1 then 'Yes' when poli.IsLATWrapper = 0 then 'No' when poli.IsLATWrapper is null then 'N/A' end as IncludedInLatWrapper
      ,CASE isnull(mphi.RDRType,'OFFPLAT') WHEN 'OFFPLAT' THEN case isnull(srle.OffPlatformRecommendReplacingExistingArrangements,99) when 1 Then 'Yes' When 0 then 'No' else 'N/A' end else 'N/A' end as OffPlatformReplacement 
      ,case plans.PlanCategory when 'PROTECT' then  case isnull((select MIN(ffmem.ReplacedAsPartOfAdviceID)
        from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_FactFindProtectionsExistingProtections] ffmem
        where  ffmem.SaleId = poli.SaleID),20) when '19' then 'Yes' else 'No' end else 'N/A' end as ProtectionReplacement  
      ,sum(case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                          ,'1006886','1011542','1011587','1011623','1011629'
                                          ,'1011630','1011631','1011632','1011633','1011634','1011635') then 0 else agmf.AMOUNT_PAID end) as AgentAmount
      ,sum(case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                          ,'1006886','1011542','1011587','1011623','1011629'
                                          ,'1011630','1011631','1011632','1011633','1011634','1011635') then agmf.AMOUNT_PAID else 0 end) as OpenworkAmount
from   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_PolicyTransactions] potr
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_policies] polm on polm.POL_NUM = potr.PolicyID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_Expectation] pacc on pacc.TransactionID = potr.ID
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_PLANS] plans on plans.CODE = polm.PLAN_CODE
left join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_PolicyAgentsB30] pb30 on pb30.PolicyID         = polm.POL_NUM
                                                                                 and pb30.SellingAgentCode = potr.AgentCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodePlanCategories] cpca on cpca.Code = plans.PlanCategory
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodeProducts] copr on copr.Code = polm.ProductCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_ProductHierarchy] mphi on mphi.ProductCode = polm.ProductCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_paymentsPending] agmf on agmf.PACC_ID = pacc.ID
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_CLIENT_1] clie on polm.CLIENT_NUM = clie.CLIENT_NUM
join   [prod_zurich_openwork_datawarehouse].[dbo].[msit_MIWarehouseCodesAndDescriptions] mi_codes on mi_codes.Code       = potr.AdminMethod
                                                                                                 and mi_codes.ColumnName = 'AdminMethod'
left join [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_policies] poli on poli.policyId = polm.PolicyRef
left join [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_SrgLetter] srle on srle.SaleID = poli.SaleID
																			and   srle.OffPlatformRecommendReplacingExistingArrangements = 1
left join Policy.sa_ows_MortgageProductSummary mpsu on mpsu.PolicyID = polm.PolicyRef
Where potr.AgentCode = @AdviserUid
--and    plans.PlanCategory in( 'MORT' ,'PEN&INV' ,'PROTECT' ) -- Protection, Mortgage, Pen&Invs
and    potr.AdminMethod != 'X'
and    agmf.CommissionType = 1
--and    agmf.CreateDateTime >= DATEADD(mm,-12,GETDATE())
and    agmf.TransactionDate >= DATEADD(mm,-12,GETDATE()) 
and    isnull(srle.LetterID,-1) = isnull((select top 1 srle1.LetterID
                        from [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_SrgLetter] srle1 
                        where srle1.SaleID = srle.SaleID
                        and   srle1.OffPlatformRecommendReplacingExistingArrangements = 1),-1) 
group by polm.START_DATE
              ,poli.SaleID
              ,case potr.AdminMethod     when 'A' Then 'Advised'
                                         when 'V' Then 'Advised'
                                         when 'F' Then 'Advised'
                                         when 'G' Then 'Advised'
                                         else 'Non Advised' end 
              ,plans.PlanCategory
              ,polm.PLAN_CODE
              ,polm.PolicyRef
              ,plans.DESCN             
              ,mphi.RDRType
			  ,poli.IsLATWrapper
              ,clie.FIRSTNAMES + ' ' + clie.NAME
              ,replace(replace(copr.Description,'RDR On -',''),'RDR Off -','') + 
               case isnull(mpsu.MortgageCategoryID,8865) when 8866 then ' - Buy To Let'
                                                                   else '' end
              ,copr.CompanyCode
            --  ,case isnull(poli.IsLatWrapper,99) when 1 then 'Yes' when 0 then 'No' else 'N/A' end 
              ,CASE isnull(mphi.RDRType,'OFFPLAT') WHEN 'OFFPLAT' THEN case isnull(srle.OffPlatformRecommendReplacingExistingArrangements,99) when 1 Then 'Yes' When 0 then 'No' else 'N/A' end else 'N/A' end 
                ;
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_AdviserSalesTotal]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/06/2016	A Groves	Temporary hardcoded access for JMD supervisors (one level up):
						Antony Lark, Duncan Jones and Philip Potter.
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_AdviserSalesTotal]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

set @ReportName               = 'pr_Ringo_AdviserSalesTotal';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
												   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding												   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
	    or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

with cte_PrdSum as 
(select plans.PlanCategory
             , potr.PolicyID
             --,MONTH(agmf.TransactionDate) RealMonthNo
             --,agmf.TransactionDate
             ,MONTH(agmf.TransactionDate) as AdjustedMonthNo 
             ,YEAR(agmf.TransactionDate) as YearNo 
             ,substring(DATENAME(MONTH,agmf.TransactionDate),1,3) +  ' ' + DATENAME(YEAR,agmf.TransactionDate)  as AdjustedMonthName
              ,sum(agmf.AMOUNT_PAID) AMOUNT_PAID
              ,case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                             ,'1006886','1011542','1011587','1011623','1011629'
                                             ,'1011630','1011631','1011632','1011633','1011634','1011635') then 'Openwork'
               else 'Adviser' end  as AgentDistribution
from   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_policyTransactions] potr
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_Policies] polm on polm.POL_NUM = potr.PolicyID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_expectation] pacc on pacc.TransactionID = potr.ID
left join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_PolicyAgentsB30] pb30 on pb30.PolicyID         = polm.POL_NUM
                                                                                 and pb30.SellingAgentCode = potr.AgentCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_PaymentsPending] agmf on agmf.PACC_ID = pacc.ID
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_PLANS] plans on plans.CODE = polm.PLAN_CODE
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodePlanCategories] cpca on cpca.Code = plans.PlanCategory
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodeProducts] copr on copr.Code = polm.ProductCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_ProductHierarchy] mphi on mphi.ProductCode = polm.ProductCode
Where  potr.AgentCode = @AdviserUid
and    agmf.CommissionType = 1
and    potr.AdminMethod != 'X'
and    agmf.TransactionDate >= DATEADD(mm,-12,GETDATE()) 
--and    potr.CreateDateTime    >= DATEADD(mm,-12,GETDATE()) 
group by plans.PlanCategory
             , potr.PolicyID
             ,MONTH(agmf.TransactionDate)
             ,YEAR(agmf.TransactionDate)
             ,substring(DATENAME(MONTH,agmf.TransactionDate),1,3) +  ' ' + DATENAME(YEAR,agmf.TransactionDate)
             --,agmf.TransactionDate
             , case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                             ,'1006886','1011542','1011587','1011623','1011629'
                                             ,'1011630','1011631','1011632','1011633','1011634','1011635') then 'Openwork'
               else 'Adviser' end
) 
select cte_PrdSum.AdjustedMonthNo
      ,cte_PrdSum.YearNo
      ,cte_PrdSum.AdjustedMonthName
      ,SUM(case cte_PrdSum.PlanCategory when 'MORT' then case cte_PrdSum.AgentDistribution when 'Adviser' then 1 else 0 end else 0 end) as MortgageCount
      ,SUM(case cte_PrdSum.PlanCategory when 'MORT' then case cte_PrdSum.AgentDistribution when 'Adviser' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as MortgageAgentAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'MORT' then case cte_PrdSum.AgentDistribution when 'Openwork' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as MortgageOpenworkAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PEN&INV' then case cte_PrdSum.AgentDistribution when 'Adviser' then 1 else 0 end else 0 end) as PenInvCount
      ,SUM(case cte_PrdSum.PlanCategory when 'PEN&INV' then case cte_PrdSum.AgentDistribution when 'Adviser' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as PenInvAgentAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PEN&INV' then case cte_PrdSum.AgentDistribution when 'Openwork' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as PenInvOpenworkAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PROTECT' then case cte_PrdSum.AgentDistribution when 'Adviser' then 1 else 0 end else 0 end) as ProtectionCount
      ,SUM(case cte_PrdSum.PlanCategory when 'PROTECT' then case cte_PrdSum.AgentDistribution when 'Adviser' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as ProtectionAgentAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PROTECT' then case cte_PrdSum.AgentDistribution when 'Openwork' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as ProtectionOpenworkAmount
from cte_PrdSum
where cte_PrdSum.PlanCategory in ('MORT','PEN&INV','PROTECT')
group by cte_PrdSum.AdjustedMonthNo,cte_PrdSum.AdjustedMonthName,cte_PrdSum.YearNo
order by cte_PrdSum.YearNo,cte_PrdSum.AdjustedMonthNo asc;
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_ringo_AdviserSPS]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/06/2016	A Groves	Temporary hardcoded access for JMD supervisors (one level up):
						Antony Lark, Duncan Jones and Philip Potter.
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.	
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.				
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_ringo_AdviserSPS]
      @PtlCode		  varchar(255),
	  @AdviserUID	  varchar (7)

AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

print 'setting parameters';
set @ReportName               = 'AdviserCPDHours';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + cast (@AdviserUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
												   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
	    or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin
with cte_licence as (
select 
uh.UserName
,uh.UserUID
,case when cd.Code_Description = 'ICOB' then count (uh.useruid) else 0 end as 'ICOB'
,case when cd.Code_Description = 'MCOB' then count (uh.useruid) else 0 end as 'MCOB'
,case when cd.Code_Description = 'COB' then count (uh.useruid) else 0 end as 'COB'
,case when cd.Code_Description = 'ICOB GI Only' then count (uh.useruid) else 0 end as 'ICOB GI Only'
from dbo.sa_insight_UserCompetency uc
join dbo.sa_insight_CodeDescription cd on cd.Code_Code = uc.UC_BusinessArea and cd.Code_CodeType = 534
join dbo.sa_insight_CodeDescription cd1 on cd1.Code_Code = uc.UC_CompetencyLevel and cd1.Code_CodeType = 55
join mi_insight_UserHierarchy uh on uh.UserGUID = uc.UC_OwnerID
join sa_swift_S_AGENTS agt on uh.UserUID = agt.CODE
join sa_swift_s_agents agt1 on agt1.CODE = agt.Manager2Code
join sa_swift_S_AGENTS agt2 on agt2.CODE = uh.BusinessUID
where 1=1
and cd.Code_Description like '%COB%'
and uc.UC_Status = 0
group by 
uh.UserName
,uh.UserUID
,uh.BusinessUID
,case when agt2.TradingName is null then agt2.DESCN else agt2.TradingName end
,agt1.DESCN
,uh.BQMName
,cd.Code_Description
,cd1.Code_Description
,uc.UC_DateAchieved
),

CTE_Lic as (
select 
ctel.UserName
,ctel.UserUID
,case when sum(ctel.icob) > 0 and sum(ctel.mcob) > 0 and sum(ctel.cob) = 0 then 'MCOB' 
 when sum(ctel.icob) > 0 and sum(ctel.mcob) > 0 and sum(ctel.cob) > 0 then 'CMCOB' 
 when sum(ctel.icob) >= 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) > 0 then 'COB'
 when sum(ctel.icob) > 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) = 0 then 'ICOB'
 when sum(ctel.icob) = 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) = 0 and sum(ctel.[ICOB GI Only]) > 0 then 'ICOB GI Only'
 else ' '
 end as 'Licence Type'
,sum(ctel.ICOB) as ICOB
,sum(ctel.MCOB) as MCOB
,sum(ctel.COB) as COB
from cte_licence ctel
group by
ctel.UserName
,ctel.UserUID
)

SELECT uh.useruid as UserUID
	  ,uh.UserName
	  ,lic.[Licence Type] as LicenceType
	  ,uh.BusinessUID
	  ,uh.BusinessCompanyName
	  ,case when staff.STAF_ControlledFunctionStartDate > dateadd (month,-30,getdate()) then staff.STAF_ControlledFunctionStartDate else Null end as ControlledFunction
	  ,case when lic.[Licence Type] not in ('COB','CMCOB') then 'N/A' when staff.STAF_ControlledFunctionStartDate > dateadd (month,-30,getdate()) then 'N/A' when cd.Code_Description = 'Expired' then 'Missing' else accbd.ACB_Description end as AccreditedBody
	  ,case when cd.Code_Description is null then 'N/A' else cd.Code_Description end as 'Status'
	  ,SPS_Status
	  ,SPS_RenewalDate as ExpiryDate
	  ,SPS_CheckDate as DipCheckDate
      ,case when cd1.Code_Description is null then 'N/A' else cd1.Code_Description end as DipCheckOutcome
  FROM mi_insight_UserHierarchy uh
  join CTE_Lic lic on lic.UserUID = uh.UserUID
  left join sa_insight_StatementOfProfessionalStanding sps on sps.SPS_UserID = uh.UserGUID
  left join sa_insight_AccreditedBody accbd on accbd.ACB_ID = sps.SPS_AccreditedBodyID
  left join sa_insight_CodeDescription cd on cd.Code_Code = sps.SPS_Status and cd.Code_CodeType = 700
  left join sa_insight_CodeDescription cd1 on cd1.Code_Code = sps.SPS_CheckOutcome and cd1.Code_CodeType = 729
  left join sa_insight_staff staff on staff.STAF_UserID = uh.UserGUID
  where 1=1
  and uh.UserUID = @AdviserUID
  --and uh.BusinessUID = '1001031'
  and (cd.Code_Description != 'Cancelled' or cd.Code_Description is null)
  and (SPS_RenewalDate = (select max(SPS_RenewalDate) 
						  from sa_insight_StatementOfProfessionalStanding sps1 
						  where sps1.SPS_UserID = sps.SPS_UserID) or SPS_RenewalDate is null)
   and SPS_Status = (select min(sps1.SPS_Status)
					from sa_insight_StatementOfProfessionalStanding sps1
					where sps1.SPS_UserID = sps.SPS_UserID)
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
