print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin

SELECT 
 AdviserUID
,AdviserName
,CustomerName
,ProductSold as Product
,DateofULS as Date
  FROM prod_zurich_openwork_datawarehouse.TandC.UnlicensedSales
  where 1=1 
  and convert(datetime,DateofULS,120) > DATEADD (month,-12,getdate())
  and AdviserUID = @AdviserUID
 
print 'Leaving try';

End

