CREATE PROCEDURE [logi].[pr_ringo_AdviserWrittenCases]
		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200),
        @AdviserUID			varchar(7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_AdviserWrittenCases]
Author      : S Inglis
Date  : 07/06/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Adviser Written Business" and is found on the "BQM MI" 
              menu. This report displays: 
              - Adviser business written in the last 12 months


              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_AdviserWrittenCases] 'ptl91371', 'Logi', '1002350'

AMENDMENT HISTORY
=================
Date        Author		Description
----        ------		-----------
4-10-17		S Inglis	Code updated to reflect where replacement flag is now set
16-10-17	S Inglis	Updated to include mortgage transaction type and total commission
						due to adviser
25-5-18		S Inglis	Addition of Commission Type to report
17-11-20	S Inglis	Addition of isnull around commission type to pick up missing cases
27-8-21		S Inglis	Addition of trust and vulnerable client marker
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 25/04/2017
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 25/04/2017

print 'setting parameters';
set @ReportName               = 'Adviser Written Business';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + cast (@AdviserUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
												   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 25/04/2017
                                                   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 25/04/2017



select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

select Distinct
potr.AgentCode,
WrittenDate,
sale.SaleID,
isnull(Amount,potr.MortgageAmount) as TotalInvestmentAmount,
fixedamount as CommCalculatedAmount, --added 16.10.17 SI
case potr.AdminMethod     when 'A' Then 'Advised'
                                 when 'V' Then 'Advised'
                                 when 'F' Then 'Advised'
                                 when 'G' Then 'Advised'
                                 else 'Non Advised' end as AdminMethod,
pol.PolicyRef,
ph.ProductGroupName as Category,
ph.ProductProviderCode,
ph.RDRType,
ct.FIRSTNAMES +' '+ct.NAME as ClientName,
pn.DESCN as ProductDescription,

case when ph.RegulationDefault = 'COB' and oppol.IsLATWrapper = 1 then 'Yes' when ph.RegulationDefault = 'COB' and oppol.IsLATWrapper = 0 then 'No' else 'N/A' end as LAT,
case when srle.OffPlatformRecommendReplacingExistingArrangements = 1 Then 'Yes' 
											When srle.OffPlatformRecommendReplacingExistingArrangements = 0 then 'No' else 'N/A' end as OffPlatformReplacement, 
case pn.PlanCategory when 'PROTECT' then  case isnull((select pps.AnyReplacementsId
													   from   PolicyOneLink.sa_ows_ProtectionProductSummary pps --updated SI 4-10-17
													   where  pps.PolicyId = pol.PolicyRef),20) 
													   when '19' then 'Yes' else 'No' end else 'N/A' end as ProtectionReplacement,		
inv.ValueName as MortgageTransactionType, --added 16.10.17 SI
potr.CommissionTypeDesc -- added 25.5.18 SI
,case when ppb.IsLife = 1 and ppb.LifeAssuredId <> 10112 then IV.ValueName else '' end as InTrust
,isnull(inp.ValueName,'No') as SpecialCareConsidered
from mstt_PolicyTransactions potr
join mstt_Policies pol on pol.POL_NUM = potr.PolicyID
join mstt_ProductHierarchy ph on ph.ProductCode = pol.ProductCode
join mstt_Clients ct on ct.CLIENT_NUM = pol.CLIENT_NUM
join mstt_Plans pn on pn.CODE = potr.CommPlanCode
join mstt_Commissions com on com.TransactionID = potr.ID and com.AGENT_CODE = potr.AgentCode and isnull(com.CommissionType,1) = 1 --added 16.10.17 SI
left join sa_ows_Policies oppol on oppol.PolicyID = pol.PolicyRef
left join sa_ows_Sale sale on sale.SaleID = oppol.SaleID
left join sa_ows_SrgLetter srle on srle.SaleID = sale.SaleID
left join vw_ows_MortgageRecommendedSolution mps on mps.PolicyID = oppol.PolicyID -- added 16.10.17 SI
left join StaticData.sa_ows_InputValues inv on inv.InputID = mps.TransactionTypeID -- added 16.10.17 SI
left join PolicyOneLink.sa_ows_ProtectionProductSummary PPS on pps.PolicyId = oppol.PolicyID
left outer join PolicyOneLink.sa_ows_ProtectionProductBenefit PPB on PPB.ProtectionProductSummaryID = PPS.ProtectionProductSummaryID 
left join StaticData.sa_ows_InputValues IV on IV.InputID = PPB.TobeHeldInTrustId
left join sa_ows_FactFindOverviewClientDetails ocd on ocd.SaleID = sale.SaleID
left join StaticData.sa_ows_InputValues inp on inp.InputID = isnull(ocd.AppropriateForSpecialCareNonOwlID,ocd.AppropriateForSpecialCareID)
where WrittenDate >= dateadd(year,-1,getdate()) 
and potr.AgentCode = @AdviserUID 
and TransType = 39
and isnull(Amount,MortgageAmount) > 1
and potr.AdminMethod != 'X'
order by WrittenDate

End

END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


