CREATE PROCEDURE [logi].[pr_ringo_CPDIDD]
				 @PtlCode		varchar(10),
				 @AQMUID		varchar(10) = 'View All',
				 @AdviserUID	varchar(7) = null,
				 @BusinessUID	varchar(7) = null,
				 @SupervisorUID varchar(7) = null,
				 @DeepSpan		varchar(14) = null,
				 @Type			varchar(20)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_CPDIDD]
Author      : S Inglis
Date  : 05/04/2019

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "CPD IDD" and is found on the "BQM MI" 
              menu. This report displays: 
              - CPD IDD Plans for all advisers


              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_CPDIDD]

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
31.7.20		S Inglis		  On the back of feedback from Natalia in Owl the following
							  details have been added to the report:
								 Adviser’s UID
								 Adviser’s start date
								 Adviser’s leaving date 
								 Adviser’s Email address
								 Adviser’s phone number
								 ASM name
								 ASM email address
								 FSQO email address
21.8.20		S Inglis		Request from D Burchell and N Mensfel to update report to include
							total hours due depending on plan start date and total hours 
							remaining
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/



/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/

Begin

SELECT case when isnull(aduid,'1111') in ('4021409','4005013') then 'Owl' else 'Openwork' end as Panel
	  ,UserUID --added 31.7.20 SI
	  ,UserName
	  ,agt.DateStarted --added 31.7.20 SI
	  ,agt.DateLeaving --added 31.7.20 SI
	  ,agt.EMAIL --added 31.7.20 SI
	  ,OwlASMName1 --added 31.7.20 SI
	  ,asm.EMAIL as ASMEmail --added 31.7.20 SI
	  ,BusinessCompanyName
	  ,UserContractStatus
	  ,uh.SupervisorName
	  ,CD_email as FSQOEmail --added 31.7.20 SI
	  ,uh.BQMName
	  ,uh.AQMName
      ,[CPDP_Description]
      ,[CPDP_StartDate]
      ,cd.Code_Description
-- ,al.CPDL_CategoryAuditList
	  ,sum(case when al.CPDL_Status = 1 and (al.CPDL_CategoryAuditList like '%7%' or al.CPDL_CategoryAuditList like '%5%') then CPDL_Awarded else 0 end)/60 as IDDHoursCompleted
  	  ,sum(case when al.CPDL_Status = 1 and (al.CPDL_CategoryAuditList not like '%7%' and al.CPDL_CategoryAuditList not like '%5%') then CPDL_Awarded else 0 end)/60 as NonIDDHoursCompleted
	,Datediff(month,CPDP_StartDate,convert(date,'01-Sep-'+convert(varchar(4),case when datepart(month,CPDP_StartDate)>8 then datepart(year,CPDP_StartDate)+1 else datepart(year,CPDP_StartDate) end)))*1.25 as HoursAllocated
	,(Datediff(month,CPDP_StartDate,convert(date,'01-Sep-'+convert(varchar(4),case when datepart(month,CPDP_StartDate)>8 then datepart(year,CPDP_StartDate)+1 else datepart(year,CPDP_StartDate) end)))*1.25) - (sum(case when al.CPDL_Status = 1 and (al.CPDL_CategoryAuditList like '%7%' or al.CPDL_CategoryAuditList like '%5%') then CPDL_Awarded else 0 end)/60) as HoursRemaining
  FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CPDPlan] p
  join mi_insight_userhierarchy uh on uh.UserGUID = cpdp_userid
  left join sa_insight_CPDAWardlog al on al.CPDL_PlanID = p.CPDP_ID
  left join sa_insight_codedescription cd on cd.Code_Code = p.CPDP_Status and code_codetype = 704
  left join mstt_agents agt on agt.CODE = UserUID --added 31.7.20 SI
  left join mstt_agents asm on asm.CODE = OwlASMUID1 --added 31.7.20 SI
  left join sa_Insight_Staff fsqo on fsqo.STAF_UserID = uh.BQMGUID --added 31.7.20 SI
  left join sa_Insight_ContactDetails on CD_ParentID = fsqo.STAF_ID --added 31.7.20 SI
  where cpdp_targetsapplysps = 0-- and al.CPDL_Status = 1
  and isnull(userjobtitlecodeseller,isnull(userjobtitlecodesupervisor,isnull(userjobtitlecodeBQM,userjobtitlecodesalesmgr))) in (4, 7, 8, 42, 52, 54, 55, 61, 63)
  and 
(UserUID = @AdviserUID and @BusinessUID is Null and @AQMUID = 'View All' and @SupervisorUID is Null and @DeepSpan is Null and @Type = 'Adviser') OR --Adviser Report
(@AdviserUID is Null and @BusinessUID is Null and @AQMUID = 'View All' and @SupervisorUID is Null and @DeepSpan is Null and @Type = 'Management') OR -- Management View All
(@AdviserUID is Null and BusinessUID = @BusinessUID and @AQMUID = 'View All' and @SupervisorUID is Null and @DeepSpan is Null and @Type = 'Firm') OR --Firm Adviser Report
(@AdviserUID is Null and @BusinessUID is Null and AQMUID = @AQMUID and @SupervisorUID is Null and @DeepSpan is Null and @Type = 'Management') OR -- Management Report
(@AdviserUID is Null and @BusinessUID is Null and @AQMUID = 'View All' and isnull(SupervisorUID,BQMUID) = @SupervisorUID and @DeepSpan = 'Shallow Span' and @Type = 'Supervisor') OR --Supervisor Shallow Span
(@AdviserUID is Null and @BusinessUID is Null and @AQMUID = 'View All' and SupervisorUID is not null --Supervisor Deep Span
					 and @SupervisorUID in (SupervisorUID2, SupervisorUID3, SupervisorUID4, SupervisorUID5, SupervisorUID6, BQMUID) 
					 and @DeepSpan = 'Deep Span' and @Type = 'Supervisor')
  group by
case when isnull(aduid,'1111')  in ('4021409','4005013') then 'Owl' else 'Openwork' end
	  ,UserUID --added 31.7.20 SI
	  ,UserName
	  ,agt.DateStarted --added 31.7.20 SI
	  ,agt.DateLeaving --added 31.7.20 SI
	  ,agt.EMAIL --added 31.7.20 SI
	  ,OwlASMName1 --added 31.7.20 SI
	  ,asm.EMAIL --added 31.7.20 SI
	  ,BusinessCompanyName
	  ,UserContractStatus
	  ,uh.SupervisorName 
	  ,CD_email --added 31.7.20 SI
	  ,uh.BQMName
	  ,uh.AQMName
      ,[CPDP_Description]
      ,[CPDP_StartDate]
      ,cd.Code_Description
	  ,Datediff(month,CPDP_StartDate,convert(date,'01-Sep-'+convert(varchar(4),case when datepart(month,CPDP_StartDate)>8 then datepart(year,CPDP_StartDate)+1 else datepart(year,CPDP_StartDate) end)))*1.25
  order by Panel, Username



End




/****************************************************************************

                  E N D                                                                                     

****************************************************************************/
GO
