CREATE PROCEDURE [logi].[pr_ringo_DeepSpan100PercentChecking]
		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200),
        @AQMUID		        varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpan100PercentChecking]
Author      : S Inglis
Date  : 19/12/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Adviser 100% Checking" and is found on the "BQM MI" 
              menu. This report displays: 
              - Advisers on 100% checking



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpan100PercentChecking] 'ptl91371', 'SQL', 'View All'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
8-5-17		S Inglis		  Update of where clause
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Adviser 100% Checking';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

With CTE_CHECKING as (
SELECT 
 uh.UserName
,UserUID
,USPS_Description
,cd.Code_Description
,USPS_Percentage
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_UserPositionSampling ups
  join dbo.sa_insight_CodeDescription cd on cd.Code_Code = ups.USPS_Type and cd.Code_CodeType = 546
  join dbo.sa_insight_UserPosition up on up.UPS_ID = ups.USPS_UserPositionID
  join mi_insight_KPIPopulation uh on uh.UserID = up.UPS_UserID
  where USPS_Percentage = 100
  and (ups.USPS_DateTo > getdate() or ups.USPS_DateTo is null)
 -- and usps_type = 0
  and USPS_Description not in ('SPINV', 'RPB')
 -- and (COBCompetencyCode = 2 or ICOBCompetencyCode = 2 or MCOBCompetencyCode = 2)
  group by USPS_Description,
	  uh.UserName
	  ,UserUID
      ,USPS_Type
	  ,cd.Code_Description
      ,USPS_Percentage
)

  select uh.AQMName
		,uh.BQMName
		,uh.SupervisorName
		,uh.BusinessCompanyName
		,uh.useruid
		,uh.UserName
		,case when ctech.UserName is null then 'N/A' else ctech.Code_Description end as CheckingReason
  from mi_insight_UserHierarchy uh
  join CTE_CHECKING ctech on ctech.UserUID = uh.UserUID
  where uh.AQMUID = @AQMUID or @AQMUID = 'View All' --updated 8/5/17 SI
  
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
