CREATE PROCEDURE [logi].[pr_ringo_DeepSpanAQTChkdCasesNew]
		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200),
        @AQMUID		        varchar(255) = 'View All'
	    --@KPIName		  varchar (255),
	    --@KPIResult		  varchar(255)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanAQTChkdCasesNew]
Author      : S Inglis
Date  : 10/03/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span AQT Chkd Cases New" and is found on the "BQM MI" 
              menu. This report displays: 
              - AQT Checked Cases and replaces pr_ringo_DeepSpanAQTChkdCases to look at a new table
			  and improve the efficiency of the report



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanAQTChkdCasesNew] 'ptl91371', 'Logi','1002714'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
17/05/2017	S Inglis		  Result data field changed from Case statement to Final Workflow
20/04/2018	S Inglis		  Change of Result to look at Final Result not Final Outcome and show any
							  Final Outcome starting with a C as a Reject
24/05/2018 S Inglis			  Change of Result to use following logic as confirmed by Sarah Wise
							  in AQT: 
							  Final Workflow 'Action Required' = TBC
							  Final Workflow 'Not Proceeded With' = Not Proceeded With
							  Initial Result A1 or A2 = Pass
							  Initial Result A3, B or C AND Final Result A1 or A2 = Passed with Comments
							  Initial Result A3, B or C AND Final Result C = Reject
28/01/2019	S Inglis		  Report updated to show cases in a R12 based on checked date not submitted
							  date
29/07/2020	S Hale			  New case outcomes and workflow updated for Result column

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare          
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 

print 'setting parameters';
set @ReportName               = 'Deep Span AQT Chkd Cases';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams		  = 'None';

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output


/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

Select
cco.AssessorUID
       ,FirstNameATT.ATTL_AttributeValue +' ' + LastNameATT.ATTL_AttributeValue 
	   ,CaseID
       ,cco.Assessor
       ,AQTH.AdviserUID
       ,AQTH.Adviser
       ,cco.Advice
       ,cco.InitialCheck as BQ_CheckDate
		,ProdConfig.RegulationCategory 
		,cco.InitialResult as Status
       ,cco.Submitted as CASE_SubmitDate
       ,AQTH.BusinessUID
       ,AQTH.FirmName
       ,AQTH.SupervisorUID
       ,AQTH.SupervisorName
       ,AQTH.BQMUID
       ,AQTH.BQMName
       ,AQTH.AQMUID
       ,AQTH.AQMName
       --,CASE  cco.InitialResult WHEN 'A1 Suitable and Complete' THEN 'Passed'
							--	WHEN 'A2 Suitable and Acceptable' THEN 'Passed'
							--			   ELSE CASE  cco.FinalResult WHEN 'Reject' THEN 
							--								    CASE cco.FinalWorkflow WHEN 752 THEN 'Reject'
							--													WHEN 753 THEN 'Reject'
							--													WHEN 757 THEN 'Reject'
							--										ELSE 'Queried' END  
       --              							ELSE 'Queried' END END 
--	   ,FinalWorkflow AS Result --17/5/17 SI
--	   ,case when cco.FinalResult like 'C%' then 'Reject' else cco.FinalResult end as Result -- Added 20/4/18
	   ,case when cco.FinalWorkflow = 'Action Required' then 'TBC'  -- added 24/05/18 SI
			 when cco.FinalWorkflow = 'Not Proceeded With' then cco.FinalWorkflow else 
	   (case when cco.InitialResult like 'A1%' or cco.initialResult like 'A2%' or cco.initialResult like 'First time pass%' then 'Pass'
			 when (cco.FinalResult like 'A3%' or cco.FinalResult like 'B%' or cco.FinalResult like 'C%' 
				  or cco.FinalResult like 'Unclear%' or cco.FinalResult like 'Unsuitable%') and cco.FinalWorkflow in ('Reject','Unsuitable advice') then 'Unsuitable advice'
			 else 'Suitable post clarification' end) end as Result  -- updated SH 29/07/2020
from mi_insight_CaseCheckOutcomes cco
join sa_insight_SalesCase saca on cco.Advice = saca.CASE_CaseReference 
join (Select distinct ATTL_ParentID, ATTl_AttributeID, ATTL_AttributeValue
		from sa_insight_AttributeLink atl
		inner join sa_insight_Attribute att on att.ATT_ID = atl.ATTL_AttributeID
		where ATT_Name = 'CASE.CLIENTFIRSTNAME') FirstNameATT
		on FirstNameATT.ATTL_ParentID = saca.CASE_ID
join (Select distinct ATTL_ParentID, ATTl_AttributeID, ATTL_AttributeValue
		from sa_insight_AttributeLink atl
		inner join sa_insight_Attribute att on att.ATT_ID = atl.ATTL_AttributeID
		where ATT_Name = 'CASE.CLIENTSURNAME') LastNameATT
		on LastNameATT.ATTL_ParentID = saca.CASE_ID
join (select distinct ProductShortName, RegulationCategory
			from dbo.mi_insight_ConfigProductTypeReplacement) ProdConfig
			on ProdConfig.ProductShortName = cco.Product
left join dbo.mi_aqt_ReportingHierarchy AQTH on AQTH.AdviserUID = cco.AdviserUID
where cco.AdviserUID is not null
and   cco.Submitted >= '01-DEC-2013'
AND   cco.InitialCheck>= DATEADD(mm,-12,dateadd(dd,0,datediff(dd,0,GETDATE()))) --updated 28.01.19 SI
AND   saca.CASE_CaseReference != '0'
AND	  aqth.AdviserUID is not null
AND   (AQTH.AQMUID = @AQMUID or @AQMUID = 'View All')

print 'Leaving try';

End


END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


