                             and    FirstNameATT1.ATTL_AttributeID = '966F042A-0407-4CC3-8B5F-EA2C37A103E3' )                            
                             ;                            

create index CTE_OUTCOME1 on #AQT_OUTCOMES (Advice,CaseOutcome,ProdShortName);


WITH CTE_OUTCOME
AS (select saca.CASE_CaseReference as Advice
      ,cofs.CFS_Description as CaseOutcome
      ,prty.PROD_ShortName  as ProdShortName 
      ,bqre.BQR_Code   
      ,bqco.BQC_Description as FinalStatus
      ,CaseStatus.Code_Description as FinalWorkFlowStatus
      ,buqu.BQ_CompletedDate FinalCheckDate
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status --updated 28/7/20 SH
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
                                               and CFQ.CFQ_QuestionCode = 1648
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType                                                                                                                                                                                        
WHERE 1=1 --saca.CASE_AdviserID = @AdviserGuid
and   saca.CASE_SubmitDate >= '01-DEC-2013'
AND   saca.CASE_SubmitDate >= DATEADD(mm,-12,dateadd(dd,0,datediff(dd,0,GETDATE())))
AND   saca.CASE_CaseReference != '0'
and   CaseStatus.code_code in (3,4,5,6,7,10,14)
and   cofs.CFS_Description like 'Case Outcome%'
and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --updated 29/7/20 SH
and   CFQ.CFQ_QuestionCode = 1648
and   bqre.BQR_ParentID = buqp.BQP_ID
and   bqco.BQC_Description is not null
AND    buqu.BQ_ActiveMonitoringStatus not in (1,3)
AND    buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
                             from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
                             where  buqu1.BQ_ParentID   = saca.CASE_ID
                             and    buqu1.BQ_Status in (3,4,5,6,7,10,14)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) )
UPDATE #AQT_OUTCOMES                             
 set    FinalStatus             = CTE_OUTCOME.FinalStatus,
        FinalCode               = CTE_OUTCOME.BQR_Code,
        FinalWorkFlowStatus     = CTE_OUTCOME.FinalWorkFlowStatus,
        FinalCheckDate          = CTE_OUTCOME.FinalCheckDate
FROM   #AQT_OUTCOMES aqou1
JOIN   CTE_OUTCOME on CTE_OUTCOME.Advice        = aqou1.Advice
                           and CTE_OUTCOME.CaseOutcome   = aqou1.CaseOutCome
                           and CTE_OUTCOME.ProdShortName = aqou1.ProdShortName;

select  AQTO.AssessorUID
       ,AQTO.ClientName
       ,AQTO.Assessor
       ,AQTH.AdviserUID
       ,AQTH.Adviser
       ,AQTO.Advice
       ,AQTO.InitialCheckDate as BQ_CheckDate
		,LOB
--		,ProdShortName  -- for testing
		,AQTO.InitialStatus as Status
--		,AQTO.FinalStatus as FinStatus  -- for testing
--		,AQTO.InitialWorkFlowStatus as Initial_Status -- for testing
--		,AQTO.FinalWorkFlowStatus as Final_Status  -- for testing
       ,AQTO.CaseSubmitDate as CASE_SubmitDate
       ,AQTH.BusinessUID
       ,AQTH.FirmName
       ,AQTH.SupervisorUID
       ,AQTH.SupervisorName
       ,AQTH.BQMUID
       ,AQTH.BQMName
       ,AQTH.AQMUID
       ,AQTH.AQMName
       ,CASE  AQTO.InitialStatus WHEN 'A1 Suitable and Complete' THEN 'Passed'
								WHEN 'A2 Suitable and Acceptable' THEN 'Passed'
								WHEN 'First time pass' THEN 'Passed'
								WHEN 'First time pass with feedback' THEN 'Passed'
										   ELSE CASE   WHEN AQTO.FinalWorkFlowStatus in ('Reject','Unsuitable advice') THEN 
															    CASE AQTO.FinalCode WHEN 752 THEN 'Unsuitable advice'
																				WHEN 753 THEN 'Unsuitable advice'
																				WHEN 757 THEN 'Unsuitable advice'
																				WHEN 352 THEN 'Unsuitable advice'
																				WHEN 362 THEN 'Unsuitable advice'
																	ELSE 'Queried' END  
                     							ELSE 'Queried' END END AS Result  --updated 29/7/20 SH
  
from      #AQT_OUTCOMES AQTO
left join dbo.mi_aqt_ReportingHierarchy AQTH on AQTH.AdviserGUID = AQTO.AdviserGUID
JOIN #LOBCODES lob on lob.ShortCode = AQTO.ProdShortName
where   AQTH.AdviserUID is not null;

print 'Leaving try';

End

