	AND   cco.Advice != '0'
	
		select aqth.Adviser,aqth.AdviserUID, aqth.FirmName, aqth.SupervisorName, aqth.BQMName, aqth.AQMUID, aqth.AQMName, count(CASE aqto.LOB WHEN 'COBI' THEN AQTO.Advice ELSE NULL END ) AS COBI_SUBMITTED  
