CREATE PROCEDURE [logi].[pr_ringo_DeepSpanAQTStats_Backup20200802AG]
		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200),
        @AQMUID		        varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanAQTStats]
Author      : S Inglis
Date  : 21/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "DeepSpanAQTStats" and is found on the "BQM MI" 
              menu. This report displays: 
              - AQT Stats



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanAQTStats] 'ptl91371', 'Logi'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------

***********************************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
--DECLARE			  @lc_UserName					 varchar(50);
--DECLARE			  @lc_UserJobTitleCodeHO		 int;
--DECLARE			  @lc_UserJobTitleCodePartner	 int;
--DECLARE			  @lc_UserJobTitleCodeSupervisor int;
--DECLARE			  @lc_UserJobTitleCodeBQM		 int;
--Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'pr_Ringo_DeepSpanAQTStats';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output



/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN
	IF @AQMUID != ''
	BEGIN



IF OBJECT_ID('tempdb..#LOBCODES') IS NOT NULL
	DROP TABLE #LOBCODES;

	CREATE TABLE #LOBCODES 
		  (
				ShortCode VARCHAR(10),
				LOB       VARCHAR(10)
		  );


	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('ONIV','COBI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('OIRP','COBI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('OFIN','COBI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('OFIR','COBI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('WOL','COBI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('WOLR','COBI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('IHT','COBI');

	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('PENS','COBP');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('PNSW','COBP');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('PNRP','COBP');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('SIPP','COBP');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('TIP','COBP');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('TIPR','COBP');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('METG','COBP');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('DTOD','RPB');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('DRAW','RPB');

	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('ICOB','ICOB');

	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('MORT','MCOB');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('BTL','MCOB');

	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('ANNS','RPB');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('ANN','RPB');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('ANNC','RPB');

	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('VCT','SI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('VCTR','SI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('EIS','SI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('EISR','SI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('BPRL','SI');
	INSERT INTO #LOBCODES (ShortCode, LOB) VALUES ('BPRR','SI');



WITH CTE_AQTCHECK As (
	select saca.CASE_CaseReference as Advice
		  ,CASE_AdviserID as AdviserGUID
		  ,'Not Checked' as CaseOutcome
		  ,prty.PROD_ShortName     as Product  
		  ,'Not Checked' as InitialResult
		  ,'Not Checked' as FinalResult
		  ,'Not Checked' as FinalWorkflow
		  ,null as FinalCheck
		  ,null AS AssessorUID
		  ,null AS Assessor
		  ,CASE_SubmitDate as Submitted
		  ,lob.LOB
	--	  ,marh.SupervisorUID
	FROM mi_insight_KPIPopulation marh 
    join mi_insight_UserHierarchy uh on uh.UserUID = marh.UserUID and marh.UserJobTitleCode in (4,42) and ADUID != '4005013'
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca on marh.UserID = saca.CASE_AdviserID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BasicPolicy] bapa     on bapa.BPOL_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = bapa.BPOL_ProductType
	join #LOBCODES lob on lob.ShortCode = PROD_ShortName 
--	join mi_insight_UserHierarchy uh on uh.UserUID = marh.AdviserUID
	WHERE  (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
	and   saca.CASE_SubmitDate >= '01-DEC-2013'
	AND   saca.CASE_SubmitDate >= DATEADD(mm,-12,GETDATE())
	AND   saca.CASE_CaseReference != '0'
	AND   (PROD_ShortName not like 'X%' or PROD_ShortName = 'DUP')
	AND   not exists (select 1
					  from   mi_insight_CaseCheckOutcomes aqto
					  where  aqto.Advice = saca.CASE_CaseReference)
	UNION ALL
	Select
	Advice,
	agt.UserID,
	CaseOutcome,
	product,
	InitialResult,
	FinalResult,
	FinalWorkflow,
	FinalCheck,
	AssessorUID,
	Assessor,
	Submitted,
	lob.LOB
	--uh.*
	from mi_insight_CaseCheckOutcomes cco
	join mi_insight_KPIPopulation agt on agt.UserUID = cco.AdviserUID  and agt.UserJobTitleCode in (4,42) 
	join mi_insight_UserHierarchy uh on uh.UserUID = agt.UserUID and ADUID != '4005013'
	join #LOBCODES lob on lob.ShortCode = Product 
	Where 
	      (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
	and   cco.Submitted >= '01-DEC-2013'
	AND   cco.Submitted >= DATEADD(mm,-12,GETDATE())
	AND   cco.Advice != '0'
	
)
		select count(CASE aqto.LOB WHEN 'COBI' THEN AQTO.Advice ELSE NULL END ) AS COBI_SUBMITTED  
		  ,count(CASE aqto.LOB WHEN 'COBI' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS COBI_CHECKED  
		  ,count(CASE aqto.LOB WHEN 'COBI' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS COBI_PASSED  
		  ,count( CASE aqto.LOB WHEN 'COBI' THEN 
							   CASE AQTO.FinalWorkFlow WHEN 'Reject' THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS COBI_REJECT  
		  ,count( CASE aqto.LOB WHEN 'COBP' THEN AQTO.Advice ELSE NULL END ) AS COBP_SUBMITTED  
		  ,count( CASE aqto.LOB WHEN 'COBP' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS COBP_CHECKED  
		  ,count( CASE aqto.LOB WHEN 'COBP' THEN CASE AQTO.InitialResult  WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS COBP_PASSED  
		  ,count( CASE aqto.LOB WHEN 'COBP' THEN 
							   CASE AQTO.FinalWorkFlow WHEN 'Reject' THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS COBP_REJECT  
		  ,count( CASE aqto.LOB WHEN 'MCOB' THEN AQTO.Advice ELSE NULL END ) AS MCOB_SUBMITTED  
		  ,count( CASE aqto.LOB WHEN 'MCOB' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS MCOB_CHECKED  
		  ,count( CASE aqto.LOB WHEN 'MCOB' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS MCOB_PASSED  
		  ,count( CASE aqto.LOB WHEN 'MCOB' THEN 
							   CASE AQTO.FinalWorkFlow WHEN 'Reject' THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS MCOB_REJECT  
		  ,count( CASE aqto.LOB WHEN 'ICOB' THEN AQTO.Advice ELSE NULL END ) AS ICOB_SUBMITTED  
		  ,count( CASE aqto.LOB WHEN 'ICOB' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS ICOB_CHECKED  
		  ,count( CASE aqto.LOB WHEN 'ICOB' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS ICOB_PASSED  
		  ,count( CASE aqto.LOB WHEN 'ICOB' THEN 
							   CASE AQTO.FinalWorkFlow WHEN 'Reject' THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS ICOB_REJECT  
		  ,count( CASE aqto.LOB WHEN 'SI' THEN AQTO.Advice ELSE NULL END ) AS SI_SUBMITTED  
		  ,count( CASE aqto.LOB WHEN 'SI' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS SI_CHECKED  
		  ,count( CASE aqto.LOB WHEN 'SI' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS SI_PASSED  
		  ,count( CASE aqto.LOB WHEN 'SI' THEN 
							   CASE AQTO.FinalWorkFlow WHEN 'Reject' THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS SI_REJECT 
		  ,count( CASE aqto.LOB WHEN 'RPB' THEN AQTO.Advice ELSE NULL END ) AS RPB_SUBMITTED  
		  ,count( CASE aqto.LOB WHEN 'RPB' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS RPB_CHECKED  
		  ,count( CASE aqto.LOB WHEN 'RPB' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS RPB_PASSED  
		  ,count( CASE aqto.LOB WHEN 'RPB' THEN 
							   CASE AQTO.FinalWorkFlow WHEN 'Reject' THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														ELSE NULL END  
														  ELSE null END 
						  ELSE null END) AS RPB_REJECT
	 
	from      CTE_AQTCHECK AQTO
	left join dbo.mi_aqt_ReportingHierarchy AQTH on AQTH.AdviserGUID = AQTO.AdviserGUID;


	END
End
End Try



