****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Competency Assessments';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

SELECT uh.AQMName as SQRMName
	  ,uh.BQMName as QRMName
	  ,uh.SupervisorName
	  ,uh.BusinessCompanyName
	  ,uh.UserName
	  ,tantm.TCTM_Description
	  ,evt.USRTE_DueDate
	  ,cd1.Code_Description as EventStatus
      ,USRTS_NextEventDate
  FROM sa_insight_UserTandCTrackModule usermod
  join sa_insight_TandCTrackModule tantm on tantm.TCTM_ID = USRTS_TrackModuleID
  join sa_insight_UserTandCTrack usertrack on usertrack.USRT_ID =  usermod.USRTS_UserTrackID
  left join sa_insight_UserTandCTrackEvent evt on evt.USRTE_ModuleID = usermod.USRTS_ID
  join mi_insight_UserHierarchy uh on uh.UserGUID = USRT_UserID
  left join sa_insight_CodeDescription cd1 on cd1.Code_Code = evt.USRTE_Status and cd1.Code_CodeType = 505
  where 1=1
  and USRTE_DueDate between dateadd(month,-6,getdate()) and getdate()
  and USRTE_DueDate > '01-Apr-2016'
and evt.USRTE_Status in (5,7)
and ADUID  not in ('4021409','4005013')
and AQMName is not null
and (AQMUID = @AQMUID or @AQMUID = 'View All')
order by AQMName, BQMName,BusinessCompanyName,UserName


print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


