CREATE PROCEDURE [logi].[pr_ringo_DeepSpanCompetencyAssessments]
		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200),
        @AQMUID		        varchar(255) = 'View All'
	    --@KPIName		  varchar (255),
	    --@KPIResult		  varchar(255)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanCompetencyAssessments]
Author      : S Inglis
Date  : 21/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Competency Assessments" and is found on the "BQM MI" 
              menu. This report displays: 
              - Competency Assessments



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanCompetencyAssessments] 'ptl91371', 'Logi'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
24.6.21		S Inglis		Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Competency Assessments';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

With CTE_Competence as(
select      Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            case when ab.ASB_RESULT = 2 then count (ab.ASB_RESULT) end as Failed, 
            case when ab.ASB_RESULT = 1 then count (ab.ASB_RESULT) end as Passed,
            ab.ASB_CompletedDate
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
where 1=1
 -- and Attendee.UserUID = @AdviserUID
  and ASB_Status = 4 
--and       ass.ASS_Description = 'Competence Assessment ICOB'
--and         trk.TCT_Description = 'DT14 - Full Competence'
and ASS_Description like 'Competence%'
and ASB_CompletedDate > DATEADD(year,-1,getdate())
Group by	Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            ab.ASB_Result, 
            ab.ASB_CompletedDate
),
CTE_Comp as
(select
ASS_Description
,ASB_AttendeeID
,COUNT(Failed) as Failed
,COUNT(passed) as Passed
from CTE_Competence
Group by ASS_Description,ASB_AttendeeID),

CTE_FandB as
(Select
ASB_AttendeeID,
ASS_description,
case when Failed = 1 and Passed = 1 then 'Yes' else 'N/A' end as 'Fail and Subsequent Pass'
from CTE_Comp),

CTE_CompAss as
			(select      
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            case when ab.ASB_RESULT = 2 then 'Fail' when ab.ASB_Result = 1 then 'Pass' end as Result,
            ab.ASB_CompletedDate,
            fandb.[Fail and Subsequent Pass]
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
            left  JOIN CTE_FandB fandb on fandb.ASS_Description = ass.ASS_Description 
where 1=1
--			and Attendee.UserUID = @AdviserUID
			and ASB_Status = 4 
			and ass.ASS_Description like 'Competence%'
			and ASB_CompletedDate > DATEADD(year,-1,getdate())
			and Attendee.ADUID not in ('4021409','4005013')
Group by	ab.ASB_AttendeeID,
            ass.ASS_Description,
            ab.ASB_Result, 
            ab.ASB_CompletedDate,
            fandb.[Fail and Subsequent Pass])

Select	 1 as QueryNumber,
		 'COB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate,
		 case when ca.ASB_CompletedDate is null then 'N/A' else convert(varchar(11),ca.ASB_CompletedDate) end as 'Competency Date Check',
		 case when ca.Result is null then 'N/A' else ca.Result end as 'Outcome',
		 case when ca.[Fail and Subsequent Pass] is null then 'N/A' else ca.[Fail and Subsequent Pass] end as 'Fail and Subsequent Pass',
		 marh.AdviserUID,
		 marh.Adviser,
		 marh.FirmName,
	     marh.BQMName,
	     marh.AQMUID,
	     marh.AQMName 
		-- 'COMPETENCY DATE CHECK'
		-- 'COMPETENCY OUTCOME'
		-- 'FAIL AND SUB PASS'
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                      And cobcomp.UC_BusinessArea = 3
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                                        And cobcode.Code_CodeType = 55
left join CTE_CompAss ca on ca.ASB_AttendeeID = marh.AdviserGUID and ca.ASS_Description = 'Competence Assessment COBS'                                                       
where 1=1
--And	  marh.AdviserUID  = @AdviserUID 
--And   marh.BusinessUID = @FirmName 
AND  (marh.AQMUID = @AQMUID or @AQMUID = 'View All')
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   cobcode.Code_Description = 'Fully Competent'
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') = 
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
                  From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
And	  ISNULL(ca.ASB_CompletedDate, '01-JAN-1900') =
	  ISNULL((Select Max (ca1.ASB_CompletedDate)
				From CTE_CompAss ca1
				Where ca1.ASB_AttendeeID = ca.ASB_AttendeeID
				and ca1.ASS_Description = 'Competence Assessment COBS'), '01-JAN-1900')

Union

Select 2 as QueryNumber,
		'MCOB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate,
		 case when ca.ASB_CompletedDate is null then 'N/A' else convert(varchar(11),ca.ASB_CompletedDate) end as 'Competency Date Check',
		 case when ca.Result is null then 'N/A' else ca.Result end as 'Outcome',
		 case when ca.[Fail and Subsequent Pass] is null then 'N/A' else ca.[Fail and Subsequent Pass] end as 'Fail and Subsequent Pass',
		 marh.AdviserUID,
		 marh.Adviser,
		 marh.FirmName,
	     marh.BQMName,
	     marh.AQMUID,
	     marh.AQMName
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                                        And cobcomp.UC_BusinessArea = 2
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                                        And cobcode.Code_CodeType = 55
left join CTE_CompAss ca on ca.ASB_AttendeeID = marh.AdviserGUID and ca.ASS_Description = 'Competence Assessment MCOB'
where 1=1
--and   marh.AdviserUID  = @AdviserUID 
--And   marh.BusinessUID = @FirmName 
AND  (marh.AQMUID = @AQMUID or @AQMUID = 'View All')
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   cobcode.Code_Description = 'Fully Competent'
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
              From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
And	  ISNULL(ca.ASB_CompletedDate, '01-JAN-1900') =
	  ISNULL((Select Max (ca1.ASB_CompletedDate)
				From CTE_CompAss ca1
				Where ca1.ASB_AttendeeID = ca.ASB_AttendeeID
				and ca1.ASS_Description = 'Competence Assessment MCOB'), '01-JAN-1900')
Union
Select   3 as QueryNumber,
		 'ICOB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate,
		 case when ca.ASB_CompletedDate is null then 'N/A' else convert(varchar(11),ca.ASB_CompletedDate) end as 'Competency Date Check',
		 case when ca.Result is null then 'N/A' else ca.Result end as 'Outcome',
		 case when ca.[Fail and Subsequent Pass] is null then 'N/A' else ca.[Fail and Subsequent Pass] end as 'Fail and Subsequent Pass',
	     marh.AdviserUID,
	     marh.Adviser,
	     marh.FirmName,
	     marh.BQMName,
	     marh.AQMUID,
	     marh.AQMName
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                                        And cobcomp.UC_BusinessArea = 1
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                      And cobcode.Code_CodeType = 55
left join CTE_CompAss ca on ca.ASB_AttendeeID = marh.AdviserGUID and ca.ASS_Description = 'Competence Assessment ICOBS'
Where 1=1
--And	  marh.AdviserUID  = @AdviserUID 
--And   marh.BusinessUID = @FirmName 
AND  (marh.AQMUID = @AQMUID or @AQMUID = 'View All')
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   cobcode.Code_Description = 'Fully Competent'
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
                    From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
And	  ISNULL(ca.ASB_CompletedDate, '01-JAN-1900') =
	  ISNULL((Select Max (ca1.ASB_CompletedDate)
				From CTE_CompAss ca1
				Where ca1.ASB_AttendeeID = ca.ASB_AttendeeID
				and ca1.ASS_Description = 'Competence Assessment ICOBS'), '01-JAN-1900')



print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
/****** Object:  StoredProcedure [logi].[pr_ringo_DeepSpanCompetencyAssessmentsAdviserLevel]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [logi].[pr_ringo_DeepSpanCompetencyAssessmentsAdviserLevel]
		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200)
       -- @AQMUID		        varchar(255) = 'View All'
	    --@KPIName		  varchar (255),
	    --@KPIResult		  varchar(255)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanCompetencyAssessmentsQRMLevel]
Author      : S Inglis
Date  : 30/01/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Competency Assessments - Adviser Level" and is found on 
              the "BQM MI" menu. This report displays: 
              - Competency Assessments at Adviser level



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanCompetencyAssessmentsAdviserLevel] 'ptl91371', 'Logi'

AMENDMENT HISTORY
=================
Date        Author			Description
----        ------			-----------
21-2-17		S Inglis		Addition of where clause to only bring back assessments completed
							in current year
13-12-17	S Inglis		Addition of new assessment - Introduction/Disclosure
26/10/2018	A Groves		SR517461 Nicki Rees asked for rows to be returned if either the 
							due date or the completed date are in the current year. 
21/11/2018	J Homer			Correction to include all relevant CAs to above change for SR17461
7/3/2019	S Inglis		Update to Introduction/Disclosure MI to include future bookings	
24.6.21		S Inglis		Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Competency Assessments - Adviser Level';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

Select	Attendee.AQMName,
		Attendee.AQMUID,
		Attendee.BQMName,
		Attendee.BQMUID,
		Attendee.SupervisorName,
		Attendee.BusinessCompanyName,
		attendee.UserGUID,
		Attendee.UserUID,
		Attendee.UserName,
		cod.Code_Description as Competence,
		cobcode.Code_Description AS CompetenceLevel,
		cobcomp.UC_DateAchieved
into #Attendees
From mi_insight_UserHierarchy attendee
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = Attendee.UserGUID 
Join sa_insight_CodeDescription cod on cod.Code_Code = cobcomp.UC_BusinessArea and cod.Code_CodeType = 534
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                                        And cobcode.Code_CodeType = 55
where 	 cobcomp.UC_Status  = '0' 
	And cobcode.Code_Description = 'Fully Competent'
	And cod.Code_Code in (1,2,3)
	And ISNULL(aduid,'999999') not in ('4021409','4005013')

select      Attendee.AQMName,
			Attendee.BQMName,
			Attendee.SupervisorName,
			Attendee.BusinessCompanyName,
			Attendee.UserUID,
			Attendee.UserName,
			Attendee.Competence,
			attendee.CompetenceLevel,
			attendee.UC_DateAchieved,
            ass.ASS_Description,
			ae.ASE_Date,
			cd.Code_Description,
            case when ab.ASB_RESULT = 2 then 'Failed' when ab.ASB_RESULT = 1 then 'Passed' else Null end as Result, 
            ab.ASB_CompletedDate
--			ae.ASE_Date,
--			cd.Code_Description as BookingStatus
into		#ICAssessments
FROM        #Attendees AS Attendee 
            left join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            left JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            left JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID and (case when ass.ASS_Description = 'Competence Assessment MCOB' then 'MCOB'
																						  when ass.ASS_Description = 'Competence Assessment ICOBS' then 'ICOB'
																						  when ass.ASS_Description = 'Competence Assessment COBS' then 'COB' else Null end) = Attendee.Competence
			left join sa_insight_CodeDescription cd on cd.Code_Code = ASB_Status and cd.Code_CodeType = 27
where 1=1
	--and ASB_Status = 4 
	and ASS_Description like 'Competence Assessment%'
	--AG 26/10/2018 Start
	--and (ASB_CompletedDate > DATEADD(year,-1,getdate())or ae.ASE_CreatedDate > DATEADD(year,-1,getdate()))
	and (year(ASE_Date) = year(getdate()) or year(ASB_CompletedDate) = year(getdate()))
	--AG 26/10/2018 End
--	and UserUID = '0138'
--Added 13/12/2017 SI
UNION
select      Distinct
			Attendee.AQMName,
			Attendee.BQMName,
			Attendee.SupervisorName,
			Attendee.BusinessCompanyName,
			Attendee.UserUID,
			Attendee.UserName,
			'Introduction/Disclosure' as Competence,
			attendee.CompetenceLevel,
			attendee.UC_DateAchieved,
            ass.ASS_Description,
			ae.ASE_Date,
			cd.Code_Description,
            case when ab.ASB_RESULT = 2 then 'Failed' when ab.ASB_RESULT = 1 then 'Passed' else Null end as Result, 
            ab.ASB_CompletedDate
--			ae.ASE_Date,
--			cd.Code_Description as BookingStatus
FROM        #Attendees AS Attendee 
            left join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            left JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            left JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID and ass.ASS_Description = 'Introduction/Disclosure'
			left join sa_insight_CodeDescription cd on cd.Code_Code = ASB_Status and cd.Code_CodeType = 27
where 1=1
	--and ASB_Status = 4 
	and ASS_Description like '%Introduction/Disclosure%'
	and (ASB_CompletedDate > DATEADD(year,-1,getdate())or ae.ASE_Date > DATEADD(year,-1,getdate())) --updated 7.3.19 SI
--	and UserUID = '0138'

Order by UserUID--, ASB_CompletedDate 

Select	distinct
		Attendee.AQMName,
		Attendee.AQMUID,
		isnull(Attendee.BQMName, 'No QRM') as BQMName,
		Attendee.BQMUID,
		isnull(Attendee.SupervisorName,'No Supervisor') as SupervisorName,
		Attendee.BusinessCompanyName,
		Attendee.UserUID,
		Attendee.UserName,
		compass.Competence,
		attendee.CompetenceLevel,
		--attendee.UC_DateAchieved,
		compass.ASB_CompletedDate,
		compass.ASE_Date,
		compass.Code_Description,
		compass.ASS_Description, 
		compass.Result 
from #Attendees attendee
left join #ICAssessments compass on compass.UserUID = attendee.UserUID and (attendee.Competence = compass.Competence or compass.Competence = 'Introduction/Disclosure')
--where datepart(year,compass.ASE_Date) = datepart(year,getdate())
where (datepart(year,compass.ASE_Date) = datepart(year,getdate()) or (datepart(year,compass.ASE_Date) = datepart(year,getdate()) +1 AND year(ASB_CompletedDate) = year(getdate()))) -- JH 21/11/18
and   (datepart(year,compass.ASB_CompletedDate) = datepart(year,getdate()) or compass.ASB_CompletedDate is null) -- added 21/02/2017 SI
and Code_Description in ('Booked','Completed','In Progress')
Order by UserUID, ASB_CompletedDate 



Drop table #Attendees
Drop table #ICAssessments


print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

