/****** Object:  StoredProcedure [logi].[pr_ringo_DeepSpanCompetencyAssessmentsQRMLevel]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [logi].[pr_ringo_DeepSpanCompetencyAssessmentsQRMLevel]
		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200),
        @AQMUID		        varchar(255) = 'View All'
	    --@KPIName		  varchar (255),
	    --@KPIResult		  varchar(255)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanCompetencyAssessmentsQRMLevel]
Author      : S Inglis
Date  : 30/01/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Competency Assessments - QRM Level" and is found on 
              the "BQM MI" menu. This report displays: 
              - Competency Assessments completed as a % of overall competency assessments



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanCompetencyAssessmentsQRMLevel] 'ptl91371', 'Logi'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
21-2-17		S Inglis		 Addition of where clause to only bring back assessments completed
							 in current year
13-12-17	S Inglis		 Addition of new assessment - Introduction/Disclosure
29-1-17		S Inglis		 Removal of Competency Achieved date as not needed
24.6.21		S Inglis		Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Competency Assessments - QRM Level';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

Select	Attendee.AQMName,
		Attendee.AQMUID,
		Attendee.BQMName,
		Attendee.BQMUID,
		Attendee.SupervisorName,
		Attendee.BusinessCompanyName,
		attendee.UserGUID,
		Attendee.UserUID,
		Attendee.UserName,
		cod.Code_Description as Competence,
		cobcode.Code_Description AS CompetenceLevel
--		cobcomp.UC_DateAchieved
into #Attendees
From mi_insight_UserHierarchy attendee
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = Attendee.UserGUID 
Join sa_insight_CodeDescription cod on cod.Code_Code = cobcomp.UC_BusinessArea and cod.Code_CodeType = 534
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                                        And cobcode.Code_CodeType = 55
where 	 cobcomp.UC_Status  = '0' 
	And cobcode.Code_Description = 'Fully Competent'
	And cod.Code_Code in (1,2,3)
	And ISNULL(aduid,'999999') not in ('4021409','4005013')

select      Attendee.AQMName,
			Attendee.BQMName,
			Attendee.SupervisorName,
			Attendee.BusinessCompanyName,
			Attendee.UserUID,
			Attendee.UserName,
			Attendee.Competence,
			attendee.CompetenceLevel,
	--		attendee.UC_DateAchieved,
            ass.ASS_Description,
			ae.ASE_Date,
			cd.Code_Description,
            case when ab.ASB_RESULT = 2 then 'Failed' when ab.ASB_RESULT = 1 then 'Passed' else Null end as Result, 
            ab.ASB_CompletedDate
--			ae.ASE_Date,
--			cd.Code_Description as BookingStatus
into		#ICAssessments
FROM        #Attendees AS Attendee 
            left join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            left JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            left JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID and (case when ass.ASS_Description = 'Competence Assessment MCOB' then 'MCOB'
																						  when ass.ASS_Description = 'Competence Assessment ICOBS' then 'ICOB'
																						  when ass.ASS_Description = 'Competence Assessment COBS' then 'COB' else Null end) = Attendee.Competence
			left join sa_insight_CodeDescription cd on cd.Code_Code = ASB_Status and cd.Code_CodeType = 27
where 1=1
	--and ASB_Status = 4 
	and ASS_Description like 'Competence Assessment%'
	and (ASB_CompletedDate > DATEADD(year,-1,getdate())or ae.ASE_Date > DATEADD(year,-1,getdate())) --Updated 7.3.19 SI
--	and UserUID = '0138'
--Added 13/12/2017 SI
UNION
select      Attendee.AQMName,
			Attendee.BQMName,
			Attendee.SupervisorName,
			Attendee.BusinessCompanyName,
			Attendee.UserUID,
			Attendee.UserName,
			'Introduction/Disclosure' as Competence,
			attendee.CompetenceLevel,
	--		attendee.UC_DateAchieved,
            ass.ASS_Description,
			ae.ASE_Date,
			cd.Code_Description,
            case when ab.ASB_RESULT = 2 then 'Failed' when ab.ASB_RESULT = 1 then 'Passed' else Null end as Result, 
            ab.ASB_CompletedDate
--			ae.ASE_Date,
--			cd.Code_Description as BookingStatus
FROM        #Attendees AS Attendee 
            left join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            left JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            left JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID and ass.ASS_Description = 'Introduction/Disclosure'
			left join sa_insight_CodeDescription cd on cd.Code_Code = ASB_Status and cd.Code_CodeType = 27
where 1=1
	--and ASB_Status = 4 
	and ASS_Description like '%Introduction/Disclosure%'
	and (ASB_CompletedDate > DATEADD(year,-1,getdate())or ae.ASE_Date > DATEADD(year,-1,getdate())) --Updated 7.3.19 SI
--	and UserUID = '0138'

Order by UserUID--, ASB_CompletedDate 

Select	distinct
		Attendee.AQMName,
		Attendee.AQMUID,
		Attendee.BQMName,
		Attendee.BQMUID,
		Attendee.SupervisorName,
		Attendee.BusinessCompanyName,
		Attendee.UserUID,
		Attendee.UserName,
		compass.Competence,
		attendee.CompetenceLevel,
--		attendee.UC_DateAchieved,
		compass.ASB_CompletedDate,
		compass.ASE_Date,
		compass.Code_Description,
		compass.ASS_Description, 
		compass.Result 
into #QRMLevel
from #Attendees attendee
left join #ICAssessments compass on compass.UserUID = attendee.UserUID and (attendee.Competence = compass.Competence or compass.Competence = 'Introduction/Disclosure')
where datepart(year,compass.ASE_Date) = datepart(year,getdate())
and   (datepart(year,compass.ASB_CompletedDate) = datepart(year,getdate()) or compass.ASB_CompletedDate is null) -- added 21/02/2017 SI
and Code_Description in ('Booked','Completed','In Progress')

Order by UserUID, ASB_CompletedDate 

Select
isnull(AQMName,'No SQRM') as AQMName,
isnull(BQMName,'No QRM') as BQMName,
count(UserName) as NumberOfAssessments,
sum(case when ASB_CompletedDate is null then 0 else 1 end) as AssessmentsCompleted
from #QRMLevel
where AQMUID = @AQMUID or @AQMUID = 'View All'
Group by BQMName, BQMUID, AQMName

Drop table #Attendees
Drop table #ICAssessments
Drop table #QRMLevel

print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     

GO
