CREATE PROCEDURE [logi].[pr_ringo_DeepSpanComplaintDetails]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
        @AQMUID		      varchar(255) = 'View All',
        @CompType		  varchar(255) = 'View All',
        @CompJust		  varchar(255) = 'View All',
        @CompPaid		  varchar(255) = 'View All',
        @Firm			  varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanComplaintDetails]
Author      : S Inglis
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Complaint Details" and is found on the "BQM MI" 
              menu. This report displays: 
              - Complaints	 



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanComplaint Details] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
24.6.21		S Inglis		Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Complaint Details';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

SELECT AdviserID
	  ,uh.UserName
	  ,uh.BusinessUID
	  ,case when uh.BusinessCompanyName IS null then uh.BusinessTradingName else uh.BusinessCompanyName end as FirmName
	  ,ComplaintType
      ,ComplaintNo
      ,ClientSurname
      ,ClientInitials
      ,PolicyNo
      ,ComplaintDetails
	  ,DateFDLetterIssued
      ,case when RedressAmt > 0 then 'Compensation Paid' else 'No Compensation Paid' end as Compensation
      ,case when AdviserJustified = 1 then 'Upheld and Justified' 
			when AdviserJustified = 0 then 'Upheld and Unjustified' else 'Unknown' end as Justified
	  ,uh.AQMName
	  ,uh.BQMName
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_CMS_tblComplaint cmp
  join sa_CMS_tblDecisionType dt on dt.ID = cmp.Decision
  join mi_insight_UserHierarchy uh on uh.UserUID = cmp.AdviserID
  where
      DateFDLetterIssued > DATEADD(year,-1,getdate())
  and Decision in (1, 8)
  and (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
  and (ComplaintType = @CompType or @CompType = 'View All')
  and (convert(varchar,AdviserJustified) = @CompJust or @CompJust = 'View All')
  and ((case when RedressAmt > 0 then 'Compensation Paid' else 'No Compensation Paid' end) = @CompPaid or @CompPaid = 'View All')
  and (uh.BusinessUID = @Firm or @Firm = 'View All')
  and  uh.ADUID not in ('4021409','4005013')
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
/****** Object:  StoredProcedure [logi].[pr_ringo_DeepSpanComplaintFirms]    Script Date: 7/3/2026 3:44:28 PM ******/
