--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

SELECT Distinct
  uh.BusinessUID,
  case when uh. BusinessCompanyName IS null then uh.BusinessTradingName else uh.BusinessCompanyName end as FirmName
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_CMS_tblComplaint cmp
  join sa_CMS_tblDecisionType dt on dt.ID = cmp.Decision
  join mi_insight_UserHierarchy uh on uh.UserUID = cmp.AdviserID
  where
      DateFDLetterIssued > DATEADD(year,-1,getdate())
  and Decision in (1, 8)
  and (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
  and uh.ADUID not in ('4021409','4005013')
  Order by case when uh. BusinessCompanyName IS null then uh.BusinessTradingName else uh.BusinessCompanyName end
  
 
print 'Leaving try';

End

