		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200),
        @AQMUID		        varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanCPDHours]
Author      : S Inglis
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span CPD Hours" and is found on the "BQM MI" 
              menu. This report displays: 
              - CPD Hours 



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanCPDHours] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
27-4-18		S Inglis		Added where clause to only include sellers
07-11-18	S Campbell		Changes to CPD to use SPS table (due to Insight release changes)
24.6.21		S Inglis		Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span CPD Hours';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

With CTE_CPD as (
SELECT   uh.UserUID
		,uh.UserName
		,uh.BusinessUID
		,uh.BusinessCompanyName
	    ,case when CPDL_Structure = 1 then sum(CPDL_Awarded)/60 end as StructuredHours
	    ,case when CPDL_Structure = 2 then sum(CPDL_Awarded)/60 end as UnstructuredHours
	    ,sum(CPDL_Awarded)/60 as TotalCPDHours
	    ,uh.AQMName
	    ,uh.BQMName 
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_CPDAwardLog cpdal
  join mi_insight_UserHierarchy uh on uh.UserGUID = cpdal.CPDL_UserID
    join dbo.sa_insight_StatementOfProfessionalStanding sps on sps.SPS_UserID = uh.UserGUID
  where UserJobTitleCodeSeller = 4
  --and CPDL_UserID = 'BCA580B9-9595-4795-933E-00B5B3880E9E'
  and CPDL_Status = 1
  --and CPDL_Category = 1  --  Removed due to Insight db schema change
  and sps.SPS_Status = 2  --  Added due to Insight db schema change
  and sps.SPS_RenewalDate > DATEADD(ss, -1, DATEADD(month, DATEDIFF(month, 0, getdate()), 0)) --  added to remove links to expired but active SPS records	

  and (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
  and  uh.ADUID not in ('4021409','4005013')
 -- and uh.BusinessUID = @FirmUID
  and CPDL_PlannedDate between dateadd(year,-1,getdate()) and getdate()
  group by 
  CPDL_UserID,
  CPDL_Structure,
  uh.UserUID
 ,uh.UserName
 ,uh.BusinessUID
 ,uh.BusinessCompanyName
 ,AQMName
 ,BQMName
 )

 Select
 UserUID
,UserName
,BusinessUID
,BusinessCompanyName
,sum(structuredHours) as StructuredHours
,sum(unstructuredhours) as UnstructuredHours
,sum(TotalCPDHours) as TotalCPDHours
,AQMName
,BQMName 
from CTE_CPD
group by UserUID
,UserName
,BusinessUID
,BusinessCompanyName
,AQMName
,BQMName
  
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
