	    @ReportFormat		varchar(200),
        @AQMUID		        varchar(255) = 'View All',
        @FirmUID			varchar(255) = 'View All',
        @Year1				varchar(255) = 'View All',
        @Year2				varchar(255) = 'View All',
        @Year3				varchar(255) = 'View All',
        @Year4				varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanDeclinedEvents3YearsClientDetail]
Author      : S Inglis
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Declined Events 3 Years Client Detail" and 
              is found on the "BQM MI" menu. This report displays: 
              - Clients who have declined a review over multiple years



      The security groups associated with is report are:
      1) 
      2)  

      Execute as follows:
      exec [logi].[pr_ringo_DeepSpanDeclinedEvents3YearsClientDetail] 'ptl91371','SQL','View All'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
14.2.17		S Inglis		  Change of code to bring back rolling 12 months not static years
7.6.17		S Inglis		  Update to code to reflect additional fields for NFAL
25-5-18		S Inglis		  Updated to include Adhoc Reviews
10-5-19		S Inglis		  Updated to ensure null and 0 values are picked up
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
19/10/2021	S Campbell	 	  OWS Decouple - Create copy in BI Schema 
							  Use BI.sa_d365_ows_Event table instead of Events.sa_ows_Event table
26/10/2021	S Campbell		  Use BI.mi_concert_ows_Event
05/04/2022	S Campbell		  Use dbo.mi_concert_ows_Event
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'DeclinedEvents3YearsClientDetail';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

select
even.PersonID
,even.DateDue
,year(even.DateDue) as EventDueYear
,even.Details
,even.DateCompleted
,even.CompletedBy
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
into #AdhocReviews
from dbo.mi_concert_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where even.EventReminderStatusID = 4
and TypeID = 8

select
even.PersonID
,even.DateDue
,even.Details
,even.DateCompleted
,even.CompletedBy
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
into #DeclinedEvents
from dbo.mi_concert_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateDue)
where outcome = 3
and TypeID = 2
and adh.PersonID is null


select
even.PersonID
,min(isnull(even.OneOffChangeToDateDue,even.DateDue)) as NextDueDate
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
into #ClientsDue
from dbo.mi_concert_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where DateCompleted is null
and TypeID = 2 and isnull(IsComplete,0) = 0 and isnull(isdeleted,0) = 0 and isnull(iscancelled,0) = 0 --Updated 10.5.19 SI
Group by even.PersonID
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN
,pers.BusinessUid
,agt1.DESCN



Select
PersonID,
max(datedue) as LastDecline,
sum(case when DateDue  >= dateadd(year,-4,getdate()) and DateDue < dateadd(year,-3,getdate()) then 1 else 0 end) as EventDeclined3YearsAgo, --Updated SI 14.2.17
sum(case when DateDue  >= dateadd(year,-3,getdate()) and DateDue < dateadd(year,-2,getdate()) then 1 else 0 end) as EventDeclined2yearsAgo, --Updated SI 14.2.17
sum(case when DateDue  >= dateadd(year,-2,getdate()) and DateDue < dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedLastYear,  --Updated SI 14.2.17
sum(case when DateDue >= dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedCurrentYear, --Updated SI 14.2.17
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
into #ClientDeclines
From #DeclinedEvents de
join mi_insight_UserHierarchy uh on uh.UserUID = de.AdviserUID
where (uh.AQMUID = @AQMUID or @AQMUID = 'View All') and uh.ADUID not in ('4021409','4005013')
Group by
PersonID,
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName

