cdec.PersonID,
cdec.BusinessUid
,cdec.FirmName
,cdec.AdviserUID
,cdec.AdviserName
,cdec.FirstName
,cdec.LastName,
AQMName,
BQMName
,cd.NextDueDate
,cdec.LastDecline
,case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end as 'ClientDeclinedCurrentYear'
,case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end as 'ClientDeclinedLastYear'
,case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end as 'ClientDeclined2YearsAgo'
,case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end as 'ClientDeclined3YearsAgo'
from #ClientDeclines cdec
join #ClientsDue cd on cd.PersonID = cdec.PersonID
where (cdec.BusinessUid = @FirmUID or @FirmUID = 'View All')
and	  (case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end = @Year1 or @Year1 = 'View All')
and	  (case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end = @Year2 or @Year2 = 'View All')
and	  (case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end = @Year3 or @Year3 = 'View All')
and	  (case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end = @Year4 or @Year4 = 'View All')

print 'Leaving try';

End

