join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateDue)
where outcome = 3
and TypeID = 2
and adh.PersonID is null
--), --removed SI 7.6.17

--CTE_BusLevelDec as ( --removed SI 7.6.17
Select
PersonID,
sum(case when DateDue  >= dateadd(year,-4,getdate()) and DateDue < dateadd(year,-3,getdate()) then 1 else 0 end) as EventDeclined3YearsAgo, --Updated SI 14.2.17
sum(case when DateDue  >= dateadd(year,-3,getdate()) and DateDue < dateadd(year,-2,getdate()) then 1 else 0 end) as EventDeclined2yearsAgo, --Updated SI 14.2.17
sum(case when DateDue  >= dateadd(year,-2,getdate()) and DateDue < dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedLastYear,  --Updated SI 14.2.17
sum(case when DateDue >= dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedCurrentYear, --Updated SI 14.2.17
FirstName,
LastName,
AdviserUID,
AdviserName,
BusinessUid,
FirmName
--From CTE_DeclinedEvents --removed SI 7.6.17
into #BusDeclines -- added 7.6.17
From #ClientDeclines --added 7.6.17
Group by
PersonID,
FirstName,
LastName,
AdviserUID,
AdviserName,
BusinessUid,
FirmName
--) --removed SI 7.6.17

Select
yd.BusinessUid,
yd.FirmName,
uh.BQMName,
uh.AQMName,
sum(case when EventDeclinedCurrentYear > 0 and EventDeclinedLastYear > 0 and EventDeclined2yearsAgo > 0 
     then 1 else 0 end) as 'Declinedlast3years' ,
sum(case when EventDeclinedCurrentYear > 0 and EventDeclinedLastYear > 0 and EventDeclined2yearsAgo = 0
	 then 1 else 0 end) as 'Declinedlast2years',
sum(case when EventDeclinedCurrentYear > 0 and EventDeclinedLastYear = 0 and EventDeclined2yearsAgo = 0
	 then 1 else 0 end) as 'Declinedthisyear'
--	 else 'ok' end as Declines
--from CTE_BusLevelDec yd --removed SI 7.6.17
from #BusDeclines yd -- added 7.6.17
join mi_insight_UserHierarchy uh on uh.UserUID = yd.AdviserUID
where (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
and uh.ADUID not in ('4021409','4005013')
Group by yd.BusinessUid,
yd.FirmName,
uh.BQMName,
uh.AQMName

print 'Leaving try';

End

