set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanDeclinedEventsFirmLevel]
Author      : S Inglis
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep SpanDeclined Events Firm Level" and is found on the "BQM MI" 
              menu. This report displays: 
              - Declined Reviews


              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanDeclinedEventsFirmLevel] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
25-5-18		S Inglis		  Updated to include Adhoc Reviews
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
19/10/2021	S Campbell	      OWS Decouple - Create copy in BI Schema 
							  Use BI.sa_d365_ows_Event table instead of Events.sa_ows_Event table
26/10/2021	S Campbell	      Use BI.mi_concert_ows_Event
05/04/2022	S Campbell		  Use dbo.mi_concert_ows_Event
30/09/2024  R251929     P Reed- Replace the Merged Event table: dbo.mi_concert_ows_Event with view that excludes OWS outstanding (1,2,3) events (concert1234_ows4_event

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'DeclinedEventsFirmLevel';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

With CTE_Reviews as (
select 
--pers.AdviserUID,
--uh.UserName,
pers.BusinessUid,
agt.descn,
--uh.AQMUID,
--uh.AQMName,
--uh.BQMName,
count(*) as NumberOfEvents,
count(distinct evt.PersonID) as NumberOfClients
from dbo.concert1234_ows4_event evt
join sa_ows_Person pers on pers.PersonID = evt.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.BusinessUid
where evt.TypeID in (2,8) --Updated 25-5-18 SI
and evt.DateDue > DATEADD(year,-1,getdate())
and   isnull(evt.IsCancelled,0) = 0 
and   isnull(evt.IsDeleted,0)   = 0
and   ((evt.TypeID = 2 and evt.EventReminderStatusID in (1,2,3)) or (evt.TypeID = 8 and evt.EventReminderStatusID = 4)) --Updated 25-5-18 SI
group by 
pers.BusinessUid,
agt.descn

),
CTE_DeclinedReviews as (
Select pers.BusinessUid
,count(distinct even.PersonID) as ClientsDecliningEvents
,count(*) as EventsDeclined	
FROM  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even
join  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
where Outcome = 3
and   TypeID  = 2
and    even.IsCancelled is null
and    even.IsDeleted   is null
and    even.DateUpdated >= DATEADD(year,-1,GETDATE())
and    exists (select 1
from   prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even1
where  even.PersonID = even1.PersonID
and    even1.Outcome is null 
and    even1.TypeID  = 2
and    even1.IsCancelled is null
and    even1.IsDeleted   is null
and    even1.EventReminderStatusID in (1,2,3))
group by pers.BusinessUid
)

Select
uh.AQMName,
uh.BQMName,
rv.BusinessUid,
rv.DESCN,
rv.NumberOfClients,
rv.NumberOfEvents,
drv.ClientsDecliningEvents,
drv.EventsDeclined,
round((convert(decimal,ClientsDecliningEvents)/convert(decimal,NumberOfClients))*100,2) as PctEventsDeclined
From CTE_Reviews rv
left join CTE_DeclinedReviews drv on drv.BusinessUid = rv.BusinessUid
join mi_insight_UserHierarchy uh on uh.BusinessUID = rv.BusinessUid
where (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
and uh.ADUID not in ('4021409','4005013')
Group by uh.AQMName,
uh.BQMName,
rv.BusinessUid,
rv.DESCN,
rv.NumberOfClients,
rv.NumberOfEvents,
drv.ClientsDecliningEvents,
drv.EventsDeclined
order by round((convert(decimal,ClientsDecliningEvents)/convert(decimal,NumberOfClients))*100,2) desc
  
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


