and    even1.IsCancelled is null
and    even1.IsDeleted   is null
and    even1.EventReminderStatusID in (1,2,3))
group by pers.BusinessUid
),
CTE_Firms as (
Select
uh.AQMName,
uh.BQMName,
rv.BusinessUid,
rv.DESCN,
--rv.AdviserUID,
--rv.UserName,
rv.NumberOfClients,
rv.NumberOfEvents,
drv.ClientsDecliningEvents,
drv.EventsDeclined,
round((convert(decimal,ClientsDecliningEvents)/convert(decimal,NumberOfClients))*100,2) as PctEventsDeclined
From CTE_Reviews rv
left join CTE_DeclinedReviews drv on drv.BusinessUid = rv.BusinessUid
join mi_insight_UserHierarchy uh on uh.BusinessUID = rv.BusinessUid
where (uh.AQMUID = @AQMUID or @AQMUID = 'View All') and uh.ADUID not in ('4021409','4005013')
Group by uh.AQMName,
uh.BQMName,
rv.BusinessUid,
rv.DESCN,
--rv.AdviserUID,
--rv.UserName,
rv.NumberOfClients,
rv.NumberOfEvents,
drv.ClientsDecliningEvents,
drv.EventsDeclined
--order by round((convert(decimal,ClientsDecliningEvents)/convert(decimal,NumberOfClients))*100,2) desc
)

select
sum(case when PctEventsDeclined >= 50 then 1 else 0 end) as FirmsMoreThan50PerCentDeclined
from CTE_Firms
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

