		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200),
        @AQMUID		        varchar(255) = 'View All'


AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanDevActionPlan]
Author      : S Inglis
Date  : 05/04/2019

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Dev Action Plan" and is found on the "BQM MI" 
              menu. This report displays: 
              - All Development Action Plans



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanDevActionPlan] 'ptl91371','1002714'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
11-04-19	S Inglis		  Addition of Owl filter
29-04-19	S Inglis		  Change in code to look at objective status	
11-12-20	S Inglis		  Update to action join to link to objective ID			
24.6.21		S Inglis		  Updated to include new Owl Sales Director code			  
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


declare          
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 


set @ReportName               = 'Deep Span AQT No Chkd Cases';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams		  = 'None';

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output


/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
 

Begin

SELECT uh.AQMName
	  ,uh.BQMName
	  ,uh.SupervisorName
	  ,uh.BusinessCompanyName
	  ,uh.UserName
	  ,ast.Code_Description as PlanStatus
      ,[AP_Description] as PlanDescription
      ,[AP_PlanCreatedDate] as PlanCreatedDate
      ,[AP_StartDate]
	  ,cd.Code_Description
	  ,act.ACT_Text
	  ,act.ACT_StatusDate as ActionUpdatedDate
	  ,act.ACT_DueDate as ActionDueDate
	  ,cd2.Code_Description as ActionStatus
	  ,act.ACT_ExternalActionRequired as ValidationEvidence
	  ,objt.Code_Description as TypeOfIssue
	  ,case when cd2.Code_Description = 'Open' and act.ACT_DueDate < getdate() then 'Yes' else 'No' end as Overdue
	  ,case when isnull(uh.aduid,'111') in ('4021409','4005013') then 'Owl' else 'Openwork' end as Panel
  FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ActionPlan] ap
  join sa_insight_objective obj on obj.OBJ_ParentID = ap.AP_ID 
  join sa_insight_codedescription at on at.Code_Code = ap.AP_Type and at.Code_CodeType = 35
  join sa_insight_codedescription apt on apt.Code_Code = ap.AP_PlanType and apt.Code_CodeType = 637
 -- join sa_insight_codedescription ast on ast.Code_Code = ap.AP_Status and ast.Code_CodeType = 39 -- Removed 29.4.19 SI
  join sa_insight_actions act on act.ACT_ParentID = OBJ_ID -- updated 11.12.20
  join mi_insight_userhierarchyallusers uh on uh.userguid = ap.AP_OwnerID and latestrowind = 1
  join sa_insight_codedescription cd on cd.Code_Code = act.ACT_Type and cd.Code_CodeType = 37
  join sa_insight_codedescription cd2 on cd2.Code_Code = act.ACT_Status and cd2.Code_CodeType = 41
  join sa_insight_codedescription objt on objt.Code_Code = obj.OBJ_Type and objt.Code_CodeType = 36
  join sa_insight_codedescription ast on ast.Code_Code = obj.OBJ_Status and ast.Code_CodeType = 40 --Added 29.4.19 SI
  where ap_plantype = 4 
  and (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
 Order by AQMName, BQMName, SupervisorName,BusinessCompanyName, Username,PlanCreatedDate, ActionDueDate

print 'Leaving try';

End


END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
