CREATE PROCEDURE [logi].[pr_ringo_DeepSpanDueEventsTotal]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
        @AQMUID		      varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanDueEventsTotal]
Author      : S Inglis
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Due Events Total" and is found on the "BQM MI" 
              menu. This report displays: 
              - Events closed within a 1 month period



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanDueEventsTotal] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
24.6.21		S Inglis		  Updated to include new Owl Sales Director code	
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'DeclinedEventsTotal';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin


--LATE EVENTS @ 1 MONTH AGO
With CTE_LateEvents as (
select
evad.DateAudited
,evad.DateDue
,evad.OneOffChangeToDateDue
,evad.EventID
,evad.IsCancelled
,evad.IsComplete
,evad.IsDeleted
,pers.BusinessUid 
from events.sa_ows_EventAudit evad
join sa_ows_Person pers on pers.PersonID = evad.PersonID
where DateAudited <= dateadd(month,-1,getdate())
and   DateAudited = (select max(evad1.DateAudited)
				   from events.sa_ows_EventAudit evad1
				   where evad.EventID = evad1.EventID
				   and evad1.DateAudited <= dateadd(mm,-1,getdate()))
and TypeID = 2
and DateCompleted is null
and IsDeleted is null
and IsCancelled is null
and outcome is null
and DateDue < dateadd(month,-3,getdate())
--and BusinessUid = '1000710'
--order by BusinessUid
),
--Completed in the last month
CTE_CompletedEvents as (
select
evad.DateAudited
,evad.DateDue
,evad.OneOffChangeToDateDue
,evad.DateCompleted
,evad.DateCompletedWithClient
,evad.EventID
,evad.IsCancelled
,evad.IsComplete
,evad.IsDeleted
,evad.Outcome
,evoc.Name
,pers.BusinessUid 
from events.sa_ows_EventAudit evad
join sa_ows_Person pers on pers.PersonID = evad.PersonID
join StaticData.sa_ows_EventOutcome evoc on evoc.EventOutcomeID = evad.Outcome
where 1=1
and   DateAudited >= dateadd(month,-1,getdate())
and   DateAudited = (select max(evad1.DateAudited)
				   from events.sa_ows_EventAudit evad1
				   where evad.EventID = evad1.EventID)
				  -- and evad1.DateAudited <= dateadd(mm,-1,getdate()))
and TypeID = 2
and Outcome in (1,2,3,4,5)
--and DateDue < dateadd(month,-3,getdate())
--and BusinessUid = '1000710'
--order by BusinessUid
),

CTE_FIRM as
(Select distinct
BusinessUID
,AQMUID
,AQMName
from mi_insight_UserHierarchy
where ADUID not in ('4021409','4005013'))

Select distinct
'View' as AQMName,
--frm.AQMName,
--lev.BusinessUid,
--agt.DESCN as BusinessName,
count(lev.EventID) as LateEvents,
count(comev.EventID) as ClosedEvents,
sum(case when comev.Outcome = 1 then 1 else 0 end) as EventMissed,
sum(case when comev.Outcome = 2 then 1 else 0 end) as EventCompleted,
sum(case when comev.Outcome = 3 then 1 else 0 end) as EventDeclined,
case when count(comev.EventID) > 0 then round(cast(count(comev.EventID) AS FLOAT) /cast((count(lev.EventID)) AS float)*100,2) else 0 end as PctClosed
--(count(comev.EventID)/count(comev.EventID))*100 as PctClosed
from CTE_LateEvents lev
left join CTE_CompletedEvents comev on comev.EventID = lev.EventID
left join sa_swift_S_AGENTS agt on agt.CODE = lev.BusinessUid
left join CTE_FIRM frm on frm.BusinessUID = lev.BusinessUid 
Where frm.AQMUID = @AQMUID or @AQMUID = 'View All'
--Group by frm.AQMName 
--Order by AQMName 

print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
