select 
FINV.BusinessUID
,FirmName
,TypeofSchemeFinancialIncentive
,OverseasTravel
,QualityOverlay
,Outcome
,AQMName
,BQMName 
from tandc.financialincentives finv
join CTE_FirmAQM aqm on aqm.BusinessUID = finv.BusinessUID
