CREATE PROCEDURE [logi].[pr_ringo_DeepSpanFirmDeclaration]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
        @AQMUID		      varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanFirmDeclaration]
Author      : S Inglis
Date  : 15/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Firm Declaration" and is found on the "BQM MI" 
              menu. This report displays: 
              - Firm Declaration Info


              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanFirmDeclaration] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Firm Declaration';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

With CTE_FirmDec as
(select  distinct
uh.useruid,
uh.UserName,
ft.FT_Description,
fs.FS_Description,
fq.FQ_Description as Question,
fq.FQ_LinkLogicMode,
fq.FQ_Mandatory,
fq.FQ_Type,
fq.FQ_Order,
--fq.*,
fac.FAC_Description,
fad.FAD_Code,
fad.FAD_Text,
fad.FAD_CreatedDate,
fad.FAD_UpdatedDate,
FQ_Order + 1 as AnswerQuestion
from sa_insight_Form fr
join sa_insight_FormData fd on fd.FD_FormID = fr.FRM_ID
join sa_insight_assessmentbooking asb on asb.ASB_FormID = fd.FD_ID
join sa_insight_FormAnswerData fad on fad.FAD_FormDataID = fd.FD_ID
join sa_insight_FormQuestion fq on fq.FQ_ID = fad.FAD_QuestionID
join sa_insight_FormAnswerCode fac on fac.FAC_Code = FAD_Code
join sa_insight_FormSection fs on fs.FS_ID = fq.FQ_SectionID
join sa_insight_FormType ft on ft.FT_Code = fr.FRM_Type
join mi_insight_UserHierarchy uh on uh.UserGUID = asb.ASB_AttendeeID
where 1=1
--and uh.useruid = '1001295'
--and ft.FT_Code = 7
and asb.ASB_Status = 4
--and FQ_Type = 0
--and FAD_FormDataID = 'EC339329-871D-421C-AA98-32C723DB324B'
and FS_Description like '%Financial Incentives%'
and ((FQ_Type = 0 and FAD_Code != 0) or (FAD_UpdatedDate!= FAD_CreatedDate and FQ_Type != 0))
--order by uh.username,fs.FS_Order,fq.FQ_Order
and exists (select * from sa_insight_Form fr1
join sa_insight_FormData fd1 on fd1.FD_FormID = fr1.FRM_ID
join sa_insight_assessmentbooking asb1 on asb1.ASB_FormID = fd1.FD_ID
join sa_insight_FormAnswerData fad1 on fad1.FAD_FormDataID = fd1.FD_ID
join sa_insight_FormQuestion fq1 on fq1.FQ_ID = fad1.FAD_QuestionID
join sa_insight_FormAnswerCode fac1 on fac1.FAC_Code = fad1.FAD_Code
join sa_insight_FormSection fs1 on fs1.FS_ID = fq1.FQ_SectionID
where 1=1
and uh.ADUID not in ('4021409','4005013')
and asb.ASB_AttendeeID = asb1.ASB_AttendeeID
and FS_Description like '%Are You a Sole Trader%'
and FAC_Description = 'No')
),

CTE_Totals as (
Select
fd.UserUID,
fd.UserName,
fd.FT_Description,
fd.FS_Description,
fd.Question,
fd.FQ_Order,
fd.FQ_Type,
fd.FAC_Description,
fd1.FAD_Text
from CTE_FirmDec fd
left join CTE_FirmDec fd1 on fd.AnswerQuestion = fd1.FQ_Order and fd.UserUID = fd1.UserUID
where fd.FQ_Type = 0
--order by fd.FQ_Order
),

CTE_FirmTotals as (
Select distinct
grqu.useruid,
grqu.username,
sum(case when grqu.FAC_Description = 'Self-employed' then 1 else 0 end) as SelfEmployed,
sum(case when grqu.FAC_Description = 'Employed' then 1 else 0 end) as Employed,
sum(case when grqu.FAC_Description = 'Employed & Self-employed' then 1 else 0 end) as MixedEmp,
sum(case when grqu.fac_description = 'Yes' then 1 else 0 end) as Incentives,
sum(case when grqu.fac_description = 'No' then 1 else 0 end) as NoIncentives,
sum(case when grqu.fq_order = 15 and grqu.FAC_Description = 'yes' then 1 else 0 end) as OverSeas
from CTE_Totals grqu
Group by grqu.username, grqu.useruid),

CTE_BusinessAnswers as (
Select
frmtt.UserUID,
frmtt.UserName,
case when uh.BusinessCompanyName is null then uh.BusinessTradingName else uh.businessCompanyName end as Business,
uh.AQMUID,
case when frmtt.SelfEmployed >=1 then 'SelfEmployed' when frmtt.Employed >= 1 then 'Employed' else 'MixedEmployment' end as EmploymentType,
case when frmtt.Incentives >= 1 then 'RiskFeatures' when frmtt.Incentives = 0 then 'NoRiskFeatures' end as RiskFeatures,
case when frmtt.OverSeas >= 1 then 'OverseasTravel' else 'NoTravel' end as PrizeBasedIncentive
from CTE_FirmTotals frmtt
join mi_insight_UserHierarchy uh on uh.useruid = frmtt.UserUID
where uh.ADUID not in ('4021409','4005013')
)

Select
count(*) as TotalNumberOfResponses,
sum(case when busan.EmploymentType = 'Employed' and busan.RiskFeatures = 'NoRiskFeatures' then 1 else 0 end) as EmployedNoRiskFeatures,
sum(case when busan.EmploymentType = 'Employed' and busan.RiskFeatures = 'RiskFeatures' then 1 else 0 end) as EmployedRiskFeatures,
sum(case when busan.EmploymentType = 'Employed' and busan.PrizeBasedIncentive = 'OverseasTravel' then 1 else 0 end) as EmployedPrizeBasedIncentive,
sum(case when busan.EmploymentType = 'SelfEmployed' and busan.RiskFeatures = 'NoRiskFeatures' then 1 else 0 end) as SelfEmployedNoRiskFeatures,
sum(case when busan.EmploymentType = 'SelfEmployed' and busan.RiskFeatures = 'RiskFeatures' then 1 else 0 end) as SelfEmployedRiskFeatures,
sum(case when busan.EmploymentType = 'SelfEmployed' and busan.PrizeBasedIncentive = 'OverseasTravel' then 1 else 0 end) as SelfEmployedPrizeBasedIncentive,
sum(case when busan.EmploymentType = 'MixedEmployment' and busan.RiskFeatures = 'NoRiskFeatures' then 1 else 0 end) as MixedEmploymentNoRiskFeatures,
sum(case when busan.EmploymentType = 'MixedEmployment' and busan.RiskFeatures = 'RiskFeatures' then 1 else 0 end) as MixedEmploymentRiskFeatures,
sum(case when busan.EmploymentType = 'MixedEmployment' and busan.PrizeBasedIncentive = 'OverseasTravel' then 1 else 0 end) as MixedEmploymentPrizeBasedIncentive
from CTE_BusinessAnswers busan
where AQMUID = @AQMUID or @AQMUID = 'View All'




  
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
