CREATE PROCEDURE [logi].[pr_ringo_DeepSpanFirmDeclarationOutcome]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
        @AQMUID		      varchar(255) = 'View All',
		@Report			  varchar(100)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanFirmDeclarationOutcome]
Author      : S Inglis
Date  : 31/05/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Firm Declaration Outcome" and is found on the "BQM MI" 
              menu. This report displays: 
              - Details of Firm Declaration Outcomes completed in the current year



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanFirmDeclarationOutcome]  'ptl91371', 'Sql','1002170','QRM'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
13/02/24	J Homer			  Change to AQM to cater for changes to quality heirarchy post reorg changes
27/03/24	E Brown			  Change the ASS_Description to 'Firm 1:1' & added or condition for failing Track- DT51 Additional Review modules

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int



print 'setting parameters';
set @ReportName               = 'Deep Span Firm Declaration Outcome';
set @StoredProcName           = object_name(@@procid);

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/


Begin

----Create list of users who have failed Additional Review module on track DT51
DROP TABLE IF EXISTS #AddReviewFail, #FirmDecPending, #FirmDecPass, #FirmDecFail

SELECT 
uh.UserGUID
INTO #AddReviewFail
FROM sa_insight_UserTandCTrackModule as utcm
INNER JOIN sa_insight_UserTandCTrack as utct on utcm.usrts_UserTrackID = utct.usrt_ID
INNER JOIN mi_insight_UserHierarchy as uh on uh.UserGuid = utct.USRT_UserID
INNER JOIN sa_insight_TandCTrackModule as  tctm on tctm.TCTM_ID = utcm.USRTS_TrackModuleID
INNER JOIN sa_insight_TandCTrack as tct on tct.TCT_ID = tctm.TCTM_TrackID
INNER JOIN sa_insight_UserTandCTrackevent as utce on utcm.USRTS_ID = utce.USRTE_ModuleID
--LEFT JOIN sa_insight_CodeDescription as code1 on utce.USRTE_Status = code1.code_code and Code_CodeType = 505
	where 1=1 
	and tct.TCT_ID = '910E1E16-DC81-4C8C-9A45-2CD1C49F741B' -- DT51
	and utcm.USRTS_TrackModuleID IN ('365CB73B-52A9-422D-91CD-D63E5CBB9276', '2F5C4EF9-9309-43EE-9A8B-35F9E37F4467') -- Additional review modules
	and utce.USRTE_Status = 2 -- Failed (Code_CodeType = 505)
	and YEAR(utce.USRTE_CompletedDate) = YEAR(GETDATE())
		GROUP BY uh.UserGUID
;

---Create seperate lists for the results of "Firm 1:1" assessments

--Firm 1:1 Pending, excluding any users in #AddReviewFail
WITH CTE_Pending as
(select      Attendee.UserGUID,
		    Attendee.username,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            max(ae.ASE_Date)as DueDate,
			'Pending' as Result
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
where
	--ASB_Status = 4 
	ASS_Description like 'Firm 1:1'
	and year(ASE_Date) = Year(Getdate())
	and ASB_Result = 0 --Fail
Group by	Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
			Attendee.UserName
)
SELECT 
pen.*
Into #FirmDecPending
FROM CTE_Pending as pen
	LEFT JOIN #AddReviewFail as arf on pen.UserGUID = arf.UserGUID
		WHERE arf.UserGUID IS NULL
;
----------------------
--Firm 1:1 Pass, excluding any users in #AddReviewFail

WITH CTE_Pass as
(
select      Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            max(ab.ASB_CompletedDate) as ASB_CompletedDate,
			'Pass' as Result
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
where
		ASB_Status = 4 
	and ASS_Description like 'Firm 1:1'
	and year(ASB_CompletedDate) = Year(GetDate())
	and ASB_Result = 1--Pass
Group by	Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description
)

SELECT 
pas.*
Into #FirmDecPass
FROM CTE_Pass as pas
	LEFT JOIN #AddReviewFail as arf on pas.UserGUID = arf.UserGUID
		WHERE arf.UserGUID IS NULL
;
--------------------------
--Mark all who have not failed Firm 1:1, But have failed additonal reviews as Fail

WITH CTE_Not_Failed as
(
select      Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            max(ab.ASB_CompletedDate) as ASB_CompletedDate,
			'Fail' as Result
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
where
		ASB_Status = 4 
	and ASS_Description like 'Firm 1:1'
	and year(ASB_CompletedDate) = Year(GetDate())
	and ASB_Result != 2 -- Not Fail
Group by	Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description
)

SELECT 
nf.*
Into #FirmDecFail
FROM CTE_Not_Failed as nf
	INNER JOIN #AddReviewFail as arf on nf.UserGUID = arf.UserGUID

--Union user who faild Firm 1:1
Union


select      Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            max(ab.ASB_CompletedDate)as ASB_CompletedDate,
			'Fail' as Result

FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
where
		ASB_Status = 4 
	and ASS_Description like 'Firm 1:1'
	and year(ASB_CompletedDate) = Year(GetDate())
	and ASB_Result = 2 --Fail
Group by	Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description


If @Report = 'Details'

Begin

Select 
CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 
	 ELSE Isnull(AQMName,'No SQRM')
END as SQRM,
isnull(BQMName,'No QRM') as QRM,
isnull(SupervisorName,'No Supervisor') as Supervisor,
isnull(fdp.ASB_AttendeeID,isnull(fdf.ASB_AttendeeID,fdpe.ASB_AttendeeID))  as AttendeeGUID,
uh.UserUID,
uh.UserName,
uh.BusinessCompanyName,
max(isnull(fdp.ASB_CompletedDate,fdf.ASB_CompletedDate)) as CompletedDate,
max(fdpe.DueDate) as DueDate,
isnull(case when fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null then fdp.Result else fdf.Result end,fdpe.Result) as Result,
case when fdf.Result is not null and fdp.Result is not null and (fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null) then 'Yes' else 'No' end as FailSubPass,
case when fdf.Result is not null and fdp.Result is not null and (fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null) then fdf.ASB_CompletedDate else null end as FailedDate
from #FirmDecPass fdp
full outer join #FirmDecFail fdf on fdf.ASB_AttendeeID = fdp.ASB_AttendeeID --and fdf.ASB_CompletedDate < fdp.ASB_CompletedDate
full outer join #FirmDecPending fdpe on fdpe.ASB_AttendeeID = fdp.ASB_AttendeeID
left join mi_insight_UserHierarchy uh on uh.UserGUID = isnull(fdp.ASB_AttendeeID,isnull(fdf.ASB_AttendeeID,fdpe.ASB_AttendeeID))  
where Isnull(AQMName,'No SQRM') is not null
and (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
Group by
isnull(fdp.ASB_AttendeeID,isnull(fdf.ASB_AttendeeID,fdpe.ASB_AttendeeID)),
isnull(BQMName,'No QRM'),
isnull(SupervisorName,'No Supervisor'),
uh.UserUID,
uh.UserName,
uh.BusinessCompanyName,
isnull(case when fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null then fdp.Result else fdf.Result end,fdpe.Result),
case when fdf.Result is not null and fdp.Result is not null and (fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null) then 'Yes' else 'No' end,
case when fdf.Result is not null and fdp.Result is not null and (fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null) then fdf.ASB_CompletedDate else null end,
CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 
	 ELSE Isnull(AQMName,'No SQRM')
END
order by UserName

End
If @Report = 'QRM'
Begin

Select 
CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 
	 ELSE Isnull(AQMName,'No SQRM')
END as AQMName,
isnull(BQMNAme,'No QRM') as QRM,
count(*) as TotalReviews,
sum(case when (isnull(fdp.ASB_CompletedDate,fdf.ASB_CompletedDate)) is null then 0 else 1 end) as Completed
from #FirmDecPass fdp
full outer join #FirmDecFail fdf on fdf.ASB_AttendeeID = fdp.ASB_AttendeeID --and fdf.ASB_CompletedDate < fdp.ASB_CompletedDate
full outer join #FirmDecPending fdpe on fdpe.ASB_AttendeeID = fdp.ASB_AttendeeID
left join mi_insight_UserHierarchy uh on uh.UserGUID = isnull(fdp.ASB_AttendeeID,isnull(fdf.ASB_AttendeeID,fdpe.ASB_AttendeeID))  
where Isnull(AQMName,'No SQRM') is not null
and (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
Group by CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 ELSE
		 Isnull(AQMName,'No SQRM')
END,isnull(BQMNAme,'No QRM')
order by 
CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 
	 ELSE Isnull(AQMName,'No SQRM')
END,
isnull(BQMNAme,'No QRM')

End
If @Report = 'Supervisor'
Begin

Select 
CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 
	 ELSE Isnull(AQMName,'No SQRM')
END as AQMName,
isnull(BQMNAme,'No QRM') as QRM,
isnull(SupervisorName,'No Supervisor') as Supervisor,
count(*) as TotalReviews,
sum(case when (isnull(fdp.ASB_CompletedDate,fdf.ASB_CompletedDate)) is null then 0 else 1 end) as Completed
from #FirmDecPass fdp
full outer join #FirmDecFail fdf on fdf.ASB_AttendeeID = fdp.ASB_AttendeeID --and fdf.ASB_CompletedDate < fdp.ASB_CompletedDate
full outer join #FirmDecPending fdpe on fdpe.ASB_AttendeeID = fdp.ASB_AttendeeID
left join mi_insight_UserHierarchy uh on uh.UserGUID = isnull(fdp.ASB_AttendeeID,isnull(fdf.ASB_AttendeeID,fdpe.ASB_AttendeeID))  
where Isnull(AQMName,'No SQRM') is not null
and (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
Group by 
CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 
	 ELSE Isnull(AQMName,'No SQRM')
END,
isnull(BQMNAme,'No QRM'),
isnull(SupervisorName,'No Supervisor')
Order by
CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 
	 ELSE Isnull(AQMName,'No SQRM')
END,
isnull(BQMNAme,'No QRM'),
isnull(SupervisorName,'No Supervisor')

End
  
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


