****************************************************************************/


Begin

select      Attendee.UserGUID,
		    Attendee.username,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            max(ae.ASE_Date)as DueDate,
			'Pending' as Result
Into #FirmDecPending
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
where
	--ASB_Status = 4 
	ASS_Description like '%Annual Declaration Outcome%'
	and year(ASE_Date) = Year(Getdate())
	and ASB_Result = 0 --Fail
Group by	Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
			Attendee.UserName

select      Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            max(ab.ASB_CompletedDate)as ASB_CompletedDate,
			'Fail' as Result
Into #FirmDecFail
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
where
		ASB_Status = 4 
	and ASS_Description like '%Annual Declaration Outcome%'
	and year(ASB_CompletedDate) = Year(GetDate())
	and ASB_Result = 2 --Fail
Group by	Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description



select      Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            max(ab.ASB_CompletedDate) as ASB_CompletedDate,
			'Pass' as Result
Into #FirmDecPass
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
where
		ASB_Status = 4 
	and ASS_Description like '%Annual Declaration Outcome%'
	and year(ASB_CompletedDate) = Year(GetDate())
	and ASB_Result = 1--Pass
Group by	Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description

If @Report = 'Details'

Begin

Select 
CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 
	 ELSE Isnull(AQMName,'No SQRM')
END as SQRM,
isnull(BQMName,'No QRM') as QRM,
isnull(SupervisorName,'No Supervisor') as Supervisor,
isnull(fdp.ASB_AttendeeID,isnull(fdf.ASB_AttendeeID,fdpe.ASB_AttendeeID))  as AttendeeGUID,
uh.UserUID,
uh.UserName,
uh.BusinessCompanyName,
max(isnull(fdp.ASB_CompletedDate,fdf.ASB_CompletedDate)) as CompletedDate,
max(fdpe.DueDate) as DueDate,
isnull(case when fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null then fdp.Result else fdf.Result end,fdpe.Result) as Result,
case when fdf.Result is not null and fdp.Result is not null and (fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null) then 'Yes' else 'No' end as FailSubPass,
case when fdf.Result is not null and fdp.Result is not null and (fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null) then fdf.ASB_CompletedDate else null end as FailedDate
from #FirmDecPass fdp
full outer join #FirmDecFail fdf on fdf.ASB_AttendeeID = fdp.ASB_AttendeeID --and fdf.ASB_CompletedDate < fdp.ASB_CompletedDate
full outer join #FirmDecPending fdpe on fdpe.ASB_AttendeeID = fdp.ASB_AttendeeID
left join mi_insight_UserHierarchy uh on uh.UserGUID = isnull(fdp.ASB_AttendeeID,isnull(fdf.ASB_AttendeeID,fdpe.ASB_AttendeeID))  
where Isnull(AQMName,'No SQRM') is not null
and (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
Group by
isnull(fdp.ASB_AttendeeID,isnull(fdf.ASB_AttendeeID,fdpe.ASB_AttendeeID)),
isnull(BQMName,'No QRM'),
isnull(SupervisorName,'No Supervisor'),
uh.UserUID,
uh.UserName,
uh.BusinessCompanyName,
isnull(case when fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null then fdp.Result else fdf.Result end,fdpe.Result),
case when fdf.Result is not null and fdp.Result is not null and (fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null) then 'Yes' else 'No' end,
case when fdf.Result is not null and fdp.Result is not null and (fdf.ASB_CompletedDate < fdp.ASB_CompletedDate or fdf.ASB_CompletedDate is null) then fdf.ASB_CompletedDate else null end,
CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 
	 ELSE Isnull(AQMName,'No SQRM')
END
order by UserName

End
If @Report = 'QRM'
Begin

Select 
CASE WHEN (AQMName IS NULL AND uh.BQMName2 IS NOT NULL) THEN uh.BQMName2 
	 ELSE Isnull(AQMName,'No SQRM')
END as AQMName,
isnull(BQMNAme,'No QRM') as QRM,
count(*) as TotalReviews,
sum(case when (isnull(fdp.ASB_CompletedDate,fdf.ASB_CompletedDate)) is null then 0 else 1 end) as Completed
from #FirmDecPass fdp
full outer join #FirmDecFail fdf on fdf.ASB_AttendeeID = fdp.ASB_AttendeeID --and fdf.ASB_CompletedDate < fdp.ASB_CompletedDate
full outer join #FirmDecPending fdpe on fdpe.ASB_AttendeeID = fdp.ASB_AttendeeID
left join mi_insight_UserHierarchy uh on uh.UserGUID = isnull(fdp.ASB_AttendeeID,isnull(fdf.ASB_AttendeeID,fdpe.ASB_AttendeeID))  
