CREATE PROCEDURE [logi].[pr_ringo_DeepSpanFullFirmDeclaration]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
        @AQMUID		      varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanFullFirmDeclaration]
Author      : S Inglis
Date  : 15/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Full Firm Declaration" and is found on the "BQM MI" 
              menu. This report displays: 
              - The full firm declration



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanFullFirmDeclaration] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
11-11-2016	S Inglis		  Addition of Firm Dec from spreadsheet for 2016 for missing data
29-6-2017	S Inglis		  Join changed to left join to include social media questions
29-6-2017	S Inglis		  Update to fields to show as per business area
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Full Firm Declaration';
set @StoredProcName           = object_name(@@procid);
/*set @StoredProcParams         = '@SupervisorUID = ' + cast (@SupervisorUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @SupervisorUID*/
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

With CTE_FirmDec as
(Select distinct
uh.useruid,
uh.UserName,
case when uh.BusinessCompanyName is null then uh.BusinessTradingName else uh.BusinessCompanyName end as BusinessName,
uh.BusinessUID,
AQMUID,
AQMName,
BQMName,
ft.FT_Description,
fs.FS_Description,
fs.FS_Order,
-- varchar,fs.FS_Description) as Descr,
fq.FQ_Description as Question,
fq.FQ_LinkLogicMode,
fq.FQ_Mandatory,
fq.FQ_Type,
fq.FQ_Order,
--fq.*,
fac.FAC_Description,
fad.FAD_Code,
fad.FAD_Text,
fad.FAD_CreatedDate,
fad.FAD_UpdatedDate,
asb.ASB_CompletedDate,
FQ_Order + 1 as AnswerQuestion
from sa_insight_Form fr
join sa_insight_FormData fd on fd.FD_FormID = fr.FRM_ID
join sa_insight_assessmentbooking asb on asb.ASB_FormID = fd.FD_ID
join sa_insight_FormAnswerData fad on fad.FAD_FormDataID = fd.FD_ID
join sa_insight_FormQuestion fq on fq.FQ_ID = fad.FAD_QuestionID
left join sa_insight_FormAnswerCode fac on fac.FAC_Code = FAD_Code --updated 29-6-17
join sa_insight_FormSection fs on fs.FS_ID = fq.FQ_SectionID
join sa_insight_FormType ft on ft.FT_Code = fr.FRM_Type
join mi_insight_UserHierarchy uh on uh.UserGUID = asb.ASB_AttendeeID
where 1=1
--and uh.useruid = '1001295'
--and ft.FT_Code = 7
and isnull(uh.ADUID,'111111') not in ('4021409','4005013')
and asb.ASB_Status = 4
and asb.ASB_CompletedDate >= dateadd(year,-1,getdate())
--and FQ_Type = 0
--and FAD_FormDataID = 'EC339329-871D-421C-AA98-32C723DB324B'
and FT_Description like '%Firm Declaration%'
and ((FQ_Type = 0 and FAD_Code != 0) or (FAD_UpdatedDate!= FAD_CreatedDate and FQ_Type != 0))
--order by uh.username,fs.FS_Order,fq.FQ_Order
)
,

CTE_Totals as (
Select distinct
fd.UserUID as UserUID,
fd.UserName,
fd.BusinessName,
fd.BQMName,
fd.AQMName,
fd.FT_Description,
fd.FS_Description,
fd.Question,
fd.FQ_Order,
fd.FS_Order as FS_Order,
fd.FQ_Type,
isnull(fd.FAC_Description,fd1.FAD_Text) as FAC_Description, --updated 29/6/17
fd.ASB_CompletedDate,
case when fd.FAC_Description is null or (fd.fs_order = 4 and fd.FQ_Order = 10) then '' else fd1.FAD_Text end as FAD_Text --updated 29/6/17
from CTE_FirmDec fd
left join CTE_FirmDec fd1 on fd1.FQ_Order = (case when fd.FQ_Type = 0 then fd.AnswerQuestion else fd.FQ_Order end) and fd.UserUID = fd1.UserUID and fd.FS_Order = fd1.FS_Order --updated 29/6/17
where fd.FQ_Type = 0 or fd.Question like 'Please confirm%'
--and (fd.AQMUID = @AQMUID or @AQMUID = 'View All')
--and fd.UserUID = '1003217'
Union
Select
UID as UserUID,
[Declaration Completed By],
case when uh.BusinessCompanyName is null then uh.BusinessTradingName else uh.BusinessCompanyName end as BusinessName,
[QRM name],
[SQRM name],
'Annual Firm Declaration',
Area,
aif.Question,
'',
case when Area = 'Business Premises' then 4 when Area = 'Other Business Interests' then 12 end as FS_Order ,
'',
Response,
case when [Completed Date] is null then fd.ASB_CompletedDate else [Completed Date] end as ASB_CompletedDate,
[Additional Comments]
from TandC.AdditionalInformationFirmMI aif
left join mi_insight_UserHierarchy uh on uh.UserUID = UID
join CTE_FirmDec fd on fd.UserUID = aif.UID
and aif.Area != 'Are You a Sole Trader'
--where UID = '1003217'
)

Select
tt.UserUID,
tt.UserName,
BusinessName,
tt.BQMName,
tt.AQMName,
FT_Description,
FS_Description,
Question,
FQ_Order,
FS_Order,
FQ_Type,
FAC_Description,
ASB_CompletedDate,
FAD_Text
from CTE_Totals tt
join mi_insight_UserHierarchy uh on uh.UserUID = tt.UserUID
where ASB_CompletedDate >= dateadd(year,-1,getdate())
--and tt.UserUID = '1003217'
and (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
order by tt.UserUID, FS_Order, FQ_Order, ASB_CompletedDate
  
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


