--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

select distinct
 KPI_ID
,KPI_Name
,KPI_DateFrom
,KPI_DateTo
,case when KPI_Type = 1 then 'Adviser'
	  when KPI_Type = 4 then 'Supervisor'
	  when KPI_Type = 9 then 'Firm' end as KPIType
from sa_insight_kpi
where KPI_DateTo is null
and (case when KPI_Type = 1 then 'Adviser'
		 when KPI_Type = 4 then 'Supervisor'
		 when KPI_Type = 9 then 'Firm' end = @UserType or @UserType is null)
order by KPI_DateFrom


End

END TRY

