CREATE PROCEDURE [logi].[pr_ringo_DeepSpanKPIResults]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
        @AQMUID		      varchar(255) = 'View All',
	    @KPIName		  varchar (255) = 'View All',
	    @KPIResult		  varchar(255) = 'View All',
	    @KPIType		  varchar(255)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanKPIResults]
Author      : S Inglis
Date  : 21/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span KPI Results" and is found on the "BQM MI" 
              menu. This report displays: 
              - All KPI Results for the most recent run



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanKPIResults] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
20-3-17		S Inglis		  Update of code to include 'View All' option - CR541
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare--           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int
--				  @StartDate					 datetime,
--				  @EndDate						 datetime; 
--DECLARE			  @return_value					 int;
--DECLARE			  @lc_UserUid					 varchar(7);
--DECLARE			  @lc_UserName					 varchar(50);
--DECLARE			  @lc_UserJobTitleCodeHO		 int;
--DECLARE			  @lc_UserJobTitleCodePartner	 int;
--DECLARE			  @lc_UserJobTitleCodeSupervisor int;
--DECLARE			  @lc_UserJobTitleCodeBQM		 int;
--Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span KPI Results';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

select distinct
KPI_ID,
KPI_Name
into #KPIName
from sa_insight_KPI
--where KPI_Type in (1,2,3)

select distinct
UserID,
pop.UserUid,
pop.UserName,
SupervisorUserName,
AQMUID,
AQMName
into #User
from mi_insight_KPIPopulation pop
join mi_insight_UserHierarchy uh on uh.UserGUID = pop.UserID
where UserJobTitleCode in (4,42)


select dist.DIST_ExternalID as BusinessUID
      ,dist.DIST_CompanyName as BusinessName
	  ,dist.DIST_ID
	  ,uh.UserUID as FirmSupervisorUID
	  ,uh.UserName as FirmSupervisorName
	  ,uh.AQMUID
	  ,uh.AQMName
into #Firm
from sa_insight_Distributor dist
join sa_insight_UserPositionLink upl on upl.UPSL_ChildUserPositionID = dist.DIST_ID
join sa_insight_UserPosition up on up.UPS_ID = upl.UPSL_ParentUserPositionID
join mi_insight_UserHierarchy uh on uh.UserGUID = up.UPS_UserID
where 1=1
--and UserUID = '1010760'
and UPSL_DateTo is null

select distinct
UserID,
pop.UserUid,
pop.UserName,
SupervisorUserName,
AQMUID,
AQMName
into #Supervisor
from mi_insight_KPIPopulation pop
join mi_insight_UserHierarchy uh on uh.UserGUID = pop.UserID
where UserJobTitleCode in (7,8,9)

If @KPIType = 'Adviser' 
select
'Adviser' as KPIType,
 SupervisorUserName as Supervisor,
 AQMName,
 kpi.KPID_KPI_ID,
 kpin.KPI_Name,
 kpi.KPID_UserID,
 uh.username as Name,
 KPI.KPID_Date,
 case when kpimi.ReasonDesc IS NOT NULL THEN cd.Code_Description + ' - ' + kpimi.ReasonDesc ELSE CD.Code_Description END as RedReason
 from sa_insight_KPIResult KPI
 join #User uh on uh.UserID = KPID_UserID
 join #KPIName kpin on kpin.KPI_ID = kpi.KPID_KPI_ID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 left join mi_insight_KPIResult kpimi on kpimi.KPID_KPI_ID = kpi.KPID_KPI_ID and kpimi.KPID_UserID = kpi.KPID_UserID
 where KPI.KPID_Date >= dateadd(month,-1,convert(date,getdate()))
 and (cd.Code_Description = @KPIResult or @KPIResult = 'View All') --amended 20-3-17
 and (kpin.KPI_Name = @KPIName or @KPIName = 'View All') --amended 20-3-17
 and (AQMUID = @AQMUID or @AQMUID = 'View All')
 
 If @KPIType = 'Firm'
 select
 'Firm' as KPIType,
 FirmSupervisorName as Supervisor,
 AQMName,
 kpi.KPID_KPI_ID,
 kpin.KPI_Name,
 kpi.KPID_UserID,
 uh.BusinessName as Name,
 KPI.KPID_Date,
 case when kpimi.ReasonDesc IS NOT NULL THEN cd.Code_Description + ' - ' + kpimi.ReasonDesc ELSE CD.Code_Description END as RedReason
 from sa_insight_KPIResult KPI
 join #Firm uh on uh.DIST_ID = KPID_UserID
 join #KPIName kpin on kpin.KPI_ID = kpi.KPID_KPI_ID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 left join mi_insight_KPIResult kpimi on kpimi.KPID_KPI_ID = kpi.KPID_KPI_ID and kpimi.KPID_UserID = kpi.KPID_UserID
 where KPI.KPID_Date >= dateadd(month,-3,convert(date,getdate()))
 and (cd.Code_Description = @KPIResult or @KPIResult = 'View All') --amended 20-3-17
 and (kpin.KPI_Name = @KPIName or @KPIName = 'View All') --amended 20-3-17
 and (AQMUID = @AQMUID or @AQMUID = 'View All')

 If @KPIType = 'Supervisor'
 
 select
 'Supervisor' as KPIType,
 SupervisorUserName as Supervisor,
 AQMName,
 kpi.KPID_KPI_ID,
 kpin.KPI_Name,
 kpi.KPID_UserID,
 uh.username as Name,
 KPI.KPID_Date,
 case when kpimi.ReasonDesc IS NOT NULL THEN cd.Code_Description + ' - ' + kpimi.ReasonDesc ELSE CD.Code_Description END as RedReason
 from sa_insight_KPIResult KPI
 join #Supervisor uh on uh.UserID = KPID_UserID
 join #KPIName kpin on kpin.KPI_ID = kpi.KPID_KPI_ID
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 left join mi_insight_KPIResult kpimi on kpimi.KPID_KPI_ID = kpi.KPID_KPI_ID and kpimi.KPID_UserID = kpi.KPID_UserID
 where KPI.KPID_Date >= dateadd(month,-1,convert(date,getdate()))
 and (cd.Code_Description = @KPIResult or @KPIResult = 'View All') --amended 20-3-17
 and (kpin.KPI_Name = @KPIName or @KPIName = 'View All') --amended 20-3-17
 and (AQMUID = @AQMUID or @AQMUID = 'View All')

print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
