CREATE PROCEDURE [logi].[pr_ringo_DeepSpanLateEvents]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
        @AQMUID		      varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanLateEvents]
Author      : S Inglis
Date  : 21/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Late Events" and is found on the "BQM MI" 
              menu. This report displays: 
              - Events that are late and greater than 6 months late



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanLateEvents] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
10/10/2017	S Inglis		  Updated to take into account one off change to date due
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
20.9.2021	S Inglis		  Changed from 6 months to 3 months
19/10/2021	S Campbell		  OWS Decouple - Create copy in BI Schema 
							  Use BI.sa_d365_ows_Event table instead of Events.sa_ows_Event table
26/10/2021	S Campbell	      Use BI.mi_concert_ows_Event
05/04/2022	S Campbell		  Use dbo.mi_concert_ows_Event
30/09/2024  R251929     P Reed- Replace the Merged Event table: dbo.mi_concert_ows_Event with view that excludes OWS outstanding (1,2,3) events (concert1234_ows4_event

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Late Events';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

with cte_svc as (SELECT -- TOP 1000
       -- miuh.AQMName
--	  , case isnull(miuh.BusinessUid,'10002') when '10002' then 'Openwork'
    --                                         else isnull(miuh.BusinessTradingName,miuh.BusinessCompanyName) end as Firm
  --    , miuh.UserName    as AdviserName
       evty.Name as EventType     
      , sum(case erst.EventReminderStatusText when 'Scheduled' then 1 else 0 end ) as ScheduledEvents
      , sum(case erst.EventReminderStatusText when 'Due' then 1 else 0 end )       as DueEvents
      , sum(case erst.EventReminderStatusText when 'Late' then 1 else 0 end ) as LateEvents
      , COUNT(1) as TotalEvents
      , sum(case erst.EventReminderStatusText when 'Late' then case when isnull(even.OneOffChangeToDateDue,even.DateDue) >= DATEADD(MONTH,-3,GETDATE()) then 1 else 0 end  else 0 end ) as LateEventsUnder6MonthsLate --Updated 10.10.17 SI
      , sum(case erst.EventReminderStatusText when 'Late' then case when isnull(even.OneOffChangeToDateDue,even.DateDue) <  DATEADD(MONTH,-3,GETDATE()) then 1 else 0 end  else 0 end ) as LateEventsOver6MonthsLate --Updated 10.10.17 SI
  FROM prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
