CREATE PROCEDURE [logi].[pr_ringo_DeepSpanRedRiskOneToOne]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
        @AQMUID		      varchar(255) = 'View All',
	    @RiskDate		  datetime

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanRedRiskOneToOne]
Author      : S Inglis
Date  : 27/07/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Red Risk One To One" and is found on the "BQM MI" 
              menu. This report displays: 
              - Any adviser who has had a red risk assessment in the last 6 months and the 
			  date of their one to one


              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanRedRiskOneToOne] 'ptl91371', 'Logi'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
05-10-2016	S Inglis		  SQL updated to include KPI's red in current month that werent in
							  previous reporting period
14-10-2016	S Inglis		  SQL updated to refer to 1:1 2016 assessment and not form
14-10-2016	S Inglis		  SQL updated to add notation and isnull to exclusion of Owl Advisers
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Red Risk One To One';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

With CTE_OneToOne as (
Select distinct
uh.useruid,
uh.UserName,
case when uh.BusinessCompanyName is null then uh.BusinessTradingName else uh.BusinessCompanyName end as BusinessName,
uh.BusinessUID,
--ft.FT_Description,
asb.ASB_CompletedDate,
asb.ASB_CreatedDate,
asb.ASB_Status
from sa_insight_Assessment fr
left join sa_insight_AssessmentEvent asse on asse.ASE_TypeID = fr.ASS_ID
--left join sa_insight_FormData fd on fd.FD_FormID = fr.FRM_ID
left join sa_insight_assessmentbooking asb on asb.ASB_EventID = asse.ASE_ID
--left join sa_insight_FormType ft on ft.FT_Code = fr.FRM_Type
left join mi_insight_UserHierarchy uh on uh.UserGUID = asb.ASB_AttendeeID
where 1=1
and isnull(uh.ADUID,999999) not in ('4021409','4005013') --exclude OWL advisers
and asb.ASB_Status = 4
and asb.ASB_CompletedDate >= dateadd(year,-1,getdate())
and fr.ASS_Description like '%1:1 2016%'
--and uh.UserUID = '1001151'
),

CTE_RedRisk as (
select
AQMUID,
AQMName,
BQMName,
SupervisorName,
Uh.UserUID,
uh.UserName,
uh.BusinessUID,
uh.BusinessCompanyName,
ra.RA_Date,
dateadd(day,31,ra_date) as OneToOneDeadline,
ra.RA_USR_Type,
cd.Code_Description as Rating
from sa_insight_RiskAssessment ra
join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
join mi_insight_UserHierarchy uh on uh.UserGUID = ra.RA_USR_ID 
where ra.RA_Date >= dateadd(month,-6,getdate())
and RA_Status = 3 --Red
and RA_USR_Type = 1 --Adviser
--order by UserUID
),

CTE_REDKPIs as
(select UseruId, UserName, KPIs
from
(
select uho.UserName, uho.UserUID
   ,RTRIM((SELECT kpi.KPI_Name + '; '
      from  sa_insight_KPI kpi 
                              join sa_insight_KPIResult kpir on kpi.KPI_ID = kpir.KPID_KPI_ID and kpir.KPID_Date = @RiskDate
                              join sa_insight_CodeDescription cd on cd.Code_Code = kpir.KPID_Status and cd.Code_CodeType = 655
                              join sa_insight_KPIResult kpirlm on kpir.KPID_KPI_ID = kpirlm.KPID_KPI_ID and kpirlm.KPID_Date between dateadd(month,-1,@RiskDate) and  @RiskDate
                              join sa_insight_CodeDescription cd1 on cd1.Code_Code = kpirlm.KPID_Status and cd1.Code_CodeType = 655
                              join mi_insight_UserHierarchy uh on uh.UserGUID = kpir.KPID_UserID
                              where kpir.KPID_UserID =  kpirlm.KPID_UserID
                              and cd1.Code_Description != 'Red' and cd.Code_Description = 'Red'
                              and uh.UserGUID = uho.UserGUID 
							  and kpi.KPI_Type = 1
                              order by uh.Username, kpi.KPI_Code
                              FOR XML PATH(''))) as KPIs
from mi_insight_UserHierarchy uho
-- where uho.UserUID = '1000927'
) results
where results.KPIs is not null)

Select
rr.AQMName,
rr.BQMName,
rr.SupervisorName,
rr.UserUID,
rr.UserName,
rr.businessCompanyName,
rr.RA_Date,
rr.Rating,
max(oo.ASB_CompletedDate) as OneToOneInMonthDate,
max(oo2.ASB_CompletedDate) as LatestOneToOne,
kpi.KPIs
from CTE_RedRisk rr
left join CTE_OneToOne oo on oo.UserUID = rr.UserUID and oo.ASB_CompletedDate between rr.RA_Date and rr.OneToOneDeadline
left join CTE_OneToOne oo2 on oo2.UserUID = rr.UserUID
left join CTE_REDKPIs kpi on kpi.UserUID = rr.UserUID
Where
RA_Date = @RiskDate 
and (rr.AQMUID = @AQMUID or @AQMUID = 'View All')
group by rr.UserUID,
rr.UserName,
rr.RA_Date,
rr.Rating,
rr.AQMName,
rr.BQMName,
rr.SupervisorName,
rr.businessCompanyName,
kpi.KPIs
--oo.ASB_CompletedDate
order by UserUID, RA_Date

 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


