                  1) T&C Team

              The report name is "Deep Span Risk Assessment DrillDown" and is found on the "BQM MI" 
              menu. This report displays: 
              - Risk Assessment details



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanRiskAssessmentDrillDown] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'DueEventsTotalFirmLevel';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

With CTE_AdviserSup as
(Select
uh.AQMUID,
uh.AQMGUID,
uh.AQMName,
uh.BQMName,
case when uh.BusinessCompanyName IS null then uh.BusinessTradingName else uh.BusinessCompanyName end as FirmName,
UserID as UniqueID,
pop.UserUID as UniqueUID,
pop.UserName as UniqueName,
case when UserJobTitleCode in (4,42)then 1 when UserJobTitleCode IN (7,8,9) then 4 end AS RiskType,
case when UserJobTitleCode in (4,42)then 'Adviser' when UserJobTitleCode IN (7,8,9) then 'Supervisor' end AS RiskUser,
pop.COBCompetencyDesc as COBSCompetency,
pop.MCOBCompetencyDesc as MCOBCompetency
From mi_insight_KPIPopulation pop
join mi_insight_UserHierarchy uh on uh.UserGUID = pop.UserID
Where UserJobTitleCode in (4,7,8,9,42)
--and uh.ADUID != '4005013'
Union
Select distinct
uh.AQMUID,
uh.AQMGUID,
uh.AQMName,
uh.BQMName,
'N/A' as FirmName,
BusinessID as UniqueID,
pop.BusinessUID as UniqueUID,
pop.BusinessName as UniqueName,
9 as RiskType,
'Firm' as RiskUser,
'' as COBSCompetency,
'' as MCOBCompetency
From mi_insight_KPIPopulation pop
join mi_insight_UserHierarchy uh on uh.BusinessGUID = pop.BusinessID
where uh.ADUID not in ('4021409','4005013'))

select 
cdvs.AQMName, 
cdvs.BQMName,
cdvs.FirmName,
cdvs.UniqueUID,
cdvs.UniqueName,
cdvs.RiskType,
cdvs.RiskUser,
cd.Code_Description,
ra.RA_Date,
COBSCompetency,
MCOBCompetency
from sa_insight_RiskAssessment ra
join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
left join CTE_AdviserSup cdvs on cdvs.UniqueID = ra.RA_USR_ID and cdvs.RiskType = ra.RA_USR_Type
where RA_Date = (select max(ra1.RA_Date)
				 from sa_insight_RiskAssessment ra1
				 where ra1.RA_USR_ID = ra.RA_USR_ID)
and RA_Date >= DATEADD(month,-4,getdate())
and UniqueUID is not null
and (cdvs.AQMUID = @AQMUID or @AQMUID = 'View All')
and cdvs.RiskUser = @UserType
and cd.Code_Description = @RiskStatus
order by UniqueUID

print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


