	    @RiskDate		  datetime

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanRiskAssessmentOverwrite]
Author      : S Inglis
Date  : 15/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Risk Assessment Overwrite" and is found on the "BQM MI" 
              menu. This report displays: 
              - Any Risk Assessment Overwrites



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanRiskAssessmentOverwrite] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Risk Assessment Overwrite';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

With CTE_FirmAQM as
(Select distinct
 BusinessUID
 ,AQMUID
 ,AQMName
 from mi_insight_UserHierarchy
 where ADUID not in ('4021409','4005013'))

select  
 distinct kpip.UserUID as UniqueID
--,RA_ID
,kpip.UserName as Name
,cd1.Code_Description as OriginalRiskRating
,cd.Code_Description as UpdatedRiskRating
,uh1.UserName as RiskAssessmentUpdatedBy
,RA_Date
,case when RA_USR_Type = 1 then 'Adviser' when RA_USR_Type = 4 then 'Supervisor' end AS UserType
,ra.RA_UpdatedDate
,uh.UserName as Supervisor
,note.NOTE_Text
,uh.AQMName
,kpip.BusinessName as FirmName
from sa_insight_RiskAssessment ra
join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
join sa_insight_CodeDescription cd1 on cd1.Code_Code = ra.RA_OriginalStatus and cd1.Code_CodeType = 500
join mi_insight_KPIPopulation kpip on kpip.UserID = RA_USR_ID
join mi_insight_UserHierarchy uh on uh.UserGUID = kpip.SupervisorUserID
join mi_insight_UserHierarchy uh1 on uh1.UserGUID = ra.RA_UpdatedBy
join sa_insight_Note note on note.NOTE_ParentID = RA_ID
join mi_insight_UserHierarchy uh2 on uh2.UserGUID = RA_USR_ID
where cd.Code_Description != cd1.Code_Description
and RA_Date >= '01-01-2016'
and RA_Date = @RiskDate 
and (uh.AQMUID = @AQMUID or @AQMUID = 'View All')
--and (uh2.AQMUID = @AQMUID or @AQMUID = 'View All')
--and kpip.UserUID = '1005170'
--and uh.UserUID = @AdviserUID
union
select  
 distinct kpip.BusinessUID as UniqueID
--,RA_ID
,kpip.BusinessName as Name
,cd1.Code_Description as OriginalRiskRating
,cd.Code_Description as UpdatedRiskRating
,uh1.UserName as RiskAssessmentUpdatedBy
,RA_Date
,'Firm' AS UserType
,ra.RA_UpdatedDate
,uh.UserName as Supervisor
,note.NOTE_Text
,aqm.AQMName
,'N/A' as FirmName
from sa_insight_RiskAssessment ra
join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
join sa_insight_CodeDescription cd1 on cd1.Code_Code = ra.RA_OriginalStatus and cd1.Code_CodeType = 500
join mi_insight_KPIPopulation kpip on kpip.businessID = RA_USR_ID
join mi_insight_UserHierarchy uh on uh.UserGUID = kpip.SupervisorUserID
join mi_insight_UserHierarchy uh1 on uh1.UserGUID = ra.RA_UpdatedBy
join sa_insight_Note note on note.NOTE_ParentID = RA_ID
join CTE_FirmAQM aqm on aqm.BusinessUID = kpip.BusinessUID
where cd.Code_Description != cd1.Code_Description
and RA_Date >= '01-01-2016'
and RA_Date = @RiskDate 
and (aqm.AQMUID = @AQMUID or @AQMUID = 'View All')
  
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


