CREATE PROCEDURE [logi].[pr_ringo_DeepSpanRiskAssessmentTotals]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
        @AQMUID		      varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanRiskAssessmentTotals]
Author      : S Inglis
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Risk Assessment Totals" and is found on the "BQM MI" 
              menu. This report displays: 
              - Latest Risk Assessments Grouped by result and assessment Type



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanRiskAssessmentTotals] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'DueEventsTotalFirmLevel';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

With CTE_Firm as(
select distinct
BusinessGUID,
case when BusinessCompanyName is null then BusinessTradingName else BusinessCompanyName end as BusinessName,
AQMUID
from mi_insight_UserHierarchy
where BusinessGUID is not null
and ADUID not in ('4021409','4005013')
)

Select 
2 as QueryNo,
'Firm' as RiskArea,
sum(case when cd.Code_Description = 'Red Flag' then 1 else 0 end) as 'RedFlagCount',
sum(case when cd.Code_Description = 'Red' then 1 else 0 end) as 'RedCount',
sum(case when cd.Code_Description = 'Amber' then 1 else 0 end) as 'AmberCount',
sum(case when cd.Code_Description = 'Green' then 1 else 0 end) as 'GreenCount'
--'Last Quarter' as RA_Date
from sa_insight_RiskAssessment ra
join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
join CTE_Firm frm on frm.BusinessGUID = ra.RA_USR_ID
where RA_Date = (select max(ra1.RA_Date)
				 from sa_insight_RiskAssessment ra1
				 where ra1.RA_USR_ID = ra.RA_USR_ID)
--and pop.UserJobTitleCode in (7,8,9)
and RA_USR_Type = 9
and (AQMUID = @AQMUID or @AQMUID = 'View All')

UNION
Select distinct
1 as QueryNo,
'Adviser' as RiskArea,
--pop.UserUID,
--pop.UserName,
--pop.UserJobTitleCode,
sum(case when cd.Code_Description = 'Red Flag' then 1 else 0 end) as 'RedFlagCount',
sum(case when cd.Code_Description = 'Red' then 1 else 0 end) as 'RedCount',
sum(case when cd.Code_Description = 'Amber' then 1 else 0 end) as 'AmberCount',
sum(case when cd.Code_Description = 'Green' then 1 else 0 end) as 'GreenCount'
--ra.RA_Date
from sa_insight_RiskAssessment ra
join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
join mi_insight_KPIPopulation pop on pop.UserID = ra.RA_USR_ID
left join mi_insight_UserHierarchy uh on uh.UserGUID = pop.UserID
where RA_Date = (select max(ra1.RA_Date)
				 from sa_insight_RiskAssessment ra1
				 where ra1.RA_USR_ID = ra.RA_USR_ID)
and pop.UserJobTitleCode in (4,42)
and RA_USR_Type = 1
and (AQMUID = @AQMUID or @AQMUID = 'View All')
--and uh.ADUID != '4005013'
--Group by ra.RA_Date
UNION
Select distinct
3 as QueryNo,
'Supervisor' as RiskArea,
sum(case when cd.Code_Description = 'Red Flag' then 1 else 0 end) as 'RedFlagCount',
sum(case when cd.Code_Description = 'Red' then 1 else 0 end) as 'RedCount',
sum(case when cd.Code_Description = 'Amber' then 1 else 0 end) as 'AmberCount',
sum(case when cd.Code_Description = 'Green' then 1 else 0 end) as 'GreenCount'
--ra.RA_Date
from sa_insight_RiskAssessment ra
join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
join mi_insight_KPIPopulation pop on pop.UserID = ra.RA_USR_ID
join mi_insight_UserHierarchy uh on uh.UserGUID = pop.UserID
where RA_Date = (select max(ra1.RA_Date)
				 from sa_insight_RiskAssessment ra1
				 where ra1.RA_USR_ID = ra.RA_USR_ID)
and pop.UserJobTitleCode in (7,8,9)
and RA_USR_Type = 4
and (AQMUID = @AQMUID or @AQMUID = 'View All')
--and uh.ADUID != '4005013'
--Group by ra.RA_Date
Order by QueryNo
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


