CREATE PROCEDURE [logi].[pr_ringo_DeepSpanSupervisorActivityManagement]
		@PtlCode		  varchar(255),
	    @ReportFormat	  varchar(200),
        @AQMUID		      varchar(255) = 'View All'
	--  @SupervisorUID	  varchar (7)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_DeepSpanSupervisorActivityManagement]
Author      : S Inglis
Date  : 15/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Deep Span Supervisor Activity Management" and is found on the "BQM MI" 
              menu. This report displays: 
              - Supervisor Activity Management



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanSupervisorActivityManagement] 30, 'ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
24.6.21		S Inglis		  Updated to include new Owl Sales Director code
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Deep Span Supervisor Activity Management';
set @StoredProcName           = object_name(@@procid);

exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                  @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print 'before query';
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
--IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

	select
		distinct pop.UserUID
		,pop.UserName
		,pop.BusinessUID
		,pop.BusinessName
		,uh.UserName as SupervisorName
		,USRTE_DueDate
		,datediff(day,usrte_DueDate,getdate()) as DaysOverdue
		,TCT_Description
		,TCTM_Description
		,uh1.AQMName
	from	dbo.mi_insight_KPIPopulation pop 
			join sa_insight_UserTandCTrack ut on ut.USRT_UserID = pop.userid
			join sa_insight_UserTandCTrackModule utm on utm.USRTS_UserTrackID = ut.USRT_ID
			join sa_insight_UserTandCTrackEvent ute on ute.USRTE_ModuleID = utm.USRTS_ID
			join sa_insight_TandCTrack t on t.TCT_ID = ut.USRT_TrackID
			join sa_insight_TandCTrackModule tm on tm.TCTM_ID = utm.USRTS_TrackModuleID
			join mi_insight_UserHierarchy uh on pop.SupervisorUserID = uh.UserGUID
			join mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
	where	pop.SupervisorJobTitleCode in (7,8,9)		--7=BQM;8=Supervisor;9=AQM
	and		pop.UserJobTitleCode in (4,42,7,8)			--4=Adviser;42=Schedule E Seller;7=BQM;8=Supervisor 
--	and		uh.useruid = @AdviserUID
	and		USRTE_CompletedDate is null
	and		ute.USRTE_DueDate <= getdate() and ute.USRTE_DueDate >= dateadd(month,-1,getdate())
	and    (uh1.AQMUID = @AQMUID or @AQMUID = 'View All')
	and     uh1.ADUID not in ('4021409','4005013')
 
print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
