04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.													
10/10/2017	S Inglis	Updated to take into account one off change to date due
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_EventServicingAdviser_Backup20210902AG]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

set @ReportName               = 'pr_Ringo_EventServicingAdviser';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
                                                   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
		or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--4007578=Elizabeth Yates; 4007612=Paul Coggins; 4007621=Antony Lark	AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

with cte_svc as (SELECT -- TOP 1000
        case isnull(miuh.BusinessUid,'10002') when '10002' then 'Openwork'
                                             else isnull(miuh.BusinessTradingName,miuh.BusinessCompanyName) end as Firm
      , miuh.UserName    as AdviserName
      , evty.Name as EventType     
      , sum(case erst.EventReminderStatusText when 'Scheduled' then 1 else 0 end ) as ScheduledEvents
      , sum(case erst.EventReminderStatusText when 'Due' then 1 else 0 end )       as DueEvents
      , sum(case erst.EventReminderStatusText when 'Late' then 1 else 0 end ) as LateEvents
      , COUNT(1) as TotalEvents
      , sum(case erst.EventReminderStatusText when 'Late' then case when isnull(even.OneOffChangeToDateDue,even.DateDue) >= DATEADD(MONTH,-6,GETDATE()) then 1 else 0 end  else 0 end ) as LateEventsUnder6MonthsLate --updated 10/10/17
      , sum(case erst.EventReminderStatusText when 'Late' then case when isnull(even.OneOffChangeToDateDue,even.DateDue) <  DATEADD(MONTH,-6,GETDATE()) then 1 else 0 end  else 0 end ) as LateEventsOver6MonthsLate --updated 10/10/17
  FROM prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
  JOIN prod_zurich_openwork_datawarehouse.dbo.mi_insight_UserHierarchy miuh on miuh.UserUID = pers.AdviserUID
  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_EventType evty on evty.EventTypeID = even.TypeID
  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_EventReminderStatus erst on erst.EventReminderStatusID = even.EventReminderStatusID
  where even.TypeID in (1,2)
  and   isnull(even.IsCancelled,0) = 0 
  and   miuh.UserUID = @AdviserUID
  and   isnull(even.IsDeleted,0)   = 0
  and   erst.EventReminderStatusID in (1,2,3)
  group by miuh.BusinessUid,
           miuh.BusinessTradingName,
           miuh.BusinessCompanyName,
           miuh.UserName,
           evty.Name
  )
  select cte_svc.Firm
        ,cte_svc.AdviserName
        ,cte_svc.EventType
        ,cte_svc.TotalEvents
        ,cte_svc.ScheduledEvents
 --       ,case when cte_svc.ScheduledEvents > 0 then round((cast (cte_svc.ScheduledEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as ScheduledEventsPct
        ,case when cte_svc.ScheduledEvents > 0 then 100 - round((cast (cte_svc.lateEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2)
                                                        - round((cast (cte_svc.dueEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as ScheduledEventsPct
        ,cte_svc.DueEvents
        ,case when cte_svc.DueEvents > 0 then round((cast (cte_svc.DueEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as DueEventsPct
        ,cte_svc.LateEvents
        ,case when cte_svc.LateEvents > 0 then round((cast (cte_svc.LateEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as LateEventsPct
       ,cte_svc.LateEventsUnder6MonthsLate
        ,cte_svc.LateEventsOver6MonthsLate
        ,case when cte_svc.LateEventsOver6MonthsLate > 0 then round((cast (cte_svc.LateEventsOver6MonthsLate AS float) / 
                                                              (cast (cte_svc.ScheduledEvents + cte_svc.DueEvents + cte_svc.LateEvents AS Float)) * 100),2)
                                                         else 0 end as PctOver6Mnths    
  from cte_svc
  order by Firm,AdviserName;
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_EventServicingAdviser_Backup20220413SC]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/06/2016	A Groves	Temporary hardcoded access for JMD supervisors (one level up):
						Antony Lark, Duncan Jones and Philip Potter.
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.	
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.													
10/10/2017	S Inglis	Updated to take into account one off change to date due
02/09/2021	S Inglis	Changed from >6 months to > 3 months
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_EventServicingAdviser_Backup20220413SC]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

set @ReportName               = 'pr_Ringo_EventServicingAdviser';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
                                                   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
		or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--4007578=Elizabeth Yates; 4007612=Paul Coggins; 4007621=Antony Lark	AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

with cte_svc as (SELECT -- TOP 1000
        case isnull(miuh.BusinessUid,'10002') when '10002' then 'Openwork'
                                             else isnull(miuh.BusinessTradingName,miuh.BusinessCompanyName) end as Firm
      , miuh.UserName    as AdviserName
      , evty.Name as EventType     
      , sum(case erst.EventReminderStatusText when 'Scheduled' then 1 else 0 end ) as ScheduledEvents
      , sum(case erst.EventReminderStatusText when 'Due' then 1 else 0 end )       as DueEvents
      , sum(case erst.EventReminderStatusText when 'Late' then 1 else 0 end ) as LateEvents
      , COUNT(1) as TotalEvents
      , sum(case erst.EventReminderStatusText when 'Late' then case when isnull(even.OneOffChangeToDateDue,even.DateDue) >= DATEADD(MONTH,-3,GETDATE()) then 1 else 0 end  else 0 end ) as LateEventsUnder6MonthsLate --updated 10/10/17
      , sum(case erst.EventReminderStatusText when 'Late' then case when isnull(even.OneOffChangeToDateDue,even.DateDue) <  DATEADD(MONTH,-3,GETDATE()) then 1 else 0 end  else 0 end ) as LateEventsOver6MonthsLate --updated 10/10/17
  FROM prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
  JOIN prod_zurich_openwork_datawarehouse.dbo.mi_insight_UserHierarchy miuh on miuh.UserUID = pers.AdviserUID
  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_EventType evty on evty.EventTypeID = even.TypeID
  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_EventReminderStatus erst on erst.EventReminderStatusID = even.EventReminderStatusID
  where even.TypeID in (1,2)
  and   isnull(even.IsCancelled,0) = 0 
  and   miuh.UserUID = @AdviserUID
  and   isnull(even.IsDeleted,0)   = 0
  and   erst.EventReminderStatusID in (1,2,3)
  group by miuh.BusinessUid,
           miuh.BusinessTradingName,
           miuh.BusinessCompanyName,
           miuh.UserName,
           evty.Name
  )
  select cte_svc.Firm
        ,cte_svc.AdviserName
        ,cte_svc.EventType
        ,cte_svc.TotalEvents
        ,cte_svc.ScheduledEvents
 --       ,case when cte_svc.ScheduledEvents > 0 then round((cast (cte_svc.ScheduledEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as ScheduledEventsPct
        ,case when cte_svc.ScheduledEvents > 0 then 100 - round((cast (cte_svc.lateEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2)
                                                        - round((cast (cte_svc.dueEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as ScheduledEventsPct
        ,cte_svc.DueEvents
        ,case when cte_svc.DueEvents > 0 then round((cast (cte_svc.DueEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as DueEventsPct
        ,cte_svc.LateEvents
        ,case when cte_svc.LateEvents > 0 then round((cast (cte_svc.LateEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as LateEventsPct
       ,cte_svc.LateEventsUnder6MonthsLate
        ,cte_svc.LateEventsOver6MonthsLate
        ,case when cte_svc.LateEventsOver6MonthsLate > 0 then round((cast (cte_svc.LateEventsOver6MonthsLate AS float) / 
                                                              (cast (cte_svc.ScheduledEvents + cte_svc.DueEvents + cte_svc.LateEvents AS Float)) * 100),2)
                                                         else 0 end as PctOver6Mnths    
  from cte_svc
  order by Firm,AdviserName;
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

