/****** Object:  StoredProcedure [logi].[pr_ringo_FirmCOBWrittenTotal]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [logi].[pr_ringo_FirmCOBWrittenTotal]
                @FirmUID      varchar(7)
               ,@PtlCode      varchar(15)


AS BEGIN
set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_FirmCOBWrittenTotal]
Author      : S Inglis
Date  : 11/08/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Firm Written COB Business Totals" and is found on the "BQM MI" 
              menu. This report displays: 
              - Adviser COB business written in the last 12 months totalled by type and 
              month at Firm level


              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_AdviserPlatWrittenTotal] 'ptl91371', 'Logi', '1002350'

AMENDMENT HISTORY
=================
Date        Author		Description
----        ------		-----------

***********************************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'pr_ringo_FirmCOBWrittenTotal';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + @FirmUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

Declare @Month1Start	 date,		@Month7Start	 date,
		@Month2Start	 date,		@Month8Start	 date,
		@Month3Start	 date,		@Month9Start	 date,
		@Month4Start	 date,		@Month10Start	 date,
		@Month5Start	 date,		@Month11Start	 date,
		@Month6Start	 date,		@Month12Start	 date,
		@Month0Start	 date
		
;

Set @Month0Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-0, 0)
Set @Month1Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-1, 0)
Set @Month2Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-2, 0)
Set @Month3Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-3, 0)
Set @Month4Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-4, 0)
Set @Month5Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-5, 0)
Set @Month6Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-6, 0)
Set @Month7Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-7, 0)
Set @Month8Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-8, 0)
Set @Month9Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-9, 0)
Set @Month10Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-10, 0)
Set @Month11Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-11, 0)
Set @Month12Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-12, 0)

select Distinct
potr.AgentCode,
WrittenDate,
isnull(Amount,MortgageAmount) as TotalInvestmentAmount,
potr.CommCalculatedAmount,
potr.CommBaseAmount + potr.CommCalculatedUplift as Due,
pol.PolicyRef,
ph.ProductGroupCode,
ph.ProductSubGroupCode					    
into #WrittenData
from mstt_PolicyTransactions potr
join mstt_Policies pol on pol.POL_NUM = potr.PolicyID
join mstt_ProductHierarchy ph on ph.ProductCode = pol.ProductCode
join mstt_Clients ct on ct.CLIENT_NUM = pol.CLIENT_NUM
join mstt_Plans pn on pn.CODE = potr.CommPlanCode
join mstt_TransAgentSplitHierarchyHistory tash on tash.TransactionID = potr.ID and tash.AgentCode = potr.AgentCode and tash.CommissionType = 1
where WrittenDate >= dateadd(year,-1,getdate()) 
and tash.FranchiseAgentCode = @FirmUID
and TransType = 39
and isnull(Amount,MortgageAmount) > 1
and potr.AdminMethod != 'X'
and ph.ProductGroupCode in (2,5)
order by WrittenDate

select Distinct
@Month0Start as WrittenDate,
DateName(Month,@Month0Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month0Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(2) and ProductSubGroupCode not in(2,61) then TotalInvestmentAmount else 0 end),0) as InvestmentValue,
isnull(sum(case when ProductGroupcode IN(2) and ProductSubGroupCode not in(2,61) then 1 else 0 end),0) as InvestmentCount,
isnull(sum(case when ProductGroupcode IN(5) and ProductSubGroupCode not in(2,61) then TotalInvestmentAmount else 0 end),0) as PensionValue,
isnull(sum(case when ProductGroupcode IN(5) and ProductSubGroupCode not in(2,61) then 1 else 0 end),0) as PensionCount,
isnull(sum(case when ProductSubGroupCode IN(61,2) then TotalInvestmentAmount else 0 end),0) as AnnuityValue,
isnull(sum(case when ProductSubGroupcode IN(61,2) then 1 else 0 end),0) as AnnuityCount	    
from #WrittenData
where WrittenDate >= @Month0Start
