				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'FirmDetails';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + cast (@FirmUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin

with CTE_FirmCPD as
(SELECT  count(distinct uh.UserUID) as NumberOfAdvisers
--		,uh.UserName
		,uh.BusinessUID
----		,uh.BusinessCompanyName
--	    ,case when CPDL_Structure = 1 then sum(CPDL_Awarded)/60 end as StructuredHours
--	    ,case when CPDL_Structure = 2 then sum(CPDL_Awarded)/60 end as UnstructuredHours
	    ,sum(CPDL_Awarded)/60 as TotalCPDHours
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_CPDAwardLog cpdal
  join mi_insight_UserHierarchy uh on uh.UserGUID = cpdal.CPDL_UserID
  join mi_insight_KPIPopulation pop on pop.UserID = uh.UserGUID and pop.UserJobTitleCode = 4
  where 1=1
  --and CPDL_UserID = 'BCA580B9-9595-4795-933E-00B5B3880E9E'
  and CPDL_Status = 1
  and CPDL_Category = 1
  and uh.BusinessUID = @FirmUID
  and CPDL_PlannedDate between dateadd(year,-1,getdate()) and getdate()
  and pop.COBCompetencyCode is not null
  group by 
 -- CPDL_UserID,
 -- CPDL_Structure,
 -- uh.UserUID
 --,uh.UserName
    uh.BusinessUID
 --,uh.BusinessCompanyName
 ),

 CTE_UNLSales as
 (select 
  agt.Firm
  ,count(*) as unlicensedsales
  from tandc.UnlicensedSales uns
  join sa_swift_S_AGENTS agt on agt.CODE = convert(varchar(7),uns.AdviserUID)
  where agt.firm = '1002524'
  and uns.DateofULS >= dateadd(yy,-1,datediff(dd,0,getdate())) -- added 1.3.17
  group by agt.Firm),

 CTE_PPBreach as
 (select
cl.AgentCode
,agt.DESCN
,agt.Firm
,uh.BusinessUID
,convert(varchar,DATE_,103) as DateOfBreach
,cac.Description
,Convert(varchar,ExpiryDate,103) as ExpirtyDate
from sa_swift_S_ENQURY enq
join sa_swift_CodeAreaOfConcern cac on cac.Code = enq.AreaOfConcernCode
join sa_swift_S_CLIENT cl on cl.CLIENT_NUM = enq.CLIENT_NUM
join sa_swift_S_AGENTS agt on agt.CODE = cl.AgentCode
join mi_insight_UserHierarchy uh on uh.UserUID = cl.AgentCode
where BusinessUID = @FirmUID
and ExpiryDate > getdate() 
and UserJobTitleCodePartner = 5 
),

 CTE_Breach as
 (select
 BusinessUID
,count(UserUID) as Occurence
from mi_insight_UserHierarchy uh
join RPT_SalesQualityMatrixPoints mp on mp.Code = uh.UserUID
where 
--UserJobTitleCodePartner = 5 and
 mp.Description != 'Total Points'
Group by BusinessUID)

select
uh.BusinessUID
,BusinessCompanyName
,qlmi.LeaguePosition as 'MCOB/ICOBQualityLeaguePosition'
,qlmc.LeaguePosition as 'COBQualityLeaguePosition'
,COUNT(distinct uh.UserUID) as NumberOfAdvisers
,fcpd.TotalCPDHours
,fcpd.TotalCPDHours/fcpd.NumberOfAdvisers as AveragePerAdviser
,cd.Code_Description as RiskAssessment
,case when br.BusinessUID is null then 'No' else 'Yes' end as Breaches
,case when crg.BusinessUID is null then 'No' else 'Yes' end as CRGReferrals
,case when ppb.BusinessUID is null then 'No' else 'Yes' end as PracticePrincipalBreach
,case when unlicsl.Firm is null then 0 else unlicsl.unlicensedsales end as UnlicencedSales
,COUNT(distinct subbus.PolicyNumber) as UnsubmittedSales
--,'Yes' as FinancialIncentivesApproved
,case when fininc.BusinessUID is null then 'No' else 'Yes' end as FinancialIncentivesApproved
from mi_insight_UserHierarchy uh
left join tandc.QLS_MCOBICOB qlmi on qlmi.BUID = uh.BusinessUID
												and qlmi.LastUploadedDate = (select max(qlsmi.LastUploadedDate) 
															from tandc.QLS_MCOBICOB qlsmi 
															where qlsmi.BUID = qlmi.BUID)
left join tandc.QLS_COB qlmc on qlmc.BUID = uh.BusinessUID
												and qlmc.LastUploadedDate = (select max(qlsmc.LastUploadedDate) 
															from tandc.QLS_COB qlsmc 
															where qlsmc.BUID = qlmc.BUID)
left join dbo.sa_insight_RiskAssessment ra on uh.BusinessGUID = RA_USR_ID 
											  and RA_Date = (select max(risk.RA_Date) 
															from sa_insight_RiskAssessment risk 
															where risk.RA_USR_ID = ra.RA_USR_ID)
left join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
left join CTE_Breach br on br.BusinessUID = uh.BusinessUID
left join TandC.UnsubmittedBusiness subbus on subbus.BUID = uh.BusinessUID and subbus.DateofBreach > dateadd(year,-1,getdate())--and subbus.UID = uh.UserUID
left join TandC.FinancialIncentives fininc on fininc.BusinessUID = uh.BusinessUID and fininc.Outcome like '%Approved%'
left join CTE_UNLSales unlicsl on unlicsl.firm = uh.BusinessUID
left join CTE_FirmCPD fcpd on fcpd.businessUID = uh.businessuid
left join CTE_PPBreach ppb on ppb.BusinessUID = uh.BusinessUID
left join tandc.CRG crg on crg.BusinessUID = uh.BusinessUID and crg.Formal = 'Y' and crg.CRGMeetingDate > dateadd(year,-1,getdate())
where uh.BusinessUID = @FirmUID
and uh.UserJobTitleCodeSeller = 4
Group by
 uh.BusinessUID
,BusinessCompanyName
,qlmi.LeaguePosition
,cd.Code_Description,fcpd.TotalCPDHours,fcpd.NumberOfAdvisers,ppb.BusinessUID	
,subbus.BUID
,crg.BusinessUID
,qlmc.LeaguePosition
,br.BusinessUID
,unlicsl.unlicensedsales
,fininc.BusinessUID
 ,unlicsl.Firm
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
