						  ELSE null END) AS MCOB_REJECT  
		  ,count( CASE aqto.LOB WHEN 'ICOB' THEN AQTO.Advice ELSE NULL END ) AS ICOB_SUBMITTED  
		  ,count( CASE aqto.LOB WHEN 'ICOB' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   WHEN 'Unclear action required' THEN AQTO.Advice
																   WHEN 'Suitable post clarification' THEN AQTO.Advice
																   WHEN 'Unsuitable advice' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS ICOB_CHECKED  
		  ,count( CASE aqto.LOB WHEN 'ICOB' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS ICOB_PASSED  
		  ,count( CASE aqto.LOB WHEN 'ICOB' THEN 
							   CASE  WHEN AQTO.FinalWorkFlow in ('Reject','Unsuitable advice') THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														WHEN 'Unclear action required' THEN AQTO.Advice
														WHEN 'Unsuitable advice' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS ICOB_REJECT  
		  ,count( CASE aqto.LOB WHEN 'SI' THEN AQTO.Advice ELSE NULL END ) AS SI_SUBMITTED  
		  ,count( CASE aqto.LOB WHEN 'SI' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   WHEN 'Unclear action required' THEN AQTO.Advice
																   WHEN 'Suitable post clarification' THEN AQTO.Advice
																   WHEN 'Unsuitable advice' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS SI_CHECKED  
		  ,count( CASE aqto.LOB WHEN 'SI' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS SI_PASSED  
		  ,count( CASE aqto.LOB WHEN 'SI' THEN 
							   CASE  WHEN AQTO.FinalWorkFlow in ('Reject','Unsuitable advice') THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														WHEN 'Unclear action required' THEN AQTO.Advice
														WHEN 'Unsuitable advice' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS SI_REJECT 
		  ,count( CASE aqto.LOB WHEN 'RPB' THEN AQTO.Advice ELSE NULL END ) AS RPB_SUBMITTED  
		  ,count( CASE aqto.LOB WHEN 'RPB' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   WHEN 'Unclear action required' THEN AQTO.Advice
																   WHEN 'Suitable post clarification' THEN AQTO.Advice
																   WHEN 'Unsuitable advice' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS RPB_CHECKED  
		  ,count( CASE aqto.LOB WHEN 'RPB' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS RPB_PASSED  
		  ,count( CASE aqto.LOB WHEN 'RPB' THEN 
							   CASE  WHEN AQTO.FinalWorkFlow in ('Reject','Unsuitable advice') THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														WHEN 'Unclear action required' THEN AQTO.Advice
														WHEN 'Unsuitable advice' THEN AQTO.Advice
														ELSE NULL END  
														  ELSE null END 
						  ELSE null END) AS RPB_REJECT
	 
	from      CTE_AQTCHECK AQTO
	left join dbo.mi_aqt_ReportingHierarchy AQTH on AQTH.AdviserGUID = AQTO.AdviserGUID;
	END
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

