CREATE PROCEDURE [logi].[pr_Ringo_FirmLevelEventServicing]
                @FirmUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
