IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

with cte_svc as (SELECT evty.Name as EventType     
      , sum(case erst.EventReminderStatusText when 'Scheduled' then 1 else 0 end ) as ScheduledEvents
      , sum(case erst.EventReminderStatusText when 'Due' then 1 else 0 end )       as DueEvents
      , sum(case erst.EventReminderStatusText when 'Late' then 1 else 0 end ) as LateEvents
      , COUNT(1) as TotalEvents
      , sum(case erst.EventReminderStatusText when 'Late' then case when isnull(OneOffChangeToDateDue, even.DateDue) >= DATEADD(MONTH,-3,GETDATE()) then 1 else 0 end  else 0 end ) as LateEventsUnder6MonthsLate
      , sum(case erst.EventReminderStatusText when 'Late' then case when isnull(OneOffChangeToDateDue, even.DateDue) <  DATEADD(MONTH,-3,GETDATE()) then 1 else 0 end  else 0 end ) as LateEventsOver6MonthsLate
  FROM prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_EventType evty on evty.EventTypeID = even.TypeID
  JOIN prod_zurich_openwork_datawarehouse.StaticData.sa_ows_EventReminderStatus erst on erst.EventReminderStatusID = even.EventReminderStatusID
  where even.TypeID in (1,2)
  and   isnull(even.IsCancelled,0) = 0 
  and   isnull(even.IsDeleted,0)   = 0
  and   pers.BusinessUID = @FirmUID
  and   erst.EventReminderStatusID in (1,2,3)
  group by evty.Name
  )
  select cte_svc.EventType
        ,cte_svc.TotalEvents
        ,cte_svc.ScheduledEvents
 --       ,case when cte_svc.ScheduledEvents > 0 then round((cast (cte_svc.ScheduledEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as ScheduledEventsPct
        ,case when cte_svc.ScheduledEvents > 0 then 100 - round((cast (cte_svc.lateEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2)
                                                        - round((cast (cte_svc.dueEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as ScheduledEventsPct
        ,cte_svc.DueEvents
        ,case when cte_svc.DueEvents > 0 then round((cast (cte_svc.DueEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as DueEventsPct
        ,cte_svc.LateEvents
        ,case when cte_svc.LateEvents > 0 then round((cast (cte_svc.LateEvents AS float) /  cast (cte_svc.TotalEvents as Float)) * 100,2) end as LateEventsPct
       ,cte_svc.LateEventsUnder6MonthsLate
        ,cte_svc.LateEventsOver6MonthsLate
        ,case when cte_svc.LateEventsOver6MonthsLate > 0 then round((cast (cte_svc.LateEventsOver6MonthsLate AS float) / 
                                                              (cast (cte_svc.ScheduledEvents + cte_svc.DueEvents + cte_svc.LateEvents AS Float)) * 100),2)
                                                         else 0 end as PctOver6Mnths    
  from cte_svc;

END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
