                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'FirmLevelKPIs';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + cast (@FirmUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin

SELECT   uh.BusinessUID
		,uh.BusinessCompanyName
  	    ,kpi.KPI_Name
	    ,cd.Code_Description as CurrentQuarter
	    ,cd2.Code_Description as '1QuarterAgo'
	    ,cd3.Code_Description as '2QuartersAgo'
	    ,cd4.Code_Description as '3QuartersAgo'
  FROM mi_insight_UserHierarchy uh
  left join sa_insight_KPIResult kpir on uh.BusinessGUID = kpir.KPID_UserID and KPID_Date > dateadd(month,-3,getdate())
  left join sa_insight_CodeDescription cd on cd.Code_Code = kpir.KPID_Status and cd.Code_CodeType = 655
  left join sa_insight_KPIResult kpir2 on kpir.KPID_KPI_ID = kpir2.KPID_KPI_ID and kpir.KPID_UserID = kpir2.KPID_UserID and kpir2.KPID_Date between dateadd(month,-6,getdate()) and dateadd(month,-3,getdate())
  left join sa_insight_CodeDescription cd2 on cd2.Code_Code = kpir2.KPID_Status and cd2.Code_CodeType = 655
  left join sa_insight_KPIResult kpir3 on kpir.KPID_KPI_ID = kpir3.KPID_KPI_ID and kpir3.KPID_UserID = kpir.KPID_UserID and kpir3.KPID_Date between dateadd(month,-9,getdate()) and dateadd(month,-6,getdate())
  left join sa_insight_CodeDescription cd3 on cd3.Code_Code = kpir3.KPID_Status and cd3.Code_CodeType = 655
  left join sa_insight_KPIResult kpir4 on kpir.KPID_KPI_ID = kpir4.KPID_KPI_ID and kpir4.KPID_UserID = kpir.KPID_UserID and kpir4.KPID_Date between dateadd(month,-12,getdate()) and dateadd(month,-9,getdate())
  left join sa_insight_CodeDescription cd4 on cd4.Code_Code = kpir4.KPID_Status and cd4.Code_CodeType = 655
  left join sa_insight_KPI kpi on kpi.KPI_ID = kpir.KPID_KPI_ID
  where uh.BusinessUID = @FirmUID
  Group by
  uh.BusinessUID
 ,uh.BusinessCompanyName
 ,kpi.KPI_Name
 ,cd.Code_Description
 ,cd2.Code_Description
 ,cd3.Code_Description
 ,cd4.Code_Description
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


