print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin

SELECT Top 2
	   sl.Name
	  ,prop.DateCreated
	  ,[UnderstandingAnalysisFlatFee]
      ,[UnderstandingAnalysisHourlyFee]
      ,case when AdviceRecommendationChargingStructureId = 9501 then 'Tiered' 
			when AdviceRecommendationChargingStructureId = 9500 then convert(varchar(5),AdviceRecommendationFlatFee) 
			end as InitialFeeOnSingles
      ,[RegularPremiumFee]
	  ,sl.OngoingServiceValue
	  ,case when [BscAccountedForId] = 19 then 'Yes' when BscAccountedForId = 20 then 'No' end as BSC
  FROM [prod_zurich_openwork_datawarehouse].[Proposition].[sa_ows_Proposition] prop
  join Proposition.sa_ows_ServiceLevel sl on sl.PropositionId = prop.PropositionId
  where prop.BusinessUid = @FirmUID
  and prop.Status = 0
  order by DateCreated desc
 
