CREATE PROCEDURE [logi].[pr_Ringo_FirmLevelOgsChk_Backup20220413SC]
                @FirmUID      varchar(7)
               ,@PtlCode      varchar(10)

with recompile	--AG 21/06/2018

AS 

BEGIN

set nocount on

/**********************************************************************************************
Name  : [logi].[pr_Ringo_FirmLevelOgsChk]
Author      : T Cummings
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Firm Level OGs Chk" and 
              is found on the "BQM MI" menu. This report displays: 
              - Details of clients under servicinfg



      The security groups associated with is report are:
      1) 
      2)  

      Execute as follows:
      exec [logi].[pr_Ringo_FirmLevelOgsChk] '1001871','ptl91371'

AMENDMENT HISTORY
=================
Date        Author		Description
----        ------		-----------
25-5-18		S Inglis	Updated to include Adhoc Reviews
21/06/2018	A Groves	SR510296. Break-fix. The Firm T&C MI report was hanging due to this proc.
						It was previously fixed the week before by Chris Mellors and Alan 
						Groves when Chris removed old query plans. Then Chris went on holiday
						and the problem recurred. The fix was to remove the query plans in
						cache and add "with recompile" to this proc.
28/07/2020	S Hale		Corrected Code_CodeType from 9 to 785
06-10-2020	S Inglis		Amended query to replace prefixes to link to Event ID	
06-10-2020	S Inglis		Amended query to replace "C" to link to Event ID	
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'Firm OGS Check';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + @FirmUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

select
even.PersonID
,year(even.DateDue) as EventDueYear
into #AdhocReviews
from Events.sa_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
----join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
----join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where even.EventReminderStatusID = 4
and TypeID = 8;

DECLARE @lc_report_event     int,
        @lc_late_status      int,
        @lc_due_status       int,
        @lc_scheduled_status int,
        @lc_review_event     int,
        @lc_declined         int;
SET @lc_report_event      = 1;
SET @lc_late_status       = 1;
SET @lc_due_status        = 2;
SET @lc_scheduled_status  = 3;
SET @lc_review_event      = 2;
SET @lc_declined          = 3;

with cte_OGS_chk as(select distinct saca.CASE_CaseReference as CaseReference
		  ,CaseStatus.Code_Description as OGS_CHK_Status
		  ,miuh.BusinessUID AS BusinessUID
		  ,pers.FirstName + ' ' + pers.LastName as ClientName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN dbo.mi_insight_UserHierarchy miuh ON  saca.CASE_AdviserID = miuh.UserGUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status -- updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	JOIN  prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even on even.Eventid = cast (Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C','') as int)   -- Updated 06/10/20
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = even.PersonID
																   and pers.BusinessUid = miuh.BusinessUID
	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	AND   miuh.BusinessUID = @FirmUID
	AND   saca.CASE_CaseReference     like 'OGS%'
	AND   saca.CASE_CaseReference not like 'OGS%x' 
	AND   saca.CASE_CaseReference not like 'OGS%X'
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS') -- omitted XOGS as that is to do with a pre-check
	and   CFQ.CFQ_QuestionCode between 2001 and 3000
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ))
, cte_OGS_count	as (SELECT  pers.BusinessUID, 
                            COUNT(*) as NoClientsServiced
  FROM prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
  where even.TypeID in (@lc_report_event)
  and   pers.BusinessUid = @FirmUID
  and   even.EventReminderStatusID in (@lc_late_status,@lc_due_status,@lc_scheduled_status)
  and   isnull(even.IsCancelled,0) = 0 
  and   isnull(even.IsDeleted,0)   = 0
  group by pers.BusinessUID
)	
, cte_OGS_declined as (Select pers.BusinessUid
                             ,count(distinct even.PersonID) as ClientsDecliningEvents
                             ,count(*) as EventsDeclined	
                       FROM  prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
                       join  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
					   left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateUpdated)
                       where Outcome = @lc_declined
                       and   pers.BusinessUid = @FirmUID
					   and   adh.PersonID is null
                       and   TypeID  = @lc_review_event
                       and    even.IsCancelled is null
                       and    even.IsDeleted   is null
                       and    even.DateUpdated >= DATEADD(year,-1,GETDATE())
                       and    exists (select 1
                                      from   prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even1
                                      where  even.PersonID = even1.PersonID
                                      and    even1.Outcome is null 
									  and    even1.TypeID  = 2
									  and    even1.IsCancelled is null
									  and    even1.IsDeleted   is null
                                      and    even1.EventReminderStatusID in (1,2,3))
                          group by pers.BusinessUid
)
  SELECT ogco.BusinessUID
        ,ogco.NoClientsServiced
        ,ogde.EventsDeclined
        ,SUM( case when ogch.CaseReference is not null then 1 else 0 end )as OGS_CHK_Status
  FROM   cte_OGS_count ogco
  LEFT JOIN   cte_OGS_chk   ogch on ogch.BusinessUID = ogco.BusinessUID 
  LEFT JOIN   cte_OGS_declined ogde on ogde.BusinessUid = ogco.BusinessUid 					   
  group by ogco.BusinessUID
          ,ogco.NoClientsServiced
          ,ogde.EventsDeclined
        order by BusinessUID;                            
                          
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
