CREATE PROCEDURE [logi].[pr_Ringo_FirmLevelSalesTotal]
                @FirmUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'pr_Ringo_AdviserSalesTotal';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + @FirmUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

with cte_PrdSum as 
(select plans.PlanCategory
             , potr.PolicyID
             --,MONTH(agmf.TransactionDate) RealMonthNo
             --,agmf.TransactionDate
             ,MONTH(agmf.TransactionDate) as AdjustedMonthNo 
             ,YEAR(agmf.TransactionDate) as YearNo 
             ,substring(DATENAME(MONTH,agmf.TransactionDate),1,3) +  ' ' + DATENAME(YEAR,agmf.TransactionDate)  as AdjustedMonthName
              ,sum(agmf.AMOUNT_PAID) AMOUNT_PAID
              ,case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                             ,'1006886','1011542','1011587','1011623','1011629'
                                             ,'1011630','1011631','1011632','1011633','1011634','1011635') then 'Openwork'
               else 'Adviser' end  as AgentDistribution
from   mi_aqt_ReportingHierarchy marh
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_policyTransactions] potr on potr.AgentCode = marh.AdviserUID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_Policies] polm on polm.POL_NUM = potr.PolicyID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_expectation] pacc on pacc.TransactionID = potr.ID
left join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_PolicyAgentsB30] pb30 on pb30.PolicyID         = polm.POL_NUM
                                                                                 and pb30.SellingAgentCode = potr.AgentCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_PaymentsPending] agmf on agmf.PACC_ID = pacc.ID
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_PLANS] plans on plans.CODE = polm.PLAN_CODE
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodePlanCategories] cpca on cpca.Code = plans.PlanCategory
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodeProducts] copr on copr.Code = polm.ProductCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_ProductHierarchy] mphi on mphi.ProductCode = polm.ProductCode
Where  Marh.BusinessUID = @FirmUid
and    agmf.CommissionType = 1
and    potr.AdminMethod != 'X'
and    agmf.TransactionDate >= DATEADD(mm,-12,GETDATE()) 
--and    potr.CreateDateTime    >= DATEADD(mm,-12,GETDATE()) 
group by plans.PlanCategory
             , potr.PolicyID
             ,MONTH(agmf.TransactionDate)
             ,YEAR(agmf.TransactionDate)
             ,substring(DATENAME(MONTH,agmf.TransactionDate),1,3) +  ' ' + DATENAME(YEAR,agmf.TransactionDate)
             , case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                             ,'1006886','1011542','1011587','1011623','1011629'
                                             ,'1011630','1011631','1011632','1011633','1011634','1011635') then 'Openwork'
               else 'Adviser' end
) 
select cte_PrdSum.AdjustedMonthNo
      ,cte_PrdSum.YearNo
      ,cte_PrdSum.AdjustedMonthName
      ,SUM(case cte_PrdSum.PlanCategory when 'MORT' then case cte_PrdSum.AgentDistribution when 'Adviser' then 1 else 0 end else 0 end) as MortgageCount
      ,SUM(case cte_PrdSum.PlanCategory when 'MORT' then case cte_PrdSum.AgentDistribution when 'Adviser' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as MortgageAgentAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'MORT' then case cte_PrdSum.AgentDistribution when 'Openwork' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as MortgageOpenworkAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PEN&INV' then case cte_PrdSum.AgentDistribution when 'Adviser' then 1 else 0 end else 0 end) as PenInvCount
      ,SUM(case cte_PrdSum.PlanCategory when 'PEN&INV' then case cte_PrdSum.AgentDistribution when 'Adviser' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as PenInvAgentAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PEN&INV' then case cte_PrdSum.AgentDistribution when 'Openwork' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as PenInvOpenworkAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PROTECT' then case cte_PrdSum.AgentDistribution when 'Adviser' then 1 else 0 end else 0 end) as ProtectionCount
      ,SUM(case cte_PrdSum.PlanCategory when 'PROTECT' then case cte_PrdSum.AgentDistribution when 'Adviser' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as ProtectionAgentAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PROTECT' then case cte_PrdSum.AgentDistribution when 'Openwork' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as ProtectionOpenworkAmount
from cte_PrdSum
where cte_PrdSum.PlanCategory in ('MORT','PEN&INV','PROTECT')
group by cte_PrdSum.AdjustedMonthNo,cte_PrdSum.AdjustedMonthName,cte_PrdSum.YearNo
order by cte_PrdSum.YearNo,cte_PrdSum.AdjustedMonthNo asc;
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
