CREATE PROCEDURE [logi].[pr_ringo_FirmLevelSPS]
      @PtlCode		  varchar(255),
	  @FirmUID		  varchar (7),
	  @Licence        varchar(7)

AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'FirmLevelSPS';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + cast (@FirmUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin

with cte_licence as (
select 
uh.UserName
,uh.UserUID
,case when cd.Code_Description = 'ICOB' then count (uh.useruid) else 0 end as 'ICOB'
,case when cd.Code_Description = 'MCOB' then count (uh.useruid) else 0 end as 'MCOB'
,case when cd.Code_Description = 'COB' then count (uh.useruid) else 0 end as 'COB'
,case when cd.Code_Description = 'ICOB GI Only' then count (uh.useruid) else 0 end as 'ICOB GI Only'
from dbo.sa_insight_UserCompetency uc
join dbo.sa_insight_CodeDescription cd on cd.Code_Code = uc.UC_BusinessArea and cd.Code_CodeType = 534
join dbo.sa_insight_CodeDescription cd1 on cd1.Code_Code = uc.UC_CompetencyLevel and cd1.Code_CodeType = 55
join mi_insight_UserHierarchy uh on uh.UserGUID = uc.UC_OwnerID
join sa_swift_S_AGENTS agt on uh.UserUID = agt.CODE
join sa_swift_s_agents agt1 on agt1.CODE = agt.Manager2Code
join sa_swift_S_AGENTS agt2 on agt2.CODE = uh.BusinessUID
where 1=1
and cd.Code_Description like '%COB%'
and uc.UC_Status = 0
AND @Licence = 'COB'
group by 
uh.UserName
,uh.UserUID
,uh.BusinessUID
,case when agt2.TradingName is null then agt2.DESCN else agt2.TradingName end
,agt1.DESCN
,uh.BQMName
,cd.Code_Description
,cd1.Code_Description
,uc.UC_DateAchieved
),

CTE_Lic as (
select 
ctel.UserName
,ctel.UserUID
,case when sum(ctel.icob) > 0 and sum(ctel.mcob) > 0 and sum(ctel.cob) = 0 then 'MCOB' 
 when sum(ctel.icob) > 0 and sum(ctel.mcob) > 0 and sum(ctel.cob) > 0 then 'CMCOB' 
 when sum(ctel.icob) >= 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) > 0 then 'COB'
 when sum(ctel.icob) > 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) = 0 then 'ICOB'
 when sum(ctel.icob) = 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) = 0 and sum(ctel.[ICOB GI Only]) > 0 then 'ICOB GI Only'
 else ' '
 end as 'Licence Type'
,sum(ctel.ICOB) as ICOB
,sum(ctel.MCOB) as MCOB
,sum(ctel.COB) as COB
from cte_licence ctel
group by
ctel.UserName
,ctel.UserUID
)

SELECT uh.useruid as UserUID
	  ,uh.UserName
	  ,lic.[Licence Type]
	  ,uh.BusinessUID
	  ,uh.BusinessCompanyName
	  ,case when staff.STAF_ControlledFunctionStartDate > dateadd (month,-30,getdate()) then staff.STAF_ControlledFunctionStartDate else Null end as ControlledFunction
	  ,case when lic.[Licence Type] not in ('COB','CMCOB') then 'N/A' when staff.STAF_ControlledFunctionStartDate > dateadd (month,-30,getdate()) then 'N/A' when cd.Code_Description = 'Expired' then 'Missing' else accbd.ACB_Description end as AccreditedBody
	  ,case when cd.Code_Description is null then 'N/A' else cd.Code_Description end as 'Status'
	  ,SPS_Status
	  ,SPS_RenewalDate as ExpiryDate
	  ,SPS_CheckDate as DipCheckDate
      ,case when cd1.Code_Description is null then 'N/A' else cd1.Code_Description end as DipCheckOutcome
  FROM mi_insight_UserHierarchy uh
  join CTE_Lic lic on lic.UserUID = uh.UserUID
  left join sa_insight_StatementOfProfessionalStanding sps on sps.SPS_UserID = uh.UserGUID
  left join sa_insight_AccreditedBody accbd on accbd.ACB_ID = sps.SPS_AccreditedBodyID
  left join sa_insight_CodeDescription cd on cd.Code_Code = sps.SPS_Status and cd.Code_CodeType = 700
  left join sa_insight_CodeDescription cd1 on cd1.Code_Code = sps.SPS_CheckOutcome and cd1.Code_CodeType = 729
  left join sa_insight_staff staff on staff.STAF_UserID = uh.UserGUID
  where 1=1
  and uh.businessUID = @FirmUID
  and lic.[Licence Type] in ('COB','CMCOB')
  --and uh.BusinessUID = '1001031'
  and (cd.Code_Description != 'Cancelled' or cd.Code_Description is null)
  and (SPS_RenewalDate = (select max(SPS_RenewalDate) 
						  from sa_insight_StatementOfProfessionalStanding sps1 
						  where sps1.SPS_UserID = sps.SPS_UserID) or SPS_RenewalDate is null)
  and SPS_Status = (select min(sps1.SPS_Status)
					from sa_insight_StatementOfProfessionalStanding sps1
					where sps1.SPS_UserID = sps.SPS_UserID)
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


