	select	distinct isnull(miuh.BusinessTradingName,miuh.BusinessCompanyName) as FirmName
			,miuh.BusinessUID
	from	mi_insight_UserHierarchy miuh
	where	((miuh.SupervisorUID = @lc_UserUid)
	or		(@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = miuh.BusinessUID))		--AG 12/09/2016 & 13/09/2016
	or		(@lc_UserUid in ('4007621','4007612','4007578','4007848') and miuh.BusinessUID = '2005309'));	--AG 12/09/2016
	******************************************/

	select	distinct isnull(miuh.BusinessTradingName,miuh.BusinessCompanyName) as FirmName
			,miuh.BusinessUID
	from	mi_insight_UserHierarchy miuh
	where	(@lc_EnhancedPAAccess = 1 and miuh.BusinessUID = @lc_UserBusinessUID)	--Either a supervisor, or they have enhanced access	AG 04/05/2017
	or		(@lc_UserUid in (miuh.SupervisorUID,miuh.SupervisorUID2,miuh.SupervisorUID3,miuh.SupervisorUID4,miuh.SupervisorUID5,miuh.SupervisorUID6))	--supervises this adviser or supervisor of supervisor (SOS)
	 
END
 
END
