CREATE PROCEDURE [logi].[pr_Ringo_FirmPlatWrittenTotal]
                @FirmUID      varchar(7)
               ,@PtlCode      varchar(15)


AS BEGIN
set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_FirmPlatWrittenTotal]
Author      : S Inglis
Date  : 11/08/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Firm Written Platform Business Totals" and is found on the "BQM MI" 
              menu. This report displays: 
              - Adviser COB business written in the last 12 months totalled by on/off platform and 
              month at Firm level


              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_AdviserPlatWrittenTotal] 'ptl91371', 'Logi', '1002350'

AMENDMENT HISTORY
=================
Date        Author		Description
----        ------		-----------

***********************************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'pr_ringo_FirmPlatWrittenTotal';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + @FirmUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

Declare @Month1Start	 date,		@Month7Start	 date,
		@Month2Start	 date,		@Month8Start	 date,
		@Month3Start	 date,		@Month9Start	 date,
		@Month4Start	 date,		@Month10Start	 date,
		@Month5Start	 date,		@Month11Start	 date,
		@Month6Start	 date,		@Month12Start	 date,
		@Month0Start	 date
		
;

Set @Month0Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-0, 0)
Set @Month1Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-1, 0)
Set @Month2Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-2, 0)
Set @Month3Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-3, 0)
Set @Month4Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-4, 0)
Set @Month5Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-5, 0)
Set @Month6Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-6, 0)
Set @Month7Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-7, 0)
Set @Month8Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-8, 0)
Set @Month9Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-9, 0)
Set @Month10Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-10, 0)
Set @Month11Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-11, 0)
Set @Month12Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-12, 0)

select Distinct
potr.AgentCode,
WrittenDate,
isnull(Amount,MortgageAmount) as TotalInvestmentAmount,
potr.CommCalculatedAmount,
potr.CommBaseAmount + potr.CommCalculatedUplift as Due,
pol.PolicyRef,
ph.ProductGroupCode,
ph.ProductSubGroupCode,
pol.COMP_CODE,
ph.RDRType					    
into #WrittenData
from mstt_PolicyTransactions potr
join mstt_Policies pol on pol.POL_NUM = potr.PolicyID
join mstt_ProductHierarchy ph on ph.ProductCode = pol.ProductCode
join mstt_Clients ct on ct.CLIENT_NUM = pol.CLIENT_NUM
join mstt_Plans pn on pn.CODE = potr.CommPlanCode
join mstt_TransAgentSplitHierarchyHistory tash on tash.TransactionID = potr.ID and tash.AgentCode = potr.AgentCode and tash.CommissionType = 1
where WrittenDate >= dateadd(year,-1,getdate()) 
and tash.FranchiseAgentCode = @FirmUID
and TransType = 39
and isnull(Amount,MortgageAmount) > 1
and potr.AdminMethod != 'X'
and pol.COMP_CODE in ('IFDL', 'Zurich Plt', 'Openwork','Pru','Metlife')
order by WrittenDate

select Distinct
@Month0Start as WrittenDate,
DateName(Month,@Month0Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month0Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount
from #WrittenData
where WrittenDate >= @Month0Start
Union
select Distinct
@Month1Start as WrittenDate,
DateName(Month,@Month1Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month1Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount
from #WrittenData
where WrittenDate >= @Month1Start and WrittenDate < @Month0Start
Union
select Distinct
@Month2Start as WrittenDate,
DateName(Month,@Month2Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month2Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount
from #WrittenData
where WrittenDate >= @Month2Start and WrittenDate < @Month1Start
Union
select Distinct
@Month3Start as WrittenDate,
DateName(Month,@Month3Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month3Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount   
from #WrittenData
where WrittenDate >= @Month3Start and WrittenDate < @Month2Start
UNION
select Distinct
@Month4Start as WrittenDate,
DateName(Month,@Month4Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month4Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount 
from #WrittenData
where WrittenDate >= @Month4Start and WrittenDate < @Month3Start
UNION
select Distinct
@Month5Start as WrittenDate,
DateName(Month,@Month5Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month5Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount       
from #WrittenData
where WrittenDate >= @Month5Start and WrittenDate < @Month4Start
UNION
select Distinct
@Month6Start as WrittenDate,
DateName(Month,@Month6Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month6Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount     
from #WrittenData
where WrittenDate >= @Month6Start and WrittenDate < @Month5Start
UNION
select Distinct
@Month7Start as WrittenDate,
DateName(Month,@Month7Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month7Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount     
from #WrittenData
where WrittenDate >= @Month7Start and WrittenDate < @Month6Start
UNION
select Distinct
@Month8Start as WrittenDate,
DateName(Month,@Month8Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month8Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount       
from #WrittenData
where WrittenDate >= @Month8Start and WrittenDate < @Month7Start
UNION
select Distinct
@Month9Start as WrittenDate,
DateName(Month,@Month9Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month9Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount
from #WrittenData
where WrittenDate >= @Month9Start and WrittenDate < @Month8Start
UNION
select Distinct
@Month10Start as WrittenDate,
DateName(Month,@Month10Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month10Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount  
from #WrittenData
where WrittenDate >= @Month10Start and WrittenDate < @Month9Start
UNION
select Distinct
@Month11Start as WrittenDate,
DateName(Month,@Month11Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month11Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount    
from #WrittenData
where WrittenDate >= @Month11Start and WrittenDate < @Month10Start
UNION
select Distinct
@Month12Start as WrittenDate,
DateName(Month,@Month12Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month12Start)) as MonthStart,
isnull(sum(case when RDRType = 'ONPLAT' then TotalInvestmentAmount else 0 end),0) as OnPlatValue,
isnull(sum(case when RDRType = 'ONPLAT' then 1 else 0 end),0) as OnPlatCount,
isnull(sum(case when RDRType = 'OFPLAT' then TotalInvestmentAmount else 0 end),0) as OffPlatValue,
isnull(sum(case when RDRType = 'OFPLAT' then 1 else 0 end),0) as OffPlatCount   
from #WrittenData
where WrittenDate >= @Month12Start and WrittenDate < @Month11Start


END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
