CREATE PROCEDURE [logi].[pr_ringo_FirmWrittenTotal]
                @FirmUID      varchar(7)
               ,@PtlCode      varchar(20)


AS BEGIN
set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_FirmCOBWrittenTotal]
Author      : S Inglis
Date  : 11/08/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Firm Written Business Totals" and is found on the "BQM MI" 
              menu. This report displays: 
              - Adviser business written in the last 12 months totalled by product group and 
              month and Firm


              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_FirmWrittenTotal] 'ptl91371', 'Logi', '1002350'

AMENDMENT HISTORY
=================
Date        Author		Description
----        ------		-----------

***********************************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'pr_ringo_FirmWrittenTotal';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + @FirmUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

Declare @Month1Start	 date,		@Month7Start	 date,
		@Month2Start	 date,		@Month8Start	 date,
		@Month3Start	 date,		@Month9Start	 date,
		@Month4Start	 date,		@Month10Start	 date,
		@Month5Start	 date,		@Month11Start	 date,
		@Month6Start	 date,		@Month12Start	 date,
		@Month0Start	 date
		
;

Set @Month0Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-0, 0)
Set @Month1Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-1, 0)
Set @Month2Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-2, 0)
Set @Month3Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-3, 0)
Set @Month4Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-4, 0)
Set @Month5Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-5, 0)
Set @Month6Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-6, 0)
Set @Month7Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-7, 0)
Set @Month8Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-8, 0)
Set @Month9Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-9, 0)
Set @Month10Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-10, 0)
Set @Month11Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-11, 0)
Set @Month12Start = DATEADD(MONTH, DATEDIFF(MONTH, 0, GETDATE())-12, 0)

select Distinct
potr.AgentCode,
WrittenDate,
isnull(Amount,MortgageAmount) as TotalInvestmentAmount,
potr.CommCalculatedAmount,
pol.PolicyRef,
ph.ProductGroupCode					    
into #WrittenData
from mstt_PolicyTransactions potr
join mstt_Policies pol on pol.POL_NUM = potr.PolicyID
join mstt_ProductHierarchy ph on ph.ProductCode = pol.ProductCode
join mstt_Clients ct on ct.CLIENT_NUM = pol.CLIENT_NUM
join mstt_Plans pn on pn.CODE = potr.CommPlanCode
join mstt_TransAgentSplitHierarchyHistory tash on tash.TransactionID = potr.ID and tash.AgentCode = potr.AgentCode and tash.CommissionType = 1
where WrittenDate >= dateadd(year,-1,getdate()) 
and tash.FranchiseAgentCode = @FirmUID
and TransType = 39
and isnull(Amount,MortgageAmount) > 1
and potr.AdminMethod != 'X'
order by WrittenDate

select Distinct
@Month0Start as WrittenDate,
DateName(Month,@Month0Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month0Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month0Start
Union
select Distinct
@Month1Start as WrittenDate,
DateName(Month,@Month1Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month1Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month1Start and WrittenDate < @Month0Start
Union
select Distinct
@Month2Start as WrittenDate,
DateName(Month,@Month2Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month2Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month2Start and WrittenDate < @Month1Start
Union
select Distinct
@Month3Start as WrittenDate,
DateName(Month,@Month3Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month3Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month3Start and WrittenDate < @Month2Start
UNION
select Distinct
@Month4Start as WrittenDate,
DateName(Month,@Month4Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month4Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month4Start and WrittenDate < @Month3Start
UNION
select Distinct
@Month5Start as WrittenDate,
DateName(Month,@Month5Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month5Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month5Start and WrittenDate < @Month4Start
UNION
select Distinct
@Month6Start as WrittenDate,
DateName(Month,@Month6Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month6Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month6Start and WrittenDate < @Month5Start
UNION
select Distinct
@Month7Start as WrittenDate,
DateName(Month,@Month7Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month7Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month7Start and WrittenDate < @Month6Start
UNION
select Distinct
@Month8Start as WrittenDate,
DateName(Month,@Month8Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month8Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month8Start and WrittenDate < @Month7Start
UNION
select Distinct
@Month9Start as WrittenDate,
DateName(Month,@Month9Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month9Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month9Start and WrittenDate < @Month8Start
UNION
select Distinct
@Month10Start as WrittenDate,
DateName(Month,@Month10Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month10Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month10Start and WrittenDate < @Month9Start
UNION
select Distinct
@Month11Start as WrittenDate,
DateName(Month,@Month11Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month11Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month11Start and WrittenDate < @Month10Start
UNION
select Distinct
@Month12Start as WrittenDate,
DateName(Month,@Month12Start) + ' ' +CONVERT(varchar(4),datepart(year,@Month12Start)) as MonthStart,
isnull(sum(case when ProductGroupcode IN(4,2,5) then TotalInvestmentAmount else 0 end),0) as COBValue,
isnull(sum(case when ProductGroupcode IN(4,2,5) then 1 else 0 end),0) as COBCount,
isnull(sum(case when ProductGroupcode IN(6) then TotalInvestmentAmount else 0 end),0) as ProtectionValue,
isnull(sum(case when ProductGroupcode IN(6) then 1 else 0 end),0) as ProtectionCount,
isnull(sum(case when ProductGroupcode IN(3) then TotalInvestmentAmount else 0 end),0) as MortgageValue,
isnull(sum(case when ProductGroupcode IN(3) then 1 else 0 end),0) as MortgageCount	    
from #WrittenData
where WrittenDate >= @Month12Start and WrittenDate < @Month11Start

END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_ringo_MatrixPointsAdviser]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [logi].[pr_ringo_MatrixPointsAdviser]
      @PtlCode		  varchar(255),
	  @AdviserUID	  varchar (7)

AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'MatrixPointsAdviser';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + cast (@AdviserUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @AdviserUID
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin

Select 
 case when Code is null then 0 else Code end as AdviserUID
,case when Name is null then 'N/A' else Name end as AdviserName
,case when Description is null then 'N/A' else Description end as Description
,Points
,case when [Expiry Date] is null then 'N/A' else [Expiry Date] end as ExpiryDate
from mi_insight_KPIPopulation pop
left join RPT_SalesQualityMatrixPoints sqmp on sqmp.Code = pop.UserUID and Description != 'TOTAL POINTS'
where pop.UserUID = @AdviserUID
and Description != 'TOTAL POINTS'
Group by Code, Name, Description, [Expiry Date],Points
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
/****** Object:  StoredProcedure [logi].[pr_ringo_MCOBBusMixAdviser_Backup20190722AG]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/06/2016	A Groves	Temporary hardcoded access for JMD supervisors (one level up):
						Antony Lark, Duncan Jones and Philip Potter.
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.
1-6-17		S Inglis	Addition of Mortgage Transaction Type to exclude remort from Debt Con
14-6-17		S Inglis	Removal of users who havent sold any mortgages in period
10-8-2017	S Inglis	CR573 Updates:
						Trigger 1 measure changing to >=85% on 2-year deals. 
						Trigger 2 measure changing to >70% of their capital and repayment 
						mortgages being written for terms of 25, 30 or 35 year terms.	
3-10-2017	S Inglis		Update to trigger 3 to only look at residential mortgages CR573B
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_ringo_MCOBBusMixAdviser_Backup20190722AG]
      @PtlCode		  varchar(255),
	  @AdviserUID	  varchar (7)

AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

set @ReportName               = 'MCOB Business Mix Adviser';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
                                                   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
		or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin


with CTE_MortgageCases as (
SELECT
       mps.PolicyID
	  ,pol.SaleID
	  ,sale.DateSubmitted
	  ,pol.ApplicationDate
	  ,sale.AdviserUID
	  ,pers.DateOfBirth
	  ,dateadd(MONTH,producttermmonths,dateadd(YEAR,producttermyears,pol.applicationdate)) as EndDate
	  ,(round(DATEDIFF(dd,pers.dateofbirth,dateadd(MONTH,producttermmonths,dateadd(YEAR,producttermyears,pol.applicationdate)))/365.25,0,1)) as AgeOnCompletion
		  ,case when ((round(DATEDIFF(dd,pers.dateofbirth,getdate())/365.25,0,1)) + mps.ProductTermYears) >= 68 and inv.ValueName = 'Residential' then 1 else 0 end as Over68 --Updated CR573B S Inglis 3.10.17
		  ,case when ((round(DATEDIFF(dd,pers.dateofbirth,getdate())/365.25,0,1)) + mps.ProductTermYears) < 68 or inv.ValueName != 'Residential' then 1 else 0 end as Under68 --Updated CR573B S Inglis 3.10.17
	  ,case when (ffl.HasLiabilitiesID is null or ffla.DebtConsolidationID is null or inv5.ValueName != 'Remortgage' ) then 1 else 0 end as NotDebtConsolidation --added 30-1-17 SI
	  ,case when ffl.HasLiabilitiesID = 19 and ffla.DebtConsolidationID = 19 and inv5.ValueName = 'Remortgage' then 1 else 0 end as DebtConsolidation --added 30-1-17
	  --,case when ffl.debtconsolidationID != 19  or obrcr.debtconsolidation = 0 then 1 else 0 end as NotDebtConsolidation
	  --,case when ffl.debtconsolidationID = 19 or obrcr.debtconsolidation = 1 then 1 else 0 end as DebtConsolidation
	  ,inv.ValueName as MortgageCategory
	  ,inv1.ValueName as MortgageType
	  ,inv2.ValueName as InterestRate
	  ,inv3.ValueName as InitialRatePeriod
	  ,case when inv3.ValueName = '2 years' or inv3.ValueName = 'Under 2 Years' then 1 else 0 end as 'Up to 2 years' 
	  ,case when inv3.ValueName in ('3 years', '4 years') then 1 else 0 end as '3-4 Years' 
	  ,case when inv2.ValueName = 'Fixed' and inv3.ValueName not in ('2 years', '3 years', '4 years') or inv3.ValueName = 'Lifetime' then 1 else 0 end as '5+ Years'
      ,MortgageAmount
      ,MortgageRate
      ,MortgageNumber
	  ,mgpr.DisplayName
      ,MortgageLVRatio
      ,ProductTermYears
      ,ProductTermMonths
	  --,case when ProductTermYears < 15 then 1 else 0 end as '15 Years or Less'  --removed 10.8.17 SI
	  --,case when ProductTermYears >= 15 and ProductTermYears < 26 then 1 else 0 end as '15-25 Years' --removed 10.8.17 SI
	  --,case when ProductTermYears >= 26 and ProductTermYears < 31 then 1 else 0 end as '26-30 Years' --removed 10.8.17 SI
	  --,case when ProductTermYears >= 31 then 1 else 0 end as '31+ Years'  --removed 10.8.17 SI
	  ,case when ProductTermYears in (25,30,35) and inv1.ValueName = 'Repayment' then 1 else 0 end as RepaymentTerm --added 10.8.17 SI
	  ,inv4.ValueName as OffsetMortgage
  FROM dbo.vw_ows_MortgageProductSummary mps
  left join sa_ows_Policies pol on pol.PolicyID = mps.PolicyID
  join policy.sa_ows_MortgageProvider mgpr on mgpr.InternalProviderID = pol.internalproviderid
  left join sa_ows_sale sale on sale.SaleID = pol.SaleID
  left join sa_ows_Person pers on pers.PersonID = sale.PersonID
 -- left join sa_ows_ClientDetailAssetsAndLiabilitiesLiabilities ffl on ffl.PersonID = sale.PersonID
 -- left join sa_ows_ClientDetailAssetsAndLiabilitiesLiabilities cdall1 on cdall1.PersonID = pers.PartnerPersonID
  left join StaticData.sa_ows_InputValues inv on inv.InputID = MortgageCategoryID
  left join StaticData.sa_ows_InputValues inv1 on inv1.InputID = MortgageTypeID
  left join StaticData.sa_ows_InputValues inv2 on inv2.InputID = InterestRateTypeID
  left join StaticData.sa_ows_InputValues inv3 on inv3.InputID = InitialRatePeriodID
  left join StaticData.sa_ows_InputValues inv4 on inv4.InputID = IsMortgageOffsetID
  left join sa_ows_FactFindAssetsAndLiabilities ffl on ffl.SaleID = sale.SaleID and (ffl.HasLiabilitiesID = 19 and ffl.ConsolidationAdviceWanted = 19)
  left join sa_ows_factfindliabilities ffla on ffla.saleID = pol.saleiD and ffla.DebtConsolidationID = 19
  left join vw_ows_MortgageRecommendedSolution mrs on mrs.PolicyID = mps.PolicyID --added 30-1-17 SI
  left join StaticData.sa_ows_InputValues inv5 on inv5.InputID = mrs.TransactionTypeID --added 30-1-17 SI
where 1=1 
and sale.AdviserUID = @AdviserUID
and pol.Status in (0,2,7)
and DateSubmitted >= dateadd(month,-12,getdate()) and DateSubmitted <= getdate()
Group by
       mps.PolicyID
	  ,pol.SaleID
	  ,pol.ApplicationDate
	  ,sale.DateSubmitted
	  ,sale.AdviserUID
	  ,pers.DateOfBirth
	  ,MortgageAmount
      ,MortgageRate
	  ,mgpr.DisplayName
      ,MortgageNumber
      ,MortgageLVRatio
      ,ProductTermYears
      ,ProductTermMonths
	  ,case when (ffl.HasLiabilitiesID is null or ffla.DebtConsolidationID is null or inv5.ValueName != 'Remortgage' ) then 1 else 0 end --added 30-1-17 SI
	  ,case when ffl.HasLiabilitiesID = 19 and ffla.DebtConsolidationID = 19 and inv5.ValueName = 'Remortgage' then 1 else 0 end --added 30-1-17
	  ,inv.ValueName
	  ,inv1.ValueName
	  ,inv2.ValueName
	  ,inv3.ValueName
	  ,inv4.ValueName
	  --,inv5.ValueName
	,ffl.HasLiabilitiesID
	,ffla.DebtConsolidationID
	  )

,CTE_MortDetails as (
	  select
	   ctemc.AdviserUID
	  ,count (ctemc.PolicyID) as 'TotalCases'
	  ,sum(ctemc.[Up to 2 years]) as 'InitialPeriodUpTo2Years'
	  ,sum(ctemc.[3-4 Years]) as 'InitialPeriod3To4Years'
	  ,sum(ctemc.[5+ Years]) as 'InitialPeriod5+Years'
	  --,sum(ctemc.[15 Years or Less]) as 'InitialPeriod15YearsOrLess' --removed 10.8.17 SI
	  --,sum (ctemc.[15-25 Years]) as 'InitialPeriod15To25Years' --removed 10.8.17 SI
	  --,sum (ctemc.[26-30 Years]) as 'InitialPeriod26To30Years' --removed 10.8.17 SI
	  --,sum (ctemc.[31+ Years]) as 'InitialPeriod31+Years' --removed 10.8.17 SI
	  ,sum(ctemc.RepaymentTerm) as RepaymentTerm -- added 10.8.17 SI
	  ,sum (ctemc.Over68) as 'Over68'
	  ,sum (ctemc.Under68) as Under68
	  ,sum (ctemc.DebtConsolidation) as 'DebtConsolidation'
	  ,sum (ctemc.NotDebtConsolidation) as 'NotDebtConsolidation'
	  from CTE_MortgageCases ctemc
	  group by
	  ctemc.AdviserUID
	  ),

cte_Lenders as (
SELECT 
   mgpr.displayname
  ,sale.AdviserUID
  ,count(displayname) as totalsold
  ,row_number () over (partition by sale.AdviserUID order by count(displayname) desc) as RowPos
 FROM dbo.vw_ows_MortgageProductSummary mps
  left join sa_ows_Policies pol on pol.PolicyID = mps.PolicyID
  join policy.sa_ows_MortgageProvider mgpr on mgpr.InternalProviderID = pol.internalproviderid
  left join sa_ows_sale sale on sale.SaleID = pol.SaleID
  left join sa_ows_Person pers on pers.PersonID = sale.PersonID
 where 1=1 
 and pol.Status in (0,2,7)
 and DateSubmitted >= dateadd(month,-12,getdate()) and DateSubmitted <= getdate()
Group by DisplayName, sale.AdviserUID
),

CTE_3Lenders as
(select adviseruid,
max (totalsold) as '1lender'
,sum (totalsold) as '3lenders'
from cte_Lenders 
where RowPos <= 3
group by AdviserUID),

cte_licence as (
select 
uh.UserName
,uh.UserUID
,case when cd.Code_Description = 'ICOB' then count (uh.useruid) else 0 end as 'ICOB'
,case when cd.Code_Description = 'MCOB' then count (uh.useruid) else 0 end as 'MCOB'
,case when cd.Code_Description = 'COB' then count (uh.useruid) else 0 end as 'COB'
,case when cd.Code_Description = 'ICOB GI Only' then count (uh.useruid) else 0 end as 'ICOB GI Only'
from dbo.sa_insight_UserCompetency uc
join dbo.sa_insight_CodeDescription cd on cd.Code_Code = uc.UC_BusinessArea and cd.Code_CodeType = 534
join dbo.sa_insight_CodeDescription cd1 on cd1.Code_Code = uc.UC_CompetencyLevel and cd1.Code_CodeType = 55
join mi_insight_UserHierarchy uh on uh.UserGUID = uc.UC_OwnerID
join sa_swift_S_AGENTS agt on uh.UserUID = agt.CODE
join sa_swift_s_agents agt1 on agt1.CODE = agt.Manager2Code
join sa_swift_S_AGENTS agt2 on agt2.CODE = uh.BusinessUID
where 1=1
and cd.Code_Description like '%COB%'
and uc.UC_Status = 0
group by 
uh.UserName
,uh.UserUID
,uh.BusinessUID
,case when agt2.TradingName is null then agt2.DESCN else agt2.TradingName end
,agt1.DESCN
,uh.BQMName
,cd.Code_Description
,cd1.Code_Description
,uc.UC_DateAchieved
),

CTE_Lic as (
select 
ctel.UserName
,ctel.UserUID
,case when sum(ctel.icob) > 0 and sum(ctel.mcob) > 0 and sum(ctel.cob) = 0 then 'MCOB' 
 when sum(ctel.icob) > 0 and sum(ctel.mcob) > 0 and sum(ctel.cob) > 0 then 'CMCOB' 
 when sum(ctel.icob) >= 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) > 0 then 'COB'
 when sum(ctel.icob) > 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) = 0 then 'ICOB'
 when sum(ctel.icob) = 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) = 0 and sum(ctel.[ICOB GI Only]) > 0 then 'ICOB GI Only'
 else ' '
 end as 'Licence Type'
,sum(ctel.ICOB) as ICOB
,sum(ctel.MCOB) as MCOB
,sum(ctel.COB) as COB
from cte_licence ctel
group by
ctel.UserName
,ctel.UserUID
)

select 
agt.CODE
,agt.DESCN
,(
case when convert(numeric,(cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100)) >= 85 and ctemd.TotalCases >=12 then 1 else 0 end --Updated 10.8.17 SI
+
--case when convert(numeric,(cast(ctemd.[InitialPeriod31+Years] as float)/ctemd.TotalCases * 100)) >= 25 and ctemd.TotalCases >=12 then 1 else 0 end -- Removed 10.8.17 SI
case when convert(numeric,(cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100)) >= 70 and ctemd.TotalCases >=12 then 1 else 0 end --Added 10.8.17 SI
+
case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) >= 50 and ctemd.TotalCases >=12 then 1 else 0 end
+
case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) >= 10 and ctemd.TotalCases >=12 then 1 else 0 end
+
case when ((cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) > 30 or (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) > 60) and ctemd.TotalCases >= 12 then 1 else 0 end)
as 'TriggersHit'
,case when ctemd.TotalCases is null then 0 else ctemd.TotalCases end as TotalCases
,case when (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) >= 85 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger1 --updated  10.8.17 SI
,case when (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) is null then 0 
 else (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) end as Trigger1Pct
,case when (cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100) >= 70 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger2 --updated  10.8.17 SI
,case when (cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100) is null then 0 --updated  10.8.17 SI 
 else (cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100) end as Trigger2Pct --updated  10.8.17 SI
,case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) >= 50 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger3
,case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) end as Trigger3Pct
,case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) >= 10 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger4
,case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) end as Trigger4Pct
,case when (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) > 30 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger5
,case when (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) end as Trigger5Pct
,case when (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) > 60 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger6
,case when (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) is null then 0
 else (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) end as Trigger6Pct
from sa_swift_S_AGENTS agt
left join dbo.mi_insight_UserHierarchy uh  on uh.UserUID = agt.CODE
left join sa_swift_s_agents agt1 on agt1.CODE = agt.Manager2Code
left join sa_swift_S_AGENTS agt2 on agt2.CODE = uh.BusinessUID
left join CTE_MortDetails ctemd on uh.UserUID = ctemd.AdviserUID
left join CTE_3Lenders cteln on cteln.adviseruid = ctemd.AdviserUID
left join CTE_Lic lic on lic.UserUID = uh.UserUID
where agt.CODE = @AdviserUID
and agt.Manager2Code != '1011671'
and isnull(ctemd.TotalCases,0)> 0 --added 14.6.17

End

Else

Begin
Print 'Access Denied'
End   

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH


