						Antony Lark, Duncan Jones and Philip Potter
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_ringo_MCOBBusMixAdviserSIAmended21716_Backup20190722AG]
      @PtlCode		  varchar(255),
	  @AdviserUID	  varchar (7)

AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'MCOB Business Mix Adviser';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin

with CTE_MortgageCases as (
SELECT
       mps.PolicyID
	  ,pol.SaleID
	  ,sale.DateSubmitted
	  ,pol.ApplicationDate
	  ,sale.AdviserUID
	  ,pers.DateOfBirth
	  ,dateadd(MONTH,producttermmonths,dateadd(YEAR,producttermyears,pol.applicationdate)) as EndDate
	  ,(round(DATEDIFF(dd,pers.dateofbirth,dateadd(MONTH,producttermmonths,dateadd(YEAR,producttermyears,pol.applicationdate)))/365.25,0,1)) as AgeOnCompletion
	  ,case when ((round(DATEDIFF(dd,pers.dateofbirth,getdate())/365.25,0,1)) + mps.ProductTermYears) >= 68 then 1 else 0 end as Over68
	  ,case when ((round(DATEDIFF(dd,pers.dateofbirth,getdate())/365.25,0,1)) + mps.ProductTermYears) < 68 then 1 else 0 end as Under68
	  ,case when (ffl.HasLiabilitiesID is null or ffla.DebtConsolidationID is null) then 1 else 0 end as NotDebtConsolidation
	  ,case when ffl.HasLiabilitiesID = 19 and ffla.DebtConsolidationID = 19 then 1 else 0 end as DebtConsolidation
	  --,case when ffl.debtconsolidationID != 19  or obrcr.debtconsolidation = 0 then 1 else 0 end as NotDebtConsolidation
	  --,case when ffl.debtconsolidationID = 19 or obrcr.debtconsolidation = 1 then 1 else 0 end as DebtConsolidation
	  ,inv.ValueName as MortgageCategory
	  ,inv1.ValueName as MortgageType
	  ,inv2.ValueName as InterestRate
	  ,inv3.ValueName as InitialRatePeriod
	  ,case when inv3.ValueName = '2 years' or inv3.ValueName = 'Under 2 Years' then 1 else 0 end as 'Up to 2 years' 
	  ,case when inv3.ValueName in ('3 years', '4 years') then 1 else 0 end as '3-4 Years' 
	  ,case when inv2.ValueName = 'Fixed' and inv3.ValueName not in ('2 years', '3 years', '4 years') or inv3.ValueName = 'Lifetime' then 1 else 0 end as '5+ Years'
      ,MortgageAmount
      ,MortgageRate
      ,MortgageNumber
	  ,mgpr.DisplayName
      ,MortgageLVRatio
      ,ProductTermYears
      ,ProductTermMonths
	  ,case when ProductTermYears < 15 then 1 else 0 end as '15 Years or Less' 
	  ,case when ProductTermYears >= 15 and ProductTermYears < 26 then 1 else 0 end as '15-25 Years'
	  ,case when ProductTermYears >= 26 and ProductTermYears < 31 then 1 else 0 end as '26-30 Years' 
	  ,case when ProductTermYears >= 31 then 1 else 0 end as '31+ Years' 
	  ,inv4.ValueName as OffsetMortgage
  FROM dbo.vw_ows_MortgageProductSummary mps
  left join sa_ows_Policies pol on pol.PolicyID = mps.PolicyID
  join policy.sa_ows_MortgageProvider mgpr on mgpr.InternalProviderID = pol.internalproviderid
  left join sa_ows_sale sale on sale.SaleID = pol.SaleID
  left join sa_ows_Person pers on pers.PersonID = sale.PersonID
 -- left join sa_ows_ClientDetailAssetsAndLiabilitiesLiabilities ffl on ffl.PersonID = sale.PersonID
 -- left join sa_ows_ClientDetailAssetsAndLiabilitiesLiabilities cdall1 on cdall1.PersonID = pers.PartnerPersonID
  left join StaticData.sa_ows_InputValues inv on inv.InputID = MortgageCategoryID
  left join StaticData.sa_ows_InputValues inv1 on inv1.InputID = MortgageTypeID
  left join StaticData.sa_ows_InputValues inv2 on inv2.InputID = InterestRateTypeID
  left join StaticData.sa_ows_InputValues inv3 on inv3.InputID = InitialRatePeriodID
  left join StaticData.sa_ows_InputValues inv4 on inv4.InputID = IsMortgageOffsetID
  left join sa_ows_FactFindAssetsAndLiabilities ffl on ffl.SaleID = sale.SaleID and (ffl.HasLiabilitiesID = 19 and ffl.ConsolidationAdviceWanted = 19)
  left join sa_ows_factfindliabilities ffla on ffla.saleID = pol.saleiD and ffla.DebtConsolidationID = 19
where 1=1 
and sale.AdviserUID = @AdviserUID
and pol.Status in (0,2,7)
and DateSubmitted >= dateadd(month,-12,getdate()) and DateSubmitted <= getdate()
Group by
       mps.PolicyID
	  ,pol.SaleID
	  ,pol.ApplicationDate
	  ,sale.DateSubmitted
	  ,sale.AdviserUID
	  ,pers.DateOfBirth
	  ,MortgageAmount
      ,MortgageRate
	  ,mgpr.DisplayName
      ,MortgageNumber
      ,MortgageLVRatio
      ,ProductTermYears
      ,ProductTermMonths
	  ,inv.ValueName
	  ,inv1.ValueName
	  ,inv2.ValueName
	  ,inv3.ValueName
	  ,inv4.ValueName
	  --,inv5.ValueName
	,ffl.HasLiabilitiesID
	,ffla.DebtConsolidationID
	  )

,CTE_MortDetails as (
	  select
	   ctemc.AdviserUID
	  ,count (ctemc.PolicyID) as 'TotalCases'
	  ,sum(ctemc.[Up to 2 years]) as 'InitialPeriodUpTo2Years'
	  ,sum(ctemc.[3-4 Years]) as 'InitialPeriod3To4Years'
	  ,sum(ctemc.[5+ Years]) as 'InitialPeriod5+Years'
	  ,sum(ctemc.[15 Years or Less]) as 'InitialPeriod15YearsOrLess'
	  ,sum (ctemc.[15-25 Years]) as 'InitialPeriod15To25Years'
	  ,sum (ctemc.[26-30 Years]) as 'InitialPeriod26To30Years'
	  ,sum (ctemc.[31+ Years]) as 'InitialPeriod31+Years'
	  ,sum (ctemc.Over68) as 'Over68'
	  ,sum (ctemc.Under68) as Under68
	  ,sum (ctemc.DebtConsolidation) as 'DebtConsolidation'
	  ,sum (ctemc.NotDebtConsolidation) as 'NotDebtConsolidation'
	  from CTE_MortgageCases ctemc
	  group by
	  ctemc.AdviserUID
	  ),

cte_Lenders as (
SELECT 
   mgpr.displayname
  ,sale.AdviserUID
  ,count(displayname) as totalsold
  ,row_number () over (partition by sale.AdviserUID order by count(displayname) desc) as RowPos
 FROM dbo.vw_ows_MortgageProductSummary mps
  left join sa_ows_Policies pol on pol.PolicyID = mps.PolicyID
  join policy.sa_ows_MortgageProvider mgpr on mgpr.InternalProviderID = pol.internalproviderid
  left join sa_ows_sale sale on sale.SaleID = pol.SaleID
  left join sa_ows_Person pers on pers.PersonID = sale.PersonID
 where 1=1 
 and pol.Status in (0,2,7)
 and DateSubmitted >= dateadd(month,-12,getdate()) and DateSubmitted <= getdate()
Group by DisplayName, sale.AdviserUID
),

CTE_3Lenders as
(select adviseruid,
max (totalsold) as '1lender'
,sum (totalsold) as '3lenders'
from cte_Lenders 
where RowPos <= 3
group by AdviserUID),

cte_licence as (
select 
uh.UserName
,uh.UserUID
,case when cd.Code_Description = 'ICOB' then count (uh.useruid) else 0 end as 'ICOB'
,case when cd.Code_Description = 'MCOB' then count (uh.useruid) else 0 end as 'MCOB'
,case when cd.Code_Description = 'COB' then count (uh.useruid) else 0 end as 'COB'
,case when cd.Code_Description = 'ICOB GI Only' then count (uh.useruid) else 0 end as 'ICOB GI Only'
from dbo.sa_insight_UserCompetency uc
join dbo.sa_insight_CodeDescription cd on cd.Code_Code = uc.UC_BusinessArea and cd.Code_CodeType = 534
join dbo.sa_insight_CodeDescription cd1 on cd1.Code_Code = uc.UC_CompetencyLevel and cd1.Code_CodeType = 55
join mi_insight_UserHierarchy uh on uh.UserGUID = uc.UC_OwnerID
join sa_swift_S_AGENTS agt on uh.UserUID = agt.CODE
join sa_swift_s_agents agt1 on agt1.CODE = agt.Manager2Code
join sa_swift_S_AGENTS agt2 on agt2.CODE = uh.BusinessUID
where 1=1
and cd.Code_Description like '%COB%'
and uc.UC_Status = 0
group by 
uh.UserName
,uh.UserUID
,uh.BusinessUID
,case when agt2.TradingName is null then agt2.DESCN else agt2.TradingName end
,agt1.DESCN
,uh.BQMName
,cd.Code_Description
,cd1.Code_Description
,uc.UC_DateAchieved
),

CTE_Lic as (
select 
ctel.UserName
,ctel.UserUID
,case when sum(ctel.icob) > 0 and sum(ctel.mcob) > 0 and sum(ctel.cob) = 0 then 'MCOB' 
 when sum(ctel.icob) > 0 and sum(ctel.mcob) > 0 and sum(ctel.cob) > 0 then 'CMCOB' 
 when sum(ctel.icob) >= 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) > 0 then 'COB'
 when sum(ctel.icob) > 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) = 0 then 'ICOB'
 when sum(ctel.icob) = 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) = 0 and sum(ctel.[ICOB GI Only]) > 0 then 'ICOB GI Only'
 else ' '
 end as 'Licence Type'
,sum(ctel.ICOB) as ICOB
,sum(ctel.MCOB) as MCOB
,sum(ctel.COB) as COB
from cte_licence ctel
group by
ctel.UserName
,ctel.UserUID
)

select 
agt.CODE
,agt.DESCN
,(
case when (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) >= 90 and ctemd.TotalCases >=12 then 1 else 0 end
+
case when (cast(ctemd.[InitialPeriod31+Years] as float)/ctemd.TotalCases * 100) >= 25 and ctemd.TotalCases >=12 then 1 else 0 end
+
case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) >= 50 and ctemd.TotalCases >=12 then 1 else 0 end
+
case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) >= 10 and ctemd.TotalCases >=12 then 1 else 0 end
+
case when ((cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) > 30 or (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) > 60) and ctemd.TotalCases >= 12 then 1 else 0 end)
as 'TriggersHit'
,case when ctemd.TotalCases is null then 0 else ctemd.TotalCases end as TotalCases
,case when (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) >= 90 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger1
,case when (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) is null then 0 
 else (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) end as Trigger1Pct
,case when (cast(ctemd.[InitialPeriod31+Years] as float)/ctemd.TotalCases * 100) >= 25 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger2
,case when (cast(ctemd.[InitialPeriod31+Years] as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(ctemd.[InitialPeriod31+Years] as float)/ctemd.TotalCases * 100) end as Trigger2Pct
,case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) >= 50 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger3
,case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) end as Trigger3Pct
,case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) >= 10 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger4
,case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) end as Trigger4Pct
,case when (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) > 30 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger5
,case when (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) end as Trigger5Pct
,case when (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) > 60 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger6
,case when (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) is null then 0
 else (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) end as Trigger6Pct
from sa_swift_S_AGENTS agt
left join dbo.mi_insight_UserHierarchy uh  on uh.UserUID = agt.CODE
left join sa_swift_s_agents agt1 on agt1.CODE = agt.Manager2Code
left join sa_swift_S_AGENTS agt2 on agt2.CODE = uh.BusinessUID
left join CTE_MortDetails ctemd on uh.UserUID = ctemd.AdviserUID
left join CTE_3Lenders cteln on cteln.adviseruid = ctemd.AdviserUID
left join CTE_Lic lic on lic.UserUID = uh.UserUID
where 1=1 
and agt.CODE = @AdviserUID

End

Else

Begin
Print 'Access Denied'
End   

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH


