/****** Object:  StoredProcedure [logi].[pr_ringo_MCOBBusMixFirm_Backup20190722AG]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [logi].[pr_ringo_MCOBBusMixFirm_Backup20190722AG]
      @PtlCode    varchar(255),
	  @FirmUID	  varchar (7)

AS 


set nocount on
/**********************************************************************************************
AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
30-01-2017	S Inglis		  Addition of Mortgage Transaction Type to exclude remort from Debt Con
14-6-17		S Inglis		  Removal of users who havent sold any mortgages in period
10-8-2017	S Inglis		  CR573 Updates:
							  Trigger 1 measure changing to >=85% on 2-year deals. 
							  Trigger 2 measure changing to >70% of their capital and repayment 
							  mortgages being written for terms of 25, 30 or 35 year terms.		
3-10-2017	S Inglis		Update to trigger 3 to only look at residential mortgages CR573B
***********************************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'MCOB Business Mix Firm';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + @FirmUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin

with CTE_MortgageCases as (
SELECT
       mps.PolicyID
	  ,pol.SaleID
	  ,sale.DateSubmitted
	  ,pol.ApplicationDate
	  ,sale.AdviserUID
	  ,sale.BusinessUid
	  ,pers.DateOfBirth
	  ,dateadd(MONTH,producttermmonths,dateadd(YEAR,producttermyears,pol.applicationdate)) as EndDate
	  ,(round(DATEDIFF(dd,pers.dateofbirth,dateadd(MONTH,producttermmonths,dateadd(YEAR,producttermyears,pol.applicationdate)))/365.25,0,1)) as AgeOnCompletion
		  ,case when ((round(DATEDIFF(dd,pers.dateofbirth,getdate())/365.25,0,1)) + mps.ProductTermYears) >= 68 and inv.ValueName = 'Residential' then 1 else 0 end as Over68 --Updated CR573B S Inglis 3.10.17
		  ,case when ((round(DATEDIFF(dd,pers.dateofbirth,getdate())/365.25,0,1)) + mps.ProductTermYears) < 68 or inv.ValueName != 'Residential' then 1 else 0 end as Under68 --Updated CR573B S Inglis 3.10.17
	  ,case when (ffl.HasLiabilitiesID is null or ffla.DebtConsolidationID is null or inv5.ValueName != 'Remortgage' ) then 1 else 0 end as NotDebtConsolidation --added 30-1-17 SI
	  ,case when ffl.HasLiabilitiesID = 19 and ffla.DebtConsolidationID = 19 and inv5.ValueName = 'Remortgage' then 1 else 0 end as DebtConsolidation --added 30-1-17
	  ,inv.ValueName as MortgageCategory
	  ,inv1.ValueName as MortgageType
	  ,inv2.ValueName as InterestRate
	  ,inv3.ValueName as InitialRatePeriod
	  ,case when inv3.ValueName = '2 years' or inv3.ValueName = 'Under 2 Years' then 1 else 0 end as 'Up to 2 years' 
	  ,case when inv3.ValueName in ('3 years', '4 years') then 1 else 0 end as '3-4 Years' 
	  ,case when inv2.ValueName = 'Fixed' and inv3.ValueName not in ('2 years', '3 years', '4 years') or inv3.ValueName = 'Lifetime' then 1 else 0 end as '5+ Years'
      ,MortgageAmount
      ,MortgageRate
      ,MortgageNumber
	  ,mgpr.DisplayName
      ,MortgageLVRatio
      ,ProductTermYears
      ,ProductTermMonths
	  --,case when ProductTermYears < 15 then 1 else 0 end as '15 Years or Less'  --removed 10.8.17 SI
	  --,case when ProductTermYears >= 15 and ProductTermYears < 26 then 1 else 0 end as '15-25 Years' --removed 10.8.17 SI
	  --,case when ProductTermYears >= 26 and ProductTermYears < 31 then 1 else 0 end as '26-30 Years' --removed 10.8.17 SI
	  --,case when ProductTermYears >= 31 then 1 else 0 end as '31+ Years'  --removed 10.8.17 SI
	  ,case when ProductTermYears in (25,30,35) and inv1.ValueName = 'Repayment' then 1 else 0 end as RepaymentTerm --added 10.8.17 SI
	  ,inv4.ValueName as OffsetMortgage
  FROM dbo.vw_ows_MortgageProductSummary mps
  left join sa_ows_Policies pol on pol.PolicyID = mps.PolicyID
  join policy.sa_ows_MortgageProvider mgpr on mgpr.InternalProviderID = pol.internalproviderid
  left join sa_ows_sale sale on sale.SaleID = pol.SaleID
  left join sa_ows_Person pers on pers.PersonID = sale.PersonID
  --left join sa_ows_ClientDetailAssetsAndLiabilitiesLiabilities ffl on ffl.PersonID = sale.PersonID
  --left join sa_ows_ClientDetailAssetsAndLiabilitiesLiabilities cdall1 on cdall1.PersonID = pers.PartnerPersonID
  left join StaticData.sa_ows_InputValues inv on inv.InputID = MortgageCategoryID
  left join StaticData.sa_ows_InputValues inv1 on inv1.InputID = MortgageTypeID
  left join StaticData.sa_ows_InputValues inv2 on inv2.InputID = InterestRateTypeID
  left join StaticData.sa_ows_InputValues inv3 on inv3.InputID = InitialRatePeriodID
  left join StaticData.sa_ows_InputValues inv4 on inv4.InputID = IsMortgageOffsetID
  left join sa_ows_FactFindAssetsAndLiabilities ffl on ffl.SaleID = sale.SaleID and (ffl.HasLiabilitiesID = 19 and ffl.ConsolidationAdviceWanted = 19)
  left join sa_ows_factfindliabilities ffla on ffla.saleID = pol.saleiD and ffla.DebtConsolidationID = 19
  left join vw_ows_MortgageRecommendedSolution mrs on mrs.PolicyID = mps.PolicyID --added 30-1-17 SI
  left join StaticData.sa_ows_InputValues inv5 on inv5.InputID = mrs.TransactionTypeID --added 30-1-17 SI
where 1=1 
and pol.Status in (0,2,7)
and DateSubmitted >= dateadd(month,-12,getdate())  and DateSubmitted <= getdate()
and sale.BusinessUid = @FirmUID
Group by
       mps.PolicyID
	  ,pol.SaleID
	  ,pol.ApplicationDate
	  ,sale.DateSubmitted
	  ,sale.AdviserUID
	  ,pers.DateOfBirth
	  ,MortgageAmount
      ,MortgageRate
	  ,mgpr.DisplayName
      ,MortgageNumber
      ,MortgageLVRatio
      ,ProductTermYears
      ,ProductTermMonths
      	  ,case when (ffl.HasLiabilitiesID is null or ffla.DebtConsolidationID is null or inv5.ValueName != 'Remortgage' ) then 1 else 0 end  --added 30-1-17 SI
	  ,case when ffl.HasLiabilitiesID = 19 and ffla.DebtConsolidationID = 19 and inv5.ValueName = 'Remortgage' then 1 else 0 end  --added 30-1-17
	  ,inv.ValueName
	  ,inv1.ValueName
	  ,inv2.ValueName
	  ,inv3.ValueName
	  ,inv4.ValueName
	  ,sale.BusinessUid
	  ,ffl.HasLiabilitiesID 
	  ,ffla.DebtConsolidationID
)

,CTE_MortDetails as (
	  select
	   ctemc.BusinessUid
	  ,count (ctemc.PolicyID) as 'TotalCases'
	  ,sum(ctemc.[Up to 2 years]) as 'InitialPeriodUpTo2Years'
	  ,sum(ctemc.[3-4 Years]) as 'InitialPeriod3To4Years'
	  ,sum(ctemc.[5+ Years]) as 'InitialPeriod5+Years'
	  --,sum(ctemc.[15 Years or Less]) as 'InitialPeriod15YearsOrLess' --removed 10.8.17 SI
	  --,sum (ctemc.[15-25 Years]) as 'InitialPeriod15To25Years' --removed 10.8.17 SI
	  --,sum (ctemc.[26-30 Years]) as 'InitialPeriod26To30Years' --removed 10.8.17 SI
	  --,sum (ctemc.[31+ Years]) as 'InitialPeriod31+Years' --removed 10.8.17 SI
	  ,sum(ctemc.RepaymentTerm) as RepaymentTerm -- added 10.8.17 SI
	  ,sum (ctemc.Over68) as 'Over68'
	  ,sum (ctemc.Under68) as Under68
	  ,sum (ctemc.DebtConsolidation) as 'DebtConsolidation'
	  ,sum (ctemc.NotDebtConsolidation) as 'NotDebtConsolidation'
	  from CTE_MortgageCases ctemc
	  group by
	  ctemc.BusinessUid
	  ),

cte_Lenders as (
SELECT 
   mgpr.displayname
  ,sale.BusinessUid
  ,count(displayname) as totalsold
  ,row_number () over (partition by sale.BusinessUID order by count(displayname) desc) as RowPos
 FROM dbo.vw_ows_MortgageProductSummary mps
  left join sa_ows_Policies pol on pol.PolicyID = mps.PolicyID
  join policy.sa_ows_MortgageProvider mgpr on mgpr.InternalProviderID = pol.internalproviderid
  left join sa_ows_sale sale on sale.SaleID = pol.SaleID
  left join sa_ows_Person pers on pers.PersonID = sale.PersonID
 where 1=1 
 and pol.Status in (0,2,7)
 and DateSubmitted >= dateadd(month,-12,getdate())  and DateSubmitted <= getdate()
Group by DisplayName, sale.BusinessUid
),

CTE_3Lenders as
(select BusinessUid,
max (totalsold) as '1lender'
,sum (totalsold) as '3lenders'
from cte_Lenders 
where RowPos <= 3
group by BusinessUid)

select 
ctemd.BusinessUid
,(
case when convert(numeric,(cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100)) >= 85 and ctemd.TotalCases >=12 then 1 else 0 end --Updated 10.8.17 SI
+
--case when convert(numeric,(cast(ctemd.[InitialPeriod31+Years] as float)/ctemd.TotalCases * 100)) >= 25 and ctemd.TotalCases >=12 then 1 else 0 end -- Removed 10.8.17 SI
case when convert(numeric,(cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100)) >= 70 and ctemd.TotalCases >=12 then 1 else 0 end --Added 10.8.17 SI
+
case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) >= 50 and ctemd.TotalCases >=12 then 1 else 0 end
+
case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) >= 10 and ctemd.TotalCases >=12 then 1 else 0 end
+
case when ((cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) > 30 or (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) > 60) and ctemd.TotalCases >= 12 then 1 else 0 end)
as 'TriggersHit'
,case when ctemd.TotalCases is null then 0 else ctemd.TotalCases end as TotalCases
,case when (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) >= 85 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger1 --updated  10.8.17 SI
,case when (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) is null then 0 
 else (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) end as Trigger1Pct
,case when (cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100) >= 70 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger2 --updated  10.8.17 SI
,case when (cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100) is null then 0 --updated  10.8.17 SI 
 else (cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100) end as Trigger2Pct --updated  10.8.17 SI
,case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) >= 50 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger3
,case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) end as Trigger3pct
,case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) >= 10 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger4
,case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) end as Trigger4pct
,case when (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) > 30 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger5
,case when (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) end as Trigger5pct
,case when (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) > 60 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger6
,case when (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) is null then 0
 else (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) end as Trigger6pct
from CTE_MortDetails ctemd
join CTE_3Lenders cteln on cteln.BusinessUid = ctemd.BusinessUid
where ctemd.BusinessUid = @FirmUID
and isnull(ctemd.TotalCases,0)> 0 --added 14.6.17

End

Else

Begin
Print 'Access Denied'
End   

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
