CREATE PROCEDURE [logi].[pr_ringo_MCOBTriggers_Backup20190722AG]
				 @PtlCode		varchar(10),
				 @AQMUID		varchar(10) = 'View All',
				 @AdviserUID	varchar(7) = null,
				 @BusinessUID	varchar(7) = null,
				 @SupervisorUID varchar(7) = null,
				 @DeepSpan		varchar(14) = null,
				 @Type			varchar(20)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_MCOBTriggers]
Author      : S Inglis
Date  : 24/10/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "MCOB Triggers" and is found on the "BQM MI" 
              menu. This report displays: 
              - Mortgage Triggers for all advisers - this report will then feed the Adviser 
              sub reports for Adviser/Firm/Supervisor and Management



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_MCOBTriggers]

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
2-11-17		S Inglis		 AQMUID parameter changed to 'View All'
2-11-17		S Inglis		 Addition of filter for debt consolidation
20-12-17	S Inglis		 Change in way national average is calculated
4-1-18		S Inglis		 Update to how trigger 1 and 2 is calculated in respect to number 
							 of triggers hit so in line with trigger calculation
10.1.18		S Inglis		 CR624: Change trigger 6 from >60% to >65%
25.5.18		S Inglis		 Where clause added to remove non-selling advisers
1.3.19		S Inglis		 Updates to triggers as per email from Nicki Rees (05/02/19):
							 Trigger 1 – change from >= 85% to >=80%
							 Trigger 3 – Remove
							 Trigger 7 – change from >= 50% to >=45%
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/



/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/

Begin

SELECT distinct
mps.PolicyID,
sale.AdviserUID,
case when ((round(DATEDIFF(dd,pers.dateofbirth,getdate())/365.25,0,1)) + mps.ProductTermYears) >= 68 and inv.ValueName = 'Residential' then 1 else 0 end as Over68,
case when ffl.HasLiabilitiesID = 19 and ffla.DebtConsolidationID = 19 and inv5.ValueName = 'Remortgage' then 1 else 0 end as DebtConsolidation, --Amended SI 2.11.17
case when inv3.ValueName = '2 years' or inv3.ValueName = 'Under 2 Years' then 1 else 0 end as UpToTwo,
case when inv5.ValueName = 'Product Transfer' then 1 else 0 end as ProductTransfers,
case when ProductTermYears in (25,30,35) and inv1.ValueName = 'Repayment' then 1 else 0 end as RepaymentTerm,
mgpr.DisplayName
into #AllMortgages
FROM vw_ows_MortgageProductSummary mps
left join sa_ows_Policies pol on pol.PolicyID = mps.PolicyID
left join policy.sa_ows_MortgageProvider mgpr on mgpr.InternalProviderID = pol.internalproviderid
left join sa_ows_sale sale on sale.SaleID = pol.SaleID
left join sa_ows_Person pers on pers.PersonID = sale.PersonID
left join StaticData.sa_ows_InputValues inv on inv.InputID = MortgageCategoryID
left join StaticData.sa_ows_InputValues inv1 on inv1.InputID = MortgageTypeID
left join StaticData.sa_ows_InputValues inv3 on inv3.InputID = InitialRatePeriodID
left join vw_ows_MortgageRecommendedSolution mrs on mrs.PolicyID = mps.PolicyID
left join StaticData.sa_ows_InputValues inv5 on inv5.InputID = mrs.TransactionTypeID
left join sa_ows_FactFindAssetsAndLiabilities ffl on ffl.SaleID = sale.SaleID and (ffl.HasLiabilitiesID = 19 and ffl.ConsolidationAdviceWanted = 19)
  left join sa_ows_factfindliabilities ffla on ffla.saleID = pol.saleiD and ffla.DebtConsolidationID = 19 --added SI 2.11.17
where 
pol.Status in (0,2,7)
and DateSubmitted >= dateadd(month,-12,getdate()) 

Select
ctemc.AdviserUID,
count (ctemc.PolicyID) as TotalCases,
sum(ctemc.UpToTwo) as InitialPeriodUpTo2Years,
sum(ctemc.RepaymentTerm) as RepaymentTerm,
SUM(ctemc.ProductTransfers) as ProductTransfers,
sum (ctemc.Over68) as Over68,
sum (ctemc.DebtConsolidation) as DebtConsolidation
into #MortgageSummary
from #AllMortgages ctemc
group by
ctemc.AdviserUID
having count(ctemc.PolicyID) > 0

SELECT 
am.displayname,
am.AdviserUID,
count(am.displayname) as totalsold,
row_number () over (partition by am.AdviserUID order by count(am.displayname) desc) as RowPos
into #Lenders
FROM #AllMortgages am
Group by am.DisplayName, am.AdviserUID

select 
adviseruid,
max (totalsold) as '1lender',
sum (totalsold) as '3lenders'
into #TopLenders
from #Lenders 
where RowPos <= 3
group by AdviserUID


select 
distinct 
 uh.AQMName
,uh.AQMUID 
,uh.BQMName
,uh.SupervisorName
,uh.SupervisorUID
,uh.SupervisorUID2
,uh.SupervisorUID3
,uh.SupervisorUID4
,uh.SupervisorUID5
,uh.SupervisorUID6
,uh.BQMUID
,uh.UserUID
,uh.UserName
,uh.BusinessUID
,uh.BusinessCompanyName
,(
case when (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) >= 80 and ctemd.TotalCases >=12 then 1 else 0 end --Updated 1.3.19 SI
+
case when (cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100) >= 70 and ctemd.TotalCases >=12 then 1 else 0 end
--+
--case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) >= 50 and ctemd.TotalCases >=12 then 1 else 0 end --Removed 1.3.19 SI
+
case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) >= 10 and ctemd.TotalCases >=12 then 1 else 0 end
+
case when ((cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) > 30 or (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) > 65) and ctemd.TotalCases >= 12 then 1 else 0 end --Updated 10.1.18 SI
+
case when (cast(ctemd.ProductTransfers as float)/ctemd.TotalCases * 100) >= 45 and ctemd.TotalCases >=12 then 1 else 0 end --updated 1.3.19 SI
)
as 'TriggersHit'
,case when ctemd.TotalCases is null then 0 else ctemd.TotalCases end as TotalCases
,case when (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) >= 80 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger1 --Updated 1.3.19 SI
,case when (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) is null then 0 
 else (cast(ctemd.InitialPeriodUpTo2Years as float)/ctemd.TotalCases * 100) end as Trigger1Pct
,case when (cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100) >= 70 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger2
,case when (cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100) is null then 0 
 else (cast(ctemd.RepaymentTerm as float)/ctemd.TotalCases * 100) end as Trigger2Pct
,case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) >= 50 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger3
,case when (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(ctemd.Over68 as float)/ctemd.TotalCases * 100) end as Trigger3Pct
,case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) >= 10 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger4
,case when (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(ctemd.DebtConsolidation as float)/ctemd.TotalCases * 100) end as Trigger4Pct
,case when (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) > 30 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger5
,case when (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(cteln.[1Lender] as float)/ctemd.TotalCases * 100) end as Trigger5Pct
,case when (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) > 65 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger6 --Updated 10.1.18 SI
,case when (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) is null then 0
 else (cast (cteln.[3Lenders] as float)/ctemd.TotalCases * 100) end as Trigger6Pct
,case when (cast(ctemd.ProductTransfers as float)/ctemd.TotalCases * 100) >= 45 and ctemd.TotalCases >=12 then 'Yes' else 'No' end as Trigger7
,case when (cast(ctemd.ProductTransfers as float)/ctemd.TotalCases * 100) is null then 0
 else (cast(ctemd.ProductTransfers as float)/ctemd.TotalCases * 100) end as Trigger7Pct
into #Triggers
from mi_insight_UserHierarchy uh
join #MortgageSummary ctemd on uh.UserUID = ctemd.AdviserUID
join #TopLenders cteln on uh.UserUID = cteln.AdviserUID
where uh.UserJobTitleCodeSeller is not null -- added 250518 SI

Select
'1' as Orders,
AQMName,
AQMUID,
BQMName,
SupervisorName,
SupervisorUID,
SupervisorUID2,
SupervisorUID3,
SupervisorUID4,
SupervisorUID5,
SupervisorUID6,
BQMUID,
UserUID,
UserName,
BusinessUID,
BusinessCompanyName,
convert(varchar(2),TriggersHit) as TriggersHit,
convert(varchar(4),TotalCases) as TotalCases,
Trigger1,
Trigger1Pct,
Trigger2,
Trigger2Pct,
Trigger3,
Trigger3Pct,
Trigger4,
Trigger4Pct,
Trigger5,
Trigger5Pct,
Trigger6,
Trigger6Pct,
Trigger7,
Trigger7Pct
from #Triggers
WHERE
(UserUID = @AdviserUID and @BusinessUID is Null and @AQMUID = 'View All' and @SupervisorUID is Null and @DeepSpan is Null and @Type = 'Adviser') OR --Adviser Report
(@AdviserUID is Null and @BusinessUID is Null and @AQMUID = 'View All' and @SupervisorUID is Null and @DeepSpan is Null and @Type = 'Management') OR -- Management View All
(@AdviserUID is Null and BusinessUID = @BusinessUID and @AQMUID = 'View All' and @SupervisorUID is Null and @DeepSpan is Null and @Type = 'Firm') OR --Firm Adviser Report
(@AdviserUID is Null and @BusinessUID is Null and AQMUID = @AQMUID and @SupervisorUID is Null and @DeepSpan is Null and @Type = 'Management') OR -- Management Report
(@AdviserUID is Null and @BusinessUID is Null and @AQMUID = 'View All' and isnull(SupervisorUID,BQMUID) = @SupervisorUID and @DeepSpan = 'Shallow Span' and @Type = 'Supervisor') OR --Supervisor Shallow Span
(@AdviserUID is Null and @BusinessUID is Null and @AQMUID = 'View All' and SupervisorUID is not null --Supervisor Deep Span
					 and @SupervisorUID in (SupervisorUID2, SupervisorUID3, SupervisorUID4, SupervisorUID5, SupervisorUID6, BQMUID) 
					 and @DeepSpan = 'Deep Span' and @Type = 'Supervisor')

Union
Select
'2' as Orders,
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'National',
'Average',
'',
SUM(cast(ms.InitialPeriodUpTo2Years as float))/sum(Cast(ms.TotalCases as float))*100 as Trigger1Pct,
'',
SUM(cast(ms.RepaymentTerm as float))/sum(Cast(ms.TotalCases as float))*100 as Trigger2Pct,
'',
SUM(cast(ms.Over68 as float))/sum(Cast(ms.TotalCases as float))*100 as Trigger3Pct,
'',
SUM(cast(ms.DebtConsolidation as float))/sum(Cast(ms.TotalCases as float))*100 as Trigger3Pct,
'',
SUM(cast(ld.[1lender] as float))/sum(Cast(ms.TotalCases as float))*100 as Trigger5Pct,
'',
SUM(cast(ld.[3lenders] as float))/sum(cast(ms.TotalCases as float))*100 as Trigger6Pct,
'',
SUM(cast(ms.ProductTransfers as float))/sum(Cast(ms.TotalCases as float))*100 as Trigger7Pct
from #TopLenders ld
join #MortgageSummary ms on ms.AdviserUID = ld.AdviserUID
Order by Orders desc


End




