CREATE PROCEDURE [logi].[pr_ringo_MCOBTriggersDeepSpan]
		@PtlCode			varchar(255),
        @AQMUID		      varchar(255) = Null

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_ringo_MCOBTriggersDeepSpan]
Author      : S Inglis
Date  : 31/10/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "MCOB Triggers Deep Span" and is found on the "BQM MI" 
              menu. This report displays: 
