set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @AdviserUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

select
even.PersonID
,year(even.DateDue) as EventDueYear
into #AdhocReviews
from Events.sa_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
----join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
----join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where even.EventReminderStatusID = 4
and TypeID = 8;

DECLARE @lc_report_event     int,
        @lc_late_status      int,
        @lc_due_status       int,
        @lc_scheduled_status int,
        @lc_review_event     int,
        @lc_declined         int;

SET @lc_report_event      = 1;
SET @lc_late_status       = 1;
SET @lc_due_status        = 2;
SET @lc_scheduled_status  = 3;
SET @lc_review_event      = 2;
SET @lc_declined          = 3;

with cte_OGS_chk as(select distinct saca.CASE_CaseReference as CaseReference
		  ,CaseStatus.Code_Description as OGS_CHK_Status
		  ,miuh.UserUID AS AdviserUID
		  ,miuh.UserName AS Adviser
		  ,pers.FirstName + ' ' + pers.LastName as ClientName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN dbo.mi_insight_UserHierarchy miuh ON  saca.CASE_AdviserID = miuh.UserGUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status -- updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	JOIN  prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even on even.Eventid = cast(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''), 'C','') as int) -- Updated 21/12/21
	--JOIN  prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even on even.Eventid =  cast (Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR','') as int)   -- Updated 14/09/20
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = even.PersonID
																   and pers.BusinessUid = miuh.BusinessUID
	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	AND   miuh.UserUID = @AdviserUID
	AND   saca.CASE_CaseReference     like 'OGS%'
	AND   saca.CASE_CaseReference not like 'OGS%x' 
	AND   saca.CASE_CaseReference not like 'OGS%X'
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS') -- omitted XOGS as that is to do with a pre-check
	and   CFQ.CFQ_QuestionCode between 2001 and 3000
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ))
, cte_OGS_count	as (SELECT  pers.AdviserUID, 
                            COUNT(*) as NoClientsServiced
  FROM prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
  where even.TypeID in (@lc_report_event)
  and   isnull(even.IsCancelled,0) = 0
  and   pers.AdviserUID = @AdviserUID
  and   isnull(even.IsDeleted,0)   = 0
  and   even.EventReminderStatusID in (@lc_late_status,@lc_due_status,@lc_scheduled_status)
  group by pers.AdviserUID
)
, cte_OGS_declined as (Select pers.AdviserUID
                             ,count(distinct even.PersonID) as ClientsDecliningEvents
                             ,count(*) as EventsDeclined	
                       FROM  prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
                       join  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
					   left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateUpdated)
                       where Outcome = @lc_declined
                       and   pers.AdviserUID = @AdviserUID
					   and   adh.PersonID is null
                       and   TypeID  = @lc_review_event
					   and   isnull(even.IsCancelled,0) = 0
                       and   isnull(even.IsDeleted,0)   = 0
                       and    even.DateUpdated >= DATEADD(year,-1,GETDATE())
                       and    exists (select 1
                                      from   prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even1
                                      where  even.PersonID = even1.PersonID
                                      and    even1.Outcome is null 
									  and    even1.TypeID  = 2
									  and    isnull(even1.IsCancelled,0) = 0
									  and    isnull(even1.IsDeleted,0) = 0
                                      and    even1.EventReminderStatusID in (1,2,3))
                          group by pers.AdviserUid
)		
  SELECT ogco.AdviserUID
        ,ogco.NoClientsServiced
        ,ogde.EventsDeclined
  --      ,ogch.CaseReference
  --      ,ogch.ClientName
        ,sum( case when ogch.CaseReference is not null then 1 else 0 end )as OGS_CHK_Status
  FROM   cte_OGS_count ogco
  LEFT JOIN   cte_OGS_chk   ogch on ogch.AdviserUID = ogco.AdviserUID 					   
  LEFT JOIN   cte_OGS_declined ogde on ogde.AdviserUid = ogco.AdviserUid 					   
  group by ogco.AdviserUID
          ,ogco.NoClientsServiced
          ,ogde.EventsDeclined
      --    ,ogch.CaseReference
      --    ,ogch.ClientName
        order by AdviserUID;                            
                          
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_ogs_chk_Backup20240531KG]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [logi].[pr_Ringo_ogs_chk_Backup20240531KG]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on

/**********************************************************************************************
Name  : [logi].[pr_Ringo_ogs_chk]
Author      : T Cummings
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Adviser Level OGs Chk" and 
              is found on the "BQM MI" menu. This report displays: 
              - Details of clients under servicing



      The security groups associated with is report are:
      1) 
      2)  

      Execute as follows:
      exec [logi].[pr_Ringo_ogs_chk] '1001872','ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
25-5-18		S Inglis		  Updated to include Adhoc Reviews
27-6-19		S Inglis		  Updated to take into account change to table in Warehouse where nulls
							  are now 0
28-7-20		S Hale			  Corrected Code_CodeType from 9 to 785
14-9-20		S Inglis		  Amended query to replace prefixes to link to Event ID
11-12-20	S Inglis		  Additional changes to where clause to amend nulls which are now 0
21-12-21    S Tourlidas		  Addressing an issue with OGS suffixing the cases with a C when the case
							  is from concert which resulted to not mapping to the event id in OWS
04/04/2022	A Groves		1) Replaced the OWS Events table with the new merged event table
								that combines Concert Hub and OWS events.
							2) Added a join to column OriginalOWSEventID to handle where a D365 
								case check has been keyed into Insight with the OWS reference.
05/04/2022	S Campbell		  Use dbo.mi_concert_ows_Event
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'RingoAdviserBQMMI';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @AdviserUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

select
even.PersonID
,year(even.DateDue) as EventDueYear
into #AdhocReviews
from Events.sa_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
----join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
----join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where even.EventReminderStatusID = 4
and TypeID = 8;

DECLARE @lc_report_event     int,
        @lc_late_status      int,
        @lc_due_status       int,
        @lc_scheduled_status int,
        @lc_review_event     int,
        @lc_declined         int;

SET @lc_report_event      = 1;
SET @lc_late_status       = 1;
SET @lc_due_status        = 2;
SET @lc_scheduled_status  = 3;
SET @lc_review_event      = 2;
SET @lc_declined          = 3;

with cte_OGS_chk as(select distinct saca.CASE_CaseReference as CaseReference
		  ,CaseStatus.Code_Description as OGS_CHK_Status
		  ,miuh.UserUID AS AdviserUID
		  ,miuh.UserName AS Adviser
		  ,pers.FirstName + ' ' + pers.LastName as ClientName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN dbo.mi_insight_UserHierarchy miuh ON  saca.CASE_AdviserID = miuh.UserGUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status -- updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.mi_concert_ows_Event even 
				on	case when even.EventID like 'SE%' 
						then case when substring(even.EventID,3,200) not like '%[^0-9]%' then cast(substring(even.EventID,3,200) as int) else -1 end 
						else case when even.EventID not like '%[^0-9]%' then cast(even.EventID as int) else -1 end 
					end
					= 
					case when replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.mi_concert_ows_Event even2 
				on	even2.OriginalOWSEventID 
					= 
					case when replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = coalesce(even.PersonID,even2.PersonID)
																   and pers.BusinessUid = miuh.BusinessUID

	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	AND   miuh.UserUID = @AdviserUID
	AND   saca.CASE_CaseReference     like 'OGS%'
	AND   saca.CASE_CaseReference not like 'OGS%x' 
	AND   saca.CASE_CaseReference not like 'OGS%X'
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS') -- omitted XOGS as that is to do with a pre-check
	and   CFQ.CFQ_QuestionCode between 2001 and 3000
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ))
, cte_OGS_count	as (SELECT  pers.AdviserUID, 
                            COUNT(*) as NoClientsServiced
  FROM prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
  where even.TypeID in (@lc_report_event)
  and   isnull(even.IsCancelled,0) = 0
  and   pers.AdviserUID = @AdviserUID
  and   isnull(even.IsDeleted,0)   = 0
  and   even.EventReminderStatusID in (@lc_late_status,@lc_due_status,@lc_scheduled_status)
  group by pers.AdviserUID
)
--, cte_OGS_declined as (Select pers.AdviserUID
--                             ,count(distinct even.PersonID) as ClientsDecliningEvents
--                             ,count(*) as EventsDeclined	
--                       FROM  prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
--                       join  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
--					   left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateUpdated)
--                       where Outcome = @lc_declined
--                       and   pers.AdviserUID = @AdviserUID
--					   and   adh.PersonID is null
--                       and   TypeID  = @lc_review_event
--					   and   isnull(even.IsCancelled,0) = 0
--                       and   isnull(even.IsDeleted,0)   = 0
--                       and    even.DateUpdated >= DATEADD(year,-1,GETDATE())
--                       and    exists (select 1
--                                      from   prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even1
--                                      where  even.PersonID = even1.PersonID
--                                      and    even1.Outcome is null 
--									  and    even1.TypeID  = 2
--									  and    isnull(even1.IsCancelled,0) = 0
--									  and    isnull(even1.IsDeleted,0) = 0
--                                      and    even1.EventReminderStatusID in (1,2,3))
--                          group by pers.AdviserUid
--)	
,CTE_DeclinedEvents as (
select
even.PersonID
,even.DateDue
,year(even.DateDue) as EventDueYear
,even.Details
,even.DateCompleted
,even.CompletedBy
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
from dbo.mi_concert_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateDue)
where outcome = 3
and adh.PersonID is null
and TypeID = 2),

CTE_ClientDeclines as (
Select
PersonID,
sum(case when DateDue  >= dateadd(year,-4,getdate()) and DateDue < dateadd(year,-3,getdate()) then 1 else 0 end) as EventDeclined3YearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-3,getdate()) and DateDue < dateadd(year,-2,getdate()) then 1 else 0 end) as EventDeclined2yearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-2,getdate()) and DateDue < dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedLastYear,  --Updated SI 27.2.17
sum(case when DateDue >= dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedCurrentYear, --Updated SI 27.2.17
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
From CTE_DeclinedEvents de
join mi_insight_UserHierarchy uh on uh.UserUID = de.AdviserUID
--where (uh.AQMUID = @AQMUID or @AQMUID = 'View All') and uh.ADUID != '4005013'
Group by
PersonID,
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
),

cte_OGS_declined AS (
Select
LastName [EventsDeclined],
AdviserUID
from CTE_ClientDeclines cd
where AdviserUID = @AdviserUID
Group by
BusinessUid
,FirmName
,AdviserUID
,AdviserName
,FirstName
,LastName,
AQMName,
BQMName
,case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end
,case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end 
,case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end
,case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end
having Sum ((case when EventDeclinedCurrentYear >= 1 then 1 else 0 end)+
			(case when EventDeclinedLastYear >= 1 then 1 else 0 end)+
			(case when EventDeclined2yearsAgo >= 1 then 1 else 0 end)+
			(case when EventDeclined3YearsAgo >= 1 then 1 else 0 end)) >=2
)


SELECT distinct ogco.AdviserUID
        ,ogco.NoClientsServiced
        --,ogde.EventsDeclined
		,count(ogde.EventsDeclined) [EventsDeclined]
  --      ,ogch.CaseReference
  --      ,ogch.ClientName
        ,sum( case when ogch.CaseReference is not null then 1 else 0 end )as OGS_CHK_Status
  FROM   cte_OGS_count ogco
  LEFT JOIN   cte_OGS_chk   ogch on ogch.AdviserUID = ogco.AdviserUID 					   
  LEFT JOIN   cte_OGS_declined ogde on ogde.AdviserUid = ogco.AdviserUid 					   
  group by ogco.AdviserUID
          ,ogco.NoClientsServiced
          ,ogde.EventsDeclined
      --    ,ogch.CaseReference
      --    ,ogch.ClientName
        order by AdviserUID;                             
                          
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_ogs_chk_Backup20240614SH]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [logi].[pr_Ringo_ogs_chk_Backup20240614SH]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on

/**********************************************************************************************
Name  : [logi].[pr_Ringo_ogs_chk]
Author      : T Cummings
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Adviser Level OGs Chk" and 
              is found on the "BQM MI" menu. This report displays: 
              - Details of clients under servicing



      The security groups associated with is report are:
      1) 
      2)  

      Execute as follows:
      exec [logi].[pr_Ringo_ogs_chk] '1001872','ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
25-5-18		S Inglis		  Updated to include Adhoc Reviews
27-6-19		S Inglis		  Updated to take into account change to table in Warehouse where nulls
							  are now 0
28-7-20		S Hale			  Corrected Code_CodeType from 9 to 785
14-9-20		S Inglis		  Amended query to replace prefixes to link to Event ID
11-12-20	S Inglis		  Additional changes to where clause to amend nulls which are now 0
21-12-21    S Tourlidas		  Addressing an issue with OGS suffixing the cases with a C when the case
							  is from concert which resulted to not mapping to the event id in OWS
04/04/2022	A Groves		1) Replaced the OWS Events table with the new merged event table
								that combines Concert Hub and OWS events.
							2) Added a join to column OriginalOWSEventID to handle where a D365 
								case check has been keyed into Insight with the OWS reference.
05/04/2022	S Campbell		  Use dbo.mi_concert_ows_Event
31/05/2024  K Garcia          Added new PROD_ShortName of OAW and OAS to be included
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'RingoAdviserBQMMI';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @AdviserUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

select
even.PersonID
,year(even.DateDue) as EventDueYear
into #AdhocReviews
from Events.sa_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
----join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
----join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where even.EventReminderStatusID = 4
and TypeID = 8;

DECLARE @lc_report_event     int,
        @lc_late_status      int,
        @lc_due_status       int,
        @lc_scheduled_status int,
        @lc_review_event     int,
        @lc_declined         int;

SET @lc_report_event      = 1;
SET @lc_late_status       = 1;
SET @lc_due_status        = 2;
SET @lc_scheduled_status  = 3;
SET @lc_review_event      = 2;
SET @lc_declined          = 3;

with cte_OGS_chk as(select distinct saca.CASE_CaseReference as CaseReference
		  ,CaseStatus.Code_Description as OGS_CHK_Status
		  ,miuh.UserUID AS AdviserUID
		  ,miuh.UserName AS Adviser
		  ,pers.FirstName + ' ' + pers.LastName as ClientName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN dbo.mi_insight_UserHierarchy miuh ON  saca.CASE_AdviserID = miuh.UserGUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status -- updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.mi_concert_ows_Event even 
				on	case when even.EventID like 'SE%' 
						then case when substring(even.EventID,3,200) not like '%[^0-9]%' then cast(substring(even.EventID,3,200) as int) else -1 end 
						else case when even.EventID not like '%[^0-9]%' then cast(even.EventID as int) else -1 end 
					end
					= 
					case when replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.mi_concert_ows_Event even2 
				on	even2.OriginalOWSEventID 
					= 
					case when replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = coalesce(even.PersonID,even2.PersonID)
																   and pers.BusinessUid = miuh.BusinessUID

	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	AND   miuh.UserUID = @AdviserUID
	AND    (saca.CASE_CaseReference     like 'OGS%'
			or saca.CASE_CaseReference     like 'OAW%'
			or saca.CASE_CaseReference     like 'OAS%')
	AND   saca.CASE_CaseReference not like 'OGS%x' 
	AND   saca.CASE_CaseReference not like 'OGS%X'
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS','OAW','OAS')  -- omitted XOGS as that is to do with a pre-check
	and   CFQ.CFQ_QuestionCode between 2001 and 3000
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ))
, cte_OGS_count	as (SELECT  pers.AdviserUID, 
                            COUNT(*) as NoClientsServiced
  FROM prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
  where even.TypeID in (@lc_report_event)
  and   isnull(even.IsCancelled,0) = 0
  and   pers.AdviserUID = @AdviserUID
  and   isnull(even.IsDeleted,0)   = 0
  and   even.EventReminderStatusID in (@lc_late_status,@lc_due_status,@lc_scheduled_status)
  group by pers.AdviserUID
)
--, cte_OGS_declined as (Select pers.AdviserUID
--                             ,count(distinct even.PersonID) as ClientsDecliningEvents
--                             ,count(*) as EventsDeclined	
--                       FROM  prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
--                       join  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
--					   left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateUpdated)
--                       where Outcome = @lc_declined
--                       and   pers.AdviserUID = @AdviserUID
--					   and   adh.PersonID is null
--                       and   TypeID  = @lc_review_event
--					   and   isnull(even.IsCancelled,0) = 0
--                       and   isnull(even.IsDeleted,0)   = 0
--                       and    even.DateUpdated >= DATEADD(year,-1,GETDATE())
--                       and    exists (select 1
--                                      from   prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even1
--                                      where  even.PersonID = even1.PersonID
--                                      and    even1.Outcome is null 
--									  and    even1.TypeID  = 2
--									  and    isnull(even1.IsCancelled,0) = 0
--									  and    isnull(even1.IsDeleted,0) = 0
--                                      and    even1.EventReminderStatusID in (1,2,3))
--                          group by pers.AdviserUid
--)	
,CTE_DeclinedEvents as (
select
even.PersonID
,even.DateDue
,year(even.DateDue) as EventDueYear
,even.Details
,even.DateCompleted
,even.CompletedBy
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
from dbo.mi_concert_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateDue)
where outcome = 3
and adh.PersonID is null
and TypeID = 2),

CTE_ClientDeclines as (
Select
PersonID,
sum(case when DateDue  >= dateadd(year,-4,getdate()) and DateDue < dateadd(year,-3,getdate()) then 1 else 0 end) as EventDeclined3YearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-3,getdate()) and DateDue < dateadd(year,-2,getdate()) then 1 else 0 end) as EventDeclined2yearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-2,getdate()) and DateDue < dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedLastYear,  --Updated SI 27.2.17
sum(case when DateDue >= dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedCurrentYear, --Updated SI 27.2.17
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
From CTE_DeclinedEvents de
join mi_insight_UserHierarchy uh on uh.UserUID = de.AdviserUID
--where (uh.AQMUID = @AQMUID or @AQMUID = 'View All') and uh.ADUID != '4005013'
Group by
PersonID,
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
),

cte_OGS_declined AS (
Select
LastName [EventsDeclined],
AdviserUID
from CTE_ClientDeclines cd
where AdviserUID = @AdviserUID
Group by
BusinessUid
,FirmName
,AdviserUID
,AdviserName
,FirstName
,LastName,
AQMName,
BQMName
,case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end
,case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end 
,case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end
,case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end
having Sum ((case when EventDeclinedCurrentYear >= 1 then 1 else 0 end)+
			(case when EventDeclinedLastYear >= 1 then 1 else 0 end)+
			(case when EventDeclined2yearsAgo >= 1 then 1 else 0 end)+
			(case when EventDeclined3YearsAgo >= 1 then 1 else 0 end)) >=2
)


SELECT distinct ogco.AdviserUID
        ,ogco.NoClientsServiced
        --,ogde.EventsDeclined
		,count(ogde.EventsDeclined) [EventsDeclined]
  --      ,ogch.CaseReference
  --      ,ogch.ClientName
        ,sum( case when ogch.CaseReference is not null then 1 else 0 end )as OGS_CHK_Status
  FROM   cte_OGS_count ogco
  LEFT JOIN   cte_OGS_chk   ogch on ogch.AdviserUID = ogco.AdviserUID 					   
  LEFT JOIN   cte_OGS_declined ogde on ogde.AdviserUid = ogco.AdviserUid 					   
  group by ogco.AdviserUID
          ,ogco.NoClientsServiced
          ,ogde.EventsDeclined
      --    ,ogch.CaseReference
      --    ,ogch.ClientName
        order by AdviserUID;                             
                          
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_ogs_chk_Backup20241410_PFR]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE  PROCEDURE [logi].[pr_Ringo_ogs_chk_Backup20241410_PFR]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on

/**********************************************************************************************
Name  : [logi].[pr_Ringo_ogs_chk]
Author      : T Cummings
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Adviser Level OGs Chk" and 
              is found on the "BQM MI" menu. This report displays: 
              - Details of clients under servicing



      The security groups associated with is report are:
      1) 
      2)  

      Execute as follows:
      exec [logi].[pr_Ringo_ogs_chk] '1001872','ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
25-5-18		S Inglis		  Updated to include Adhoc Reviews
27-6-19		S Inglis		  Updated to take into account change to table in Warehouse where nulls
							  are now 0
28-7-20		S Hale			  Corrected Code_CodeType from 9 to 785
14-9-20		S Inglis		  Amended query to replace prefixes to link to Event ID
11-12-20	S Inglis		  Additional changes to where clause to amend nulls which are now 0
21-12-21    S Tourlidas		  Addressing an issue with OGS suffixing the cases with a C when the case
							  is from concert which resulted to not mapping to the event id in OWS
04/04/2022	A Groves		1) Replaced the OWS Events table with the new merged event table
								that combines Concert Hub and OWS events.
							2) Added a join to column OriginalOWSEventID to handle where a D365 
								case check has been keyed into Insight with the OWS reference.
05/04/2022	S Campbell		  Use dbo.mi_concert_ows_Event
31/05/2024  K Garcia          Added new PROD_ShortName of OAW and OAS to be included
12/06/2024  S Hale			  Further updates for new OAW and OAS product types
30/09/2024  R251929     P Reed- Replace the Merged Event table: dbo.mi_concert_ows_Event with view that excludes OWS outstanding (1,2,3) events (concert1234_ows4_event

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'RingoAdviserBQMMI';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @AdviserUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

select
even.PersonID
,year(even.DateDue) as EventDueYear
into #AdhocReviews
from Events.sa_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
----join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
----join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where even.EventReminderStatusID = 4
and TypeID = 8;

DECLARE @lc_report_event     int,
        @lc_late_status      int,
        @lc_due_status       int,
        @lc_scheduled_status int,
        @lc_review_event     int,
        @lc_declined         int;

SET @lc_report_event      = 1;
SET @lc_late_status       = 1;
SET @lc_due_status        = 2;
SET @lc_scheduled_status  = 3;
SET @lc_review_event      = 2;
SET @lc_declined          = 3;

with cte_OGS_chk as(select distinct saca.CASE_CaseReference as CaseReference
		  ,CaseStatus.Code_Description as OGS_CHK_Status
		  ,miuh.UserUID AS AdviserUID
		  ,miuh.UserName AS Adviser
		  ,pers.FirstName + ' ' + pers.LastName as ClientName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN dbo.mi_insight_UserHierarchy miuh ON  saca.CASE_AdviserID = miuh.UserGUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status -- updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even 
				on	case when even.EventID like 'SE%' 
						then case when substring(even.EventID,3,200) not like '%[^0-9]%' then cast(substring(even.EventID,3,200) as int) else -1 end 
						else case when even.EventID not like '%[^0-9]%' then cast(even.EventID as int) else -1 end 
					end
					= 
					case when replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'  --updated 12/6/24 SH
						then cast(replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even2 
				on	even2.OriginalOWSEventID 
					= 
					case when replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = coalesce(even.PersonID,even2.PersonID)
																   and pers.BusinessUid = miuh.BusinessUID

	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	AND   miuh.UserUID = @AdviserUID
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS','OAW','OAS')  -- omitted XOGS as that is to do with a pre-check
	and   CFQ.CFQ_QuestionCode = 1648  -- updated 12/6/24 SH
	and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --,769,767,768) Not checked, Adviser Own, NPW   --added 12/6/2024 SH
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ))
, cte_OGS_count	as (SELECT  pers.AdviserUID, 
                            COUNT(*) as NoClientsServiced
  FROM prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
  where even.TypeID in (@lc_report_event)
  and   isnull(even.IsCancelled,0) = 0
  and   pers.AdviserUID = @AdviserUID
  and   isnull(even.IsDeleted,0)   = 0
  and   even.EventReminderStatusID in (@lc_late_status,@lc_due_status,@lc_scheduled_status)
  group by pers.AdviserUID
)
--, cte_OGS_declined as (Select pers.AdviserUID
--                             ,count(distinct even.PersonID) as ClientsDecliningEvents
--                             ,count(*) as EventsDeclined	
--                       FROM  prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
--                       join  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
--					   left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateUpdated)
--                       where Outcome = @lc_declined
--                       and   pers.AdviserUID = @AdviserUID
--					   and   adh.PersonID is null
--                       and   TypeID  = @lc_review_event
--					   and   isnull(even.IsCancelled,0) = 0
--                       and   isnull(even.IsDeleted,0)   = 0
--                       and    even.DateUpdated >= DATEADD(year,-1,GETDATE())
--                       and    exists (select 1
--                                      from   prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even1
--                                      where  even.PersonID = even1.PersonID
--                                      and    even1.Outcome is null 
--									  and    even1.TypeID  = 2
--									  and    isnull(even1.IsCancelled,0) = 0
--									  and    isnull(even1.IsDeleted,0) = 0
--                                      and    even1.EventReminderStatusID in (1,2,3))
--                          group by pers.AdviserUid
--)	
,CTE_DeclinedEvents as (
select
even.PersonID
,even.DateDue
,year(even.DateDue) as EventDueYear
,even.Details
,even.DateCompleted
,even.CompletedBy
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
from dbo.concert1234_ows4_event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateDue)
where outcome = 3
and adh.PersonID is null
and TypeID = 2),

CTE_ClientDeclines as (
Select
PersonID,
sum(case when DateDue  >= dateadd(year,-4,getdate()) and DateDue < dateadd(year,-3,getdate()) then 1 else 0 end) as EventDeclined3YearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-3,getdate()) and DateDue < dateadd(year,-2,getdate()) then 1 else 0 end) as EventDeclined2yearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-2,getdate()) and DateDue < dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedLastYear,  --Updated SI 27.2.17
sum(case when DateDue >= dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedCurrentYear, --Updated SI 27.2.17
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
From CTE_DeclinedEvents de
join mi_insight_UserHierarchy uh on uh.UserUID = de.AdviserUID
--where (uh.AQMUID = @AQMUID or @AQMUID = 'View All') and uh.ADUID != '4005013'
Group by
PersonID,
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
),

cte_OGS_declined AS (
Select
LastName [EventsDeclined],
AdviserUID
from CTE_ClientDeclines cd
where AdviserUID = @AdviserUID
Group by
BusinessUid
,FirmName
,AdviserUID
,AdviserName
,FirstName
,LastName,
AQMName,
BQMName
,case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end
,case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end 
,case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end
,case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end
having Sum ((case when EventDeclinedCurrentYear >= 1 then 1 else 0 end)+
			(case when EventDeclinedLastYear >= 1 then 1 else 0 end)+
			(case when EventDeclined2yearsAgo >= 1 then 1 else 0 end)+
			(case when EventDeclined3YearsAgo >= 1 then 1 else 0 end)) >=2
)


SELECT distinct ogco.AdviserUID
        ,ogco.NoClientsServiced
        --,ogde.EventsDeclined
		,count(ogde.EventsDeclined) [EventsDeclined]
  --      ,ogch.CaseReference
  --      ,ogch.ClientName
        ,sum( case when ogch.CaseReference is not null then 1 else 0 end )as OGS_CHK_Status
  FROM   cte_OGS_count ogco
  LEFT JOIN   cte_OGS_chk   ogch on ogch.AdviserUID = ogco.AdviserUID 					   
  LEFT JOIN   cte_OGS_declined ogde on ogde.AdviserUid = ogco.AdviserUid 					   
  group by ogco.AdviserUID
          ,ogco.NoClientsServiced
          ,ogde.EventsDeclined
      --    ,ogch.CaseReference
      --    ,ogch.ClientName
        order by AdviserUID;                             
                          
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_ogs_chk_Backup20241410_pfr2]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE  PROCEDURE [logi].[pr_Ringo_ogs_chk_Backup20241410_pfr2]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on

/**********************************************************************************************
Name  : [logi].[pr_Ringo_ogs_chk]
Author      : T Cummings
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Adviser Level OGs Chk" and 
              is found on the "BQM MI" menu. This report displays: 
              - Details of clients under servicing



      The security groups associated with is report are:
      1) 
      2)  

      Execute as follows:
      exec [logi].[pr_Ringo_ogs_chk] '1001872','ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
25-5-18		S Inglis		  Updated to include Adhoc Reviews
27-6-19		S Inglis		  Updated to take into account change to table in Warehouse where nulls
							  are now 0
28-7-20		S Hale			  Corrected Code_CodeType from 9 to 785
14-9-20		S Inglis		  Amended query to replace prefixes to link to Event ID
11-12-20	S Inglis		  Additional changes to where clause to amend nulls which are now 0
21-12-21    S Tourlidas		  Addressing an issue with OGS suffixing the cases with a C when the case
							  is from concert which resulted to not mapping to the event id in OWS
04/04/2022	A Groves		1) Replaced the OWS Events table with the new merged event table
								that combines Concert Hub and OWS events.
							2) Added a join to column OriginalOWSEventID to handle where a D365 
								case check has been keyed into Insight with the OWS reference.
05/04/2022	S Campbell		  Use dbo.mi_concert_ows_Event
31/05/2024  K Garcia          Added new PROD_ShortName of OAW and OAS to be included
12/06/2024  S Hale			  Further updates for new OAW and OAS product types
30/09/2024  R251929     P Reed- Replace the Merged Event table: dbo.mi_concert_ows_Event with view that excludes OWS outstanding (1,2,3) events (concert1234_ows4_event

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'RingoAdviserBQMMI';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @AdviserUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

select
even.PersonID
,year(even.DateDue) as EventDueYear
into #AdhocReviews
from --Events.sa_ows_Event even 14102024
prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
----join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
----join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where even.EventReminderStatusID = 4
and TypeID = 8;

DECLARE @lc_report_event     int,
        @lc_late_status      int,
        @lc_due_status       int,
        @lc_scheduled_status int,
        @lc_review_event     int,
        @lc_declined         int;

SET @lc_report_event      = 1;
SET @lc_late_status       = 1;
SET @lc_due_status        = 2;
SET @lc_scheduled_status  = 3;
SET @lc_review_event      = 2;
SET @lc_declined          = 3;

with cte_OGS_chk as(select distinct saca.CASE_CaseReference as CaseReference
		  ,CaseStatus.Code_Description as OGS_CHK_Status
		  ,miuh.UserUID AS AdviserUID
		  ,miuh.UserName AS Adviser
		  ,pers.FirstName + ' ' + pers.LastName as ClientName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN dbo.mi_insight_UserHierarchy miuh ON  saca.CASE_AdviserID = miuh.UserGUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status -- updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even 
				on	case when even.EventID like 'SE%' 
						then case when substring(even.EventID,3,200) not like '%[^0-9]%' then cast(substring(even.EventID,3,200) as int) else -1 end 
						else case when even.EventID not like '%[^0-9]%' then cast(even.EventID as int) else -1 end 
					end
					= 
					case when replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'  --updated 12/6/24 SH
						then cast(replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even2 
				on	even2.OriginalOWSEventID 
					= 
					case when replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = coalesce(even.PersonID,even2.PersonID)
																   and pers.BusinessUid = miuh.BusinessUID

	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	AND   miuh.UserUID = @AdviserUID
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS','OAW','OAS')  -- omitted XOGS as that is to do with a pre-check
	and   CFQ.CFQ_QuestionCode = 1648  -- updated 12/6/24 SH
	and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --,769,767,768) Not checked, Adviser Own, NPW   --added 12/6/2024 SH
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ))
, cte_OGS_count	as (SELECT  pers.AdviserUID, 
                            COUNT(*) as NoClientsServiced
  FROM --prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even 141024
  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
  where even.TypeID in (@lc_report_event)
  and   isnull(even.IsCancelled,0) = 0
  and   pers.AdviserUID = @AdviserUID
  and   isnull(even.IsDeleted,0)   = 0
  and   even.EventReminderStatusID in (@lc_late_status,@lc_due_status,@lc_scheduled_status)
  group by pers.AdviserUID
)
--, cte_OGS_declined as (Select pers.AdviserUID
--                             ,count(distinct even.PersonID) as ClientsDecliningEvents
--                             ,count(*) as EventsDeclined	
--                       FROM  prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
--                       join  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
--					   left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateUpdated)
--                       where Outcome = @lc_declined
--                       and   pers.AdviserUID = @AdviserUID
--					   and   adh.PersonID is null
--                       and   TypeID  = @lc_review_event
--					   and   isnull(even.IsCancelled,0) = 0
--                       and   isnull(even.IsDeleted,0)   = 0
--                       and    even.DateUpdated >= DATEADD(year,-1,GETDATE())
--                       and    exists (select 1
--                                      from   prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even1
--                                      where  even.PersonID = even1.PersonID
--                                      and    even1.Outcome is null 
--									  and    even1.TypeID  = 2
--									  and    isnull(even1.IsCancelled,0) = 0
--									  and    isnull(even1.IsDeleted,0) = 0
--                                      and    even1.EventReminderStatusID in (1,2,3))
--                          group by pers.AdviserUid
--)	
,CTE_DeclinedEvents as (
select
even.PersonID
,even.DateDue
,year(even.DateDue) as EventDueYear
,even.Details
,even.DateCompleted
,even.CompletedBy
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
from dbo.concert1234_ows4_event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateDue)
where outcome = 3
and adh.PersonID is null
and TypeID = 2),

CTE_ClientDeclines as (
Select
PersonID,
sum(case when DateDue  >= dateadd(year,-4,getdate()) and DateDue < dateadd(year,-3,getdate()) then 1 else 0 end) as EventDeclined3YearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-3,getdate()) and DateDue < dateadd(year,-2,getdate()) then 1 else 0 end) as EventDeclined2yearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-2,getdate()) and DateDue < dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedLastYear,  --Updated SI 27.2.17
sum(case when DateDue >= dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedCurrentYear, --Updated SI 27.2.17
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
From CTE_DeclinedEvents de
join mi_insight_UserHierarchy uh on uh.UserUID = de.AdviserUID
--where (uh.AQMUID = @AQMUID or @AQMUID = 'View All') and uh.ADUID != '4005013'
Group by
PersonID,
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
),

cte_OGS_declined AS (
Select
LastName [EventsDeclined],
AdviserUID
from CTE_ClientDeclines cd
where AdviserUID = @AdviserUID
Group by
BusinessUid
,FirmName
,AdviserUID
,AdviserName
,FirstName
,LastName,
AQMName,
BQMName
,case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end
,case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end 
,case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end
,case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end
having Sum ((case when EventDeclinedCurrentYear >= 1 then 1 else 0 end)+
			(case when EventDeclinedLastYear >= 1 then 1 else 0 end)+
			(case when EventDeclined2yearsAgo >= 1 then 1 else 0 end)+
			(case when EventDeclined3YearsAgo >= 1 then 1 else 0 end)) >=2
)


SELECT distinct ogco.AdviserUID
        ,ogco.NoClientsServiced
        --,ogde.EventsDeclined
		,count(ogde.EventsDeclined) [EventsDeclined]
  --      ,ogch.CaseReference
  --      ,ogch.ClientName
        ,sum( case when ogch.CaseReference is not null then 1 else 0 end )as OGS_CHK_Status
  FROM   cte_OGS_count ogco
  LEFT JOIN   cte_OGS_chk   ogch on ogch.AdviserUID = ogco.AdviserUID 					   
  LEFT JOIN   cte_OGS_declined ogde on ogde.AdviserUid = ogco.AdviserUid 					   
  group by ogco.AdviserUID
          ,ogco.NoClientsServiced
          ,ogde.EventsDeclined
      --    ,ogch.CaseReference
      --    ,ogch.ClientName
        order by AdviserUID;                             
                          
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_ogs_chk_BACKUP20241510pfr_v2]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE  PROCEDURE [logi].[pr_Ringo_ogs_chk_BACKUP20241510pfr_v2]
                @AdviserUID      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on

/**********************************************************************************************
Name  : [logi].[pr_Ringo_ogs_chk]
Author      : T Cummings
Date  : 14/03/2016

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Adviser Level OGs Chk" and 
              is found on the "BQM MI" menu. This report displays: 
              - Details of clients under servicing



      The security groups associated with is report are:
      1) 
      2)  

      Execute as follows:
      exec [logi].[pr_Ringo_ogs_chk] '1001872','ptl91371'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
25-5-18		S Inglis		  Updated to include Adhoc Reviews
27-6-19		S Inglis		  Updated to take into account change to table in Warehouse where nulls
							  are now 0
28-7-20		S Hale			  Corrected Code_CodeType from 9 to 785
14-9-20		S Inglis		  Amended query to replace prefixes to link to Event ID
11-12-20	S Inglis		  Additional changes to where clause to amend nulls which are now 0
21-12-21    S Tourlidas		  Addressing an issue with OGS suffixing the cases with a C when the case
							  is from concert which resulted to not mapping to the event id in OWS
04/04/2022	A Groves		1) Replaced the OWS Events table with the new merged event table
								that combines Concert Hub and OWS events.
							2) Added a join to column OriginalOWSEventID to handle where a D365 
								case check has been keyed into Insight with the OWS reference.
05/04/2022	S Campbell		  Use dbo.mi_concert_ows_Event
31/05/2024  K Garcia          Added new PROD_ShortName of OAW and OAS to be included
12/06/2024  S Hale			  Further updates for new OAW and OAS product types
30/09/2024  R251929     P Reed- Replace the Merged Event table: dbo.mi_concert_ows_Event with view that excludes OWS outstanding (1,2,3) events (concert1234_ows4_event

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'RingoAdviserBQMMI';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @AdviserUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

select
even.PersonID
,year(even.DateDue) as EventDueYear
into #AdhocReviews
from Events.sa_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
----join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
----join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where even.EventReminderStatusID = 4
and TypeID = 8;

DECLARE @lc_report_event     int,
        @lc_late_status      int,
        @lc_due_status       int,
        @lc_scheduled_status int,
        @lc_review_event     int,
        @lc_declined         int;

SET @lc_report_event      = 1;
SET @lc_late_status       = 1;
SET @lc_due_status        = 2;
SET @lc_scheduled_status  = 3;
SET @lc_review_event      = 2;
SET @lc_declined          = 3;

with cte_OGS_chk as(select distinct saca.CASE_CaseReference as CaseReference
		  ,CaseStatus.Code_Description as OGS_CHK_Status
		  ,miuh.UserUID AS AdviserUID
		  ,miuh.UserName AS Adviser
		  ,pers.FirstName + ' ' + pers.LastName as ClientName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN dbo.mi_insight_UserHierarchy miuh ON  saca.CASE_AdviserID = miuh.UserGUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status -- updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even 
				on	case when even.EventID like 'SE%' 
						then case when substring(even.EventID,3,200) not like '%[^0-9]%' then cast(substring(even.EventID,3,200) as int) else -1 end 
						else case when even.EventID not like '%[^0-9]%' then cast(even.EventID as int) else -1 end 
					end
					= 
					case when replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'  --updated 12/6/24 SH
						then cast(replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even2 
				on	even2.OriginalOWSEventID 
					= 
					case when replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = coalesce(even.PersonID,even2.PersonID)
																   and pers.BusinessUid = miuh.BusinessUID

	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	AND   miuh.UserUID = @AdviserUID
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS','OAW','OAS')  -- omitted XOGS as that is to do with a pre-check
	and   CFQ.CFQ_QuestionCode = 1648  -- updated 12/6/24 SH
	and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --,769,767,768) Not checked, Adviser Own, NPW   --added 12/6/2024 SH
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ))
, cte_OGS_count	as (SELECT  pers.AdviserUID, 
                            COUNT(*) as NoClientsServiced
  FROM prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
  JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
  where even.TypeID in (@lc_report_event)
  and   isnull(even.IsCancelled,0) = 0
  and   pers.AdviserUID = @AdviserUID
  and   isnull(even.IsDeleted,0)   = 0
  and   even.EventReminderStatusID in (@lc_late_status,@lc_due_status,@lc_scheduled_status)
  group by pers.AdviserUID
)
--, cte_OGS_declined as (Select pers.AdviserUID
--                             ,count(distinct even.PersonID) as ClientsDecliningEvents
--                             ,count(*) as EventsDeclined	
--                       FROM  prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even
--                       join  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID = even.PersonID
--					   left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateUpdated)
--                       where Outcome = @lc_declined
--                       and   pers.AdviserUID = @AdviserUID
--					   and   adh.PersonID is null
--                       and   TypeID  = @lc_review_event
--					   and   isnull(even.IsCancelled,0) = 0
--                       and   isnull(even.IsDeleted,0)   = 0
--                       and    even.DateUpdated >= DATEADD(year,-1,GETDATE())
--                       and    exists (select 1
--                                      from   prod_zurich_openwork_datawarehouse.Events.sa_ows_Event even1
--                                      where  even.PersonID = even1.PersonID
--                                      and    even1.Outcome is null 
--									  and    even1.TypeID  = 2
--									  and    isnull(even1.IsCancelled,0) = 0
--									  and    isnull(even1.IsDeleted,0) = 0
--                                      and    even1.EventReminderStatusID in (1,2,3))
--                          group by pers.AdviserUid
--)	
,CTE_DeclinedEvents as (
select
even.PersonID
,even.DateDue
,year(even.DateDue) as EventDueYear
,even.Details
,even.DateCompleted
,even.CompletedBy
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
from dbo.concert1234_ows4_event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateDue)
where outcome = 3
and adh.PersonID is null
and TypeID = 2),

CTE_ClientDeclines as (
Select
PersonID,
sum(case when DateDue  >= dateadd(year,-4,getdate()) and DateDue < dateadd(year,-3,getdate()) then 1 else 0 end) as EventDeclined3YearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-3,getdate()) and DateDue < dateadd(year,-2,getdate()) then 1 else 0 end) as EventDeclined2yearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-2,getdate()) and DateDue < dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedLastYear,  --Updated SI 27.2.17
sum(case when DateDue >= dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedCurrentYear, --Updated SI 27.2.17
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
From CTE_DeclinedEvents de
join mi_insight_UserHierarchy uh on uh.UserUID = de.AdviserUID
--where (uh.AQMUID = @AQMUID or @AQMUID = 'View All') and uh.ADUID != '4005013'
Group by
PersonID,
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName,
AQMName,
BQMName
),

cte_OGS_declined AS (
Select
LastName [EventsDeclined],
AdviserUID
from CTE_ClientDeclines cd
where AdviserUID = @AdviserUID
Group by
BusinessUid
,FirmName
,AdviserUID
,AdviserName
,FirstName
,LastName,
AQMName,
BQMName
,case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end
,case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end 
,case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end
,case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end
having Sum ((case when EventDeclinedCurrentYear >= 1 then 1 else 0 end)+
			(case when EventDeclinedLastYear >= 1 then 1 else 0 end)+
			(case when EventDeclined2yearsAgo >= 1 then 1 else 0 end)+
			(case when EventDeclined3YearsAgo >= 1 then 1 else 0 end)) >=2
)


SELECT distinct ogco.AdviserUID
        ,ogco.NoClientsServiced
        --,ogde.EventsDeclined
		,count(ogde.EventsDeclined) [EventsDeclined]
  --      ,ogch.CaseReference
  --      ,ogch.ClientName
        ,sum( case when ogch.CaseReference is not null then 1 else 0 end )as OGS_CHK_Status
  FROM   cte_OGS_count ogco
  LEFT JOIN   cte_OGS_chk   ogch on ogch.AdviserUID = ogco.AdviserUID 					   
  LEFT JOIN   cte_OGS_declined ogde on ogde.AdviserUid = ogco.AdviserUid 					   
  group by ogco.AdviserUID
          ,ogco.NoClientsServiced
          ,ogde.EventsDeclined
      --    ,ogch.CaseReference
      --    ,ogch.ClientName
        order by AdviserUID;                             
                          
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_ogs_chk_FirmLevelDetails]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE  PROCEDURE [logi].[pr_Ringo_ogs_chk_FirmLevelDetails]
                @PtlCode      varchar(10)
               ,@FirmUID      varchar(7)


AS BEGIN
set nocount on

/**********************************************************************************************

AMENDMENT HISTORY
=================
Date        Author          Description
----        ------          -----------
28-07-2020	S Hale			Corrected Code_CodeType from 9 to 785
06-10-2020	S Inglis		Amended query to replace prefixes to link to Event ID			
06-10-2020	S Inglis		Amended query to replace "C" to link to Event ID			
22-03-2022	A Groves		Re-factored double query with union back to single query
							following the introduction of the new merged event table
							that combines Concert Hub and OWS events.
24-03-2022	A Groves		Added join to column OriginalOWSEventID to handle where a D365 
							case check has been keyed into Insight with the OWS reference.
05-04-2022	S Campbell		Use dbo.mi_concert_ows_Event
13/06/2024	S Hale			Update for OAS and OAW
30/09/2024  R251929     P Reed- Replace the Merged Event table: dbo.mi_concert_ows_Event with view that excludes OWS outstanding (1,2,3) events (concert1234_ows4_event)

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'RingoAdviserBQMMI';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + @FirmUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

DECLARE @lc_report_event     int,
        @lc_late_status      int,
        @lc_due_status       int,
        @lc_scheduled_status int;
SET @lc_report_event      = 1;
SET @lc_late_status       = 1;
SET @lc_due_status        = 2;
SET @lc_scheduled_status  = 3;

select distinct saca.CASE_CaseReference as CaseReference
		       ,CaseStatus.Code_Description as OGS_CHK_Status
		       ,pers.FirstName + ' ' + pers.LastName as ClientName
		       ,miuh.UserUID
		       ,miuh.UserName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN dbo.mi_insight_UserHierarchy miuh ON  saca.CASE_AdviserID = miuh.UserGUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status -- updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even 
				on	case when even.EventID like 'SE%' 
						then case when substring(even.EventID,3,200) not like '%[^0-9]%' then cast(substring(even.EventID,3,200) as int) else -1 end 
						else case when even.EventID not like '%[^0-9]%' then cast(even.EventID as int) else -1 end 
					end
					= 
					case when replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'  --updated 13/6/24 SH
						then cast(replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even2 
				on	even2.OriginalOWSEventID 
					= 
					case when replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = coalesce(even.PersonID,even2.PersonID)
																   and pers.BusinessUid = miuh.BusinessUID
	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	AND   miuh.BusinessUID = @FirmUID
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS','OAS','OAW')    --updated 13/6/24 SH
	and   CFQ.CFQ_QuestionCode = 1648  --updated 13/6/24 SH
	and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --,769,767,768) Not checked, Adviser Own, NPW   --added 13/6/2024 SH
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) ;                            
                          
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_ogs_chk_FirmLevelDetails_BACKUP_30092024_PFR]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE  PROCEDURE [logi].[pr_Ringo_ogs_chk_FirmLevelDetails_BACKUP_30092024_PFR]
                @PtlCode      varchar(10)
               ,@FirmUID      varchar(7)


AS BEGIN
set nocount on

/**********************************************************************************************

AMENDMENT HISTORY
=================
Date        Author          Description
----        ------          -----------
28-07-2020	S Hale			Corrected Code_CodeType from 9 to 785
06-10-2020	S Inglis		Amended query to replace prefixes to link to Event ID			
06-10-2020	S Inglis		Amended query to replace "C" to link to Event ID			
22-03-2022	A Groves		Re-factored double query with union back to single query
							following the introduction of the new merged event table
							that combines Concert Hub and OWS events.
24-03-2022	A Groves		Added join to column OriginalOWSEventID to handle where a D365 
							case check has been keyed into Insight with the OWS reference.
05-04-2022	S Campbell		Use dbo.mi_concert_ows_Event
13/06/2024	S Hale			Update for OAS and OAW

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'RingoAdviserBQMMI';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + @FirmUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

DECLARE @lc_report_event     int,
        @lc_late_status      int,
        @lc_due_status       int,
        @lc_scheduled_status int;
SET @lc_report_event      = 1;
SET @lc_late_status       = 1;
SET @lc_due_status        = 2;
SET @lc_scheduled_status  = 3;

select distinct saca.CASE_CaseReference as CaseReference
		       ,CaseStatus.Code_Description as OGS_CHK_Status
		       ,pers.FirstName + ' ' + pers.LastName as ClientName
		       ,miuh.UserUID
		       ,miuh.UserName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN dbo.mi_insight_UserHierarchy miuh ON  saca.CASE_AdviserID = miuh.UserGUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status -- updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.mi_concert_ows_Event even 
				on	case when even.EventID like 'SE%' 
						then case when substring(even.EventID,3,200) not like '%[^0-9]%' then cast(substring(even.EventID,3,200) as int) else -1 end 
						else case when even.EventID not like '%[^0-9]%' then cast(even.EventID as int) else -1 end 
					end
					= 
					case when replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'  --updated 13/6/24 SH
						then cast(replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.mi_concert_ows_Event even2 
				on	even2.OriginalOWSEventID 
					= 
					case when replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'OAS',''),'OAW',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = coalesce(even.PersonID,even2.PersonID)
																   and pers.BusinessUid = miuh.BusinessUID
	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	AND   miuh.BusinessUID = @FirmUID
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS','OAS','OAW')    --updated 13/6/24 SH
	and   CFQ.CFQ_QuestionCode = 1648  --updated 13/6/24 SH
	and   bqre.BQR_Code in (400,752,753,755,756,757,350,351,352,361,362)  --,769,767,768) Not checked, Adviser Own, NPW   --added 13/6/2024 SH
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) ;                            
                          
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
