CREATE PROCEDURE [logi].[pr_Ringo_ogs_chk_FirmLevelDetails_Backup20240614SH]
                @PtlCode      varchar(10)
               ,@FirmUID      varchar(7)


AS BEGIN
set nocount on

/**********************************************************************************************

AMENDMENT HISTORY
=================
Date        Author          Description
----        ------          -----------
28-07-2020	S Hale			Corrected Code_CodeType from 9 to 785
06-10-2020	S Inglis		Amended query to replace prefixes to link to Event ID			
06-10-2020	S Inglis		Amended query to replace "C" to link to Event ID			
22-03-2022	A Groves		Re-factored double query with union back to single query
							following the introduction of the new merged event table
							that combines Concert Hub and OWS events.
24-03-2022	A Groves		Added join to column OriginalOWSEventID to handle where a D365 
							case check has been keyed into Insight with the OWS reference.
05-04-2022	S Campbell		Use dbo.mi_concert_ows_Event
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'RingoAdviserBQMMI';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@FirmUID = ' + @FirmUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @FirmUID

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

DECLARE @lc_report_event     int,
        @lc_late_status      int,
        @lc_due_status       int,
        @lc_scheduled_status int;
SET @lc_report_event      = 1;
SET @lc_late_status       = 1;
SET @lc_due_status        = 2;
SET @lc_scheduled_status  = 3;

select distinct saca.CASE_CaseReference as CaseReference
		       ,CaseStatus.Code_Description as OGS_CHK_Status
		       ,pers.FirstName + ' ' + pers.LastName as ClientName
		       ,miuh.UserUID
		       ,miuh.UserName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN dbo.mi_insight_UserHierarchy miuh ON  saca.CASE_AdviserID = miuh.UserGUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status -- updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.mi_concert_ows_Event even 
				on	case when even.EventID like 'SE%' 
						then case when substring(even.EventID,3,200) not like '%[^0-9]%' then cast(substring(even.EventID,3,200) as int) else -1 end 
						else case when even.EventID not like '%[^0-9]%' then cast(even.EventID as int) else -1 end 
					end
					= 
					case when replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.mi_concert_ows_Event even2 
				on	even2.OriginalOWSEventID 
					= 
					case when replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = coalesce(even.PersonID,even2.PersonID)
																   and pers.BusinessUid = miuh.BusinessUID
	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	AND   miuh.BusinessUID = @FirmUID
	AND   saca.CASE_CaseReference     like 'OGS%'
	AND   saca.CASE_CaseReference not like 'OGS%x' 
	AND   saca.CASE_CaseReference not like 'OGS%X'
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS') -- omitted XOGS as that is to do with a pre-check
	and   CFQ.CFQ_QuestionCode between 2001 and 3000
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) ;                            
                          
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_Replacements]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
14/06/2016	A Groves	Temporary hardcoded access for JMD supervisors (one level up):
						Antony Lark, Duncan Jones and Philip Potter.
12/09/2016	A Groves	SR449740. "@EnhancedPAAccess" parameter added to 
						"logi.pr_Ringo_UserSecurity" to give supervisor access to PAs
						in configured enterprises.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.
25/04/2017	A Groves	SR473819. Removed JMD hardcoding to give Tommy Taylor supervisor 
						of supervisor (SOS) access to supervisor Emma Bremer's advisers.
04/05/2017	A Groves	GHL and First Affinity supervisors are not linked to the same
						enterprise as those they supervise, so this restriction removed.
*******************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_Replacements]
                @AdviserUid      varchar(7)
               ,@PtlCode      varchar(10)


AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;
DECLARE			  @lc_EnhancedPAAccess			 int;			--AG 12/09/2016
DECLARE			  @lc_UserBusinessUID			 varchar(7);	--AG 13/09/2016

set @ReportName               = 'pr_Ringo_AdviserSalesTotal';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + @AdviserUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
                                                   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 12/09/2016
                                                   @UserBusinessUID=@lc_UserBusinessUID OUTPUT		--AG 13/09/2016

/*****************************************
SR473819. AG 25/04/2017. Removed JMD hardcoding                                                  
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh 
--where @lc_UserUid = uh.SupervisorUID 
where ((@lc_UserUid = uh.SupervisorUID)
		or (@lc_EnhancedPAAccess = 1 and @lc_UserBusinessUID = uh.BusinessUID)		--AG 12/09/2016 & 13/09/2016
		or (@lc_UserUid in ('4007621','4007612','4007578') and uh.BusinessUID = '2005309')	--4007578=Elizabeth Yates; 4007612=Paul Coggins; 4007621=Antony Lark	AG 12/09/2016
		or (@lc_UserUid = '4007621' and uh.SupervisorUID in ('4007597','4007601'))	--407621=Antony Lark; 4007597=Tommy Taylor; 4007601=Scott Sander
		or (@lc_UserUid = '4007616' and uh.SupervisorUID in ('4007591','4007600','4007603','4007617','4007618','4007627'))	--4007616=Duncan Jones; 4007591=John Doughty; 4007600=Laura Pointer; 4007603=Gareth Lowndes; 4007617=Gary Hitchcock; 4007618=Darren Mead; 4007627=Peter Carter
		or (@lc_UserUid = '4007587' and uh.SupervisorUID in ('4007573','4007574','4007585','4007586','4008007')))	--4007587=Philip Potter; 4007573=Paul McGrath; 4007574=Andrew Lake; 4007585=Andrew Johnson; 4007586=William Murphy-Brown; 4008007=Annette Billard
and uh.UserUID = @AdviserUID
******************************************/

select	@LC_SupervisorPermission = 1 
from	mi_insight_UserHierarchy uh 
where	uh.UserUID = @AdviserUID				--The adviser being reported
and		((@lc_EnhancedPAAccess = 1 and uh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this adviser	AG 04/05/2017
or		(@lc_UserUid in (uh.SupervisorUID,uh.SupervisorUID2,uh.SupervisorUID3,uh.SupervisorUID4,uh.SupervisorUID5,uh.SupervisorUID6)))	--supervises this adviser or supervisor of supervisor (SOS)

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

with cte_cicrep as (select	miuh.UserUID as AdviserUID,
            miuh.BusinessUID,
            bpol.BPOL_BackOfficeID,
            MAX(attlcic.ATTL_AttributeValue) as IsCIC, 
            max(attlrep.ATTL_AttributeValue) as IsReplacement
  from	    dbo.mi_insight_KPIPopulation pop
  join dbo.sa_insight_SalesCase sc on sc.CASE_AdviserID = pop.UserID
  JOIN dbo.mi_insight_UserHierarchy miuh ON  sc.CASE_AdviserID = miuh.UserGUID
  join dbo.sa_insight_BasicPolicy as bpol on bpol.BPOL_ParentID = sc.CASE_ID 
  join (select	distinct ProductType, RegulationCode
			from	dbo.mi_insight_ConfigProductTypeReplacement
			where   RegulationCode = 'ICOB'
			) RegGrp on RegGrp.ProductType = bpol.BPOL_ProductType
  join sa_insight_KPI kpi on kpi.KPI_Code = 'CICREP' 
                         and kpi.KPI_Type = 1	-- CIC Replacement & Adviser KPI
  join dbo.sa_insight_Attribute AS attrcic ON attrcic.ATT_Name = 'PRODUCT.RFC'
  JOIN dbo.sa_insight_AttributeLink AS attlcic ON attlcic.ATTL_ParentID = bpol.BPOL_ID 
                                              and attlcic.ATTL_AttributeID = attrcic.ATT_ID
  join dbo.sa_insight_Attribute AS attrrep ON attrrep.ATT_Name = 'CASE.REPLACEMENT'
  JOIN dbo.sa_insight_AttributeLink AS attlrep ON attlrep.ATTL_ParentID = sc.CASE_ID 
                                              and attlrep.ATTL_AttributeID = attrrep.ATT_ID
  WHERE	sc.CASE_SubmitDate	>= DATEADD(year,-1,GETDATE())
  and		RegGrp.RegulationCode = 'ICOB'			--A ICOB case
  and		ISNUMERIC(bpol.BPOL_BackOfficeID) = 1	--CaseID is valid
  and		bpol.BPOL_BackOfficeID <> '0'			--Unwanted DUPLICATE setting
  and		bpol.BPOL_ProductType <> 25				--Ignore DUPLICATEs
  and		pop.UserJobTitleCode in (4,42)			--4=Adviser;42=Schedule E Seller 
  and		pop.ICOBCompetencyCode = 3				--Fully Competent (ICOB/protection)
  and		patindex('%CICR,%',attlcic.ATTL_AttributeValue) > 0	--CICR replacement
  and       miuh.UserUID = @AdviserUID
  and       (attlrep.ATTL_AttributeValue in ('Yes','yes') or attlcic.ATTL_AttributeValue in ('Yes','yes'))
group	by sc.CASE_ID, bpol.BPOL_ID,bpol.BPOL_BackOfficeID,miuh.UserUID,miuh.BusinessUID)
,cte_cobrep as (select	miuh.UserUID as AdviserUID,
        miuh.BusinessUID,
        bpol.BPOL_BackOfficeID,
        MAX(attlsw.ATTL_AttributeValue) as IsSwitch, 
        max(attlrep.ATTL_AttributeValue) as IsReplacement
from	dbo.mi_insight_KPIPopulation pop
join dbo.sa_insight_SalesCase sc on sc.CASE_AdviserID = pop.UserID
JOIN dbo.mi_insight_UserHierarchy miuh ON  sc.CASE_AdviserID = miuh.UserGUID
join dbo.sa_insight_BasicPolicy as bpol on bpol.BPOL_ParentID = sc.CASE_ID 
join (select	distinct ProductType, RegulationCode
	  from	dbo.mi_insight_ConfigProductTypeReplacement
	  where   RegulationCode = 'COB') RegGrp on RegGrp.ProductType = bpol.BPOL_ProductType
join sa_insight_KPI kpi on kpi.KPI_Code = 'COBREP' and kpi.KPI_Type = 1	-- COB Replacement & Adviser KPI
left join dbo.sa_insight_Attribute AS attrsw ON attrsw.ATT_Name = 'PRODUCT.SWITCH'
left JOIN dbo.sa_insight_AttributeLink AS attlsw ON attlsw.ATTL_ParentID = bpol.BPOL_ID and attlsw.ATTL_AttributeID = attrsw.ATT_ID
left join dbo.sa_insight_Attribute AS attrrep ON attrrep.ATT_Name = 'CASE.REPLACEMENT'
left JOIN dbo.sa_insight_AttributeLink AS attlrep ON attlrep.ATTL_ParentID = sc.CASE_ID and attlrep.ATTL_AttributeID = attrrep.ATT_ID
WHERE	sc.CASE_SubmitDate	between DATEADD(year,-1,GETDATE())and		getdate()
and		RegGrp.RegulationCode = 'COB'			--A COB case
and		ISNUMERIC(bpol.BPOL_BackOfficeID) = 1	--CaseID is valid
and		bpol.BPOL_BackOfficeID <> '0'			--Unwanted DUPLICATE setting
and		bpol.BPOL_ProductType <> 25				--Ignore DUPLICATEs
and		pop.UserJobTitleCode in (4,42)			--4=Adviser;42=Schedule E Seller 
and		pop.COBCompetencyCode = 3				--Fully Competent
and     (attlrep.ATTL_AttributeValue in ('Yes','yes') or attlsw.ATTL_AttributeValue in ('Yes','yes'))
and     miuh.UserUID = @AdviserUID
group	by bpol.BPOL_BackOfficeID,miuh.UserUID,
        miuh.BusinessUID)
select cte_cicrep.AdviserUID
      ,'ICOB CIC' as ReplacementType 
      ,COUNT(*) as NoOfReplacements
from cte_cicrep
group by cte_cicrep.AdviserUID      
UNION
select cte_cobrep.AdviserUID
      ,'COB' as ReplacementType 
      ,COUNT(*)   as NoOfReplacements  
from    cte_cobrep
group by cte_cobrep.AdviserUID;

END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
