CREATE PROCEDURE [logi].[pr_Ringo_SupervisorClientDeclines]
                @PtlCode			varchar(10)
               ,@SupervisorUID	    varchar(7)
               ,@Span				varchar(20)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_Ringo_SupervisorClientDeclines]
Author      : S Inglis
Date  : 29/03/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Supervisor Client Declines" and is found on the "BQM MI" 
              menu. This report displays: 
              - Client Declines at Supervisor Deep and Shallow Span



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_Ringo_SupervisorClientDeclines]  'ptl91371', '1001871','Deep Span'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
10-4-17		S Inglis		  Addition of Supervisor
9-5-17		S Inglis		  Update to supervisor span code to include supervisors 2-6 as Deep
							  Span if uid exists in these fields	
25-5-18		S Inglis		  Updated to include Adhoc Reviews
19/10/2021	S Campbell		  OWS Decouple - Create copy in BI Schema 
							  Use BI.sa_d365_ows_Event table instead of Events.sa_ows_Event table 
26/10/2021	S Campbell		  Use BI.mi_concert_ows_Event
05/04/2022	S Campbell		  Use dbo.mi_concert_ows_Event
***********************************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'SupervisorSpanCPDHours';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + cast (@SupervisorUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

 SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
		, pop.BusinessUID
		, pop.BusinessName
		, pop.UserID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span --update 9.5.17

select
even.PersonID
,year(even.DateDue) as EventDueYear
into #AdhocReviews
from dbo.mi_concert_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
----join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
----join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
where even.EventReminderStatusID = 4
and TypeID = 8;

select
even.PersonID
,even.DateDue
,year(even.DateDue) as EventDueYear
,even.Details
,even.DateCompleted
,even.CompletedBy
,pers.FirstName
,pers.LastName
,pers.AdviserUID
,agt.DESCN as AdviserName
,pers.BusinessUid
,agt1.DESCN as FirmName
into #DeclinedEvents
from dbo.mi_concert_ows_Event even
join sa_ows_Person pers on pers.PersonID = even.PersonID
join sa_swift_S_AGENTS agt on agt.CODE = pers.AdviserUID
join sa_swift_S_AGENTS agt1 on agt1.CODE = pers.BusinessUid
left join #AdhocReviews adh on adh.PersonID = even.PersonID and adh.EventDueYear = year(even.DateDue)
where outcome = 3
and TypeID = 2
and adh.PersonID is null


Select
PersonID,
sum(case when DateDue  >= dateadd(year,-4,getdate()) and DateDue < dateadd(year,-3,getdate()) then 1 else 0 end) as EventDeclined3YearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-3,getdate()) and DateDue < dateadd(year,-2,getdate()) then 1 else 0 end) as EventDeclined2yearsAgo, --Updated SI 27.2.17
sum(case when DateDue  >= dateadd(year,-2,getdate()) and DateDue < dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedLastYear,  --Updated SI 27.2.17
sum(case when DateDue >= dateadd(year,-1,getdate()) then 1 else 0 end) as EventDeclinedCurrentYear, --Updated SI 27.2.17
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName
into #ClientDeclines
From #DeclinedEvents de
join #Span uh on uh.UserUID = de.AdviserUID
--where (uh.AQMUID = @AQMUID or @AQMUID = 'View All') and uh.ADUID != '4005013'
Group by
PersonID,
FirstName,
LastName,
AdviserUID,
AdviserName,
de.BusinessUid,
FirmName

Select
cd.BusinessUid
,FirmName as BusinessName
,uh.SupervisorName
,AdviserUID
,AdviserName
,FirstName
,LastName
--AQMName,
--BQMName
,case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end as 'ClientDeclinedCurrentYear'
,case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end as 'ClientDeclinedLastYear'
,case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end as 'ClientDeclined2YearsAgo'
,case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end as 'ClientDeclined3YearsAgo'
,Sum ((case when EventDeclinedCurrentYear >= 1 then 1 else 0 end)+
			(case when EventDeclinedLastYear >= 1 then 1 else 0 end)+
			(case when EventDeclined2yearsAgo >= 1 then 1 else 0 end)+
			(case when EventDeclined3YearsAgo >= 1 then 1 else 0 end)) as TwoOrMoreYrDec
from #ClientDeclines cd
join mi_insight_UserHierarchy uh on uh.UserUID = cd.AdviserUID
--where AdviserUID = @AdviserUID
Group by
cd.BusinessUid
,uh.SupervisorName
,FirmName
,AdviserUID
,AdviserName
,FirstName
,LastName
--AQMName,
--BQMName
,case when EventDeclinedCurrentYear >= 1 then 'Yes' else 'No' end
,case when EventDeclinedLastYear >= 1 then 'Yes' else 'No' end 
,case when EventDeclined2yearsAgo >= 1 then 'Yes' else 'No' end
,case when EventDeclined3YearsAgo >= 1 then 'Yes' else 'No' end
having Sum ((case when EventDeclinedCurrentYear >= 1 then 1 else 0 end)+
			(case when EventDeclinedLastYear >= 1 then 1 else 0 end)+
			(case when EventDeclined2yearsAgo >= 1 then 1 else 0 end)+
			(case when EventDeclined3YearsAgo >= 1 then 1 else 0 end)) >=2
  
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH



/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
