CREATE PROCEDURE [logi].[pr_ringo_SupervisorDataSP]
      @PtlCode		  varchar(255),
	  @AdviserUID	  varchar (7)

AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime; 
				  DECLARE @return_value int;
				DECLARE @lc_UserUid varchar(7);
				DECLARE @lc_UserName varchar(50);
				DECLARE @lc_UserJobTitleCodeHO int;
				DECLARE @lc_UserJobTitleCodePartner int;
				DECLARE @lc_UserJobTitleCodeSupervisor int;
				DECLARE @lc_UserJobTitleCodeBQM int;
				Declare @LC_SupervisorPermission int;

print 'setting parameters';
set @ReportName               = 'SupervisorDataSP';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + cast (@AdviserUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @AdviserUID
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin
WITH CTE_RA as
(SELECT
	   uh.UserUID
	  ,cd.Code_Description
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_RiskAssessment ra
  join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
  join mi_insight_UserHierarchy uh on uh.UserGUID = RA_USR_ID
  where RA_Date = (select max(risk.RA_Date) from sa_insight_RiskAssessment risk where risk.RA_USR_ID = ra.RA_USR_ID)
  and RA_USR_Type = 4
  ),

 CTE_CPD as
(SELECT   uh.UserUID
		,uh.UserName
	    ,sum(CPDL_Awarded)/60 as TotalCPDHours
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_CPDAwardLog cpdal
  join mi_insight_UserHierarchy uh on uh.UserGUID = cpdal.CPDL_UserID
  where 1=1
  and CPDL_Status = 1
  and CPDL_Category = 1
   and CPDL_PlannedDate between dateadd(year,-1,getdate()) and getdate()
  and uh.UserUID = @AdviserUID
  group by 
  CPDL_UserID,
  uh.UserUID
 ,uh.UserName
),

 CTE_RiskOverWritten as
  (select  
 distinct kpip.UserUID
,kpip.UserName
,cd1.Code_Description as OriginalRiskRating
,cd.Code_Description as UpdatedRiskRating
,uh1.UserName as RiskAssessmentUpdatedBy
,ra.RA_UpdatedDate
,uh.UserName as Supervisor
,uh.UserUID as SupervisorUID
from sa_insight_RiskAssessment ra
join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500
join sa_insight_CodeDescription cd1 on cd1.Code_Code = ra.RA_OriginalStatus and cd1.Code_CodeType = 500
join mi_insight_KPIPopulation kpip on kpip.UserID = RA_USR_ID
join mi_insight_UserHierarchy uh on uh.UserGUID = kpip.SupervisorUserID
join mi_insight_UserHierarchy uh1 on uh1.UserGUID = ra.RA_UpdatedBy
where cd.Code_Description != cd1.Code_Description
and RA_Date > dateadd(year,-1,getdate())),

CTE_Activity as (
select
distinct pop.UserUID
,pop.UserName
,pop.BusinessUID
,pop.BusinessName
,USRTE_DueDate
,datediff(day,usrte_DueDate,getdate()) as DaysOverdue
,TCT_Description
,TCTM_Description
,uh.UserUID as SupervisorUID
from	dbo.mi_insight_KPIPopulation pop 
join sa_insight_UserTandCTrack ut on ut.USRT_UserID = pop.userid
join sa_insight_UserTandCTrackModule utm on utm.USRTS_UserTrackID = ut.USRT_ID
join sa_insight_UserTandCTrackEvent ute on ute.USRTE_ModuleID = utm.USRTS_ID
join sa_insight_TandCTrack t on t.TCT_ID = ut.USRT_TrackID
join sa_insight_TandCTrackModule tm on tm.TCTM_ID = utm.USRTS_TrackModuleID
join mi_insight_UserHierarchy uh on pop.SupervisorUserID = uh.UserGUID
where	pop.SupervisorJobTitleCode in (7,8,9)		--7=BQM;8=Supervisor;9=AQM
and		pop.UserJobTitleCode in (4,42,7,8)			--4=Adviser;42=Schedule E Seller;7=BQM;8=Supervisor 
--and		uh.useruid = @AdviserUID
and		USRTE_CompletedDate is null
and		ute.USRTE_DueDate <= getdate() and ute.USRTE_DueDate >= dateadd(month,-1,getdate())),

CTE_SkillsAudit as (
select	Top 1
			pop.UserID,
			pop.UserUID,
		    pop.UserName,
			ass.ASS_Description,
			ab.ASB_Result,
			cd.Code_Description,
			ab.ASB_CompletedDate
--	into	#SOA
	FROM	dbo.mi_insight_KPIPopulation pop 
			inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = pop.UserID
			inner JOIN sa_insight_AssessmentEvent AS ae ON ae.ASE_ID = ab.ASB_EventID 
			inner JOIN sa_insight_Assessment AS ass ON ass.ASS_ID = ae.ASE_TypeID 
			inner join  sa_insight_CodeDescription cd on cd.Code_Code = ab.ASB_Result and cd.Code_CodeType = 505
	where	pop.UserJobTitleCode in (7,8)			--7=BQM;8=Supervisor 
	and		ass.ASS_Description in ('Observation of Supervisor coaching skills','Audit of Adviser tracks and documents Qrtly',
									'Observation of Supervisor conducting a Competence Assessment','Observation of an Adviser 1:1',
									'Supervisor Audit')
	and		ab.ASB_CompletedDate	>= dateadd(year,-1,getdate())
	and	    ab.ASB_Result in (1,2)
	and     pop.useruid = @AdviserUID
	order by Code_Description)

 
 Select top 1
  uh.UserUID
 ,uh.UserName
 ,ra.Code_Description as RiskAssessment
 ,case when cpd.UserUID is null then 0 else cpd.TotalCPDHours end as CPDHours
 ,sat.Code_Description as SkillAudit
 ,case when act.SupervisorUID is null then 'No' else 'Yes' end as ActivityManagement
 ,case when ro.SupervisorUID is null then 'No' else 'Yes' end as RiskAssessmentOverride
 from mi_insight_KPIPopulation kpip
 join mi_insight_UserHierarchy uh on uh.UserGUID = kpip.SupervisorUserID
 left join CTE_CPD cpd on cpd.UserUID = uh.UserUID
 left join CTE_RA ra on ra.UserUID = uh.UserUID
 left join CTE_RiskOverWritten ro on ro.SupervisorUID = uh.UserUID
 left join CTE_Activity act on act.SupervisorUID = uh.UserUID
 left join CTE_SkillsAudit sat on sat.UserUID = uh.UserUID
 where uh.UserUID = @AdviserUID
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


