CREATE PROCEDURE [logi].[pr_Ringo_SupervisorFirmList]
                @PtlCode varchar(8)

AS BEGIN

DECLARE	@return_value int;
DECLARE @lc_UserUid varchar(7);
DECLARE @lc_UserName varchar(50);
DECLARE @lc_UserJobTitleCodeHO int;
DECLARE @lc_UserJobTitleCodePartner int;
DECLARE @lc_UserJobTitleCodeSupervisor int;
DECLARE @lc_UserJobTitleCodeBQM int;
DECLARE @lc_UserBusinessUID varchar(7);			--AG 21/08/2018
DECLARE @lc_EnhancedFirmAccess int;				--AG 21/08/2018

EXEC @return_value = logi.pr_Ringo_UserSecurity	
							@PtlCode, 
							@UserUid=@lc_UserUid OUTPUT,
							@UserName=@lc_UserName OUTPUT,
							@UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
							@UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
							@UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
							@UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
							@UserBusinessUID=@lc_UserBusinessUID OUTPUT,			--AG 21/08/2018
							@EnhancedFirmAccess=@lc_EnhancedFirmAccess OUTPUT		--AG 21/08/2018


IF @lc_EnhancedFirmAccess > 0	--AG 21/08/2018
BEGIN
	SELECT	DISTINCT marh.FirmName + ' ' +'(' + marh.BusinessUID+')' as 'FirmName'
				   ,marh.BusinessUID
	FROM	mi_aqt_ReportingHierarchy marh
	where	marh.BusinessUID = @lc_UserBusinessUID
	order	by  marh.FirmName+ ' ' +'(' + marh.BusinessUID+')'
END
ELSE IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0)
BEGIN 

	SELECT	DISTINCT marh.FirmName + ' ' +'(' + marh.BusinessUID+')' as 'FirmName'
				   ,marh.BusinessUID
	FROM	mi_aqt_ReportingHierarchy marh
	where	marh.BusinessUID is not null --added 21.9.17
	order	by  marh.FirmName+ ' ' +'(' + marh.BusinessUID+')'
	/*
	SELECT	DISTINCT marh.FirmName
				   ,marh.BusinessUID
	FROM	mi_aqt_ReportingHierarchy marh
	where	marh.BusinessUID is not null --added 21.9.17
	order	by  marh.FirmName	--AG 21/09/2017*/          --Removed by SC 16.02.18- added UID to dropdown list for easier identification

	-- Removed 21.9.17 SI
	--select distinct dist.DIST_CompanyName as FirmName
	--			   ,dist.DIST_ExternalID  as BusinessUID
	--from sa_insight_Distributor dist
	--join sa_insight_UserPositionLink upl on upl.UPSL_ChildUserPositionID = dist.DIST_ID
	--join sa_insight_UserPosition     up  on up.UPS_ID                    = upl.UPSL_ParentUserPositionID
	--join mi_insight_UserHierarchy    uh  on uh.UserGUID                  = up.UPS_UserID;

END
ELSE IF @lc_UserJobTitleCodeSupervisor > 0 
BEGIN
	select distinct dist.DIST_CompanyName + ' ' +'(' + dist.DIST_ExternalID+')' as FirmName  --  SC 16.02.18 added UID to dropdown list
				   ,dist.DIST_ExternalID  as BusinessUID
	from sa_insight_Distributor dist
	join sa_insight_UserPositionLink upl on upl.UPSL_ChildUserPositionID = dist.DIST_ID
	join sa_insight_UserPosition     up  on up.UPS_ID                    = upl.UPSL_ParentUserPositionID
	join mi_insight_UserHierarchy    uh  on uh.UserGUID                  = up.UPS_UserID
	where uh.UserUID = @lc_UserUid
	order by dist.DIST_CompanyName + ' ' +'(' + dist.DIST_ExternalID+')'	--AG 21/09/2017   -- SC 16.02.18  added UID to dropdown list
END
 

--Test

--SELECT @lc_UserUID

END
GO
