DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'pr_Ringo_EventServicingAdviser';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + @SupervisorUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0)  
BEGIN

Select 1 as QueryNumber,
       'COB Supervisor' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
	   IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                      And cobcomp.UC_BusinessArea = 12
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
									  And cobcode.Code_CodeType = 55
Where marh.AdviserUID  = @SupervisorUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') = 
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
		      From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
Union
Select 2 as QueryNumber,
       'COB SOS' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
	   IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                      And cobcomp.UC_BusinessArea = 16
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
									  And cobcode.Code_CodeType = 55
Where marh.AdviserUID  = @SupervisorUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') = 
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
		      From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
Union
Select 3 as QueryNumber,
       'MCOB Supervisor' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
	   IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
									  And cobcomp.UC_BusinessArea = 11
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
									  And cobcode.Code_CodeType = 55
Where marh.AdviserUID  = @SupervisorUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
              From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
Union
Select 4 as QueryNumber,
       'MCOB SOS' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
	   IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
									  And cobcomp.UC_BusinessArea = 15
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
									  And cobcode.Code_CodeType = 55
Where marh.AdviserUID  = @SupervisorUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
              From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
Union
Select 5 as QueryNumber,
       'ICOB Supervisor' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
       IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
									  And cobcomp.UC_BusinessArea = 10
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                      And cobcode.Code_CodeType = 55
Where marh.AdviserUID = @SupervisorUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
			  From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
Union
Select 6 as QueryNumber,
       'ICOB SOS' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
       IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
									  And cobcomp.UC_BusinessArea = 14
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                      And cobcode.Code_CodeType = 55
Where marh.AdviserUID = @SupervisorUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
			  From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
Union
Select 7 as QueryNumber,
       'SI Supervisor' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
       IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
									  And cobcomp.UC_BusinessArea = 13
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                      And cobcode.Code_CodeType = 55
Where marh.AdviserUID = @SupervisorUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
			  From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
Union
Select 8 as QueryNumber,
       'SI SOS' As Licence,
	   IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
       IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
									  And cobcomp.UC_BusinessArea = 17
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                      And cobcode.Code_CodeType = 55
Where marh.AdviserUID = @SupervisorUID 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
			  From sa_insight_UserCompetency cobcomp1
			  Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
			  And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
			  And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
order by QueryNumber;

END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_SupervisorList]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*************************************************************************************************
Author:		Trevor Cummings (at a guess)

Date:		14/12/2015

Purpose:	This proc is used in the Ringo Supervisor Report and feeds the drop down list that
			selects the supervisor.

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
02/06/2017	S Inglis	SR476663: Introduction of impersonation. Changed security 
						from	logi.pr_Ringo_UserSecurityJMD
						to		logi.pr_Ringo_UserSecurity
02/06/2017	A Groves	1) Removed JMD hardcoding.
						2) @PTLCode increased fom 8 to 50 for UAT accounts. 
**************************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_SupervisorList]
                @PtlCode varchar(50)						--AG 02/06/2017

AS BEGIN

DECLARE	@return_value int;
DECLARE @lc_UserUid varchar(7);
DECLARE @lc_UserName varchar(50);
DECLARE @lc_UserJobTitleCodeHO int;
DECLARE @lc_UserJobTitleCodePartner int;
DECLARE @lc_UserJobTitleCodeSupervisor int;
DECLARE @lc_UserJobTitleCodeBQM int;
DECLARE	@lc_EnhancedPAAccess int;		--AG 02/06/2017
DECLARE @lc_UserBusinessUID varchar(7);

EXEC	@return_value = logi.pr_Ringo_UserSecurity @PtlCode, 
												   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT,
												   @EnhancedPAAccess=@lc_EnhancedPAAccess OUTPUT,	--AG 02/06/2017
												   @UserBusinessUID = @lc_UserBusinessUID OUTPUT;

/* AG 02/06/2017 DEBUG CODE
select	'NEW' as Source,
		@lc_UserJobTitleCodeHO as ' @lc_UserJobTitleCodeHO',
		@lc_UserJobTitleCodeBQM as '@lc_UserJobTitleCodeBQM',
		@lc_UserJobTitleCodeSupervisor as '@lc_UserJobTitleCodeSupervisor',
		@lc_UserUid as '@lc_UserUid',
		@lc_UserBusinessUID as '@lc_UserBusinessUID',
		@lc_EnhancedPAAccess as '@lc_EnhancedPAAccess'
*/		

IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0)
BEGIN 
select miuh_bqm.UserUID,
       miuh_bqm.UserName
						from   mi_insight_UserHierarchy miuh_bqm
						where  miuh_bqm.UserUid in (select miuh_super.SupervisorUID
													from   mi_insight_UserHierarchy miuh_super
													where  miuh_super.SupervisorUID is not null)
union select distinct miuh_bqm.bqmuid as UserUID,
                      miuh_bqm.BQMName as UserName
from   mi_insight_UserHierarchy miuh_bqm
union 
select distinct miuh_aqm.aqmuid as UserUID,
                      miuh_aqm.AQMName as UserName
from   mi_insight_UserHierarchy miuh_aqm 													
					   order by UserName;
END		

--AG 02/06/2017 Start
/*
ELSE IF @lc_UserJobTitleCodeSupervisor > 0 and @lc_UserUid in ('4007621','4007612','4007578','4007848') and @lc_UserBusinessUID = '2005309'
Begin
select miuh.UserUID,
       miuh.UserName
from   mi_insight_UserHierarchy miuh
where  miuh.UserJobTitleCodeSupervisor > 0 and miuh.BusinessUID = '2005309'

END

ELSE IF @lc_UserJobTitleCodeSupervisor > 0 and @lc_UserBusinessUID = '2005309'
Begin
select miuh.UserUID,
       miuh.UserName
from   mi_insight_UserHierarchy miuh
where  (miuh.UserUID = @lc_UserUid or miuh.SupervisorUID = @lc_UserUid)
        and miuh.UserJobTitleCodeSupervisor > 0 and miuh.BusinessUID = '2005309'

END
			  
ELSE IF @lc_UserJobTitleCodeSupervisor > 0
BEGIN
select miuh.UserUID,
       miuh.UserName
from   mi_insight_UserHierarchy miuh
where  miuh.UserUID = @lc_UserUid;
END
*/

ELSE IF @lc_UserJobTitleCodeSupervisor > 0
BEGIN
select miuh.UserUID,
       miuh.UserName
from   mi_insight_UserHierarchy miuh
where  miuh.UserJobTitleCodeSupervisor > 0
and	   ((@lc_EnhancedPAAccess = 1 and miuh.BusinessUID = @lc_UserBusinessUID)	--Set if config returned by pr_Ringo_UserSecurity gives access to this supervisor	AG 02/06/2017
or	   (miuh.UserUID = @lc_UserUid)
or	   (@lc_UserUid in (miuh.SupervisorUID,miuh.SupervisorUID2,miuh.SupervisorUID3,miuh.SupervisorUID4,miuh.SupervisorUID5,miuh.SupervisorUID6)))	--supervisor of supervisor (SOS)
END
--AG 02/06/2017 End

--Test

--SELECT @lc_UserUID

END
GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_SupervisorOGSChecks]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [logi].[pr_Ringo_SupervisorOGSChecks]
                @PtlCode			varchar(10)
               ,@SupervisorUID	    varchar(7)
               ,@Span				varchar(20)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_Ringo_SupervisorOGSChecks]
Author      : S Inglis
Date  : 29/03/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Supervisor OGS Checks" and is found on the "BQM MI" 
              menu. This report displays: 
              - Ongoing Service Checks at Supervisor Deep and Shallow Span



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_Ringo_SupervisorOGSChecks]  'ptl91371', '1001871','Deep Span'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
10-4-17		S Inglis		Addition of Supervisor Column
9-5-17		S Inglis		Update to Span selection to include supervisor UIDs 2,3,4,5,6 to
							enable deep span view	
28-07-2020	S Hale			Corrected Code_CodeType from 9 to 785
06-10-2020	S Inglis		Amended query to replace prefixes to link to Event ID				
06-10-2020	S Inglis		Amended query to replace "C" to link to Event ID				
04/04/2022	A Groves		1) Replaced the OWS Events table with the new merged event table
								that combines Concert Hub and OWS events.
							2) Added a join to column OriginalOWSEventID to handle where a D365 
								case check has been keyed into Insight with the OWS reference.
05/04/2022	S Campbell		Use dbo.mi_concert_ows_Event
27/09/2024  R251929     P Reed- Replace the Merged Event table: dbo.mi_concert_ows_Event with view that excludes OWS outstanding (1,2,3) events (concert1234_ows4_event
***********************************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'SupervisorOGSChecks';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + cast (@SupervisorUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

 SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
		, pop.BusinessUID
		, pop.BusinessName
		, pop.UserID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span --update 9.5.17

select distinct saca.CASE_CaseReference as CaseReference,
               (select min(buqu1.BQ_StartedDate)
				from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
				where  buqu1.BQ_ParentID   = saca.CASE_ID
				--and    buqu1.BQ_Status in (3,4,5,6,7,10)
				--and    buqu1.BQ_ActiveMonitoringStatus not in (1,3)
				) as CheckStartedDate
		       ,CaseStatus.Code_Description as OGS_CHK_Status
		       ,pers.FirstName + ' ' + pers.LastName as ClientName
			   ,miuh.UserName as AdviserName
			   ,uh.BusinessCompanyName as BusinessName
			   ,uh.SupervisorName
	FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca
	JOIN #Span miuh ON  saca.CASE_AdviserID = miuh.UserID
	Join mi_insight_UserHierarchy uh on uh.UserUID = miuh.UserUID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_CodeDescription] CaseStatus on CaseStatus.Code_CodeType = 785 and CaseStatus.Code_Code = buqu.BQ_Status --updated 28/7/20 SH
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityPolicy] buqp on buqp.BQP_ParentID = buqu.BQ_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityResult] bqre on bqre.BQR_ParentID = buqp.BQP_ID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormQuestion] CFQ on CFQ.CFQ_ID    = bqre.BQR_QuestionID 
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ComplianceFormSection] cofs on cofs.CFS_ID   = CFQ.CFQ_SectionID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQualityCode] bqco on bqco.bqc_code = bqre.bqr_code
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = cofs.CFS_ProductType 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even 
				on	case when even.EventID like 'SE%' 
						then case when substring(even.EventID,3,200) not like '%[^0-9]%' then cast(substring(even.EventID,3,200) as int) else -1 end 
						else case when even.EventID not like '%[^0-9]%' then cast(even.EventID as int) else -1 end 
					end
					= 
					case when replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	LEFT JOIN  prod_zurich_openwork_datawarehouse.dbo.concert1234_ows4_event even2 
				on	even2.OriginalOWSEventID 
					= 
					case when replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') not like '%[^0-9]%'
						then cast(replace(replace(replace(Replace(Replace(Replace(saca.CASE_CaseReference,'OGS',''),'RO',''),'RR',''),'C',''),'DB',''),'a','') as int)
						else -2
					end 
	JOIN  prod_zurich_openwork_datawarehouse.dbo.sa_ows_Person pers on pers.PersonID    = coalesce(even.PersonID,even2.PersonID)
																   and pers.BusinessUid = miuh.BusinessUID
	WHERE saca.CASE_SubmitDate >= DATEADD(YEAR,-1,GETDATE())
	--AND   miuh.UserUID = @AdviserUID
	AND   saca.CASE_CaseReference     like 'OGS%'
	AND   saca.CASE_CaseReference not like 'OGS%x' 
	AND   saca.CASE_CaseReference not like 'OGS%X'
	and   CaseStatus.code_code in (3,4,5,6,7,10,14)
	and   prty.PROD_ShortName in ('OGS') -- omitted XOGS as that is to do with a pre-check
	and   CFQ.CFQ_QuestionCode between 2001 and 3000
	and   bqre.BQR_ParentID = buqp.BQP_ID
	and   bqco.BQC_Description is not null
	AND   buqu.BQ_ActiveMonitoringStatus not in (1,3)
	AND   buqu.BQ_CompletedDate = (select max(buqu1.BQ_CompletedDate)
								   from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu1 
								   where  buqu1.BQ_ParentID   = saca.CASE_ID
								   and    buqu1.BQ_Status in (3,4,5,6,7,10)
								   and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) ;   
 
  
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH



