CREATE PROCEDURE [logi].[pr_ringo_SupervisorSkillsAudit]
      @PtlCode		  varchar(255),
	  @AdviserUID	  varchar (7)

AS 


set nocount on
/**********************************************************************************************
Name  : [logi].[pr_ringo_SupervisorSkillsAudit]
Author      : S Inglis
Date  : 15/03/2016


AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
06-04-2017	S Inglis		  Change of code to mirror KPI
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'SupervisorSkillsAudit';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@AdviserUID = ' + cast (@AdviserUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.UserUID = @AdviserUID
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
Begin

select	Distinct
		pop.UserID,
	    pop.UserName,
		TCTM_Description as ASS_Description,
		ab.ASB_Result,
		cd.Code_Description,
		ab.ASB_CompletedDate,
		uh.AQMName
FROM	dbo.mi_insight_KPIPopulation pop 
		inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = pop.UserID
		inner JOIN sa_insight_AssessmentEvent AS ae ON ae.ASE_ID = ab.ASB_EventID 
		inner JOIN sa_insight_Assessment AS ass ON ass.ASS_ID = ae.ASE_TypeID 
		inner join  sa_insight_CodeDescription cd on cd.Code_Code = ab.ASB_Result and cd.Code_CodeType = 505
		inner join mi_insight_UserHierarchy uh on uh.UserGUID = pop.UserID
		INNER JOIN  --added 6/4/17 SI
			(select TCTM_Description, tctm_linkedid, max(TCTM_CreatedDate) dt--, TCTM_Description 
			 from sa_insight_TandCTrackModule 
			 where TCTM_Description in ('Observation of Supervisor coaching skills','Audit of Adviser tracks and documents Qrtly',
									    'Observation of Supervisor conducting a Competence Assessment','Observation of an Adviser 1:1',
									    'Supervisor Audit')			 group by tctm_linkedid, TCTM_Description--,TCTM_Description
			 ) lid on lid.tctm_linkedid = ass.ASS_ID 
where	pop.UserJobTitleCode in (7,8)			--7=BQM;8=Supervisor Removed 6/4/17
--and		ass.ASS_Description in ('Observation of Supervisor coaching skills','Audit of Adviser tracks and documents Qrtly',
--								'Observation of Supervisor conducting a Competence Assessment','Observation of an Adviser 1:1',
--								'Supervisor Audit')
and		ab.ASB_CompletedDate	>= dateadd(year,-1,getdate())
and	    ab.ASB_Result in (1,2)
and		uh.UserUID = @AdviserUID
order by pop.username, Code_Description

 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


