CREATE PROCEDURE [logi].[pr_ringo_SupervisorSpanAdviserLicenceAndCompetency280317]
      @PtlCode		      varchar(255),
	  @SupervisorUID	  varchar (7),
	  @Licence		      varchar(7),
	  @Span				  varchar(20)
AS 


set nocount on


/**********************************************************************************************
Name  : [logi].[pr_Ringo_SupervisorSpanAdviserLicenceAndCompetency]
Author      : S Inglis
Date  : 10/03/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Supervisor Span Adviser Licence & Competency" and is 
              found on the "BQM MI" menu. This report displays: 
              - Advisers within the Supervisors shallow and deep span and their licences 
              and competencies



              The security groups associated with is report are:
              1) 
              2)  

       Execute as follows:
       exec [logi].[pr_ringo_SupervisorSpanAdviserLicenceAndCompetency] 'ptl91371', 'Logi','1002714'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
23-3-17		S Inglis		  Additional code added to allow for switch between shallow 
							  and deep span
10-4-17		S Inglis		  Addition of Supervisor
9-5-17		S Inglis	Update to Span selection to include supervisor UIDs 2,3,4,5,6 to
						enable deep span view	
***********************************************************************************************/



/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'SupervisorSpanAdviserLicenceAndCompetency';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + cast (@SupervisorUID as varchar(7));
set @StoredProcParams         = @StoredProcParams + ' @Licence = ' + cast (@Licence as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

 SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
		, pop.BusinessUID
		, pop.BusinessName
		, pop.UserID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span; --update 9.5.17

With CTE_FirmLevelCompetency as
(
Select	 1 as QueryNumber,
		 'COB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate,
		 marh.UserUID as AdviserUID,
		 marh.UserName as Adviser,
		 case when marh.UserJobTitleCode = 4 then 'Seller' 
		      when UserJobTitleCode = 7 then 'BQM' 
			  when UserJobTitleCode = 8 then 'Supervisor' 
			  when UserJobTitleCode = 9 then 'AQM'
			  when UserJobTitleCode = 42 then 'Selling BDD'
			  End as JobTitle,
		 marh.BusinessUID,
		 marh.BusinessName
		-- 'COMPETENCY DATE CHECK'
		-- 'COMPETENCY OUTCOME'
		-- 'FAIL AND SUB PASS'
From mi_insight_KPIPopulation marh
join #Span span on span.UserUID = marh.UserUID
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.UserID 
                                      And cobcomp.UC_BusinessArea = 3
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                                        And cobcode.Code_CodeType = 55
Where 1=1 --marh.AdviserUID  = @AdviserUID 
--And   marh.BusinessUID = @FirmName 
--And   uh.UserUID = @SupervisorUID
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') = 
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
                  From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')

Union
Select 2 as QueryNumber,
		'MCOB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate,
		 marh.UserUID as AdviserUID,
		 marh.UserName as Adviser,
		 case when marh.UserJobTitleCode = 4 then 'Seller' 
		when UserJobTitleCode = 7 then 'BQM' 
		when UserJobTitleCode = 8 then 'Supervisor' 
		when UserJobTitleCode = 9 then 'AQM'
		when UserJobTitleCode = 42 then 'Selling BDD'
		End as JobTitle,
		 marh.BusinessUID,
		 marh.BusinessName
		-- 'COMPETENCY DATE CHECK'
		-- 'COMPETENCY OUTCOME'
		-- 'FAIL AND SUB PASS'
From mi_insight_KPIPopulation marh
join #Span span on span.UserUID = marh.UserUID
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.UserID 
                                                        And cobcomp.UC_BusinessArea = 2
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                                        And cobcode.Code_CodeType = 55
Where 1=1 --marh.AdviserUID  = @AdviserUID 
--And   marh.BusinessUID = @FirmName 
--And   uh.UserUID = @SupervisorUID
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
              From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
Union
Select   3 as QueryNumber,
		'ICOB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
       IsNull(Convert(varchar(11),cobcomp.UC_DateAchieved), 'Competency Date: N/A') As CompetencyDate,
		 marh.UserUID as AdviserUID,
		 marh.UserName as Adviser,
		 case when marh.UserJobTitleCode = 4 then 'Seller' 
		      when UserJobTitleCode = 7 then 'BQM' 
			  when UserJobTitleCode = 8 then 'Supervisor' 
			  when UserJobTitleCode = 9 then 'AQM'
			  when UserJobTitleCode = 42 then 'Selling BDD'
			  End as JobTitle,
		 marh.BusinessUID,
		 marh.BusinessName
		-- 'COMPETENCY DATE CHECK'
		-- 'COMPETENCY OUTCOME'
		-- 'FAIL AND SUB PASS'
From mi_insight_KPIPopulation marh
join #Span span on span.UserUID = marh.UserUID
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.UserID 
                                                        And cobcomp.UC_BusinessArea = 1
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                      And cobcode.Code_CodeType = 55
Where 1=1 --marh.AdviserUID  = @AdviserUID 
--And   marh.BusinessUID = @FirmName 
--And   uh.UserUID = @SupervisorUID
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
                    From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')

UNION
Select   4 as QueryNumber,
		'SI' As Licence,
		 case when uh.UserUID is not null then 'Yes' end as Competency,
		 'N/A' as CompetencyDate,
		 uh.userUID as AdviserUID,
		 uh.UserName as Adviser,
		 case when UserJobTitleCode = 4 then 'Seller' 
		      when UserJobTitleCode = 7 then 'BQM' 
			  when UserJobTitleCode = 8 then 'Supervisor' 
			  when UserJobTitleCode = 9 then 'AQM'
			  when UserJobTitleCode = 42 then 'Selling BDD'
			  End as JobTitle,
		 uh.BusinessUID,
		 uh.BusinessName
FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_UserLicence ul
join mi_insight_KPIPopulation uh on uh.UserID = ul.ULIC_UserID
join #Span span on span.UserUID = uh.UserUID
join sa_insight_Licence lic on lic.LIC_ID = ul.ULIC_LicenceID
			and lic.LIC_Code in ('LIC78', 'LIC70', 'LIC69')
Where 
--uh1.UserUID = @SupervisorUID
ul.ULIC_Status = 2
--uh.businessuid = @FirmName -- uh.UserUID  = @AdviserUID
GROUP BY uh.UserUID,uh.UserName,
		 uh.BusinessUID, uh.BusinessName,
		 case when UserJobTitleCode = 4 then 'Seller' 
		      when UserJobTitleCode = 7 then 'BQM' 
			  when UserJobTitleCode = 8 then 'Supervisor' 
			  when UserJobTitleCode = 9 then 'AQM'
			  when UserJobTitleCode = 42 then 'Selling BDD'
			  End
UNION
Select   5 as QueryNumber,
		'APS' As Licence,
		 case when uh.UserUID is not null then 'Yes' end as Competency,
		 'N/A' as CompetencyDate,
		 uh.userUID as AdviserUID,
		 uh.UserName as Adviser,
		 case when UserJobTitleCode = 4 then 'Seller' 
		      when UserJobTitleCode = 7 then 'BQM' 
			  when UserJobTitleCode = 8 then 'Supervisor' 
			  when UserJobTitleCode = 9 then 'AQM'
			  when UserJobTitleCode = 42 then 'Selling BDD'
			  End as JobTitle,
		 uh.BusinessUID,
		 uh.BusinessName
FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_UserLicence ul
join mi_insight_KPIPopulation uh on uh.UserID = ul.ULIC_UserID
join #Span span on span.UserUID = uh.UserUID
join sa_insight_Licence lic on lic.LIC_ID = ul.ULIC_LicenceID
			and lic.LIC_Code in ('LIC110', 'LIC107', 'LIC63', 'LIC104')
Where --uh1.UserUID = @SupervisorUID
 ul.ULIC_Status = 2
--uh.BusinessUID = @FirmName -- uh.UserUID  = @AdviserUID
GROUP BY uh.UserUID,uh.UserName,
		 uh.BusinessUID, uh.BusinessName,
		 case when UserJobTitleCode = 4 then 'Seller' 
		      when UserJobTitleCode = 7 then 'BQM' 
			  when UserJobTitleCode = 8 then 'Supervisor' 
			  when UserJobTitleCode = 9 then 'AQM'
			  when UserJobTitleCode = 42 then 'Selling BDD'
			  End
--order by QueryNumber
)

Select
Licence
,Competency
,CompetencyDate
,AdviserUID
,Adviser
,JobTitle
,uh.BusinessUID
,BusinessCompanyName
,uh.SupervisorName
from CTE_FirmLevelCompetency flc
join mi_insight_UserHierarchy uh on uh.UserUID = flc.AdviserUID
where 1=1 
And Licence = @licence
And JobTitle is not null
order by BusinessName, Adviser
  
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
/****** Object:  StoredProcedure [logi].[pr_ringo_SupervisorSpanAdvisers280317]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [logi].[pr_ringo_SupervisorSpanAdvisers280317]
      @PtlCode		      varchar(255),
	  @SupervisorUID	  varchar (7),
	  @Span				  varchar(20)

AS 


set nocount on
/***************************************************************************
Name  : [logi].[pr_Ringo_SupervisorSpanAdvisers]
Author      : S Inglis
Date  : 10/03/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Supervisor Span Advisers" and is found on the "BQM MI" 
              menu. This report displays: 
              - Advisers within the Supervisors shallow and deep span and their latest
			  risk assessment


              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanAQTChkdCasesNew] 'ptl91371', 'Logi','1002714'
              
AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
17-10-16	S Inglis		  Amendment of risk assessment joins to make them
							  left join to pick up users who haven't had a risk
							  assessment yet
23-3-17		S Inglis		  Additional code added to allow for switch between 
							  shallow and deep span
10-4-17		S Inglis		  Addition of Supervisor
9-5-17		S Inglis		  Update to Span selection to include supervisor UIDs 
							  2,3,4,5,6 to enable deep span view	
2.3.18		S Inglis		  Update to filter to look back 1 month rather than 31 days
27.11.20	S Inglis		  Addition of code to look at if Adviser has an IC track
							  if so they are marked as IC, otherwise as FC
24.6.21		S Inglis		  Added code to account for advisers who work for different firms
							  now matches on Business UID and Adviser UID
							  Code added to exclude new Owl Sales Director
****************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'SupervisorSpanAdvisers';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + cast (@SupervisorUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0 )  

Begin

/* Added 27.11.20 SI */
Select distinct
 tt.TCT_Description as TrackName
,uh.UserUID
,uh.UserName
into #InterimCompetent
from sa_insight_UserTandCTrackEvent ute
join sa_insight_AssessmentBooking asb on asb.ASB_UserTAndCTrackEventID = ute.USRTE_ID
join sa_insight_UserTandCTrackModule utm on utm.USRTS_ID = ute.USRTE_ModuleID
join sa_insight_UserTandCTrack ut on ut.USRT_ID = utm.USRTS_UserTrackID
join mi_insight_UserHierarchy uh on uh.UserGUID = ut.USRT_UserID
join sa_insight_TandCTrackModule ttm on ttm.TCTM_ID = utm.USRTS_TrackModuleID
join sa_insight_TandCTrack tt on tt.TCT_ID = ttm.TCTM_TrackID
JOIN sa_insight_AssessmentEvent AS ae ON ae.ASE_ID = asb.ASB_EventID
Join mstt_Agents agt on agt.CODE = uh.UserUID
Join mstt_Agents bqm on bqm.CODE = uh.BQMUID
where USRTS_CompletedDate is null and USRT_CompletedDate is null and asb.ASB_CompletedDate is null
and isnull(uh.ADUID,'111') not in  ('4005013','4021409') -- updated 24.6.21
and uh.SupervisorUID is null 
and LEFT(TCT_Description,4) in ('DT25','DT26','DT27','DT28','DT35')
and agt.CompetentStatusDescription = 'Active'
--End--
 SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
		, pop.BusinessUID
		, pop.BusinessName
		, pop.UserID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span --update 9.5.17
 

select
 pop.UserUID
,pop.UserName
,pop.UserJobTitleDesc
,pop.BusinessUID
,pop.BusinessName
,uh.SupervisorName
--,RA_Date
--,RA_Status
--,RA_USR_Type
,cd.Code_Description as LatestRiskAssessmentStatus
,ra.RA_Result
,case when ic.UserUID is null then 'FC' else 'IC' end as CompetentStatus --Added 27.11.20 SI
from mi_insight_KPIPopulation pop 
join #Span span on pop.UserUID = span.UserUID 
join mi_insight_UserHierarchy uh on uh.UserUID = span.UserUID and uh.BusinessUID = span.BusinessUID -- updated 24.6.21
left join sa_insight_RiskAssessment ra on ra.RA_USR_ID = pop.userid and ra.RA_USR_Type = (case when pop.UserJobTitleDesc = 'ADV' then 1
																	else 4 end) --Amended 17/10/16 SI
left join sa_insight_CodeDescription cd on cd.Code_Code = ra.RA_Status and cd.Code_CodeType = 500 --Amended 17/10/16 SI
left join #InterimCompetent ic on ic.UserUID = pop.UserUID --Added 27.11.20 SI
where 
--uh.UserUID = @supervisorUID and 
UserJobTitleDesc != 'PP'
and (RA_Date > dateadd(month,-1,getdate()) or RA_Date is null) --Amended 17/10/16 SI
order by BusinessUID, UserUID
  
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
