		, pop.BusinessUID
		, pop.BusinessName
		, pop.UserID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span --update 9.5.17

Select
cco.AssessorUID
       ,FirstNameATT.ATTL_AttributeValue +' ' + LastNameATT.ATTL_AttributeValue as ClientName
	   ,CaseID
       ,cco.Assessor
       ,AQTH.UserUID
       ,AQTH.UserName
       ,cco.Advice
       ,cco.InitialCheck as BQ_CheckDate
	--	,LOB
		,ProdConfig.RegulationCategory 
--		,ProdShortName  -- for testing
		,cco.InitialResult as Status
--		,AQTO.FinalStatus as FinStatus  -- for testing
--		,AQTO.InitialWorkFlowStatus as Initial_Status -- for testing
--		,AQTO.FinalWorkFlowStatus as Final_Status  -- for testing
       ,cco.Submitted as CASE_SubmitDate
       ,uh.BusinessUID
       ,uh.BusinessCompanyName as BusinessName
       --,AQTH.SupervisorUID
       ,UH.SupervisorName
       --,AQTH.BQMUID
       --,AQTH.BQMName
       --,AQTH.AQMUID
       --,AQTH.AQMName
       --,CASE  cco.InitialResult WHEN 'A1 Suitable and Complete' THEN 'Passed'
							--	WHEN 'A2 Suitable and Acceptable' THEN 'Passed'
							--			   ELSE CASE  cco.FinalResult WHEN 'Reject' THEN 
							--								    CASE cco.FinalWorkflow WHEN 752 THEN 'Reject'
							--													WHEN 753 THEN 'Reject'
							--													WHEN 757 THEN 'Reject'
							--										ELSE 'Queried' END  
       --              							ELSE 'Queried' END END 
--	   ,FinalWorkflow AS Result --17/5/17 SI
--	   ,case when cco.FinalResult like 'C%' then 'Reject' else cco.FinalResult end as Result -- Added 20/4/18
	   ,case when cco.FinalWorkflow = 'Action Required' then 'TBC'  -- added 24/05/18 SI
			 when cco.FinalWorkflow = 'Not Proceeded With' then cco.FinalWorkflow else 
	   (case when cco.InitialResult like 'A1%' or cco.initialResult like 'A2%' or cco.initialResult like 'First time pass%'  then 'Pass'
			 when (cco.FinalResult like 'A3%' or cco.FinalResult like 'B%' or cco.FinalResult like 'C%' 
				  or cco.FinalResult like 'Unclear%' or cco.FinalResult like 'Unsuitable%') and cco.FinalWorkflow in ('Reject','Unsuitable advice') then 'Unsuitable advice'
			 else 'Suitable post clarification' end) end as Result  -- updated SH 28/07/2020
from mi_insight_CaseCheckOutcomes cco
join sa_insight_SalesCase saca on cco.Advice = saca.CASE_CaseReference 
join (Select distinct ATTL_ParentID, ATTl_AttributeID, ATTL_AttributeValue
		from sa_insight_AttributeLink atl
		inner join sa_insight_Attribute att on att.ATT_ID = atl.ATTL_AttributeID
		where ATT_Name = 'CASE.CLIENTFIRSTNAME') FirstNameATT
		on FirstNameATT.ATTL_ParentID = saca.CASE_ID
join (Select distinct ATTL_ParentID, ATTl_AttributeID, ATTL_AttributeValue
		from sa_insight_AttributeLink atl
		inner join sa_insight_Attribute att on att.ATT_ID = atl.ATTL_AttributeID
		where ATT_Name = 'CASE.CLIENTSURNAME') LastNameATT
		on LastNameATT.ATTL_ParentID = saca.CASE_ID
join (select distinct ProductShortName, RegulationCategory
			from dbo.mi_insight_ConfigProductTypeReplacement) ProdConfig
			on ProdConfig.ProductShortName = cco.Product
left join #Span AQTH on AQTH.UserUID = cco.AdviserUID
left join mi_insight_UserHierarchy uh on uh.UserUID = cco.AdviserUID
where cco.AdviserUID is not null
and   cco.Submitted >= '01-DEC-2013'
AND   cco.InitialCheck >= DATEADD(mm,-12,dateadd(dd,0,datediff(dd,0,GETDATE()))) --updated 28.1.19 SI
AND   saca.CASE_CaseReference != '0'
AND	  AQTH.UserUID is not null
--AND   aqth.SupervisorUID = @SupervisorUID



	END
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END


