/**********************************************************************************************
Name  : [logi].[pr_Ringo_SupervisorSpanAQTCasesChecked280317]
Author      : S Inglis
Date  : 10/03/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Supervisor Span AQT Chkd Cases New" and is found on the "BQM MI" 
              menu. This report displays: 
              - AQT Checked Cases and replaces pr_Ringo_SupervisorSpanAQTCasesChecked to look at a new table
			  and improve the efficiency of the report



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanAQTChkdCasesNew] 'ptl91371', 'Logi','1002714'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
28-3-17		S Inglis		  Additional code added to allow for switch between shallow 
							  and deep span
10-4-17		S Inglis		  Addition of Supervisor
9-5-17		S Inglis		  Update to Span selection to include supervisor UIDs 2,3,4,5,6 to
							  enable deep span view	
17/05/2017	S Inglis		  Result data field changed from Case statement to Final Workflow
20/04/2018	S Inglis		  Change of Result to look at Final Result not Final Outcome and show any
							  Final Outcome starting with a C as a Reject
24/05/2018 S Inglis			  Change of Result to use following logic as confirmed by Sarah Wise
							  in AQT: 
							  Final Workflow 'Action Required' = TBC
							  Final Workflow 'Not Proceeded With' = Not Proceeded With
							  Initial Result A1 or A2 = Pass
							  Initial Result A3, B or C AND Final Result A1 or A2 = Passed with Comments
							  Initial Result A3, B or C AND Final Result C = Reject
28/01/2019	S Inglis		  Report updated to show cases in a R12 based on checked date not submitted
							  date
***********************************************************************************************/

CREATE PROCEDURE [logi].[pr_Ringo_SupervisorSpanAQTCasesChecked280317_Backup20200802AG]
                @SupervisorUID      varchar(7)
               ,@PtlCode			varchar(10)
               ,@Span				varchar(20)
               
AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'pr_Ringo_EventServicingAdviser';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + @SupervisorUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN
	IF @SupervisorUID != ''
	BEGIN

 SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
		, pop.BusinessUID
		, pop.BusinessName
		, pop.UserID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span --update 9.5.17

Select
cco.AssessorUID
       ,FirstNameATT.ATTL_AttributeValue +' ' + LastNameATT.ATTL_AttributeValue as ClientName
	   ,CaseID
       ,cco.Assessor
       ,AQTH.UserUID
       ,AQTH.UserName
       ,cco.Advice
       ,cco.InitialCheck as BQ_CheckDate
	--	,LOB
		,ProdConfig.RegulationCategory 
--		,ProdShortName  -- for testing
		,cco.InitialResult as Status
--		,AQTO.FinalStatus as FinStatus  -- for testing
--		,AQTO.InitialWorkFlowStatus as Initial_Status -- for testing
--		,AQTO.FinalWorkFlowStatus as Final_Status  -- for testing
       ,cco.Submitted as CASE_SubmitDate
       ,uh.BusinessUID
       ,uh.BusinessCompanyName as BusinessName
       --,AQTH.SupervisorUID
       ,UH.SupervisorName
       --,AQTH.BQMUID
       --,AQTH.BQMName
       --,AQTH.AQMUID
       --,AQTH.AQMName
       --,CASE  cco.InitialResult WHEN 'A1 Suitable and Complete' THEN 'Passed'
							--	WHEN 'A2 Suitable and Acceptable' THEN 'Passed'
							--			   ELSE CASE  cco.FinalResult WHEN 'Reject' THEN 
							--								    CASE cco.FinalWorkflow WHEN 752 THEN 'Reject'
							--													WHEN 753 THEN 'Reject'
							--													WHEN 757 THEN 'Reject'
							--										ELSE 'Queried' END  
       --              							ELSE 'Queried' END END 
--	   ,FinalWorkflow AS Result --17/5/17 SI
--	   ,case when cco.FinalResult like 'C%' then 'Reject' else cco.FinalResult end as Result -- Added 20/4/18
	   ,case when cco.FinalWorkflow = 'Action Required' then 'TBC'  -- added 24/05/18 SI
			 when cco.FinalWorkflow = 'Not Proceeded With' then cco.FinalWorkflow else 
	   (case when cco.InitialResult like 'A1%' or cco.initialResult like 'A2%' then 'Pass'
			 when (cco.InitialResult like 'A3%' or cco.InitialResult like 'B%' or cco.InitialResult like 'C%') and cco.FinalResult like 'C%' then 'Reject'
			 else 'Passed With Comments' end) end as Result
from mi_insight_CaseCheckOutcomes cco
join sa_insight_SalesCase saca on cco.Advice = saca.CASE_CaseReference 
join (Select distinct ATTL_ParentID, ATTl_AttributeID, ATTL_AttributeValue
		from sa_insight_AttributeLink atl
		inner join sa_insight_Attribute att on att.ATT_ID = atl.ATTL_AttributeID
		where ATT_Name = 'CASE.CLIENTFIRSTNAME') FirstNameATT
		on FirstNameATT.ATTL_ParentID = saca.CASE_ID
join (Select distinct ATTL_ParentID, ATTl_AttributeID, ATTL_AttributeValue
		from sa_insight_AttributeLink atl
		inner join sa_insight_Attribute att on att.ATT_ID = atl.ATTL_AttributeID
		where ATT_Name = 'CASE.CLIENTSURNAME') LastNameATT
		on LastNameATT.ATTL_ParentID = saca.CASE_ID
join (select distinct ProductShortName, RegulationCategory
			from dbo.mi_insight_ConfigProductTypeReplacement) ProdConfig
			on ProdConfig.ProductShortName = cco.Product
left join #Span AQTH on AQTH.UserUID = cco.AdviserUID
left join mi_insight_UserHierarchy uh on uh.UserUID = cco.AdviserUID
where cco.AdviserUID is not null
and   cco.Submitted >= '01-DEC-2013'
AND   cco.InitialCheck >= DATEADD(mm,-12,dateadd(dd,0,datediff(dd,0,GETDATE()))) --updated 28.1.19 SI
AND   saca.CASE_CaseReference != '0'
AND	  AQTH.UserUID is not null
--AND   aqth.SupervisorUID = @SupervisorUID



	END
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END


