JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca on popu.UserID = saca.CASE_AdviserID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BusinessQuality] buqu on buqu.BQ_ParentID = saca.CASE_ID
