                             and    buqu1.BQ_Status in (3,4,5,6,7,10,14)
                             and    buqu1.BQ_ActiveMonitoringStatus not in (1,3) ) )
UPDATE #AQT_OUTCOMES                             
 set    FinalStatus             = CTE_OUTCOME.FinalStatus,
