--		,AQTO.FinalWorkFlowStatus as Final_Status  -- for testing
       ,AQTO.CaseSubmitDate as CASE_SubmitDate
       ,AQTH.BusinessUID
       ,AQTH.FirmName as BusinessName
       ,AQTH.SupervisorUID
       ,AQTH.SupervisorName
       ,AQTH.BQMUID
       ,AQTH.BQMName
       ,AQTH.AQMUID
       ,AQTH.AQMName
       ,CASE  AQTO.InitialStatus WHEN 'A1 Suitable and Complete' THEN 'Passed'
								WHEN 'A2 Suitable and Acceptable' THEN 'Passed'
										   ELSE CASE  AQTO.FinalWorkFlowStatus WHEN 'Reject' THEN 
															    CASE AQTO.FinalCode WHEN 752 THEN 'Reject'
																				WHEN 753 THEN 'Reject'
																				WHEN 757 THEN 'Reject'
																	ELSE 'Queried' END  
                     							ELSE 'Queried' END END AS Result
  
from      #AQT_OUTCOMES AQTO
left join dbo.mi_aqt_ReportingHierarchy AQTH on AQTH.AdviserGUID = AQTO.AdviserGUID
JOIN #LOBCODES lob on lob.ShortCode = AQTO.ProdShortName
where   AQTH.AdviserUID is not null;

END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_SupervisorSpanAQTStats280317]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [logi].[pr_Ringo_SupervisorSpanAQTStats280317]
                @SupervisorUID      varchar(7)
               ,@PtlCode      varchar(10)
               ,@Span			varchar(20)
AS BEGIN
set nocount on

 /**********************************************************************************************
Name  : [logi].[pr_Ringo_SupervisorSpanAQTStats]
Author      : S Inglis


Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Supervisor Span AQT Stats" and is found on the "BQM MI" 
              menu. This report displays: 
              - Advisers within the Supervisors shallow and deep span and the AQT Stats



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanAQTChkdCasesNew] 'ptl91371', 'Logi','1002714'

AMENDMENT HISTORY
=================
Date        Author          Description
----        ------          -----------
28-3-17		S Inglis		Additional code added to allow for switch between shallow 
							and deep span
9-5-17		S Inglis		Update to Span selection to include supervisor UIDs 2,3,4,5,6 to
							enable deep span view	
27-07-20	S Hale			1) updated for new outcomes and workflow
							2) SI updated to SpInv	
01/10/2024	S Hale			Added new case outcomes for Wealth (Unclear - Minor/Major Admin/Advice)

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'pr_Ringo_SupervisorSpanAQTStats';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + @SupervisorUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
/*select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
and uh.BusinessUID = @SupervisorUID;*/

select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh where @SupervisorUID = uh.SupervisorUID 


/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN
	IF @SupervisorUID != ''
	BEGIN

 SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
		, pop.BusinessUID
		, pop.BusinessName
		, pop.UserID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span --update 9.5.17
;
WITH CTE_AQTCHECK As (
	select saca.CASE_CaseReference as Advice
		  ,saca.CASE_AdviserID as AdviserGUID
		  ,'Not Checked' as CaseOutcome
		  ,PROD_ShortName    as Product  
		  ,'Not Checked' as InitialResult
		  ,'Not Checked' as FinalResult
		  ,'Not Checked' as FinalWorkflow
		  ,null as FinalCheck
		  ,null AS AssessorUID
		  ,null AS Assessor
		  ,saca.CASE_SubmitDate as Submitted
		  ,ProdConfig.RegulationCategory
	--	  ,marh.SupervisorUID
	FROM 	[prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca --on marh.UserID = saca.CASE_AdviserID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BasicPolicy] bapa     on bapa.BPOL_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = bapa.BPOL_ProductType
	join (select distinct ProductShortName, RegulationCategory
			from dbo.mi_insight_ConfigProductTypeReplacement) ProdConfig
			on ProdConfig.ProductShortName = PROD_ShortName
	join #Span span on span.UserID = saca.CASE_AdviserID

--	join mi_insight_UserHierarchy uh on uh.UserUID = marh.AdviserUID
	WHERE saca.CASE_SubmitDate >= '01-DEC-2013'
	AND   saca.CASE_SubmitDate >= DATEADD(mm,-12,GETDATE())
	AND   saca.CASE_CaseReference != '0'
	AND   (PROD_ShortName not like 'X%' or PROD_ShortName = 'DUP')
	AND   not exists (select 1
					  from   mi_insight_CaseCheckOutcomes aqto
					  where  aqto.Advice = saca.CASE_CaseReference)

	UNION ALL
	Select
	Advice,
	cco.AdviserUID,
	CaseOutcome,
	product,
	InitialResult,
	FinalResult,
	FinalWorkflow,
	FinalCheck,
	AssessorUID,
	Assessor,
	Submitted,
	ProdConfig.RegulationCategory
	--uh.*
	FROM mi_insight_CaseCheckOutcomes cco
	join sa_insight_SalesCase saca on cco.Advice = saca.CASE_CaseReference 
	join (select distinct ProductShortName, RegulationCategory
			from dbo.mi_insight_ConfigProductTypeReplacement) ProdConfig
			on ProdConfig.ProductShortName = cco.Product
	join #Span span on span.UserUID = cco.AdviserUID
	Where 
	      cco.Submitted >= '01-DEC-2013'
	AND   cco.Submitted >= DATEADD(mm,-12,GETDATE())
	AND   cco.Advice != '0'
	
)

select count(CASE aqto.RegulationCategory WHEN 'COBI' THEN AQTO.Advice ELSE NULL END ) AS COBI_SUBMITTED  
		  ,count(CASE aqto.RegulationCategory WHEN 'COBI' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   WHEN 'Unclear action required' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Admin' THEN AQTO.Advice   --updated 01/10/2024 SH
																   WHEN 'Unclear - Major Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
																   WHEN 'Unclear - Major Advice' THEN AQTO.Advice
																   WHEN 'Suitable post clarification' THEN AQTO.Advice
																   WHEN 'Unsuitable advice' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS COBI_CHECKED  
		  ,count(CASE aqto.RegulationCategory WHEN 'COBI' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS COBI_PASSED  
		  ,count( CASE aqto.RegulationCategory WHEN 'COBI' THEN 
							   CASE  WHEN AQTO.FinalWorkFlow in ('Reject','Unsuitable advice') THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														WHEN 'Unclear action required' THEN AQTO.Advice
														WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
														WHEN 'Unclear - Major Admin' THEN AQTO.Advice
														WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
														WHEN 'Unclear - Major Advice' THEN AQTO.Advice
														WHEN 'Unsuitable advice' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS COBI_REJECT  
		  ,count( CASE aqto.RegulationCategory WHEN 'COBP' THEN AQTO.Advice ELSE NULL END ) AS COBP_SUBMITTED  
		  ,count( CASE aqto.RegulationCategory WHEN 'COBP' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   WHEN 'Unclear action required' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Major Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
																   WHEN 'Unclear - Major Advice' THEN AQTO.Advice
																   WHEN 'Suitable post clarification' THEN AQTO.Advice
																   WHEN 'Unsuitable advice' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS COBP_CHECKED  
		  ,count( CASE aqto.RegulationCategory WHEN 'COBP' THEN CASE AQTO.InitialResult  WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS COBP_PASSED  
		  ,count( CASE aqto.RegulationCategory WHEN 'COBP' THEN 
							   CASE  WHEN AQTO.FinalWorkFlow in ('Reject','Unsuitable advice') THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														WHEN 'Unclear action required' THEN AQTO.Advice
														WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
														WHEN 'Unclear - Major Admin' THEN AQTO.Advice
														WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
														WHEN 'Unclear - Major Advice' THEN AQTO.Advice
														WHEN 'Unsuitable advice' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS COBP_REJECT  
		  ,count( CASE aqto.RegulationCategory WHEN 'MCOB' THEN AQTO.Advice ELSE NULL END ) AS MCOB_SUBMITTED  
		  ,count( CASE aqto.RegulationCategory WHEN 'MCOB' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   WHEN 'Unclear action required' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Major Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
																   WHEN 'Unclear - Major Advice' THEN AQTO.Advice
																   WHEN 'Suitable post clarification' THEN AQTO.Advice
																   WHEN 'Unsuitable advice' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS MCOB_CHECKED  
		  ,count( CASE aqto.RegulationCategory WHEN 'MCOB' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS MCOB_PASSED  
		  ,count( CASE aqto.RegulationCategory WHEN 'MCOB' THEN 
							   CASE  WHEN AQTO.FinalWorkFlow in ('Reject','Unsuitable advice') THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														WHEN 'Unclear action required' THEN AQTO.Advice
														WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
														WHEN 'Unclear - Major Admin' THEN AQTO.Advice
														WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
														WHEN 'Unclear - Major Advice' THEN AQTO.Advice
														WHEN 'Unsuitable advice' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS MCOB_REJECT  
		  ,count( CASE aqto.RegulationCategory WHEN 'ICOB' THEN AQTO.Advice ELSE NULL END ) AS ICOB_SUBMITTED  
		  ,count( CASE aqto.RegulationCategory WHEN 'ICOB' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   WHEN 'Unclear action required' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Major Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
																   WHEN 'Unclear - Major Advice' THEN AQTO.Advice
																   WHEN 'Suitable post clarification' THEN AQTO.Advice
																   WHEN 'Unsuitable advice' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS ICOB_CHECKED  
		  ,count( CASE aqto.RegulationCategory WHEN 'ICOB' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS ICOB_PASSED  
		  ,count( CASE aqto.RegulationCategory WHEN 'ICOB' THEN 
							   CASE  WHEN AQTO.FinalWorkFlow in ('Reject','Unsuitable advice') THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														WHEN 'Unclear action required' THEN AQTO.Advice
														WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
														WHEN 'Unclear - Major Admin' THEN AQTO.Advice
														WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
														WHEN 'Unclear - Major Advice' THEN AQTO.Advice
														WHEN 'Unsuitable advice' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS ICOB_REJECT  
		  ,count( CASE aqto.RegulationCategory WHEN 'SpInv' THEN AQTO.Advice ELSE NULL END ) AS SI_SUBMITTED  
		  ,count( CASE aqto.RegulationCategory WHEN 'SpInv' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   WHEN 'Unclear action required' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Major Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
																   WHEN 'Unclear - Major Advice' THEN AQTO.Advice
																   WHEN 'Suitable post clarification' THEN AQTO.Advice
																   WHEN 'Unsuitable advice' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS SI_CHECKED  
		  ,count( CASE aqto.RegulationCategory WHEN 'SpInv' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS SI_PASSED  
		  ,count( CASE aqto.RegulationCategory WHEN 'SpInv' THEN 
							   CASE  WHEN AQTO.FinalWorkFlow in ('Reject','Unsuitable advice') THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														WHEN 'Unclear action required' THEN AQTO.Advice
														WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
														WHEN 'Unclear - Major Admin' THEN AQTO.Advice
														WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
														WHEN 'Unclear - Major Advice' THEN AQTO.Advice
														WHEN 'Unsuitable advice' THEN AQTO.Advice
														ELSE NULL END  
							   ELSE null END 
						  ELSE null END) AS SI_REJECT 
		  ,count( CASE aqto.RegulationCategory WHEN 'RPB' THEN AQTO.Advice ELSE NULL END ) AS RPB_SUBMITTED  
		  ,count( CASE aqto.RegulationCategory WHEN 'RPB' THEN CASE AQTO.InitialResult WHEN 'A1 Suitable and Complete' THEN AQTO.Advice 
																   WHEN 'B Clarify' THEN AQTO.Advice
																   WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
																   WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   WHEN 'Unclear action required' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Major Admin' THEN AQTO.Advice
																   WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
																   WHEN 'Unclear - Major Advice' THEN AQTO.Advice
																   WHEN 'Suitable post clarification' THEN AQTO.Advice
																   WHEN 'Unsuitable advice' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS RPB_CHECKED  
		  ,count( CASE aqto.RegulationCategory WHEN 'RPB' THEN CASE AQTO.InitialResult WHEN 'A2 Suitable and Acceptable' THEN AQTO.Advice
																   WHEN 'A1 Suitable and Complete' THEN AQTO.Advice
																   WHEN 'First time pass' THEN AQTO.Advice
																   WHEN 'First time pass with feedback' THEN AQTO.Advice
																   ELSE null END ELSE null END) AS RPB_PASSED  
		  ,count( CASE aqto.RegulationCategory WHEN 'RPB' THEN 
							   CASE  WHEN AQTO.FinalWorkFlow in ('Reject','Unsuitable advice') THEN 
									CASE AQTO.Finalresult WHEN 'B Clarify' THEN AQTO.Advice
														WHEN 'A3 Suitable but Defective' THEN AQTO.Advice
														WHEN 'C Potentially Unsuitable' THEN AQTO.Advice
														WHEN 'Unclear action required' THEN AQTO.Advice
														WHEN 'Unclear - Minor Admin' THEN AQTO.Advice
														WHEN 'Unclear - Major Admin' THEN AQTO.Advice
														WHEN 'Unclear - Minor Advice' THEN AQTO.Advice
														WHEN 'Unclear - Major Advice' THEN AQTO.Advice
														WHEN 'Unsuitable advice' THEN AQTO.Advice
														ELSE NULL END  
														  ELSE null END 
						  ELSE null END) AS RPB_REJECT
	 
	from      CTE_AQTCHECK AQTO


END
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_SupervisorSpanAQTStats280317_Backup20200802AG]    Script Date: 7/3/2026 3:44:28 PM ******/
