/****** Object:  StoredProcedure [logi].[pr_Ringo_SupervisorSpanAQTStatsNew]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name  : [logi].[pr_Ringo_SupervisorSpanAQTStatsNew]
Author      : S Inglis
Date  : 10/03/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Supervisor Span AQT Chkd Cases New" and is found on the "BQM MI" 
              menu. This report displays: 
              - AQT Checked Cases and replaces pr_Ringo_SupervisorSpanAQTStatss to look at a new table
			  and improve the efficiency of the report



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_DeepSpanAQTChkdCasesNew] 'ptl91371', 'Logi','1002714'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
03-04-17	S Inglis		  additional code added to allow for supervisor to be Supervisor
							  or BQM
27-07-20	S Hale			  1) updated for new outcomes and workflow
							  2) fixed 'Result' column to include 'Unsuitable advice'

***********************************************************************************************/

CREATE PROCEDURE [logi].[pr_Ringo_SupervisorSpanAQTStatsNew]
                @SupervisorUID      varchar(7)
               ,@PtlCode      varchar(10)
AS BEGIN
set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'pr_Ringo_EventServicingAdviser';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + @SupervisorUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN
	IF @SupervisorUID != ''
	BEGIN
Select
cco.AssessorUID
       ,FirstNameATT.ATTL_AttributeValue +' ' + LastNameATT.ATTL_AttributeValue 
	   ,CaseID
       ,cco.Assessor
       ,AQTH.AdviserUID
       ,AQTH.Adviser
       ,cco.Advice
       ,cco.InitialCheck as BQ_CheckDate
	--	,LOB
		,ProdConfig.RegulationCategory 
--		,ProdShortName  -- for testing
		,cco.InitialResult as Status
--		,AQTO.FinalStatus as FinStatus  -- for testing
--		,AQTO.InitialWorkFlowStatus as Initial_Status -- for testing
--		,AQTO.FinalWorkFlowStatus as Final_Status  -- for testing
       ,cco.Submitted as CASE_SubmitDate
       ,AQTH.BusinessUID
       ,AQTH.FirmName
       ,AQTH.SupervisorUID
       ,AQTH.SupervisorName
       ,AQTH.BQMUID
       ,AQTH.BQMName
       ,AQTH.AQMUID
       ,AQTH.AQMName
       ,CASE  cco.InitialResult WHEN 'A1 Suitable and Complete' THEN 'Passed'
								WHEN 'A2 Suitable and Acceptable' THEN 'Passed'
								WHEN 'First time pass' THEN 'Passed'
								WHEN 'First time pass with feedback' THEN 'Passed'
										   ELSE CASE   WHEN cco.FinalWorkflow in ('Reject','Unsuitable advice') THEN 
															    CASE cco.FinalResult WHEN 'B Clarify' THEN 'Unsuitable advice'
																				WHEN 'C Potentially Unsuitable' THEN 'Unsuitable advice'
																				WHEN 'A3 Suitable but Defective'THEN 'Unsuitable advice'
																				WHEN 'Unclear action required'THEN 'Unsuitable advice'
																				WHEN 'Unsuitable advice'THEN 'Unsuitable advice'
																	ELSE 'Queried' END  
                     							ELSE 'Queried' END END AS Result
from mi_insight_CaseCheckOutcomes cco
join sa_insight_SalesCase saca on cco.Advice = saca.CASE_CaseReference 
join (Select distinct ATTL_ParentID, ATTl_AttributeID, ATTL_AttributeValue
		from sa_insight_AttributeLink atl
		inner join sa_insight_Attribute att on att.ATT_ID = atl.ATTL_AttributeID
		where ATT_Name = 'CASE.CLIENTFIRSTNAME') FirstNameATT
		on FirstNameATT.ATTL_ParentID = saca.CASE_ID
join (Select distinct ATTL_ParentID, ATTl_AttributeID, ATTL_AttributeValue
		from sa_insight_AttributeLink atl
		inner join sa_insight_Attribute att on att.ATT_ID = atl.ATTL_AttributeID
		where ATT_Name = 'CASE.CLIENTSURNAME') LastNameATT
		on LastNameATT.ATTL_ParentID = saca.CASE_ID
join (select distinct ProductShortName, RegulationCategory
			from dbo.mi_insight_ConfigProductTypeReplacement) ProdConfig
			on ProdConfig.ProductShortName = cco.Product
left join dbo.mi_aqt_ReportingHierarchy AQTH on AQTH.AdviserUID = cco.AdviserUID
where cco.AdviserUID is not null
and   cco.Submitted >= '01-DEC-2013'
AND   cco.Submitted>= DATEADD(mm,-12,dateadd(dd,0,datediff(dd,0,GETDATE())))
AND   saca.CASE_CaseReference != '0'
AND	  aqth.AdviserUID is not null
AND   isnull(aqth.SupervisorUID,BQMUID) = @SupervisorUID --amended 03.04.17 SI



	END
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     


GO
