CREATE PROCEDURE [logi].[pr_ringo_SupervisorSpanBreaches]
      @PtlCode		      varchar(255),
	  @SupervisorUID	  varchar (7)

AS 


set nocount on
/*AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
16.01.16    Sam C			  removed date conversion to VarChar for Date
							  For ticket #462419 - raised by Mike Shepherson, wants to be able to sort by date in Logi report
							  cannot do this with a varchar */

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
