GO

CREATE PROCEDURE [logi].[pr_ringo_SupervisorSpanCompetencyChecks280317]
      @PtlCode		      varchar(255),
	  @SupervisorUID	  varchar (7),
	  @Span				  varchar(20)

AS 


set nocount on

/*AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
16.01.17    Sam C			  removed date conversion to VarChar for Competency Date and Competency Date check
							  For ticket #463240 - raised by Mike Shepherson, wants to be able to sort by date in Logi report
							  cannot do this with a varchar - is null amended to set date to 01-01-1900
17.01.17	S Inglis		  Changed CTE tables to # temp tables to improve performance
28-3-17		S Inglis		  Additional code added to allow for switch between shallow 
							  and deep span			
10-4-17		S Inglis		  Addition of Supervisor name
9-5-17		S Inglis		  Update to Span selection to include supervisor UIDs 2,3,4,5,6 to
							  enable deep span view	
14-12-17	S Inglis		  Update to include Introduction/Disclosure competency check
/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/*/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'SupervisorSpanCompetencyChecks';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + cast (@SupervisorUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin


SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
--		, pop.BusinessUID
--		, pop.BusinessName
		, pop.UserID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span --update 9.5.17

select      Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            case when ab.ASB_RESULT = 2 then count (ab.ASB_RESULT) end as Failed, 
            case when ab.ASB_RESULT = 1 then count (ab.ASB_RESULT) end as Passed,
            ab.ASB_CompletedDate
into #Competence
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
where 1=1
--  and Attendee.UserUID = @AdviserUID
  and ASB_Status = 4 
--and       ass.ASS_Description = 'Competence Assessment ICOB'
--and         trk.TCT_Description = 'DT14 - Full Competence'
and (ass.ASS_Description like 'Competence%' or ass.ASS_Description like 'Introduction/Disclosure')
and ASB_CompletedDate > DATEADD(year,-1,getdate())
Group by	Attendee.UserGUID,
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            ab.ASB_Result, 
            ab.ASB_CompletedDate

 select
ASS_Description
,ASB_AttendeeID
,COUNT(Failed) as Failed
,COUNT(passed) as Passed
into #Comp
from #Competence
Group by ASS_Description,ASB_AttendeeID

Select
ASB_AttendeeID,
ASS_description,
case when Failed = 1 and Passed = 1 then 'Yes' else 'N/A' end as 'Fail and Subsequent Pass'
into #FandB
from #Comp


			select      
            ab.ASB_AttendeeID,
            ass.ASS_Description,
            case when fandb.[Fail and Subsequent Pass] = 'Yes' then 'Pass' else (case when ab.ASB_RESULT = 2 then 'Fail' when ab.ASB_Result = 1 then 'Pass' end)end as Result,
            ab.ASB_CompletedDate,
            fandb.[Fail and Subsequent Pass]
into #CompAss
FROM        mi_insight_UserHierarchy AS Attendee 
            inner join sa_insight_AssessmentBooking ab ON ab.ASB_AttendeeID = Attendee.UserGUID
            inner JOIN sa_insight_AssessmentEvent AS ae ON ab.ASB_EventID = ae.ASE_ID
            inner JOIN sa_insight_Assessment AS ass ON ae.ASE_TypeID = ass.ASS_ID
            left  JOIN #FandB fandb on fandb.ASS_Description = ass.ASS_Description and ab.ASB_AttendeeID = fandb.ASB_AttendeeID
where 1=1
--			and Attendee.UserUID = @AdviserUID
			and ASB_Status = 4 
			and (ass.ASS_Description like 'Competence%' or ass.ASS_Description like 'Introduction/Disclosure')
			and ASB_CompletedDate > DATEADD(year,-1,getdate())
Group by	ab.ASB_AttendeeID,
            ass.ASS_Description,
            case when fandb.[Fail and Subsequent Pass] = 'Yes' then 'Pass' else (case when ab.ASB_RESULT = 2 then 'Fail' when ab.ASB_Result = 1 then 'Pass' end)end, 
            ab.ASB_CompletedDate,
            fandb.[Fail and Subsequent Pass]

Select	 1 as QueryNumber,
		 'COB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(cobcomp.UC_DateAchieved, '1900-01-01 00:00:00.000') As CompetencyDate,
		 case when ca.ASB_CompletedDate is null then '1900-01-01 00:00:00.000' else ca.ASB_CompletedDate end as CompetencyDateCheck,
		 case when ca.Result is null then 'N/A' else ca.Result end as 'Outcome',
		 ca.[Fail and Subsequent Pass] as FailandSubsequentPass,
		 marh.AdviserUID,
		 marh.Adviser,
		 marh.BusinessUID,
		 marh.FirmName,
		 uh.SupervisorName
		-- 'COMPETENCY DATE CHECK'
		-- 'COMPETENCY OUTCOME'
		-- 'FAIL AND SUB PASS'
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                      And cobcomp.UC_BusinessArea = 3
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                                        And cobcode.Code_CodeType = 55
join #CompAss ca on ca.ASB_AttendeeID = marh.AdviserGUID and ca.ASS_Description = 'Competence Assessment COBS' 
join #Span span on span.UserUID = marh.AdviserUID 
join mi_insight_UserHierarchy uh on uh.UserUID = span.UserUID
--join mi_insight_UserHierarchy uh on uh.UserUID = marh.AdviserUID                                                     
where 1=1
--And	  marh.AdviserUID  = @AdviserUID 
--And   marh.BusinessUID = @FirmName 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') = 
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
                  From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
And	  ISNULL(ca.ASB_CompletedDate, '01-JAN-1900') =
	  ISNULL((Select Max (ca1.ASB_CompletedDate)
				From #CompAss ca1
				Where ca1.ASB_AttendeeID = ca.ASB_AttendeeID
				and ca1.ASS_Description = 'Competence Assessment COBS'), '01-JAN-1900')

Union

Select 2 as QueryNumber,
		'MCOB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(cobcomp.UC_DateAchieved, '1900-01-01 00:00:00.000') As CompetencyDate,
		 case when ca.ASB_CompletedDate is null then '1900-01-01 00:00:00.000' else ca.ASB_CompletedDate end as CompetencyDateCheck,
		 case when ca.Result is null then 'N/A' else ca.Result end as 'Outcome',
		 ca.[Fail and Subsequent Pass] as FailandSubsequentPass,
		 marh.AdviserUID,
		 marh.Adviser,
		 marh.BusinessUID,
		 marh.FirmName,
		 uh.SupervisorName
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                                        And cobcomp.UC_BusinessArea = 2
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                                        And cobcode.Code_CodeType = 55
join #CompAss ca on ca.ASB_AttendeeID = marh.AdviserGUID and ca.ASS_Description = 'Competence Assessment MCOB'
join #Span span on span.UserUID = marh.AdviserUID 
join mi_insight_UserHierarchy uh on uh.UserUID = span.UserUID
--join mi_insight_UserHierarchy uh on uh.UserUID = marh.AdviserUID
where 1=1
--and   marh.AdviserUID  = @AdviserUID 
--And   marh.BusinessUID = @FirmName 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
              From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
And	  ISNULL(ca.ASB_CompletedDate, '01-JAN-1900') =
	  ISNULL((Select Max (ca1.ASB_CompletedDate)
				From #CompAss ca1
				Where ca1.ASB_AttendeeID = ca.ASB_AttendeeID
				and ca1.ASS_Description = 'Competence Assessment MCOB'), '01-JAN-1900')
Union
Select   3 as QueryNumber,
		 'ICOB' As Licence,
         IsNull(cobcode.Code_Description, 'Competency: N/A') As Competency,
         IsNull(cobcomp.UC_DateAchieved, '1900-01-01 00:00:00.000') As CompetencyDate,
		 case when ca.ASB_CompletedDate is null then '1900-01-01 00:00:00.000' else ca.ASB_CompletedDate end as CompetencyDateCheck,
		 case when ca.Result is null then 'N/A' else ca.Result end as 'Outcome',
		 ca.[Fail and Subsequent Pass] as FailandSubsequentPass,
	     marh.AdviserUID,
		 marh.Adviser,
		 marh.BusinessUID,
		 marh.FirmName,
		 uh.SupervisorName
From mi_aqt_ReportingHierarchy marh
Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
                                                        And cobcomp.UC_BusinessArea = 1
Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
                                      And cobcode.Code_CodeType = 55
join #CompAss ca on ca.ASB_AttendeeID = marh.AdviserGUID and ca.ASS_Description = 'Competence Assessment ICOBS'
join #Span span on span.UserUID = marh.AdviserUID 
join mi_insight_UserHierarchy uh on uh.UserUID = span.UserUID
--join mi_insight_UserHierarchy uh on uh.UserUID = marh.AdviserUID
Where 1=1
--And	  marh.AdviserUID  = @AdviserUID 
--And   marh.BusinessUID = @FirmName 
And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
      IsNull((Select Max(cobcomp1.UC_DateAchieved)
                    From sa_insight_UserCompetency cobcomp1
                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
And	  ISNULL(ca.ASB_CompletedDate, '01-JAN-1900') =
	  ISNULL((Select Max (ca1.ASB_CompletedDate)
				From #CompAss ca1
				Where ca1.ASB_AttendeeID = ca.ASB_AttendeeID
				and ca1.ASS_Description = 'Competence Assessment ICOBS'), '01-JAN-1900')
UNION --Added 14/12/17 SI
Select   4 as QueryNumber,
		 'Introduction/Disclosure' As Licence,
         'Competency: N/A' As Competency,
         '1900-01-01 00:00:00.000' As CompetencyDate,
		 case when ca.ASB_CompletedDate is null then '1900-01-01 00:00:00.000' else ca.ASB_CompletedDate end as CompetencyDateCheck,
		 case when ca.Result is null then 'N/A' else ca.Result end as 'Outcome',
		 ca.[Fail and Subsequent Pass] as FailandSubsequentPass,
	     marh.AdviserUID,
		 marh.Adviser,
		 marh.BusinessUID,
		 marh.FirmName,
		 uh.SupervisorName
From mi_aqt_ReportingHierarchy marh
--Join sa_insight_UserCompetency cobcomp On cobcomp.UC_OwnerID = marh.AdviserGUID 
--                                                        And cobcomp.UC_BusinessArea = 1
--Join sa_insight_CodeDescription cobcode On cobcode.Code_Code = cobcomp.UC_CompetencyLevel 
--                                      And cobcode.Code_CodeType = 55
join #CompAss ca on ca.ASB_AttendeeID = marh.AdviserGUID and ca.ASS_Description = 'Introduction/Disclosure'
join #Span span on span.UserUID = marh.AdviserUID 
join mi_insight_UserHierarchy uh on uh.UserUID = span.UserUID
--join mi_insight_UserHierarchy uh on uh.UserUID = marh.AdviserUID
Where 1=1
--And	  marh.AdviserUID  = @AdviserUID 
--And   marh.BusinessUID = @FirmName 
--And   cobcomp.UC_Status  = '0' -- '0' UC_STATUS indicates active
--And   IsNull(cobcomp.UC_DateAchieved, '01-JAN-1900') =
--      IsNull((Select Max(cobcomp1.UC_DateAchieved)
--                    From sa_insight_UserCompetency cobcomp1
--                    Where cobcomp1.UC_OwnerID = cobcomp.UC_OwnerID 
--                    And   cobcomp1.UC_BusinessArea = cobcomp.UC_BusinessArea
--                    And   cobcomp1.UC_Status  = '0'), '01-JAN-1900')
And	  ISNULL(ca.ASB_CompletedDate, '01-JAN-1900') =
	  ISNULL((Select Max (ca1.ASB_CompletedDate)
				From #CompAss ca1
				Where ca1.ASB_AttendeeID = ca.ASB_AttendeeID
				and ca1.ASS_Description = 'Introduction/Disclosure'), '01-JAN-1900')
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


