/**********************************************************************************************
Name  : [logi].[pr_Ringo_SupervisorSpanDetails]
Author      : S Inglis
Date  : 10/03/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Supervisor Span Details" and is found on the "BQM MI" 
              menu. This report displays: 
              - Shallow and Deep Span details for the supervisor



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_ringo_SupervisorSpanDetails] 'ptl91371', 'Logi','1002714'

AMENDMENT HISTORY
=================
Date        Author           Description
----        ------           -----------
23-3-17		S Inglis		 Additional code added to allow for switch between shallow 
							 and deep span
9-5-17		S Inglis		Update to Span selection to include supervisor UIDs 2,3,4,5,6 to
							enable deep span view	
11.10.18	S Campbell		updated CPD CTE due to Insight schema change - SPS hours no longer
							identified by CPD Award Log table category - now join to			
							Statement of Professional Standing table to identify SPS hours	
***********************************************************************************************/
CREATE PROCEDURE [logi].[pr_ringo_SupervisorSpanDetails280317_NEW]
      @PtlCode		      varchar(255),
	  @SupervisorUID	  varchar (7),
	  @Span				  varchar(20)

AS 


set nocount on


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'SupervisorSpanDetails';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + cast (@SupervisorUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)
--or @lc_UserUid ='254' )  --added for testing  

Begin

 SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
		, pop.BusinessUID
		, pop.BusinessName
		, pop.UserID
		, pop.COBCompetencyCode
		, @SupervisorUID as SupervisorUID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span --update 9.5.17

select
 pop.UserUID
,pop.UserName
,pop.UserJobTitleDesc
,pop.BusinessUID
,pop.BusinessName
,span.SupervisorUID
into #AdviserNumbers
from mi_insight_KPIPopulation pop 
join #Span span on pop.UserUID = span.UserUID
where UserJobTitleDesc != 'PP'

--CTE_CPDTotals as
--(
SELECT  count (distinct span.UserUID) as NumberofAdvisers
	    ,sum(CPDL_Awarded)/60 as TotalCPDHours
		,SupervisorUID
  into #CPDTotals
  FROM prod_zurich_openwork_datawarehouse.dbo.sa_insight_CPDAwardLog cpdal
  JOIN #Span span on span.UserID = cpdal.CPDL_UserID and span.COBCompetencyCode is not null
  join mi_insight_KPIPopulation pop on pop.UserID = cpdal.CPDL_UserID
  join dbo.sa_insight_StatementOfProfessionalStanding sps on sps.SPS_UserID = pop.UserID --  Added due to Insight db schema change
  where 1=1
  --and CPDL_UserID = 'BCA580B9-9595-4795-933E-00B5B3880E9E'
  and CPDL_Status = 1
  --and CPDL_Category = 1  --  Removed due to Insight db schema change
  and sps.SPS_Status = 2  --  Added due to Insight db schema change
  and CPDL_PlannedDate between dateadd(year,-1,getdate()) and getdate()
  Group by SupervisorUID
  --),
 
-- CTE_CRGReferral as
-- (
select
referraldate
,AdviserUID
,Adviser
,Reason
,span.SupervisorUID
into #CRGReferral
from tandc.crg
join #Span span on span.UserUID = crg.AdviserUID
where Formal = 'Y'
--),

-- CTE_MysteryShops as
--(
select
EnterpriseName
,EnterpriseUID
,PartnerName
,PartnerUID
,ScenarioType
,GradingOfShop
,DateFinalReportIssued
,span.SupervisorUID
into #MysteryShop
from tandc.MysteryShop ms
join #Span span on span.UserUID = ms.PartnerUID
where convert(datetime,DateFinalReportIssued,101) > dateadd(year,-1,getdate())
--),

--CTE_QualityCalls as
--(
select
 qc.UID
,spn.SupervisorUID
 into #QualityCalls
 From tandC.Quality_Calls qc
 join #Span spn on spn.UserUID = qc.UID
 where qc.OutcomeDate >= dateadd(year,-1,getdate())
-- ),

--CTE_UnlicensedSales as
--(
select
AdviserUID
,AdviserName
,span.BusinessUID
,span.BusinessName
,unlics.CustomerName
,ProductSold as Product
,span.SupervisorUID 
,DateofULS as Date
,ReasonforUnlicensedSaleLDComments as Reason 
into #UnlicensedSales
from TandC.UnlicensedSales unlics
join #Span span on span.UserUID = unlics.AdviserUID
--),

--CTE_Breaches as
--(
select 
 sqmp.Code
,sqmp.Name
,span.BusinessUID
,span.BusinessName
,Description
,Points
,[Expiry Date]
,span.SupervisorUID
into #Breaches
from RPT_SalesQualityMatrixPoints sqmp
join #Span span on span.UserUID = sqmp.Code
where Description != 'TOTAL POINTS'
--),

--CTE_UnsubmittedSales as
--(
Select
Firm,
BUID,
Adviser,
UID
,ClientName
,PolicyNumber
,DateofBreach
,span.SupervisorUID
into #UnsubmittedSales
From TandC.UnsubmittedBusiness
join #Span span on span.UserUID = UID
Where DateofBreach > DATEADD(year,-1,getdate())
--),

--CTE_FinancialIncentives as
--(
select  
fin.BusinessUID
,FirmName
,TypeofSchemeFinancialIncentive
,OverseasTravel
,QualityOverlay
,Outcome
,span.SupervisorUID
into #FinancialIncentives
from tandc.financialincentives fin
join #Span span on span.BusinessUID = fin.BusinessUID
--)

  Select
  count(distinct san.UserUID) as AdviserCount,
  'View' as SPSDetails,
  cpd.TotalCPDHours/cpd.NumberofAdvisers as AverageCPDHours,
  'View' as '100PercentChecking',
  case when ms.supervisoruid is null then 'No' else 'Yes' end as MysteryShops,
  case when us.SupervisorUID is null then 'No' else 'Yes' end as TrueUnlicensedSales,
  case when cr.SupervisorUID is null then 'No' else 'Yes' end as CRGReferrals,
  case when br.SupervisorUID is null then 'No' else 'Yes' end as Breaches,
  case when ub.SupervisorUID is null then 'No' else 'Yes' end as UnsubmittedSales,
  case when fi.SupervisorUID is null then 'No' else 'Yes' end as FinancialIncentives,
  'View' as BusinessMixMCOBDetails,
  'View' as AdviserCasesChecked,
  'View' as AdviserSalesSplit,
  'View' as AdviserCOBPlatformSplit,
  'View' as AdviserCOBProductLineSplit,
  case when qc.SupervisorUID is null then 'No' else 'Yes' end as QualityCalls
  from #AdviserNumbers san
  left join #CPDTotals cpd on cpd.SupervisorUID = san.SupervisorUID
  left join #MysteryShop ms on ms.SupervisorUID = san.SupervisorUID
  left join #UnlicensedSales us on san.SupervisorUID = us.SupervisorUID
  left join #CRGReferral cr on cr.SupervisorUID = san.SupervisorUID
  left join #Breaches br on br.SupervisorUID = san.SupervisorUID
  left join #UnsubmittedSales ub on ub.SupervisorUID = san.SupervisorUID 
  left join #FinancialIncentives fi on fi.SupervisorUID = san.SupervisorUID
  left join #QualityCalls qc on qc.SupervisorUID = san.SupervisorUID
  group by cpd.TotalCPDHours, cpd.NumberofAdvisers, ms.SupervisorUID,cr.SupervisorUID,
		   br.SupervisorUID, ub.SupervisorUID, fi.SupervisorUID, us.SupervisorUID, qc.SupervisorUID
 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


