CREATE PROCEDURE [logi].[pr_Ringo_SupervisorSpanRedKPIs]
                @PtlCode			varchar(10)
               ,@SupervisorUID	    varchar(7)
               ,@Span				varchar(20)

AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_Ringo_SupervisorSpanRedKPIs]
Author      : S Inglis
Date  : 12/04/2017

Purpose     : This report is used for Project Ringo. The recipients are:
                  1) T&C Team

              The report name is "Supervisor Span Red KPIs" and is found on the "BQM MI" 
              menu. This report displays: 
              - Red KPI's for Supervisors Deep and Shallow Span for 
						-	Advisers over 3 months
						-	Firms over 6 months (2 quarterly runs)
						-	Supervisors over 3 months


              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_Ringo_SupervisorSpanRedKPIs]  'ptl91371', '1001871','Deep Span'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------
9-5-17		S Inglis	Update to Span selection to include supervisor UIDs 2,3,4,5,6 to
						enable deep span view	
7-11-17		S Inglis	Update to link KPI type to user type
***********************************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'Supervisor Span Red KPIs';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + cast (@SupervisorUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
		--, pop.BusinessUID
		--, pop.BusinessName
		, pop.UserID
		,uh1.UserJobTitleCodeBQM as UserBQM
--		,pop.COBCompetencyCode
		,case when uh.UserUID = @SupervisorUID then 'Shallow Span' when uh1.BQMUID = @SupervisorUID then 'Deep Span' end as SpanType
		,@SupervisorUID as SupervisorUID
		,uh3.UserJobTitleCodeBQM
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 left join mi_insight_UserHierarchy uh3 on uh3.UserUID = @supervisorUID
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span --update 9.5.17
 Union
select dist.DIST_ExternalID as BusinessUID
      ,dist.DIST_CompanyName as BusinessName
	  ,dist.DIST_ID
	  ,uh.UserJobTitleCodeBQM as UserBQM
	  ,'Shallow Span' as SpanType
	  ,uh.UserUID as FirmSupervisorUID
	  ,uh.UserJobTitleCodeBQM
	  --,uh.AQMUID
	  --,uh.AQMName
from sa_insight_Distributor dist
join sa_insight_UserPositionLink upl on upl.UPSL_ChildUserPositionID = dist.DIST_ID
join sa_insight_UserPosition up on up.UPS_ID = upl.UPSL_ParentUserPositionID
join mi_insight_UserHierarchy uh on uh.UserGUID = up.UPS_UserID
--join #Span spn on spn.UserUID = uh.UserUID and spn.UserBQM is not null
where UPSL_DateTo is null
and 'Shallow Span' = @Span
and uh.UserUID = @SupervisorUID
 

 select distinct
KPI_ID,
KPI_Name,
KPI_Type --Update 7.11.17
into #KPIName
from sa_insight_KPI
--where KPI_Type in (1,2,3)

select distinct
pop.UserID,
pop.UserUid,
pop.UserName,
uh.SupervisorName,
uh.BQMName,
AQMUID,
AQMName
into #User
from mi_insight_KPIPopulation pop
join mi_insight_UserHierarchy uh on uh.UserGUID = pop.UserID
join #Span spn on spn.UserUID = pop.UserUID
where UserJobTitleCode in (4,42)


select dist.DIST_ExternalID as BusinessUID
      ,dist.DIST_CompanyName as BusinessName
	  ,dist.DIST_ID
	  ,uh.UserUID as FirmSupervisorUID
	  ,uh.UserName as FirmSupervisorName
	  ,uh.AQMUID
	  ,uh.AQMName
into #Firm
from sa_insight_Distributor dist
join sa_insight_UserPositionLink upl on upl.UPSL_ChildUserPositionID = dist.DIST_ID
join sa_insight_UserPosition up on up.UPS_ID = upl.UPSL_ParentUserPositionID
join mi_insight_UserHierarchy uh on uh.UserGUID = up.UPS_UserID
join #Span spn on spn.UserUID = dist.DIST_ExternalID and spn.UserJobTitleCodeBQM is not null
where 1=1
--and UserUID = '1010760'
and UPSL_DateTo is null

select distinct
pop.UserID,
pop.UserUid,
pop.UserName,
SupervisorUserName,
AQMUID,
AQMName
into #Supervisor
from mi_insight_KPIPopulation pop
join mi_insight_UserHierarchy uh on uh.UserGUID = pop.UserID
join #Span spn on spn.UserUID = pop.UserUID and spn.UserJobTitleCodeBQM is not null
where UserJobTitleCode in (7,8,9)

select
'Adviser' as KPIType,
 AQMName,
 BQMName,
 SupervisorName as Supervisor,
 --kpi.KPID_KPI_ID,
 kpin.KPI_Name,
 --kpi.KPID_UserID,
 uh.username as Name,
 KPI.KPID_Date,
 case when kpimi.ReasonDesc IS NOT NULL THEN cd.Code_Description + ' - ' + kpimi.ReasonDesc ELSE CD.Code_Description END as RedReason
 from sa_insight_KPIResult KPI
 join #User uh on uh.UserID = KPID_UserID
 join #KPIName kpin on kpin.KPI_ID = kpi.KPID_KPI_ID and kpin.KPI_Type = 1 --Update 7.11.17
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 --join #Span spn on spn.UserUID = uh.UserUID
 left join mi_insight_KPIResult kpimi on kpimi.KPID_KPI_ID = kpi.KPID_KPI_ID and kpimi.KPID_UserID = kpi.KPID_UserID
 where KPI.KPID_Date >= dateadd(month,-3,convert(date,getdate()))
 and (cd.Code_Description = 'Red') --amended 20-3-17
 Union
  select
 'Firm' as KPIType,
  AQMName,
 FirmSupervisorName as Supervisor,
 Null as Supervisor,
 -- kpi.KPID_KPI_ID,
 kpin.KPI_Name,
 --kpi.KPID_UserID,
 uh.BusinessName as Name,
 KPI.KPID_Date,
 case when kpimi.ReasonDesc IS NOT NULL THEN cd.Code_Description + ' - ' + kpimi.ReasonDesc ELSE CD.Code_Description END as RedReason
 from sa_insight_KPIResult KPI
 join #Firm uh on uh.DIST_ID = KPID_UserID 
 join #KPIName kpin on kpin.KPI_ID = kpi.KPID_KPI_ID and kpin.KPI_Type = 9 --Update 7.11.17
 --join #Span spn on spn.SupervisorUID = uh.FirmSupervisorUID and spn.UserJobTitleCodeBQM is not null
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
 left join mi_insight_KPIResult kpimi on kpimi.KPID_KPI_ID = kpi.KPID_KPI_ID and kpimi.KPID_UserID = kpi.KPID_UserID
 where KPI.KPID_Date >= dateadd(month,-6,convert(date,getdate()))
  and (cd.Code_Description = 'Red')
 Union
  select
 'Supervisor' as KPIType,
  AQMName,
 SupervisorUserName as Supervisor,
 null as Supervisor,
 --kpi.KPID_KPI_ID,
 kpin.KPI_Name,
 --kpi.KPID_UserID,
 uh.username as Name,
 KPI.KPID_Date,
 case when kpimi.ReasonDesc IS NOT NULL THEN cd.Code_Description + ' - ' + kpimi.ReasonDesc ELSE CD.Code_Description END as RedReason
 from sa_insight_KPIResult KPI
 join #Supervisor uh on uh.UserID = KPID_UserID
 join #KPIName kpin on kpin.KPI_ID = kpi.KPID_KPI_ID and kpin.KPI_Type = 4 --Update 7.11.17
 join sa_insight_CodeDescription cd on cd.Code_Code = KPID_Status and cd.Code_CodeType = 655
-- join #Span span on span.UserUID = uh.UserUID and span.UserJobTitleCodeBQM is not null
 left join mi_insight_KPIResult kpimi on kpimi.KPID_KPI_ID = kpi.KPID_KPI_ID and kpimi.KPID_UserID = kpi.KPID_UserID
 where KPI.KPID_Date >= dateadd(month,-3,convert(date,getdate()))
  and (cd.Code_Description = 'Red') 
 order by uh.UserName, kpin.KPI_Name, KPID_Date;


 
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
