 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span --update 9.5.17

select pop.BusinessUID
       ,pop.BusinessName
	   ,uh.SupervisorName
       ,pop.UserUID
       ,pop.UserName
       ,polm.START_DATE as DateSubmitted
       ,poli.SaleID as AdviceID
       ,potr.PolicyID
       ,case potr.AdminMethod when 'A' Then 'Advised'
							  when 'V' Then 'Advised'
                              when 'F' Then 'Advised'
                              when 'G' Then 'Advised'
                              else 'Non Advised' end as AdminMethod
       ,case plans.PlanCategory WHEN 'MORT' Then 'MCOB'
                                WHEN 'PROTECT' THEN 'ICOB'
                                WHEN 'PEN&INV' THEN 'COBS' end as PlanCategory
      ,polm.PolicyRef
      ,plans.DESCN             
      ,case isnull(mphi.RDRType,'OFPLAT') when 'ONPLAT' then 'On Platform'
                                                        else 'Off Platform' end as RDRType
      ,clie.FIRSTNAMES + ' ' + clie.NAME as ClientName
      ,replace(replace(copr.Description,'RDR On -',''),'RDR Off -','') + 
       case isnull(mpsu.MortgageCategoryID,8865) when 8866 then ' - Buy To Let'
                                                           else '' end as ProdDescr
      ,copr.CompanyCode
      ,case isnull(poli.IsLatWrapper,99) when 1 then 'Yes' when 0 then 'No' else 'N/A' end as IncludedInLatWrapper
      ,CASE isnull(mphi.RDRType,'OFFPLAT') WHEN 'OFFPLAT' THEN case isnull(srle.OffPlatformRecommendReplacingExistingArrangements,99) when 1 Then 'Yes' When 0 then 'No' else 'N/A' end else 'N/A' end as OffPlatformReplacement 
      ,case plans.PlanCategory when 'PROTECT' then  case isnull((select MIN(ffmem.ReplacedAsPartOfAdviceID)
        from   [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_FactFindProtectionsExistingProtections] ffmem
        where  ffmem.SaleId = poli.SaleID),20) when '19' then 'Yes' else 'No' end else 'N/A' end as ProtectionReplacement 
from   #Span miuh_sup
join   mi_insight_KPIPopulation pop on pop.UserID = miuh_sup.UserID
join   mi_insight_UserHierarchy uh  on uh.UserUID = miuh_sup.UserUID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_policyTransactions] potr on potr.AgentCode = pop.UserUID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_Policies] polm on polm.POL_NUM = potr.PolicyID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_expectation] pacc on pacc.TransactionID = potr.ID
left join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_PolicyAgentsB30] pb30 on pb30.PolicyID         = polm.POL_NUM
                                                                                 and pb30.SellingAgentCode = potr.AgentCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_PaymentsPending] agmf on agmf.PACC_ID = pacc.ID
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_PLANS] plans on plans.CODE = polm.PLAN_CODE
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodePlanCategories] cpca on cpca.Code = plans.PlanCategory
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodeProducts] copr on copr.Code = polm.ProductCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_ProductHierarchy] mphi on mphi.ProductCode = polm.ProductCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_CLIENT_1] clie on polm.CLIENT_NUM = clie.CLIENT_NUM
left join Policy.sa_ows_MortgageProductSummary mpsu on mpsu.PolicyID = polm.PolicyRef
left join [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_policies] poli on poli.policyId = polm.PolicyRef
left join [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_SrgLetter] srle on srle.SaleID = poli.SaleID
																			and   srle.OffPlatformRecommendReplacingExistingArrangements = 1
Where  
--miuh_sup.UserUID= @SupervisorUID  and    
pop.UserJobTitleCode = 4
and    agmf.CommissionType = 1
and    potr.AdminMethod != 'X'
and    agmf.TransactionDate >= DATEADD(mm,-12,GETDATE()) 
group by pop.BusinessUID
        ,pop.BusinessName
		,uh.SupervisorName
        ,pop.UserUID
        ,pop.UserName
        ,plans.PlanCategory
        ,potr.PolicyID
        ,polm.PolicyRef
        ,plans.DESCN
        ,copr.CompanyCode
        ,poli.SaleID
        ,polm.START_DATE
        ,case isnull(poli.IsLatWrapper,99) when 1 then 'Yes' when 0 then 'No' else 'N/A' end
        ,case potr.AdminMethod when 'A' Then 'Advised'
							  when 'V' Then 'Advised'
                              when 'F' Then 'Advised'
                              when 'G' Then 'Advised'
                              else 'Non Advised' end
        ,clie.FIRSTNAMES 
        ,clie.NAME 
        ,replace(replace(copr.Description,'RDR On -',''),'RDR Off -','') + 
         case isnull(mpsu.MortgageCategoryID,8865) when 8866 then ' - Buy To Let'
                                                           else '' end
        ,case isnull(mphi.RDRType,'OFPLAT') when 'ONPLAT' then 'On Platform'
                                                        else 'Off Platform' end 
      ,CASE isnull(mphi.RDRType,'OFFPLAT') WHEN 'OFFPLAT' THEN case isnull(srle.OffPlatformRecommendReplacingExistingArrangements,99) when 1 Then 'Yes' When 0 then 'No' else 'N/A' end else 'N/A' end         
      Order by  pop.BusinessName
        ,pop.UserName
        ,polm.PolicyRef
        ;

END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_Ringo_SupervisorSpanSalesTotal280317]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [logi].[pr_Ringo_SupervisorSpanSalesTotal280317]
                @PtlCode      varchar(10)
               ,@SupervisorUID      varchar(7)
               ,@Span			varchar(20)


AS BEGIN
set nocount on
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

28-3-17		S Inglis	Additional code added to allow for switch between shallow 
						and deep span	
10-4-17		S Inglis	Addition of Supervisor name															
9-5-17		S Inglis	Update to Span selection to include supervisor UIDs 2,3,4,5,6 to
						enable deep span view	
*******************************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY

declare           @ErrorMessage                 varchar(500),
                  @ReportName                   varchar(200),
                  @StoredProcName               varchar(200),
                  @StoredProcParams				varchar(4000),
                  @ErrMsg                       nvarchar(4000),
                  @LastAuditID                  int,
                  @ErrNum                       int,
                  @ErrSev                       int,
                  @ErrLine                      int,
				  @StartDate					datetime,
				  @EndDate						datetime 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

set @ReportName               = 'pr_Ringo_SupervisorSpanSalesTotal';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + @SupervisorUID;
set @LC_SupervisorPermission  =  0;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output

EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
--print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
--print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
--print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  
BEGIN

 SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
--		, pop.BusinessUID
--		, pop.BusinessName
		, pop.UserID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span; --update 9.5.17

with cte_PrdSum as 
(select pop.BusinessUID
       ,pop.BusinessName
	   ,uh.SupervisorName
       ,pop.UserUID
       ,pop.UserName
       ,plans.PlanCategory
       ,potr.PolicyID
       ,sum(agmf.AMOUNT_PAID) AMOUNT_PAID
       ,case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                       ,'1006886','1011542','1011587','1011623','1011629'
                                       ,'1011630','1011631','1011632','1011633','1011634','1011635') then 'Openwork'
        else 'Adviser' end  as AgentDistribution
from   #Span miuh_sup  
join   mi_insight_KPIPopulation pop on pop.UserID = miuh_sup.UserID
join   mi_insight_UserHierarchy uh on uh.UserUID = miuh_sup.UserUID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_policyTransactions] potr on potr.AgentCode =miuh_sup.UserUID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_Policies] polm on polm.POL_NUM = potr.PolicyID
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_expectation] pacc on pacc.TransactionID = potr.ID
left join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_PolicyAgentsB30] pb30 on pb30.PolicyID         = polm.POL_NUM
                                                                                 and pb30.SellingAgentCode = potr.AgentCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_PaymentsPending] agmf on agmf.PACC_ID = pacc.ID
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_PLANS] plans on plans.CODE = polm.PLAN_CODE
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodePlanCategories] cpca on cpca.Code = plans.PlanCategory
join   [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_CodeProducts] copr on copr.Code = polm.ProductCode
join   [prod_zurich_openwork_datawarehouse].[dbo].[mstt_ProductHierarchy] mphi on mphi.ProductCode = polm.ProductCode
Where  pop.UserJobTitleCode = 4
and    agmf.CommissionType = 1
and    potr.AdminMethod != 'X'
and    agmf.TransactionDate >= DATEADD(mm,-12,GETDATE()) 
--and    potr.CreateDateTime    >= DATEADD(mm,-12,GETDATE()) 
group by pop.BusinessUID
        ,pop.BusinessName
		,uh.SupervisorName
        ,pop.UserUID
        ,pop.UserName
        ,plans.PlanCategory
        ,potr.PolicyID
        ,case when agmf.AGENT_CODE in ( '1011543','10002','10004','10005','1006124'
                                       ,'1006886','1011542','1011587','1011623','1011629'
                                       ,'1011630','1011631','1011632','1011633','1011634','1011635') then 'Openwork'
        else 'Adviser' end
) 
select cte_PrdSum.BusinessUID
      ,cte_PrdSum.BusinessName
	  ,cte_PrdSum.SupervisorName
      ,cte_PrdSum.UserUID
      ,cte_PrdSum.UserName
      ,SUM(case cte_PrdSum.PlanCategory when 'MORT' then case cte_PrdSum.AgentDistribution when 'Adviser' then 1 else 0 end else 0 end) as MortgageCount
      ,SUM(case cte_PrdSum.PlanCategory when 'MORT' then case cte_PrdSum.AgentDistribution when 'Adviser' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as MortgageAgentAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'MORT' then case cte_PrdSum.AgentDistribution when 'Openwork' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as MortgageOpenworkAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PEN&INV' then case cte_PrdSum.AgentDistribution when 'Adviser' then 1 else 0 end else 0 end) as PenInvCount
      ,SUM(case cte_PrdSum.PlanCategory when 'PEN&INV' then case cte_PrdSum.AgentDistribution when 'Adviser' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as PenInvAgentAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PEN&INV' then case cte_PrdSum.AgentDistribution when 'Openwork' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as PenInvOpenworkAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PROTECT' then case cte_PrdSum.AgentDistribution when 'Adviser' then 1 else 0 end else 0 end) as ProtectionCount
      ,SUM(case cte_PrdSum.PlanCategory when 'PROTECT' then case cte_PrdSum.AgentDistribution when 'Adviser' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as ProtectionAgentAmount
      ,SUM(case cte_PrdSum.PlanCategory when 'PROTECT' then case cte_PrdSum.AgentDistribution when 'Openwork' then cte_PrdSum.AMOUNT_PAID else 0 end else 0 end) as ProtectionOpenworkAmount
from cte_PrdSum
where cte_PrdSum.PlanCategory in ('MORT','PEN&INV','PROTECT')
group by cte_PrdSum.BusinessUID
        ,cte_PrdSum.BusinessName
        ,cte_PrdSum.UserUID
        ,cte_PrdSum.UserName
		,cte_PrdSum.SupervisorName
order by cte_PrdSum.BusinessName, cte_PrdSum.UserName
;
END
ELSE
BEGIN
Print 'Access Denied'
END  

END TRY

BEGIN CATCH 

      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
      
END CATCH
END

GO
/****** Object:  StoredProcedure [logi].[pr_ringo_SupervisorSpanSPS280317]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [logi].[pr_ringo_SupervisorSpanSPS280317]
      @PtlCode		      varchar(255),
	  @SupervisorUID	  varchar (7),
	  @Span				  varchar(20)

AS 


set nocount on
/******************************************************************************************


AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

28-3-17		S Inglis	Additional code added to allow for switch between shallow 
						and deep span		
10-4-17		S Inglis	Addition of Supervisor Name														
9-5-17		S Inglis	Update to Span selection to include supervisor UIDs 2,3,4,5,6 to
						enable deep span view	
*******************************************************************************************/

/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);
DECLARE			  @lc_UserJobTitleCodeHO		 int;
DECLARE			  @lc_UserJobTitleCodePartner	 int;
DECLARE			  @lc_UserJobTitleCodeSupervisor int;
DECLARE			  @lc_UserJobTitleCodeBQM		 int;
Declare			  @LC_SupervisorPermission		 int;

print 'setting parameters';
set @ReportName               = 'SupervisorSpanSPS';
set @StoredProcName           = object_name(@@procid);
set @StoredProcParams         = '@SupervisorUID = ' + cast (@SupervisorUID as varchar(7));
set @LC_SupervisorPermission  =  0;
print @StoredProcParams;

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
                                                                --  @StoredProcParams, @LastAuditID output
EXEC  @return_value = logi.pr_Ringo_UserSecurity   @PtlCode, 
                                                   @UserUid=@lc_UserUid OUTPUT,
                                                   @UserName=@lc_UserName OUTPUT,
                                                   @UserJobTitleCodeHO=@lc_UserJobTitleCodeHO OUTPUT ,
                                                   @UserJobTitleCodePartner=@lc_UserJobTitleCodePartner OUTPUT,
                                                   @UserJobTitleCodeSupervisor=@lc_UserJobTitleCodeSupervisor OUTPUT,
                                                   @UserJobTitleCodeBQM=@lc_UserJobTitleCodeBQM OUTPUT;
                                                   
--select @LC_SupervisorPermission = 1 
--from mi_insight_UserHierarchy uh where @lc_UserUid = uh.SupervisorUID 
--and uh.UserUID = @SupervisorUID
select @LC_SupervisorPermission = 1 
from mi_insight_UserHierarchy uh
where uh.UserUID  = @SupervisorUID
and exists (select 1 
            from mi_insight_UserHierarchy uh2
            where uh.UserUID = uh2.SupervisorUID);
/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/
print 'before query';
print '@LC_userJobtitleCodeHO ' + convert(char,@LC_userJobtitleCodeHO) 
print '@lc_UserJobTitleCodeBQM ' + convert(char,@lc_UserJobTitleCodeBQM)
print '@LCSupervisorPermission ' + convert(char,@LC_SupervisorPermission)
IF (@lc_UserJobTitleCodeHO > 0 or @lc_UserJobTitleCodeBQM > 0 or @LC_SupervisorPermission > 0)  

Begin

 SELECT 
 DISTINCT pop.UserUID
		, pop.UserName
--		, pop.BusinessUID
--		, pop.BusinessName
		, pop.UserID
 into     #Span
 FROM     mi_insight_KPIPopulation pop
 Left JOIN  mi_insight_UserHierarchy uh on uh.UserGUID = pop.SupervisorUserID
 Left join  mi_insight_UserHierarchy uh1 on uh1.UserGUID = pop.UserID
 left join  mi_insight_UserHierarchy uh2 on uh2.UserGUID = uh1.BQMGUID and uh2.SupervisorGUID is null
 WHERE    (uh.UserUID = @SupervisorUID or @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6)) --update 9.5.17
 and case when uh.UserUID = @SupervisorUID then 'Shallow Span' 
 when  @SupervisorUID in (uh1.BQMUID, uh1.SupervisorUID2, uh1.SupervisorUID3, uh1.SupervisorUID4, uh1.SupervisorUID5, uh1.SupervisorUID6) then 'Deep Span' end = @Span; --update 9.5.17

with cte_licence as (
select 
uh.UserName
,uh.UserUID
,case when cd.Code_Description = 'ICOB' then count (uh.useruid) else 0 end as 'ICOB'
,case when cd.Code_Description = 'MCOB' then count (uh.useruid) else 0 end as 'MCOB'
,case when cd.Code_Description = 'COB' then count (uh.useruid) else 0 end as 'COB'
,case when cd.Code_Description = 'ICOB GI Only' then count (uh.useruid) else 0 end as 'ICOB GI Only'
from dbo.sa_insight_UserCompetency uc
join dbo.sa_insight_CodeDescription cd on cd.Code_Code = uc.UC_BusinessArea and cd.Code_CodeType = 534
join dbo.sa_insight_CodeDescription cd1 on cd1.Code_Code = uc.UC_CompetencyLevel and cd1.Code_CodeType = 55
join mi_insight_UserHierarchy uh on uh.UserGUID = uc.UC_OwnerID
join sa_swift_S_AGENTS agt on uh.UserUID = agt.CODE
join sa_swift_s_agents agt1 on agt1.CODE = agt.Manager2Code
join sa_swift_S_AGENTS agt2 on agt2.CODE = uh.BusinessUID
where 1=1
and cd.Code_Description like '%COB%'
and uc.UC_Status = 0
group by 
uh.UserName
,uh.UserUID
,uh.BusinessUID
,case when agt2.TradingName is null then agt2.DESCN else agt2.TradingName end
,agt1.DESCN
,uh.BQMName
,cd.Code_Description
,cd1.Code_Description
,uc.UC_DateAchieved
),

CTE_Lic as (
select 
ctel.UserName
,ctel.UserUID
,case when sum(ctel.icob) > 0 and sum(ctel.mcob) > 0 and sum(ctel.cob) = 0 then 'MCOB' 
 when sum(ctel.icob) > 0 and sum(ctel.mcob) > 0 and sum(ctel.cob) > 0 then 'CMCOB' 
 when sum(ctel.icob) >= 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) > 0 then 'COB'
 when sum(ctel.icob) > 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) = 0 then 'ICOB'
 when sum(ctel.icob) = 0 and sum(ctel.mcob) = 0 and sum(ctel.cob) = 0 and sum(ctel.[ICOB GI Only]) > 0 then 'ICOB GI Only'
 else ' '
 end as 'Licence Type'
,sum(ctel.ICOB) as ICOB
,sum(ctel.MCOB) as MCOB
,sum(ctel.COB) as COB
from cte_licence ctel
group by
ctel.UserName
,ctel.UserUID
)

SELECT pop.useruid as UserUID
	  ,pop.UserName
	  ,pop.UserJobTitleDesc
	  ,lic.[Licence Type] as LicenceType
	  ,pop.BusinessUID
	  ,pop.BusinessName
	  ,uh1.SupervisorName
	  ,case when staff.STAF_ControlledFunctionStartDate > dateadd (month,-30,getdate()) then staff.STAF_ControlledFunctionStartDate else Null end as ControlledFunction
	  ,case when lic.[Licence Type] not in ('COB','CMCOB') then 'N/A' when staff.STAF_ControlledFunctionStartDate > dateadd (month,-30,getdate()) then 'N/A' when cd.Code_Description = 'Expired' then 'Missing' else accbd.ACB_Description end as AccreditedBody
	  ,'StatusV1'
	  ,case when cd.Code_Description is null then 'N/A' else cd.Code_Description end as SPS_Status
	  ,SPS_RenewalDate as ExpiryDate
	  ,SPS_CheckDate as DipCheckDate
      ,case when cd1.Code_Description is null then 'N/A' else cd1.Code_Description end as DipCheckOutcome
  FROM mi_insight_KPIPopulation pop
  join CTE_Lic lic on lic.UserUID = pop.UserUID
  join #Span uh on uh.UserID = pop.UserID
  join mi_insight_UserHierarchy uh1 on uh1.UserUID = pop.UserUID
  left join sa_insight_StatementOfProfessionalStanding sps on sps.SPS_UserID = pop.UserID
  left join sa_insight_AccreditedBody accbd on accbd.ACB_ID = sps.SPS_AccreditedBodyID
  left join sa_insight_CodeDescription cd on cd.Code_Code = sps.SPS_Status and cd.Code_CodeType = 700
  left join sa_insight_CodeDescription cd1 on cd1.Code_Code = sps.SPS_CheckOutcome and cd1.Code_CodeType = 729
  left join sa_insight_staff staff on staff.STAF_UserID = pop.UserID
  where 1=1
--  and uh.UserUID = @SupervisorUID
  and pop.UserJobTitleDesc != 'PP'
  --and pop.BusinessUID = @FirmUID
  --and uh.BusinessUID = '1001031'
  and (cd.Code_Description != 'Cancelled' or cd.Code_Description is null)
  and (SPS_RenewalDate = (select max(SPS_RenewalDate) 
						  from sa_insight_StatementOfProfessionalStanding sps1 
						  where sps1.SPS_UserID = sps.SPS_UserID) or SPS_RenewalDate is null) 
    and SPS_Status = (select min(sps1.SPS_Status)
					from sa_insight_StatementOfProfessionalStanding sps1
					where sps1.SPS_UserID = sps.SPS_UserID)
print 'Leaving try';

End

Else

Begin
Print 'Access Denied'
End   
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


