/****** Object:  StoredProcedure [logi].[pr_Ringo_UserSecurity_Backup20180821AG]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************************************
Name:	pr_Ringo_UserSecurity
Author:	T Cummings
Date:	23/11/2015

Description: When given a PTL code, this proc returns information about the user to determine
			 what span of people they are able to see in their report.

AMENDMENT HISTORY
=================

Date		Author		Description
----		------		-----------
12/09/2016	A Groves	SR449740. Introduced enhanced access for PAs. This work has been actioned
						to enable Laura Hide of JMD to see all users. Rodney Sloan currently has
						the same access hardcoded in 23 Ringo Logi stored procs. The hardcoding 
						is being removed as part of this change. The enhanced PA access is limited 
						to just those enterprises that have a config row on table 
						"owt_SelectionControl".
						
						To give a PA of another enterprise the same level of access, carry out the 
						following:
						1) Give them a PA role on Insight
						2) Add the PA user's enterprise to table "owt_SelectionControl" - see code 
							below for values.
13/09/2016	A Groves	Added @UserBusinessUID to tighten security.
24/04/2017	A Groves	SR473819. Removed JMD hard coding from the procs using this security proc
						as it was out of date and a big maintenance overhead. New config given by 
						alias sc2 was added to give full access to Elizabeth Yates, Paul Coggins a
						nd Antony Lark who are senior JMD staff. They probably have the supervisor 
						role but as they have no span, then we have to force full access for them.
22/05/2017	A Groves	SR476663/CH17482. Introduced the ability for a restricted group to be able 
						to impersonate any user. 
23/05/2017	A Groves	Moved the setting of @UserJobTitleCodeHO=12 after @PTLCode has (potentially)
						been changed by the impersonation.
24/05/2017	A Groves	Removed the openwork\ hard coding to enable this proc to work correctly in UAT.
*****************************************************************************************************/
CREATE PROCEDURE [logi].[pr_Ringo_UserSecurity_Backup20180821AG]
                @PtlCode varchar(50),					--AG 22/05/2017 Changed from 8 to 50 for UAT accounts. 
                @UserUid varchar(50) OUT,
                @UserName varchar(50) OUT,
                @UserJobTitleCodeHO int OUT,
                @UserJobTitleCodePartner int OUT,
                @UserJobTitleCodeSupervisor int OUT,
                @UserJobTitleCodeBQM int OUT,
                @EnhancedPAAccess int = null OUT,		--AG 12/09/2016
                @UserBusinessUID varchar(7) = null OUT	--AG 13/09/2016

AS BEGIN

SELECT	@UserUid=UserUIDProfile.Field1Value
		,@PtlCode=coalesce(imp.Impersonated,@PtlCode)	--AG 23/05/2017. This is needed for Head Office user check
		,@UserName=UserName
		,@UserJobTitleCodeHO=@UserJobTitleCodeHO
		,@UserJobTitleCodePartner=isnull(UserJobTitleCodePartner,0)
		,@UserJobTitleCodeBQM=isnull(UserJobTitleCodeBQM,0)
		,@UserJobTitleCodeSupervisor=isnull(UserJobTitleCodeSupervisor,0)
		,@EnhancedPAAccess=case when sc.KeyValue is not null or sc2.KeyValue is not null then 1 else 0 end	--AG 12/09/2016 & AG 24/04/2017
		,@UserBusinessUID=miuh.BusinessUID										--AG 13/09/2016
FROM	[prod_zurich_openwork_datawarehouse].[dbo].[sa_ISL_SingleSignOnApplicationProfile] UserUIDProfile
		inner join [prod_zurich_openwork_datawarehouse].[dbo].[sa_ISL_SingleSignOnApplicationProfile] PtlProfile on UserUIDProfile.SingleSignOnUserId = PtlProfile.SingleSignOnUserId
		inner join prod_zurich_openwork_datawarehouse.dbo.mi_insight_UserHierarchy miuh on miuh.UserUID = UserUIDProfile.Field1Value
		left join owt_SelectionControl sc
					on	sc.Process = 'Ringo Logi'
					and	sc.SelectionType = 'PA Enhanced Access'
					and	sc.KeyType = 'EnterpriseUID'
					and	dateadd(dd,0,datediff(dd,0,getdate())) between sc.EffectiveStartDate and sc.EffectiveEndDate 
					and sc.KeyValue = miuh.BusinessUID
					and miuh.UserJobTitleCodePA is not null
		left join owt_SelectionControl sc2			--AG 24/04/2017
					on	sc2.Process = 'Ringo Logi'
					and	sc2.SelectionType = 'PA Enhanced Access'
					and	sc2.KeyType = 'UserUID'
					and sc2.KeyValue = miuh.BusinessUID
					and sc2.KeyValue2 = UserUIDProfile.Field1Value
					and	dateadd(dd,0,datediff(dd,0,getdate())) between sc2.EffectiveStartDate and sc2.EffectiveEndDate 
		left join	(select Impersonator, max(i.ID) as MaxID
					 from	logi.Impersonation i
							inner join dbo.owt_HeadOfficeReportDevelopers rd on rd.LoginAccount = i.Impersonator
					 where	i.Active=1
					 group by Impersonator) impdedupe on impdedupe.Impersonator = @PtlCode
		left join logi.Impersonation imp on imp.ID = impdedupe.MaxID 
WHERE  PtlProfile.Field1Value = coalesce(imp.Impersonated,@PtlCode)
and    UserUIDProfile.SingleSignOnApplicationId = 3

--Set the Head Office User following any changes for impersonation
SELECT	@UserJobTitleCodeHO=12
FROM	mst_DataImportConfiguration dic															--AG 24/05/2017
		inner join dbo.msct_HeadOfficeUsers hou on hou.DomainLogin = dic.Path + '\' + @PtlCode	--AG 24/05/2017
where	dic.Client	= 'Openwork'
and		dic.Module	= 'Domain'
and		dic.Type	= 'Domain'
and		dic.Active	= 1

END

