/************************************************************************************************
  	 Program:  	OWL.MarketingReport						
	  Author:	J Bolton (implemented by S Campbell)
Date created:	07/09/2018
		
		Type:	Extract
											
 Description:   This proc creates an output file for use by Owl Marketing .
				
				It is called as follows:

				exec OWL.MarketingReport 'Openwork' ,'OwlMarketingDataExtract'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
10.10.18	S Campbell	Replace commas in email addresses with full stops - CR#22882
01.07.21	C Mellors	Added new Owl Sales Director aduid 4021409, following Pat McKenna leaving 
************************************************************************************************/

CREATE PROCEDURE [OWL].[MarketingReport] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)

/****************************************************************************

	Log start 
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start 
																		
****************************************************************************/

SET NOCOUNT ON
SET ANSI_WARNINGS OFF


-----------------------
-- client/adviser/policy information

--GDPR contact flag
------- 

insert into OWL.GDPR
select distinct PersonID,
--[if last advice start date < 25/5/18 and GDPR marketing preferences not updated] contactable if opt-out = false
dateupdated,new,old,
case when ((dateupdated >= '05/25/2018' or New is not null) and New = 1) or((dateupdated < '05/25/2018' and New is null) and old = 'No') then 'Yes'
	 when (dateupdated < '05/25/2018' and Old ='Yes') then 'No'
	 when new is null and old = 'Yes' then 'No'
	 else 'No' end as contact_flag

--	  into #gdpr
 from 
		(select s.saleid,s.personid, s.dateupdated, gdpr.byemail new, iv2.ValueName old  from sa_ows_sale s inner join  

			(select personid, max(dateupdated) dateupdated from sa_ows_Sale group by PersonID) temp
			on temp.dateupdated = s.dateupdated and temp.personid = s.personid
		left join mstt_agents ag on ag.code = s.adviseruid	
		left join GDPR.sa_ows_DataProtectionMarketingPreferences gdpr on gdpr.personid = s.personid	 -- 1 yes, 0 no
		left join owt_ows_FactFindOverviewGeneralOptOut20180622 gdpr_old on gdpr_old.saleid = s.saleid 
		left join StaticData.sa_ows_InputValues iv2 on iv2.inputid = gdpr_old.marketingoptoutrequestedid
		 where ag.Manager2Code = '1011671') tmp


--------------
insert into [OWL].MarketingReportData
select 
pol.PolicyID, pmv.providercodeswift
,convert(date,Min(sal.datesubmitted)) earliestsubmissiondate
,pers.personid,iv.ValueName cl_Title,ltrim(rtrim(pers.Firstname)) cl_Firstname,ltrim(rtrim(pers.lastname)) cl_surname,convert(date,pers.dateofbirth) cl_DoB, upper(pers.PostCode) cl_Postcode, pers.EmailAddress cl_email,pers.AdviserUID Adv_UID
,st2.Staf_Forename asm1_Forename,st2.staf_Surname asm1_Surname

,uhd.username Adv_Name,uhd.OWLAsmName1,uhd.OWLAsmName2										  
,icd.cd_email Adv_email, icd.CD_Mobile Adv_Phone
,icd2.cd_email ASM1_Email
,icd2.CD_Mobile ASM1_Phone
,case when dep.dependantid >0 then 'Y' else 'N' end dependants
,sum(case when datediff(yy,dep.dateofbirth,getdate()) < 25 then 1 else 0 end) Num_Children
,la.cont_num lapse
,gdpr.contact_flag
,spol.productcode
--into #temp

from sa_ows_Policies pol inner join sa_ows_sale sal on sal.SaleID = pol.SaleID 
	left join staticdata.sa_ows_ProductMergeView pmv on pmv.internalproductid = pol.internalproductid 
		left join sa_ows_Person pers on pers.personid = sal.PersonID and pers.persontype = pol.policyownertype
		left join sa_ows_FactFindOverviewDependants dep on dep.saleid = pol.saleid
		left join StaticData.sa_ows_InputValues iv on iv.inputid = pers.titleid
		-- adviser CD
		left join mi_insight_userhierarchyallusers uhd on uhd.Useruid = pers.adviseruid
		left join sa_insight_Staff st on st.STAF_UserID = uhd.userguid
		left join dbo.sa_insight_ContactDetails icd on icd.CD_ParentID = st.STAF_ID		
		-- manager CD
		left join mi_insight_userhierarchyallusers uhd2 on uhd2.Useruid = uhd.OWLAsmuid1
		left join sa_insight_Staff st2 on st2.STAF_UserID = uhd2.userguid
		left join dbo.sa_insight_ContactDetails icd2 on icd2.CD_ParentID = st2.STAF_ID

		-- swift join for lapse scan
		left join mstt_policies spol on spol.Policyref = pol.policyid
		left join mi_Owl_Lapses la on la.cont_num = spol.cont_num and la.excluded is null

		-- GDPR flag
		left join OWL.GDPR gdpr on gdpr.personid = sal.personid

		
		
where uhd.effectiveenddate >= getdate()
	 and uhd.aduid IN (4005013, 4021409)
	 and sal.datesubmitted is not null
	 and (pers.EmailAddress is not null and pers.EmailAddress <> '')

group by 
pmv.displayname,pmv.providercodeswift,
iv.ValueName,pers.Firstname,pers.lastname,convert(date,pers.dateofbirth), pers.PostCode, pers.EmailAddress,pers.AdviserUID
,uhd.username,uhd.OWLAsmName1,uhd.OWLAsmName2										  
,icd.CD_email,icd.cd_email
,icd2.cd_email
,pol.PolicyID,pol.internalproductid,pol.InternalProviderID
,pers.personid
,la.cont_num
,spol.cont_num
,case when dep.dependantid >0 then 'Y' else 'N' end
,gdpr.contact_flag
,icd2.CD_Mobile, icd.CD_Mobile
,st2.Staf_Forename,st2.staf_Surname
,spol.productcode

----------

insert into [OWL].[MarketingExtract]
select
--tem.personid,
tem.GDPRFlag marketing_consent
,min(EarliestSubDt)earliestOWSsubmissiondate

,datediff(mm,min(EarliestSubDt),getdate()) 'Months Since Start Date'
,datediff(yy,min(EarliestSubDt),getdate()) 'Years Since Start Date'
,tem.Title

-------------
,case when unicode(substring(tem.firstname,2,1)) = unicode(upper(substring(tem.firstname,2,1))) then left(tem.firstname,1) + lower(substring(tem.firstname,2,100)) else tem.firstname end cl_firstname
,case when unicode(substring(tem.surname,2,1)) = unicode(upper(substring(tem.surname,2,1))) then left(tem.surname,1) + lower(substring(tem.surname,2,100)) else tem.surname end cl_surname
-------------
,tem.DOB,datediff(yy,tem.DOB,getdate()) cl_age
,tem.postcode
,tem.dependants cl_dependants

,NumChildren
,--tem.clEmail
replace(tem.clemail,',','.') ClEmail -- CR#22882
,tem.AdviserUID,tem.AdvName
,replace(tem.advemail,',','.') AdvEmail -- CR#22882
--,tem.advemail
,left(replace(tem.advPhone,' ',''),5) + ' ' + right(replace(tem.advPhone,' ',''), len(replace(tem.advPhone,' ',''))-5) adv_Phone
,tem.ASMname1
,tem.asmForname,tem.asmSurname
,tem.ASMname2,tem.ASM1email
,left(replace(tem.ASM1Phone,' ',''),5) + ' ' + right(replace(tem.ASM1Phone,' ',''), len(replace(tem.ASM1Phone,' ',''))-5) ASM1_Phone
,sum(case when tem.lapse is not null then 1 else 0 end) Lapse_No

,case when sum(case when tem.lapse is not null then 1 else 0 end) > 0  then 'Yes' else 'No' end 'Lapses?'

,sum(case when tem.provcodeswift like 'ZURICH' then 1 else 0 end) Zurich
,sum(case when tem.provcodeswift like 'Aviva' then 1 else 0 end) Aviva
,sum(case when tem.provcodeswift like 'LV' then 1 else 0 end) LV
,sum(case when tem.provcodeswift like 'Metlife' then 1 else 0 end) Metlife
,sum(case when tem.provcodeswift like 'legal' then 1 else 0 end) 'L&G'
,count(tem.provcodeswift) - sum(case when tem.lapse is not null then 1 else 0 end) Net_Active_Pol

,sum(case when tem.productcode = 'DMCP OWL' then 1 else 0 end) Zurich_DMCP
,sum(case when tem.productcode = 'WOLOWL' then 1 else 0 end) Zurich_WOL
,sum(case when tem.productcode = 'LPP OWL' then 1 else 0 end) Zurich_LPP

,datediff(mm,max(case tem.provcodeswift when 'Metlife' then EarliestSubDt else null end),getdate()) Metlife_months_since_start_date

from OWL.MarketingReportData tem



--dedupe by client firstname,surname,DOB,postcode
inner join (select min(EarliestSubDt) LatestOWSsubmissiondate, firstname,surname,postcode,DOB from OWL.MarketingReportData group by firstname,surname,postcode,DOB ) dedupe
			on dedupe.LatestOWSsubmissiondate = tem.EarliestSubDt
				and dedupe.firstname =tem.firstname 
				and dedupe.surname =tem.surname
				and dedupe.DOB =tem.DOB
				and dedupe.postcode =tem.postcode
group by 
tem.Title,tem.firstname,tem.surname,tem.DOB,tem.postcode,tem.clEmail
,tem.AdviserUId,tem.AdvName,tem.advemail,tem.advPhone, tem.ASM1Phone
,tem.asmname1,tem.asmname2,tem.ASM1email
,tem.dependants
,tem.GDPRflag 
,tem.DOB,datediff(yy,tem.DOB,getdate()) 
,tem.asmForname,tem.asmSurname
,NumChildren

having count(tem.provcodeswift) - sum(case when tem.lapse is not null then 1 else 0 end)  <> 0
order by earliestOWSsubmissiondate

--drop table #gdpr,#temp

select *
from  [OWL].[MarketingExtract]


/****************************************************************************

	Log End 
																		
****************************************************************************/

exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

/****************************************************************************

			E N D															

****************************************************************************/



GO
