/*********************************************************************************************************

Program:		[OwlEvolution].[pr_DWHTransfer]			
Author:			Alan Groves
Date created:	13/11/2018
											
Description:
===========

This proc transfers the Owl Evolution hierarchy payment data to the Data Warehouse.

Initially it is truncate and load.

In the future, it may become a MERGE or may be TR'd.

This proc is called as follows:
	
	exec [OwlEvolution].[pr_DWHTransfer] 'Owl', 'OwlHierarchyPayments'
			
AMENDMENT HISTORY				
=================								

Date		Author		Description
----		------		-----------
16/11/2018	A Groves	Changed DateInserted and DateLastUpdated to be the original dates
						from the source table as these are used to drive the incremental
						processing into the OpenAccess table: dbo.owoa_OwlHierarchyPayments.
*************************************************************************************************************/

CREATE PROCEDURE [OwlEvolution].[pr_DWHTransfer] 
	@Client		varchar(50),
	@Module		Varchar(50)

as

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,			
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'
set @Process			= object_name(@@procid)
set @DateLastUpdated	= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
	
	/****************************************************************************
	
		truncate and load OwlEvolution.PaymentToHierarchy
	
	****************************************************************************/

	truncate table OwlEvolution.sa_SwiftLogging_PaymentToHierarchy
	
	insert into OwlEvolution.sa_SwiftLogging_PaymentToHierarchy
	(
		ID,
		AGMID,
		RoleEnterpriseUID,
		RoleAdviserUID,
		RoleAmount,
		RolePct,
		PaymentStage,
		PaymentRole,
		CommType,
		Type,
		AnnualisedPremium,
		AdviserUID,
		AdviserAmount,
		AdviserPanel,
		AdviserBand,
		TransactionID,
		CreateDateTime,
		CreateDate,
		ProposalDate,
		FranchiseUpliftPercent,
		FirstPaymentAGMID,
		FirstPaymentCreateDateTime,
		FirstPaymentCreateDate,
		CaseID,
		PolicyNumber,
		CommCompanyCode,
		CommProductCode,
		CommInitialPeriod,
		CodeCommissionShapeID,
		PaymentCollected,
		PaymentCollectedDateTime,
		StandingOrderID,
		DateInserted,
		DateLastUpdated
	)
	select 	ID,
			AGMID,
			RoleEnterpriseUID,
			RoleAdviserUID,
			RoleAmount,
			RolePct,
			PaymentStage,
			PaymentRole,
			CommType,
			Type,
			AnnualisedPremium,
			AdviserUID,
			AdviserAmount,
			AdviserPanel,
			AdviserBand,
			TransactionID,
			CreateDateTime,
			CreateDate,
			ProposalDate,
			FranchiseUpliftPercent,
			FirstPaymentAGMID,
			FirstPaymentCreateDateTime,
			FirstPaymentCreateDate,
			CaseID,
			PolicyNumber,
			CommCompanyCode,
			CommProductCode,
			CommInitialPeriod,
			CodeCommissionShapeID,
			PaymentCollected,
			PaymentCollectedDateTime,
			StandingOrderID,
			DateInserted,
			DateLastUpdated
	from	OwlEvolution.Synonym_SwiftLogging_PaymentToHierarchy
		
	set @RowCount = @@rowcount
	set @ProcessMessage = 'Insert into sa_SwiftLogging_PaymentToHierarchy = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************
	
		truncate and load OwlEvolution.PaymentStandingOrders
	
	****************************************************************************/

	truncate table OwlEvolution.sa_SwiftLogging_PaymentStandingOrders

	insert into OwlEvolution.sa_SwiftLogging_PaymentStandingOrders
	(
		StandingOrderID,
		AgentCode,
		StandingOrderCode,
		Description,
		StartDate,
		EndDate,
		NextPaymentDue,
		Frequency,
		PaymentAmount,
		TotalPaymentAmount,
		AmountPaidToDate,
		Suspend,
		SubjectToVAT,
		CreatedBy,
		CreatedDate,
		Authorised,
		AuthorisedBy,
		AuthorisedDate,
		Exported,
		ExportedDateTime,
		ExportedStandingOrderID,
		DateInserted,
		DateLastUpdated
	)
	select	StandingOrderID,
			AgentCode,
			StandingOrderCode,
			Description,
			StartDate,
			EndDate,
			NextPaymentDue,
			Frequency,
			PaymentAmount,
			TotalPaymentAmount,
			AmountPaidToDate,
			Suspend,
			SubjectToVAT,
			CreatedBy,
			CreatedDate,
			Authorised,
			AuthorisedBy,
			AuthorisedDate,
			Exported,
			ExportedDateTime,
			ExportedStandingOrderID,
			DateInserted,
			DateLastUpdated
	from	OwlEvolution.Synonym_SwiftLogging_PaymentStandingOrders

	set @RowCount = @@rowcount
	set @ProcessMessage = 'Insert into sa_SwiftLogging_PaymentStandingOrders = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [OwlEvolution].[pr_PaymentsLoadToOpenAccess]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************

Program:		OwlEvolution.pr_PaymentsLoadToOpenAccess					
Author:			Alan Groves
Date created:	16/11/2018
											
Description:
===========

The proc loads the Owl Hierarchy Payments into the OpenAccess Owl Payment Hierarchy Download
table i.e.
from:	OwlEvolution.sa_SwiftLogging_PaymentToHierarchy
To:		dbo.owoa_OwlHierarchyPayments

This process uses a MERGE statement. However, there is no DELETE component in case the staging table
breaks and we end up with an empty staging table. In this scenario we wouldn't want this process to
remove all the payments from the download table.

This proc is called as follows:
	
	exec [OwlEvolution].[pr_PaymentsLoadToOpenAccess] 'Owl', 'OpenAccess'
	
AMENDMENT HISTORY				
=================								

Date		Author		Description
----		------		-----------
28/11/2018	A Groves	Removed processing to identify the latest date from which changes should
						be drawn as this was stopping the standing order details from being updated.
13/12/2018	A Groves	Warranty fix: Exclude payments where the Enterprise UID is null. This can
						occur where the RoleAdviserUID is the Owl Orphan Override pot code 1011623.
10/10/2019	S Campbell	Fix the join to mstt_policies as caseid isn't alway present (use payment id back to transaction) CR#26472
11/03/2020	A Groves	Added in PlanCode and DA to enable mortgage APE to be calculated.
*************************************************************************************************************/

CREATE PROCEDURE [OwlEvolution].[pr_PaymentsLoadToOpenAccess]
	@Client		varchar(50),
	@Module		Varchar(50)

AS

set nocount on

declare		@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseError				varchar(50),
			@PhaseLog				varchar(50),
			@ProcName				varchar(100),
			@ProcessMessage			varchar(100),
			@RowCount				int,
			@OALRowCount			int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int,
			@DateLastUpdated		datetime
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd			= 'END'
set @PhaseError			= 'ERROR'
set @PhaseLog			= 'LOG'
set @ErrNum				= 0	
set @DateLastUpdated	= getdate()

-- We want this logging irrespective of whether or not there is a rollback
