	/****************************************************************************

		Merge the temporary table into the permanent table (IC data)
																		
	****************************************************************************/

	create table #TEMP_owoa_OwlHierarchyPayments
	(
		HierarchyPaymentID			int,
		AGMID						int,
		RoleEnterpriseUID			varchar(7),
		RoleAdviserUID				varchar(7),
		AdviserUID					varchar(7), 
		AdviserName					varchar(255), 
		CaseID						int, 
		PolicyNumber				varchar(30), 
		Client						varchar(130),
		CommissionTypeCode			smallint,
		CommissionTypeDesc			varchar(50),
		PaymentBasis				varchar(20),
		PaymentAmount				decimal(16,2),
		PctOfAdviserPayment			decimal(8,4),
		PaymentStage				varchar(20),
		PaymentRole					varchar(20),
		AdviserAmount				decimal(16,2),
		AdviserPanel				varchar(30),
		AdviserBand					int,
		AnnualisedPremium			decimal(16,2),
		ProposalDate				datetime,	
		DateOfAdviserPayment		datetime,
		ProductCode					varchar(8),
		ProviderCode				varchar(10),
		InitialPeriod				smallint,
		PaymentCollectedDate		datetime,
		StandingOrderDescription	varchar(50),
		DateInserted				datetime,
		DateLastUpdated				datetime
	 )

--	declare @MaxDateLastUpdated datetime
--	select	@MaxDateLastUpdated = max(DateLastUpdated)
--	from	dbo.owoa_OwlHierarchyPayments

--	select @MaxDateLastUpdated = isnull(@MaxDateLastUpdated,'2000-01-01')

	insert into #TEMP_owoa_OwlHierarchyPayments
	(
		HierarchyPaymentID,
		AGMID,
		RoleEnterpriseUID,
		RoleAdviserUID,
		AdviserUID, 
		AdviserName, 
		CaseID, 
		PolicyNumber, 
		Client,
		CommissionTypeCode,
		CommissionTypeDesc,
		PaymentBasis,
		PaymentAmount,
		PctOfAdviserPayment,
		PaymentStage,
		PaymentRole,
		AdviserAmount,
		AdviserPanel,
		AdviserBand,
		AnnualisedPremium,
		ProposalDate,	
		DateOfAdviserPayment,
		ProductCode,
		ProviderCode,
		InitialPeriod,
		PaymentCollectedDate,
		StandingOrderDescription,
		DateInserted,
		DateLastUpdated
	)
	select	pth.ID as HierarchyPaymentID,
			pth.AGMID,
			pth.RoleEnterpriseUID,
			pth.RoleAdviserUID,
			pth.AdviserUID, 
			adv.Descn as AdviserName, 
			pth.CaseID, 
			pth.PolicyNumber, 
			case when cli.Firstnames is null then '' else left(cli.Firstnames,60) + ' ' end + left(isnull(cli.Name,''),60) as Client,
			pth.Type as CommissionTypeCode,
			crcc.SwiftDescription as CommissionTypeDesc,
			case pth.CommType
				when 'F' then 'Accr' 
				when 'T' then 'IT' 
				when 'L' then 'Level' 
			end as PaymentBasis, 
			pth.RoleAmount as PaymentAmount,
			pth.RolePct as PctOfAdviserPayment,
			pth.PaymentStage,
			pth.PaymentRole,
			pth.AdviserAmount,
			pth.AdviserPanel,
			pth.AdviserBand,
			pth.AnnualisedPremium,
			pth.ProposalDate,	
			pth.CreateDate as DateOfAdviserPayment,
			pth.CommProductCode as ProductCode,
			pth.CommCompanyCode as ProviderCode,
			pth.CommInitialPeriod as InitialPeriod,
			dateadd(dd,0,datediff(dd,0,pth.PaymentCollectedDateTime)) as PaymentCollectedDate,
			pso.Description as StandingOrderDescription,
			pth.DateInserted,
			pth.DateLastUpdated
	from	OwlEvolution.sa_SwiftLogging_PaymentToHierarchy pth
			inner join mstt_Agents adv on adv.CODE = pth.AdviserUID
			inner join mstt_Policies pol on pol.PolicyRef = pth.CaseID
			inner join mstt_Clients cli on pol.Client_Num = cli.Client_Num
			inner join dbo.msit_CommissionReportingClassCodes crcc
							on crcc.SwiftField = 'CommissionType'
							and crcc.SwiftCode = pth.Type
			left join OwlEvolution.sa_SwiftLogging_PaymentStandingOrders pso on pso.StandingOrderID = pth.StandingOrderID
	where	pth.RoleEnterpriseUID is not null		--AG 13/12/2018

	/****************************************************************************

		Merge the temporary table into the permanent table (IC data)
																		
	****************************************************************************/

	BEGIN TRANSACTION

	declare @SummaryOfChanges table (Change varchar(20))
	merge	dbo.owoa_OwlHierarchyPayments as trg
	using	#TEMP_owoa_OwlHierarchyPayments as src
	on		trg.HierarchyPaymentID = src.HierarchyPaymentID
	when	matched 
	and		binary_checksum(trg.AGMID,trg.RoleEnterpriseUID,trg.RoleAdviserUID,trg.AdviserUID,trg.AdviserName, 
							trg.CaseID,trg.PolicyNumber,trg.Client,trg.CommissionTypeCode,trg.CommissionTypeDesc,
							trg.PaymentBasis,trg.PaymentAmount,trg.PctOfAdviserPayment,trg.PaymentStage,
							trg.PaymentRole,trg.AdviserAmount,trg.AdviserPanel,trg.AdviserBand,trg.AnnualisedPremium,
							trg.ProposalDate,trg.DateOfAdviserPayment,trg.ProductCode,trg.ProviderCode,
							trg.InitialPeriod,trg.PaymentCollectedDate,trg.StandingOrderDescription)
			<>
			binary_checksum(src.AGMID,src.RoleEnterpriseUID,src.RoleAdviserUID,src.AdviserUID,src.AdviserName, 
							src.CaseID,src.PolicyNumber,src.Client,src.CommissionTypeCode,src.CommissionTypeDesc,
							src.PaymentBasis,src.PaymentAmount,src.PctOfAdviserPayment,src.PaymentStage,
							src.PaymentRole,src.AdviserAmount,src.AdviserPanel,src.AdviserBand,src.AnnualisedPremium,
							src.ProposalDate,src.DateOfAdviserPayment,src.ProductCode,src.ProviderCode,
							src.InitialPeriod,src.PaymentCollectedDate,src.StandingOrderDescription)
	then	update 
				set trg.AGMID						= src.AGMID,
					trg.RoleEnterpriseUID			= src.RoleEnterpriseUID,
					trg.RoleAdviserUID				= src.RoleAdviserUID,
					trg.AdviserUID					= src.AdviserUID,
					trg.AdviserName					= src.AdviserName, 
					trg.CaseID						= src.CaseID,
					trg.PolicyNumber				= src.PolicyNumber,
					trg.Client						= src.Client,
					trg.CommissionTypeCode			= src.CommissionTypeCode,
					trg.CommissionTypeDesc			= src.CommissionTypeDesc,
					trg.PaymentBasis				= src.PaymentBasis,
					trg.PaymentAmount				= src.PaymentAmount,
					trg.PctOfAdviserPayment			= src.PctOfAdviserPayment,
					trg.PaymentStage				= src.PaymentStage,
					trg.PaymentRole					= src.PaymentRole,
					trg.AdviserAmount				= src.AdviserAmount,
					trg.AdviserPanel				= src.AdviserPanel,
					trg.AdviserBand					= src.AdviserBand,
					trg.AnnualisedPremium			= src.AnnualisedPremium,
					trg.ProposalDate				= src.ProposalDate,
					trg.DateOfAdviserPayment		= src.DateOfAdviserPayment,
					trg.ProductCode					= src.ProductCode,
					trg.ProviderCode				= src.ProviderCode,
					trg.InitialPeriod				= src.InitialPeriod,
					trg.PaymentCollectedDate		= src.PaymentCollectedDate,
					trg.StandingOrderDescription	= src.StandingOrderDescription,
					trg.DateInserted				= src.DateInserted,
					trg.DateLastUpdated				= src.DateLastUpdated
	when	not matched by target 
	then	insert
			(
				HierarchyPaymentID,
				AGMID,
				RoleEnterpriseUID,
				RoleAdviserUID,
				AdviserUID, 
				AdviserName, 
				CaseID, 
				PolicyNumber, 
				Client,
				CommissionTypeCode,
				CommissionTypeDesc,
				PaymentBasis,
				PaymentAmount,
				PctOfAdviserPayment,
				PaymentStage,
				PaymentRole,
				AdviserAmount,
				AdviserPanel,
				AdviserBand,
				AnnualisedPremium,
				ProposalDate,	
				DateOfAdviserPayment,
				ProductCode,
				ProviderCode,
				InitialPeriod,
				PaymentCollectedDate,
				StandingOrderDescription,
				DateInserted,
				DateLastUpdated
			)		
			values
			(
				src.HierarchyPaymentID,
				src.AGMID,
				src.RoleEnterpriseUID,
				src.RoleAdviserUID,
				src.AdviserUID,
				src.AdviserName, 
				src.CaseID,
				src.PolicyNumber,
				src.Client,
				src.CommissionTypeCode,
				src.CommissionTypeDesc,
				src.PaymentBasis,
				src.PaymentAmount,
				src.PctOfAdviserPayment,
				src.PaymentStage,
				src.PaymentRole,
				src.AdviserAmount,
				src.AdviserPanel,
				src.AdviserBand,
				src.AnnualisedPremium,
				src.ProposalDate,
				src.DateOfAdviserPayment,
				src.ProductCode,
				src.ProviderCode,
				src.InitialPeriod,
				src.PaymentCollectedDate,
				src.StandingOrderDescription,
				src.DateInserted,
				src.DateLastUpdated
			)				
	output $action into @SummaryOfChanges;		--Merge statements must have a ;
						
	COMMIT TRANSACTION      
	
	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'INSERT'

	set @ProcessMessage = 'owoa_OwlHierarchyPayments (insert) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'UPDATE'

	set @ProcessMessage = 'owoa_OwlHierarchyPayments (update) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		T H E   E N D
																		
	****************************************************************************/
	
	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	-- Test XACT_STATE for 0, 1, or -1.
    -- If 1, the transaction is committable.
    -- If -1, the transaction is uncommittable and should be rolled back.
    -- If 0, there is no transaction and a commit or rollback operation would generate an error.

	if @ErrState = -1			-- Transaction is uncommitable
		rollback transaction

	if @ErrState = 1			
		commit transaction

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

