CREATE PROCEDURE [Staging].[msit_CommissionStatementPeriods_Hash_Generation]
@Mode	CHAR(4)	= 'FULL' --'FULL' or 'MOVE'
AS
/******************************************************************************

Date      Amended By  Change Details
========  ==========  ==============
21/05/19  C Mellors   Created SP

*******************************************************************************/
SET NOCOUNT ON;

BEGIN TRY
	EXEC [dbo].[msp_ProcessLog] 'HASH', '1) Start msit_CommissionStatementPeriods_Hash_Generation', null, 'msit_CommissionStatementPeriods_Hash_Generation', 'Openwork';

	-- Rows to Delete
	DELETE	[Staging].[msit_CommissionStatementPeriods_Hash]
	WHERE	[Month] NOT IN (SELECT [Month] FROM [dbo].[msit_CommissionStatementPeriods]);

	IF @Mode = 'MOVE'
	BEGIN
		MERGE [Staging].[msit_CommissionStatementPeriods_Hash] AS Target
		USING	(
			SELECT	 [Month]
					,HASHBYTES('SHA1'	, ISNULL(CONVERT(VARCHAR(4000), [Month]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [PeriodStartDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [PeriodEndDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [MonthName]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [OSCARStartDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [OSCAREndDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [DateLoaded]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RefreshAccount]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [Year]),'')
							) AS [HashValue]
			FROM	[dbo].[msit_CommissionStatementPeriods] csp
			WHERE	EXISTS	(
							SELECT	*
							FROM	[Staging].[msit_CommissionStatementPeriods_Movement] m
							WHERE	m.[Month] = csp.[Month]
							)
		) AS Source
			ON Target.[Month] = Source.[Month]
		WHEN NOT MATCHED BY TARGET THEN
			INSERT	([Month]
					,[HashValue] 
					)
			VALUES	(Source.[Month]
					,Source.[HashValue]
					) 
		WHEN MATCHED AND Source.[HashValue] <> Target.[HashValue] THEN 
			UPDATE SET	 [HashValue] = Source.[HashValue];
	END
	ELSE
	BEGIN
		MERGE [Staging].[msit_CommissionStatementPeriods_Hash] AS Target
		USING	(
			SELECT	 [Month]
					,HASHBYTES('SHA1'	, ISNULL(CONVERT(VARCHAR(4000), [Month]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [PeriodStartDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [PeriodEndDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [MonthName]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [OSCARStartDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [OSCAREndDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [DateLoaded]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RefreshAccount]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [Year]),'')
							) AS [HashValue]
			FROM	[dbo].[msit_CommissionStatementPeriods] csp
		) AS Source
			ON Target.[Month] = Source.[Month]
		WHEN NOT MATCHED BY TARGET THEN
			INSERT	([Month]
					,[HashValue] 
					)
			VALUES	(Source.[Month]
					,Source.[HashValue]
					) 
		WHEN MATCHED AND Source.[HashValue] <> Target.[HashValue] THEN 
			UPDATE SET	 [HashValue] = Source.[HashValue];
	END

	-- Empty the source movement tables
	TRUNCATE TABLE [Staging].[msit_CommissionStatementPeriods_Movement];

	EXEC [dbo].[msp_ProcessLog] 'HASH', '2) End msit_CommissionStatementPeriods_Hash_Generation', null, 'msit_CommissionStatementPeriods_Hash_Generation', 'Openwork';
END TRY
BEGIN CATCH
	DECLARE	 @ErrorNumber INT = ERROR_NUMBER()
			,@Message VARCHAR(MAX) = ERROR_MESSAGE()
			,@Severity INT = ERROR_SEVERITY()
			,@State SMALLINT = ERROR_STATE()
			;

	EXEC [dbo].[msp_ProcessLog] 'HASH', '9) FAILED msit_CommissionStatementPeriods_Hash_Generation', null, 'msit_CommissionStatementPeriods_Hash_Generation', 'Openwork';
 
	RAISERROR (@Message, @Severity, @State);
END CATCH
GO
