SET NOCOUNT ON;

BEGIN TRY
	EXEC [dbo].[msp_ProcessLog] 'HASH', '1) Start msit_MIWarehouseCodesAndDescriptions_Hash_Generation', null, 'msit_MIWarehouseCodesAndDescriptions_Hash_Generation', 'Openwork';

	-- Rows to Delete
	DELETE	h
	FROM	[Staging].[msit_MIWarehouseCodesAndDescriptions_Hash] h
	WHERE	NOT EXISTS	(
						SELECT	*
						FROM	[dbo].[msit_MIWarehouseCodesAndDescriptions] cd
						WHERE	cd.[ColumnName] = h.[ColumnName] 
						AND		cd.[Code] = h.[Code]
						);

	IF @Mode = 'MOVE'
	BEGIN
		MERGE [Staging].[msit_MIWarehouseCodesAndDescriptions_Hash] AS Target
		USING	(
			SELECT	 [ColumnName]
					,[Code]
					,HASHBYTES('SHA1'	, ISNULL(CONVERT(VARCHAR(4000), [ColumnName]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [Code]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [Description]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [LongDescription]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ShortDescription]),'')
								) AS [HashValue]
			FROM	[dbo].[msit_MIWarehouseCodesAndDescriptions] cd
			WHERE	EXISTS	(
