							FROM	[Staging].[msit_MIWarehouseCodesAndDescriptions_Movement] m
							WHERE	m.[ColumnName] = cd.[ColumnName]
							AND		m.[Code] = cd.[Code]
							)
		) AS Source
			ON Target.[ColumnName] = Source.[ColumnName]
			AND Target.[Code] = Source.[Code]
		WHEN NOT MATCHED BY TARGET THEN
			INSERT	([ColumnName]
					,[Code]
					,[HashValue] 
					)
			VALUES	(Source.[ColumnName]
					,Source.[Code]
					,Source.[HashValue]
					) 
		WHEN MATCHED AND Source.[HashValue] <> Target.[HashValue] THEN 
			UPDATE SET	 [HashValue] = Source.[HashValue];
	END
	ELSE
	BEGIN
		MERGE [Staging].[msit_MIWarehouseCodesAndDescriptions_Hash] AS Target
		USING	(
			SELECT	 [ColumnName]
					,[Code]
					,HASHBYTES('SHA1'	, ISNULL(CONVERT(VARCHAR(4000), [ColumnName]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [Code]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [Description]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [LongDescription]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ShortDescription]),'')
								) AS [HashValue]
			FROM	[dbo].[msit_MIWarehouseCodesAndDescriptions] cd
		) AS Source
			ON Target.[ColumnName] = Source.[ColumnName]
			AND Target.[Code] = Source.[Code]
		WHEN NOT MATCHED BY TARGET THEN
			INSERT	([ColumnName]
					,[Code]
					,[HashValue] 
					)
			VALUES	(Source.[ColumnName]
					,Source.[Code]
					,Source.[HashValue]
					) 
		WHEN MATCHED AND Source.[HashValue] <> Target.[HashValue] THEN 
			UPDATE SET	 [HashValue] = Source.[HashValue];
	END

	-- Empty the source movement tables
	TRUNCATE TABLE [Staging].[msit_MIWarehouseCodesAndDescriptions_Movement];

	EXEC [dbo].[msp_ProcessLog] 'HASH', '2) End msit_MIWarehouseCodesAndDescriptions_Hash_Generation', null, 'msit_MIWarehouseCodesAndDescriptions_Hash_Generation', 'Openwork';
END TRY
BEGIN CATCH
	DECLARE	 @ErrorNumber INT = ERROR_NUMBER()
			,@Message VARCHAR(MAX) = ERROR_MESSAGE()
			,@Severity INT = ERROR_SEVERITY()
			,@State SMALLINT = ERROR_STATE()
			;

	EXEC [dbo].[msp_ProcessLog] 'HASH', '9) FAILED msit_MIWarehouseCodesAndDescriptions_Hash_Generation', null, 'msit_MIWarehouseCodesAndDescriptions_Hash_Generation', 'Openwork';
 
	RAISERROR (@Message, @Severity, @State);
END CATCH
GO
