AS
/******************************************************************************

Date      Amended By  Change Details
========  ==========  ==============
21/05/19  C Mellors   Created SP

*******************************************************************************/
SET NOCOUNT ON;

BEGIN TRY
	EXEC [dbo].[msp_ProcessLog] 'HASH', '1) Start mstt_Policies_Hash_Generation', null, 'mstt_Policies_Hash_Generation', 'Openwork';

	-- Rows to Delete
	DELETE	[Staging].[mstt_Policies_Hash]
