										+ ISNULL(CONVERT(VARCHAR(4000), [Discontinuance]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [DiscontinuanceReasons]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [AssessmentCheckPerformed]),'')
