										+ ISNULL(CONVERT(VARCHAR(4000), [ReplacedPremium]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [MortgageRelated]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RetirementInvestment]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [PPSwitch]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [EPSReference]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ReferralCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [SuspendCommission]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [SuspendCommissionLastUpdated]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [SoldThroughB30]),'')
