										+ ISNULL(CONVERT(VARCHAR(4000), [SalesQualityAdviserLevelCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [PracticeCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [SuspendCommInd]),'')
								)  AS [HashValue]
			FROM	[dbo].[mstt_Policies] p
			WHERE	EXISTS	(
							SELECT	*
							FROM	[Staging].[mstt_Policies_Movement] m
							WHERE	m.[POL_NUM] = p.[POL_NUM]
							)
		) AS Source
			ON Target.[POL_NUM] = Source.[POL_NUM]
		WHEN NOT MATCHED BY TARGET THEN
			INSERT	([POL_NUM]
					,[HashValue] 
					)
			VALUES	(Source.[POL_NUM]
					,Source.[HashValue]
					) 
		WHEN MATCHED AND Source.[HashValue] <> Target.[HashValue] THEN 
			UPDATE SET	 [HashValue] = Source.[HashValue];
	END
	ELSE
	BEGIN
		MERGE [Staging].[mstt_Policies_Hash] AS Target
		USING	(
			SELECT	 [POL_NUM]
					,HASHBYTES('SHA1'	, ISNULL(CONVERT(VARCHAR(4000), [POL_NUM]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [CLIENT_NUM]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [JOINT_NUM]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [SCHEME_NUM]),'')
