SET NOCOUNT ON;

BEGIN TRY
	EXEC [dbo].[msp_ProcessLog] 'HASH', '1) Start mstt_ProductHierarchy_Hash_Generation', null, 'mstt_ProductHierarchy_Hash_Generation', 'Openwork';

	-- Rows to Delete
	DELETE	[Staging].[mstt_ProductHierarchy_Hash]
	WHERE	[ProductCode] NOT IN (SELECT [ProductCode] FROM [dbo].[mstt_ProductHierarchy]);

	IF @Mode = 'MOVE'
	BEGIN
		MERGE [Staging].[mstt_ProductHierarchy_Hash] AS Target
		USING	(
			SELECT	 [ProductCode]
					,HASHBYTES('SHA1'	, ISNULL(CONVERT(VARCHAR(4000), [ProductCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ProductName]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ProductType]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ReportingProductCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RegulationDefault]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [DualSalesProcess]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [APE_Flag]),'')
