										+ ISNULL(CONVERT(VARCHAR(4000), [RegularPremBasisCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RegularPremABCRate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [StructuredProduct]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RDRType]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RetentionRateFactor]),'')
								) AS [HashValue]
			FROM	[dbo].[mstt_ProductHierarchy] ph
			WHERE	EXISTS	(
							SELECT	*
							FROM	[Staging].[mstt_ProductHierarchy_Movement] m
							WHERE	m.[ProductCode] = ph.[ProductCode]
							)
		) AS Source
			ON Target.[ProductCode] = Source.[ProductCode]
		WHEN NOT MATCHED BY TARGET THEN
