										+ ISNULL(CONVERT(VARCHAR(4000), [ProductGroupName]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ProductCategoryCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ProductCategoryName]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ProductProviderCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ReportingProductProviderCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [CommRepProductProviderCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ZFSGroupFlag]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [LeagueIncludeFlag]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [SinglePremBasisCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [SinglePremABCRate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RegularPremBasisCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RegularPremABCRate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [StructuredProduct]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RDRType]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RetentionRateFactor]),'')
								) AS [HashValue]
			FROM	[dbo].[mstt_ProductHierarchy] ph
		) AS Source
			ON Target.[ProductCode] = Source.[ProductCode]
		WHEN NOT MATCHED BY TARGET THEN
			INSERT	([ProductCode]
					,[HashValue] 
					)
			VALUES	(Source.[ProductCode]
					,Source.[HashValue]
					) 
		WHEN MATCHED AND Source.[HashValue] <> Target.[HashValue] THEN 
			UPDATE SET	 [HashValue] = Source.[HashValue];
	END

	-- Empty the source movement tables
	TRUNCATE TABLE [Staging].[mstt_ProductHierarchy_Movement];

	EXEC [dbo].[msp_ProcessLog] 'HASH', '2) End mstt_ProductHierarchy_Hash_Generation', null, 'mstt_ProductHierarchy_Hash_Generation', 'Openwork';
END TRY
BEGIN CATCH
	DECLARE	 @ErrorNumber INT = ERROR_NUMBER()
			,@Message VARCHAR(MAX) = ERROR_MESSAGE()
			,@Severity INT = ERROR_SEVERITY()
