										+ ISNULL(CONVERT(VARCHAR(4000), [AuthorisedBy]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [AuthorisedDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ParentID]),'')
								) AS [HashValue]
			FROM	[dbo].[sa_swift_S_PACC] spacc
			WHERE	EXISTS	(
							SELECT	*
							FROM	[Staging].[sa_swift_S_PACC_Movement] m
							WHERE	m.[ID] = spacc.[ID]
							)
		) AS Source
			ON Target.[ID] = Source.[ID]
		WHEN NOT MATCHED BY TARGET THEN
			INSERT	([ID]
					,[HashValue] 
					)
			VALUES	(Source.[ID]
					,Source.[HashValue]
					) 
		WHEN MATCHED AND Source.[HashValue] <> Target.[HashValue] THEN 
			UPDATE SET	 [HashValue] = Source.[HashValue];
	END
	ELSE
	BEGIN
		MERGE [Staging].[sa_swift_S_PACC_Hash] AS Target
		USING	(
			SELECT	 [ID]
					,HASHBYTES('SHA1'	, ISNULL(CONVERT(VARCHAR(4000), [ID]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [POL_NUM]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [STATEMENT]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [DATE_DUE]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [AMOUNT_DUE]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [DATE_RECV]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [AMOUNT_REC]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [TYPE]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [STATUS]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ADJUST]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [COMP_CODE]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [CLIENT_NUM]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [NOTES]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [Rebate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [StatementCreatedFrom]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [VAT]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [UnallocatedReasonCode]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [RenewalType]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [TransactionID]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [PMBSerial]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [PMBContra]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [MatchID]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [FutureExpectationID]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [Manual]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [Authorised]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [OriginalAmountReceived]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [CreatedBy]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [CreatedDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [AuthorisedBy]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [AuthorisedDate]),'')
										+ ISNULL(CONVERT(VARCHAR(4000), [ParentID]),'')
								) AS [HashValue]
			FROM	[dbo].[sa_swift_S_PACC] spacc
		) AS Source
			ON Target.[ID] = Source.[ID]
		WHEN NOT MATCHED BY TARGET THEN
			INSERT	([ID]
					,[HashValue] 
					)
			VALUES	(Source.[ID]
					,Source.[HashValue]
					) 
		WHEN MATCHED AND Source.[HashValue] <> Target.[HashValue] THEN 
			UPDATE SET	 [HashValue] = Source.[HashValue];
	END

	-- Empty the source movement tables
	TRUNCATE TABLE [Staging].[sa_swift_S_PACC_Movement];

	EXEC [dbo].[msp_ProcessLog] 'HASH', '2) End sa_swift_S_PACC_Hash_Generation', null, 'sa_swift_S_PACC_Hash_Generation', 'Openwork';
END TRY
