-- =============================================
-- Author:		Serafeim Tourlidas
-- Create date: 15/06/2022
-- Description:	Import the concessions spreadsheet for the KPIs
-- =============================================
CREATE PROCEDURE [TandC].[Pr_Concessions_Insert]
	
AS
BEGIN
	SET NOCOUNT ON;


DELETE from [prod_zurich_openwork_datawarehouse].[TandC].[Concessions_Staging]
  WHERE COALESCE([DateLogged],[Authorisedby],[AdviserName],[AdviserUID],[FirmName],[FirmUID],[LicenceArea],[TypeofConcession],[TOCDetails]
,[Reason],[ReasonDetails],[ExtendedUntil],[QRMUID],[QRM],[SQRMLeadQRM],[Loggedby],[Comments]) IS NULL 



	   merge [prod_zurich_openwork_datawarehouse].[TandC].[Concessions]  as t 
		using (SELECT [DateLogged],[ConcessionNumber],[Authorisedby],[AdviserName],[AdviserUID],[FirmName],[FirmUID],[LicenceArea],[TypeofConcession],[TOCDetails],[Reason],[ReasonDetails],[ExtendedUntil],[QRMUID],[QRM],[SQRMLeadQRM],[Loggedby],[Comments] fROM [prod_zurich_openwork_datawarehouse].[TandC].[Concessions_Staging]   WHERE COALESCE([DateLogged],[Authorisedby],[AdviserName],[AdviserUID],[FirmName],[FirmUID],[LicenceArea],[TypeofConcession],[TOCDetails]
		,[Reason],[ReasonDetails],[ExtendedUntil],[QRMUID],[QRM],[SQRMLeadQRM],[Loggedby],[Comments]) IS NOT NULL )  as s 
	 on (t.[ConcessionNumber] = s.[ConcessionNumber])  
		when matched  and (isnull(t.[DateLogged],'') <> isnull(s.[DateLogged],'') OR isnull(t.[Authorisedby],'') <> isnull(s.[Authorisedby],'') OR isnull(t.[AdviserName],'') <> isnull(s.[AdviserName],'') OR isnull(t.[AdviserUID],'') <> isnull(s.[AdviserUID],'') OR isnull(t.[FirmName],'') <> isnull(s.[FirmName],'') OR isnull(t.[FirmUID],'') <> isnull(s.[FirmUID],'') OR 
isnull(t.[LicenceArea],'') <> isnull(s.[LicenceArea],'') OR isnull(t.[TypeofConcession],'') <> isnull(s.[TypeofConcession],'') OR isnull(t.[TOCDetails],'') <> isnull(s.[TOCDetails],'') OR isnull(t.[Reason],'') <> isnull(s.[Reason],'') OR isnull(t.[ReasonDetails],'') <> isnull(s.[ReasonDetails],'') OR 
isnull(t.[ExtendedUntil],'') <> isnull(s.[ExtendedUntil],'') OR isnull(t.[QRMUID],'') <> isnull(s.[QRMUID],'') OR isnull(t.[QRM],'') <> isnull(s.[QRM],'') OR isnull(t.[SQRMLeadQRM],'') <> isnull(s.[SQRMLeadQRM],'') OR isnull(t.[Loggedby],'') <> isnull(s.[Loggedby],'') OR isnull(t.[Comments],'') <> isnull(s.[Comments],''))
	 then update set 
		 t.[DateLogged]=s.[DateLogged], t.[Authorisedby]=s.[Authorisedby], t.[AdviserName]=s.[AdviserName], t.[AdviserUID]=s.[AdviserUID], t.[FirmName]=s.[FirmName], t.[FirmUID]=s.[FirmUID], 
		t.[LicenceArea]=s.[LicenceArea], t.[TypeofConcession]=s.[TypeofConcession], t.[TOCDetails]=s.[TOCDetails], t.[Reason]=s.[Reason], t.[ReasonDetails]=s.[ReasonDetails], 
		t.[ExtendedUntil]=s.[ExtendedUntil], t.[QRMUID]=s.[QRMUID], t.[QRM]=s.[QRM], t.[SQRMLeadQRM]=s.[SQRMLeadQRM], t.[Loggedby]=s.[Loggedby], t.[Comments]=s.[Comments], t.[DateUpdated]=getdate()
		when not matched by target then 
			insert ([DateLogged],[ConcessionNumber],[Authorisedby],[AdviserName],[AdviserUID],[FirmName],[FirmUID],[LicenceArea],[TypeofConcession],[TOCDetails],[Reason],[ReasonDetails],[ExtendedUntil],[QRMUID],[QRM],[SQRMLeadQRM],[Loggedby],[Comments]) 
			values ([DateLogged],[ConcessionNumber],[Authorisedby],[AdviserName],[AdviserUID],[FirmName],[FirmUID],[LicenceArea],[TypeofConcession],[TOCDetails],[Reason],[ReasonDetails],[ExtendedUntil],[QRMUID],[QRM],[SQRMLeadQRM],[Loggedby],[Comments]); 

END
GO
