Date		Author		Description
----		------		-----------
08/12/2016	A Groves	New version of the spreadsheet has Yes and No rather than Y and N.
						The Yes and No are transformed to Y and N as needed by the KPI proc. 
03/01/2017	A Groves	New version of this proc:
						1) Column TandC.CRG.LastUploadedDate removed.
						2) New columns appended to TandC.CRG:
							Outcome	(needed for Customer Outcomes Board Pack)
							DateInserted
							DateLastUpdated
						3) MERGE statement used in case old data is removed from the spreadsheet.
************************************************************************************************/
CREATE procedure [TandC].[Pr_CRG_Insert]

As

--truncate table TandC.CRG	AG 03/01/2016

declare @DateLastUpdated datetime
set @DateLastUpdated = GETDATE()

select top 0 * into #CRG from TandC.CRG

insert into #CRG
(
	CRGID, 
	ReferralDate, 
	Adviser, 
	AdviserUID, 
	Business, 
	BusinessUID, 
	Informal, 
	Formal, 
	Reason, 
	AdviserNotified, 
	CRGMeetingDate, 
	TerminatedNotFitAndProper, 
	TerminationCommercial, 
	FullAndFinalWarningOrBreach, 
	SupervisoryActions, 
	Other, 
	AllActionsCompleted,
	Outcome,
	DateInserted,
	DateLastUpdated
)
Select	--UID + CAST(Month([CRG Meeting Date])as varchar(2)) as CRGID, 
		case when ISDATE([CRG Meeting Date]) = 1 
			then UID + convert(varchar(8),CONVERT(datetime,[CRG Meeting Date],120),112)			
			else UID + '19000101' 
		end as CRGID,
		DATENAME(mm,[CRG Meeting date])+' '+CAST(YEAR([CRG Meeting Date]) as varchar(4)) as ReferralDate, 
		Adviser, 
		UID, 
		Business, 
		[Business UID], 
		case when Informal is null then 'N' else Informal end as Informal,	-- AG 08/12/2016. No longer in spreadsheet
		case																-- AG 08/12/2016 
			when isnull(Formal,'') = '' then 'N' 
			when Formal = 'No' then 'N'
			when Formal = 'Yes' then 'Y'
			when Formal in ('N','Y') then UPPER(Formal)
			else 'N'
		end as Formal, 
		[Reason for Referral], 
		[Adviser notified], 
		[CRG meeting date], 
		[Termination (not fit and proper)], 
		[Termination (commercial)], 
		[Full and Final Warning/Breach], 
		[Supervisory actions], 
		Other, 
		case																-- AG 08/12/2016 
			when isnull([All actions completed],'') = '' then 'N' 
			when [All actions completed] = 'No' then 'N'
			when [All actions completed] = 'Yes' then 'Y'
			when [All actions completed] in ('N','Y') then UPPER([All actions completed])
			else 'N'
		end as [All actions completed], 
		Outcome,
		GETDATE() as DateInserted,
		GETDATE() as DateLastUpdated
from	TandC.CRG_Staging
where	UID is not null
and		isnumeric(UID) = 1

/****************************************************************************

	Merge rows into the destination table

****************************************************************************/

merge	TandC.CRG as target
using	#CRG as source
on		target.CRGID = source.CRGID 
when	matched 
		and (isnull(target.ReferralDate,'') <> isnull(source.ReferralDate,'')
		or	 isnull(target.Adviser,'') <> isnull(source.Adviser,'')
		or	 isnull(target.AdviserUID,'') <> isnull(source.AdviserUID,'')
		or	 isnull(target.Business,'') <> isnull(source.Business,'')
		or	 isnull(target.BusinessUID,'') <> isnull(source.BusinessUID,'')
		or	 isnull(target.Informal,'') <> isnull(source.Informal,'')
		or	 isnull(target.Formal,'') <> isnull(source.Formal,'')
		or	 isnull(target.Reason,'') <> isnull(source.Reason,'')
		or	 isnull(target.AdviserNotified,'') <> isnull(source.AdviserNotified,'')
		or	 isnull(target.CRGMeetingDate,'') <> isnull(source.CRGMeetingDate,'')
		or	 isnull(target.TerminatedNotFitAndProper,'') <> isnull(source.TerminatedNotFitAndProper,'')
		or	 isnull(target.TerminationCommercial,'') <> isnull(source.TerminationCommercial,'')
		or	 isnull(target.FullAndFinalWarningOrBreach,'') <> isnull(source.FullAndFinalWarningOrBreach,'')
		or	 isnull(target.SupervisoryActions,'') <> isnull(source.SupervisoryActions,'')
		or	 isnull(target.Other,'') <> isnull(source.Other,'')
		or	 isnull(target.AllActionsCompleted,'') <> isnull(source.AllActionsCompleted,'')
		or	 isnull(target.Outcome,'') <> isnull(source.Outcome,''))
then	update 
			set target.ReferralDate = source.ReferralDate,
				target.Adviser = source.Adviser,
				target.AdviserUID = source.AdviserUID,
				target.Business = source.Business,
				target.BusinessUID = source.BusinessUID,
				target.Informal = source.Informal,
				target.Formal = source.Formal,
				target.Reason = source.Reason,
				target.AdviserNotified = source.AdviserNotified,
				target.CRGMeetingDate = source.CRGMeetingDate,
				target.TerminatedNotFitAndProper = source.TerminatedNotFitAndProper,
				target.TerminationCommercial = source.TerminationCommercial,
				target.FullAndFinalWarningOrBreach = source.FullAndFinalWarningOrBreach,
				target.SupervisoryActions = source.SupervisoryActions,
				target.Other = source.Other,
				target.AllActionsCompleted = source.AllActionsCompleted,
				target.Outcome = source.Outcome,
				target.DateLastUpdated = @DateLastUpdated
when	not matched by target
then	insert
		(
			CRGID, 
			ReferralDate, 
			Adviser, 
			AdviserUID, 
			Business, 
			BusinessUID, 
			Informal, 
			Formal, 
			Reason, 
			AdviserNotified, 
			CRGMeetingDate, 
			TerminatedNotFitAndProper, 
			TerminationCommercial, 
			FullAndFinalWarningOrBreach, 
			SupervisoryActions, 
			Other, 
			AllActionsCompleted,
			Outcome,
			DateInserted,
			DateLastUpdated
		)		
		values
		(
			source.CRGID, 
			source.ReferralDate, 
			source.Adviser, 
			source.AdviserUID, 
			source.Business, 
			source. BusinessUID, 
			source.Informal, 
			source.Formal, 
			source.Reason, 
			source.AdviserNotified, 
			source.CRGMeetingDate, 
			source.TerminatedNotFitAndProper, 
			source.TerminationCommercial, 
			source.FullAndFinalWarningOrBreach, 
			source.SupervisoryActions, 
			source.Other, 
			source.AllActionsCompleted,
			source.Outcome,
			@DateLastUpdated,
			@DateLastUpdated
		);

GO
