/****** Object:  StoredProcedure [TandC].[Pr_FMQ_From_FMQAPP]    Script Date: 7/3/2026 3:44:28 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: Pr_FMQ_From_FMQAPP
Author	: A Groves
Date	: 19/09/2017

Purpose	:	This proc stages the FMQ data from FMQAPP which is a Logi app that was introduced
			for maintaining FMQ data in place of a spreadsheet.
			
			The existing stored procedure "TandC.Pr_FMQ_Insert" is then run to upload the 
			staged data to the destination table.

			Execute as follows:
			
				exec [TandC].[Pr_FMQ_From_FMQAPP] 

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
21/09/2017	A Groves	Added additional job titles to the role look-up:
						NASP, supervisor, PA and Admin.
***********************************************************************************************/
CREATE PROCEDURE [TandC].[Pr_FMQ_From_FMQAPP] 

AS

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/

declare		@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int,
			@DateLastUpdated		datetime = getdate(),
			@Client					varchar(50),
			@Module					varchar(50),
			@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseError				varchar(50),
			@PhaseLog				varchar(50)

			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @Module				= object_name(@@procid)
set @Client				= 'FMQ APP'
set @PhaseStart			= 'START'
set @PhaseEnd			= 'END'
set @PhaseError			= 'ERROR'
set @PhaseLog			= 'LOG'
set @ErrNum				= 0				

/****************************************************************************

	Start transaction
																		
****************************************************************************/

SET XACT_ABORT ON	-- Needed if XACT_STATE() function is used.

BEGIN TRY

	BEGIN TRANSACTION

	/****************************************************************************

		Load to FMQ staging table
																		
	****************************************************************************/

	truncate table TandC.FMQ_Staging

	insert into TandC.FMQ_Staging
	(
		Adviser,
		Role,
		Code,
		Enterprise,
		Supervisor,
		BQM,
		AQM,
		[Original Rating],
		[Date of original Rating],
		[Reason for rating],
		[Current rating],
		[Date risk rating applied],
		[Date of next review],
		[Case Owner],
		[state of play],
		LastUploadedDate
	)
	select	uh.UserName as Adviser,
			cd.Code_Description as Role, 
			fm.AdviserUID as Code,
			coalesce(uh.BusinessTradingName,uh.BusinessCompanyName) as Enterprise,
			isnull(uh.SupervisorName,uh.BQMName) as Supervisor,
			uh.BQMName as BQM, 
			uh.AQMName as AQM,
			fm.OriginalRating,
			fm.DateOfOriginalRating,
			fm.ReasonForRating,
			fm.CurrentRating,
			fm.DateOfRisk as DateRiskRaingApplied,
			fm.DateOfNextReview,
			fm.CaseWorker as CaseOwner,
			left(fm.Notes,255) as StateOfPlay,
			@DateLastUpdated as LastUploadedDate
	from	FMQAPP.dbo.FinancialMonitoring fm
			left join mi_insight_UserHierarchy uh on uh.UserUID = fm.AdviserUID
			left join sa_insight_CodeDescription cd 
						on cd.Code_CodeType = 54 
						and cd.Code_Code = coalesce(uh.UserJobTitleCodePartner, uh.UserJobTitleCodeSeller,
													uh.UserJobTitleCodeNASP, uh.UserJobTitleCodeSupervisor, 
													uh.UserJobTitleCodePA, uh.UserJobTitleCodeAdmin) 
	where	fm.Deleted = 0
	--and		fm.AdviserUID = '4008038'
	
	/****************************************************************************

		Load to FMQ destination table
																		
	****************************************************************************/

	exec TandC.Pr_FMQ_Insert
	
	/****************************************************************************

		Commit transaction
																		
	****************************************************************************/
	 
	COMMIT TRANSACTION      
	
END TRY

/****************************************************************************

	Error handling
																		
****************************************************************************/

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	-- Test XACT_STATE for 0, 1, or -1.
    -- If 1, the transaction is committable.
    -- If -1, the transaction is uncommittable and should be rolled back.
    -- If 0, there is no transaction and a commit or rollback operation would generate an error.

	if @ErrState = -1			-- Transaction is uncommitable
		rollback transaction

	if @ErrState = 1			
		commit transaction

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															
																	
****************************************************************************/
GO
