/******************************************************************************************************
Program:	Pr_MysteryShop_Insert
Date:		30th Dec 2015
Author:		Sarah Inglis

AMENDMENT HISTORY
=================
Date		Author			Description
----		------			-----------
13/12/2016	A Groves		SR456151/CH15222 Customer Outcomes project. This proc was changed to
							use a MERGE to update values on previously loaded mystery shops.
14/12/2016	A Groves		Paul Staines asked for data fields to strip off leading and trailing
							blanks.
*******************************************************************************************************/
CREATE procedure [TandC].[Pr_MysteryShop_Insert]

As

/****************************************************************************

	Transform the data into a temporary table with the appropriate data types

****************************************************************************/

select top 0 * into #MysteryShop from TandC.MysteryShop

insert into #MysteryShop
(
	MysteryShopsID,
	Year,
	Quarter,
	EnterpriseName,
	EnterpriseUID,
	PartnerName,
	PartnerUID,
	AQM,
	ScenarioType,
	Scenario,
	DateAppt,
	Date1stMeetingCompleted,
	Date2ndMeetingCompleted,
	Date3rdMeetingCompleted,
	ShopComplete,
	DateOfReview,
	GradingOfShop,
	DateFinalReportIssued,
	DateActionsSignedOff,
	Notes
) 
SELECT	ltrim(rtrim([YEAR])) + ltrim(rtrim([Quarter])) + ltrim(rtrim([EnterpriseUID])) as [MysteryShopsID],
		ltrim(rtrim([Year])) as Year,
		ltrim(rtrim([Quarter])) as Quarter,
		ltrim(rtrim([EnterpriseName])) as EnterpriseName,
		ltrim(rtrim([EnterpriseUID])) as EnterpriseUID,
		ltrim(rtrim([PartnerName])) as PartnerName,
		ltrim(rtrim([PartnerUID])) as PartnerUID,
		ltrim(rtrim([AQM])) as AQM,
		ltrim(rtrim([ScenarioType])) as ScenarioType,
		ltrim(rtrim([Scenario])) as Scenario,
		ltrim(rtrim([DateAppt])) as DateAppt,
		CASE WHEN isDate([Date1stMeetingCompleted]) = 1 
			THEN [Date1stMeetingCompleted] 
			ELSE NULL
		end as [Date1stMeetingCompleted] ,
		CASE WHEN isDate([Date2ndMeetingCompleted] ) = 1 
			THEN [Date2ndMeetingCompleted] 
			ELSE NULL
		end as  [Date2ndMeetingCompleted] ,
		CASE WHEN isDate([Date3rdMeetingCompleted]) = 1 
			THEN [Date3rdMeetingCompleted] 
			ELSE NULL
		end as  [Date3rdMeetingCompleted] ,
		ltrim(rtrim(ShopComplete)) as ShopComplete,
		ltrim(rtrim(DateOfReview)) as DateOfReview,
		ltrim(rtrim(GradingOfShop)) as GradingOfShop,
		ltrim(rtrim(DateFinalReportIssued)) as DateFinalReportIssued,
		ltrim(rtrim(DateActionsSignedOff)) as DateActionsSignedOff,
		ltrim(rtrim(Notes)) as Notes
FROM	tandc.MysteryShop_Staging mss
where	[EnterpriseUID] is not null
and		ISNUMERIC(EnterpriseUID) = 1

/****************************************************************************

	Merge rows into the destination table

****************************************************************************/

merge	TandC.MysteryShop as target
using	#MysteryShop as source
on		target.PartnerUID = source.PartnerUID
and		target.Year = source.Year
and		target.Quarter = source.Quarter				
when	matched 
		and	(isnull(target.MysteryShopsID,'') <> isnull(source.MysteryShopsID,'')
		or	 isnull(target.EnterpriseName,'') <> isnull(source.EnterpriseName,'')
		or	 isnull(target.EnterpriseUID,-1) <> isnull(source.EnterpriseUID,-1)
		or	 isnull(target.PartnerName,'') <> isnull(source.PartnerName,'')
		or	 isnull(target.AQM,'') <> isnull(source.AQM,'')
		or	 isnull(target.ScenarioType,'') <> isnull(source.ScenarioType,'')
		or	 isnull(target.Scenario,'') <> isnull(source.Scenario,'')
		or	 isnull(target.DateAppt,'') <> isnull(source.DateAppt,'')
		or	 isnull(target.Date1stMeetingCompleted,'') <> isnull(source.Date1stMeetingCompleted,'')
		or	 isnull(target.Date2ndMeetingCompleted,'') <> isnull(source.Date2ndMeetingCompleted,'') 
		or	 isnull(target.Date3rdMeetingCompleted,'') <> isnull(source.Date3rdMeetingCompleted,'')
		or	 isnull(target.ShopComplete,'') <> isnull(source.ShopComplete,'')
		or	 isnull(target.DateOfReview,'') <> isnull(source.DateOfReview,'')
		or	 isnull(target.GradingOfShop,'') <> isnull(source.GradingOfShop,'')
		or	 isnull(target.DateFinalReportIssued,'') <> isnull(source.DateFinalReportIssued,'')
		or	 isnull(target.DateActionsSignedOff,'') <> isnull(source.DateActionsSignedOff,'')
		or	 isnull(target.Notes,'') <> isnull(source.Notes,''))
then	update 
			set	target.MysteryShopsID = source.MysteryShopsID,
				target.Year = source.Year,			-- Matching field is updated in case of trailing blanks
				target.Quarter = source.Quarter,	-- Matching field is updated in case of trailing blanks
				target.EnterpriseName = source.EnterpriseName,
				target.EnterpriseUID = source.EnterpriseUID,
				target.PartnerName = source.PartnerName,
				target.AQM = source.AQM,
				target.ScenarioType = source.ScenarioType,
				target.Scenario = source.Scenario,
				target.DateAppt = source.DateAppt,
				target.Date1stMeetingCompleted = source.Date1stMeetingCompleted,
				target.Date2ndMeetingCompleted = source.Date2ndMeetingCompleted,
				target.Date3rdMeetingCompleted = source.Date3rdMeetingCompleted,
				target.ShopComplete = source.ShopComplete,
				target.DateOfReview = source.DateOfReview,
				target.GradingOfShop = source.GradingOfShop,
				target.DateFinalReportIssued = source.DateFinalReportIssued,
				target.DateActionsSignedOff = source.DateActionsSignedOff,
				target.Notes = source.Notes,
				target.LastUpdated = getdate()	
when	not matched by target
then	insert
		(
			MysteryShopsID,
			Year,
			Quarter,
			EnterpriseName,
			EnterpriseUID,
			PartnerName,
			PartnerUID,
			AQM,
			ScenarioType,
			Scenario,
			DateAppt,
			Date1stMeetingCompleted,
			Date2ndMeetingCompleted,
			Date3rdMeetingCompleted,
			ShopComplete,
			DateOfReview,
			GradingOfShop,
			DateFinalReportIssued,
			DateActionsSignedOff,
			Notes,
			LastUpdated,
			DateInserted
		)		
		values
		(
			source.MysteryShopsID,
			source.Year,
			source.Quarter,
			source.EnterpriseName,
			source.EnterpriseUID,
			source.PartnerName,
			source.PartnerUID,
			source.AQM,
			source.ScenarioType,
			source.Scenario,
			source.DateAppt,
			source.Date1stMeetingCompleted,
			source.Date2ndMeetingCompleted,
			source.Date3rdMeetingCompleted,
			source.ShopComplete,
			source.DateOfReview,
			source.GradingOfShop,
			source.DateFinalReportIssued,
			source.DateActionsSignedOff,
			source.Notes,
			getdate(),
			getdate()
		);


GO
