Date		Who			Description
----		---			-----------
29/04/2016	A Groves	SR429678. The destination table is not structured to store any more
						than the current league. Therefore a table truncation has been 
						introduced prior to the table load.
************************************************************************************************/

CREATE procedure [TandC].[Pr_QLS_MCOBICOB_Insert]

As

begin

truncate table TandC.QLS_MCOBICOB

insert into TandC.QLS_MCOBICOB
(
	BUID, 
	Firmname, 
	LeaguePosition, 
	QualityScore,
	LastUploadedDate
)
select	BUID, 
		[Firm name], 
		[League Position], 
		[Quality Score],
		GETDATE()
from	TandC.QLS_MCOBICOB_Staging
where	BUID is not null
 
end

GO
