/************************************************************************************************
  	 Program:  	[TandC].[Pr_Quality_Calls_Insert]					
	  Author:	S Inglis
Date created:	30/12/2015
													
 Description:   This proc transfers the Call Quality data from the staging table loaded by SSIS
				to the main table.
				
				It is called as follows:

				exec [TandC].[Pr_Quality_Calls_Insert]
													
Amendment History								
-----------------								
											
Date		Who			Description
----		---			-----------
25/04/2016	A Groves	SR429678. Introduced new spreadsheet column "OutcomeDate" for use in the
						QCFMS (adviser) KPI proc.
28/11/2016	A Groves	SR456151/CH15222. 
						1)	The spreadsheet has changed: The worksheet name is used for Area and 
							previously this was 'Protection'. It has now become 'ICOB' and this 
							change ensures that Area remains unchanged. 
						2)	Invalid dates causing failures. Defensive coding added. 
04/01/2016	A Groves	Proc re-written to use MERGE statement as this will ensure that
							any updates on old cases will update on the destination table.
10/10/2018	A Groves	1)	Handle unknown UID values by either not updating them or inserting 
							blank rather than null.
						2)	Remove time component in "Date" column to ensure any queries that 
							apply a date range condition work correctly. 
************************************************************************************************/
CREATE procedure [TandC].[Pr_Quality_Calls_Insert]

as

declare @DateLastUpdated datetime
set @DateLastUpdated = GETDATE()

select top 0 * into #QC from [TandC].[Quality_Calls]

INSERT INTO #QC
(	
	[Area],
	[Date],
	[Client],
	[CaseID],
	[CallType],
	[CallTime],
	[NumberCalled],
	[Adviser],
	[UID],        
	[Enterprise],                                                                                                                                                                                                                                                   
	[EnterpriseCode], 
	[Product],                                                                                                                                                                                                                                                     
	[Disclosure],                                                                                                                                                                                                                                                      
	[FeeAgreement],                                                                                                                                                                                                                                                    
	[FactFind],                                                                                                                                                                                                                                                        
	[FormulatingAdvice],                                                                                                                                                                                                                                               
	[Affordability],                                                                                                                                                                                                                                                   
	[Presenting the recommendation],                                                                                                                                                                                                                                   
	[Suitability Report],                                                                                                                                                                                                                                              
	[Customer experience],                                                                                                                                                                                                                                             
	[NPS 1],       
	[NPS 2],       
	[NPS 3],       
	[Outcome],  
	[OutcomeDate],							--AG 25/04/2016                                                                                                                                                                                                                                                       
	[DateInserted],
	[DateLastUpdated]
)
SELECT	case replace([Area],'$','')			--AG 28/11/2016
			when 'ICOB' then 'Protection'
			else replace([Area],'$','')	
		end as Area,
		case when isdate([Date]) = 1 
			then case when CONVERT(datetime,[Date],120) <= '2079-06-06'
					then convert(date,[Date])	--AG 10/10/2018 (2)
					else null
				 end
			else null
		end as [Date], --AG 28/11/2016
		[Client],
		[CaseID],
		[CallType],
		[CallTime],
		[NumberCalled],
		[Adviser],
		[UID],        
		[Enterprise],                                                                                                                                                                                                                                                   
		[EnterpriseCode], 
		[Product],                                                                                                                                                                                                                                                     
		[Disclosure],                                                                                                                                                                                                                                                      
		[FeeAgreement],                                                                                                                                                                                                                                                    
		[FactFind],                                                                                                                                                                                                                                                        
		[FormulatingAdvice],                                                                                                                                                                                                                                               
		[Affordability],                                                                                                                                                                                                                                                   
		[Presenting the recommendation],                                                                                                                                                                                                                                   
		[Suitability Report],                                                                                                                                                                                                                                              
		[Customer experience],                                                                                                                                                                                                                                             
		[NPS 1],
		[NPS 2],
		[NPS 3],
		[Outcome],
		case when isdate(OutcomeDate) = 1 
			then case when CONVERT(datetime,OutcomeDate,120) <= '2079-06-06'
					then OutcomeDate
					else null
				 end
			else null
		end as OutcomeDate, 	--AG 25/04/2016 & AG 28/11/2016.		
		getdate() as DateInserted,
		getdate() as DateLastUpdated
FROM	[TandC].[Quality_Calls_Staging] 
where	[Caseid] is not null

/****************************************************************************

	Merge rows into the destination table

****************************************************************************/

merge	[TandC].[Quality_Calls] as target
using	#QC as source
on		target.CaseID = source.CaseID 
when	matched 
		and BINARY_CHECKSUM(target.[Area],target.[Date],target.[Client],target.[CaseID],target.[CallType],target.[CallTime],target.[NumberCalled],target.[Adviser],
							target.[UID],target.[Enterprise],target.[EnterpriseCode],target.[Product],target.[Disclosure],target.[FeeAgreement],
							target.[FactFind],target.[FormulatingAdvice],target.[Affordability],target.[Presenting the recommendation],
							target.[Suitability Report],target.[Customer experience],target.[NPS 1],target.[NPS 2],target.[NPS 3],target.[Outcome],
							target.[OutcomeDate]) <> 	
			BINARY_CHECKSUM(source.[Area],source.[Date],source.[Client],source.[CaseID],source.[CallType],source.[CallTime],source.[NumberCalled],source.[Adviser],
							source.[UID],source.[Enterprise],source.[EnterpriseCode],source.[Product],source.[Disclosure],source.[FeeAgreement],
							source.[FactFind],source.[FormulatingAdvice],source.[Affordability],source.[Presenting the recommendation],
							source.[Suitability Report],source.[Customer experience],source.[NPS 1],source.[NPS 2],source.[NPS 3],source.[Outcome],
							source.[OutcomeDate])
then	update 
			set target.[Area] = source.[Area],
				target.[Date] = source.[Date],
				target.[Client] = source.[Client],
				target.[CaseID] = source.[CaseID],
				target.[CallType] = source.[CallType],
				target.[CallTime] = source.[CallTime],
				target.[NumberCalled] = source.[NumberCalled],
				target.[Adviser] = source.[Adviser],
				target.[UID] = case when isnull(source.[UID],'') <> '' then source.[UID] else target.[UID] end,	--AG 10/10/2018 (1)
				target.[Enterprise] = source.[Enterprise],                                                                                                                                                                                                                                                   
				target.[EnterpriseCode] = source.[EnterpriseCode], 
				target.[Product] = source.[Product],                                                                                                                                                                                                                                                     
				target.[Disclosure] = source.[Disclosure],                                                                                                                                                                                                                                                      
				target.[FeeAgreement] = source.[FeeAgreement],                                                                                                                                                                                                                                                    
				target.[FactFind] = source.[FactFind],                                                                                                                                                                                                                                                        
				target.[FormulatingAdvice] = source.[FormulatingAdvice],                                                                                                                                                                                                                                               
				target.[Affordability] = source.[Affordability],                                                                                                                                                                                                                                                   
				target.[Presenting the recommendation] = source.[Presenting the recommendation],                                                                                                                                                                                                                                   
				target.[Suitability Report] = source.[Suitability Report],                                                                                                                                                                                                                                              
				target.[Customer experience] = source.[Customer experience],                                                                                                                                                                                                                                             
				target.[NPS 1] = source.[NPS 1],       
				target.[NPS 2] = source.[NPS 2],       
				target.[NPS 3] = source.[NPS 3],       
				target.[Outcome] = source.[Outcome],  
				target.[OutcomeDate] = source.[OutcomeDate],  
				target.[DateLastUpdated] = @DateLastUpdated
when	not matched by target
then	insert
		(
			[Area],
			[Date],
			[Client],
			[CaseID],
			[CallType],
			[CallTime],
			[NumberCalled],
			[Adviser],
			[UID],        
			[Enterprise],                                                                                                                                                                                                                                                   
			[EnterpriseCode], 
			[Product],                                                                                                                                                                                                                                                     
			[Disclosure],                                                                                                                                                                                                                                                      
			[FeeAgreement],                                                                                                                                                                                                                                                    
			[FactFind],                                                                                                                                                                                                                                                        
			[FormulatingAdvice],                                                                                                                                                                                                                                               
			[Affordability],                                                                                                                                                                                                                                                   
			[Presenting the recommendation],                                                                                                                                                                                                                                   
			[Suitability Report],                                                                                                                                                                                                                                              
			[Customer experience],                                                                                                                                                                                                                                             
			[NPS 1],       
			[NPS 2],       
			[NPS 3],       
			[Outcome],  
			[OutcomeDate],			                                                                                                                                                                                                                                           
			[DateInserted],
			[DateLastUpdated]
		)		
		values
		(
			source.[Area],
			source.[Date],
			source.[Client],
			source.[CaseID],
			source.[CallType],
			source.[CallTime],
			source.[NumberCalled],
			source.[Adviser],
			source.[UID],        
			source.[Enterprise],                                                                                                                                                                                                                                                   
			source.[EnterpriseCode], 
			source.[Product],                                                                                                                                                                                                                                                     
			source.[Disclosure],                                                                                                                                                                                                                                                      
			source.[FeeAgreement],                                                                                                                                                                                                                                                    
			source.[FactFind],                                                                                                                                                                                                                                                        
			source.[FormulatingAdvice],                                                                                                                                                                                                                                               
			source.[Affordability],                                                                                                                                                                                                                                                   
			source.[Presenting the recommendation],                                                                                                                                                                                                                                   
			source.[Suitability Report],                                                                                                                                                                                                                                              
			source.[Customer experience],                                                                                                                                                                                                                                             
			source.[NPS 1],       
			source.[NPS 2],       
			source.[NPS 3],       
			source.[Outcome],  
			source.[OutcomeDate],		
			@DateLastUpdated,
			@DateLastUpdated
		);



GO
