		case 
			when Cases.Joint = 1 and Cases.Client = 1 and Cases.Partner = 1 and Cases.JointProduct <> Cases.ClientProduct and Cases.JointProduct <> Cases.PartnerProduct and Cases.ClientProduct <> Cases.PartnerProduct then Cases.JointProduct + ' & ' + Cases.ClientProduct + ' & ' + Cases.PartnerProduct
			when Cases.Joint = 1 and Cases.Client = 1 and Cases.Partner = 1 and Cases.ClientProduct = Cases.PartnerProduct and Cases.ClientProduct <> Cases.JointProduct then Cases.JointProduct + ' & ' + Cases.ClientProduct
			when Cases.Joint = 1 and Cases.Client = 1 and Cases.Partner = 1 and Cases.ClientProduct = Cases.PartnerProduct and Cases.PartnerProduct <> Cases.JointProduct then Cases.JointProduct + ' & ' + Cases.PartnerProduct
			when Cases.Joint = 1 and Cases.Client = 1 and Cases.JointProduct <> Cases.ClientProduct then Cases.JointProduct + ' & ' + Cases.ClientProduct
			when Cases.Joint = 1 then Cases.JointProduct
			when Cases.Client = 1 and Cases.Partner = 1 and Cases.ClientProduct <> Cases.PartnerProduct then Cases.ClientProduct + ' & ' + Cases.PartnerProduct
			when Client = 1 then Cases.ClientProduct
			when Partner = 1 then Cases.PartnerProduct
		end as ProductSold,
		Opp.UnlicencedSaleReason as ReasonforUnlicensedSaleLDComments,
		Opp.DateSentToQRM as DatesenttoAQMBQMforinvestigation,
		Opp.DateOfQRMDeadline as DeadlineforResponse5workingdays,
		Opp.DateOfQRMResponse as Dateresponsereceived,
		Opp.QRMInvestigationFeedback as BQMFeedbackfrominvestigation,
		Opp.SQRMInvestigationFeedback as AQMFeedbackfrominvestigation,
		Opp.AdviserBreach,
		Opp.CheckedByAQT as HascasebeencheckedbyAQT,
		Opp.AQTCheckOutcome as AQTcheckoutcomeHastherebeenanyclientdetriment,
		NULL as WasClientvisitedcontactedbyalicensedadviserNameofadviser,
		Opp.ClientContactOutcome as Outcomeofclientvisitcontact,
		NULL as Hastherebeenanyclientdetriment,
		NULL as SignoffbyJennyClose,
		Opp.ReferredToCRG as ImmediatereferraltoCRG,
		getdate() as LastUploadedDate
from	TandC.Opportunity Opp
		inner join CTE_Cases Cases on Cases.OpportunityURN = Opp.OpportunityURN
where	Opp.Deleted = 0

/******************************************************************************************************

Merge rows into the destination table

Note: "not matched by source" is not a delete condition as old unlicenced sales have not been
		added into the app - so we don't want to lose them from this table.

*******************************************************************************************************/

merge	TandC.UnlicensedSales as target
using	#UnlicensedSales as source
on		target.UnlicensedSaleID = source.UnlicensedSaleID
when	matched 
and		(isnull(target.CaseStatus,'') <> isnull(source.CaseStatus,'') 
or		isnull(target.CustomerName,'') <> isnull(source.CustomerName,'') 
or		isnull(target.BQMSupervisorName,'') <> isnull(source.BQMSupervisorName,'') 
or		isnull(target.AQM,'') <> isnull(source.AQM,'') 
or		isnull(target.ProductSold,'') <> isnull(source.ProductSold,'') 
or		isnull(target.ReasonforUnlicensedSaleLDComments,'') <> isnull(source.ReasonforUnlicensedSaleLDComments,'') 
or		isnull(target.DatesenttoAQMBQMforinvestigation,'') <> isnull(source.DatesenttoAQMBQMforinvestigation,'') 
or		isnull(target.DeadlineforResponse5workingdays,'') <> isnull(source.DeadlineforResponse5workingdays,'') 
or		isnull(target.Dateresponsereceived,'') <> isnull(source.Dateresponsereceived,'') 
or		isnull(target.BQMFeedbackfrominvestigation,'') <> isnull(source.BQMFeedbackfrominvestigation,'') 
or		isnull(target.AQMFeedbackfrominvestigation,'') <> isnull(source.AQMFeedbackfrominvestigation,'') 
or		isnull(target.AdviserBreach,'') <> isnull(source.AdviserBreach,'') 
or		isnull(target.HascasebeencheckedbyAQT,'') <> isnull(source.HascasebeencheckedbyAQT,'') 
or		isnull(target.AQTcheckoutcomeHastherebeenanyclientdetriment,'') <> isnull(source.AQTcheckoutcomeHastherebeenanyclientdetriment,'') 
or		isnull(target.WasClientvisitedcontactedbyalicensedadviserNameofadviser,'') <> isnull(source.WasClientvisitedcontactedbyalicensedadviserNameofadviser,'') 
or		isnull(target.Outcomeofclientvisitcontact,'') <> isnull(source.Outcomeofclientvisitcontact,'') 
or		isnull(target.Hastherebeenanyclientdetriment,'') <> isnull(source.Hastherebeenanyclientdetriment,'') 
or		isnull(target.[Signoff byJennyClose],'') <> isnull(source.[Signoff byJennyClose],'') 
or		isnull(target.ImmediatereferraltoCRG,'') <> isnull(source.ImmediatereferraltoCRG,''))
then	update 
			set     target.CaseStatus=source.CaseStatus,
					target.CustomerName=source.CustomerName,
					target.BQMSupervisorName=source.BQMSupervisorName,
					target.AQM=source.AQM,
					target.ProductSold=source.ProductSold,
					target.ReasonforUnlicensedSaleLDComments=source.ReasonforUnlicensedSaleLDComments,
					target.DatesenttoAQMBQMforinvestigation=source.DatesenttoAQMBQMforinvestigation,
					target.DeadlineforResponse5workingdays=source.DeadlineforResponse5workingdays,
					target.Dateresponsereceived=source.Dateresponsereceived,
					target.BQMFeedbackfrominvestigation=source.BQMFeedbackfrominvestigation,
					target.AQMFeedbackfrominvestigation=source.AQMFeedbackfrominvestigation,
					target.AdviserBreach=source.AdviserBreach,
					target.HascasebeencheckedbyAQT=source.HascasebeencheckedbyAQT,
					target.AQTcheckoutcomeHastherebeenanyclientdetriment=source.AQTcheckoutcomeHastherebeenanyclientdetriment,
					target.WasClientvisitedcontactedbyalicensedadviserNameofadviser=source.WasClientvisitedcontactedbyalicensedadviserNameofadviser,
					target.Outcomeofclientvisitcontact=source.Outcomeofclientvisitcontact,
					target.Hastherebeenanyclientdetriment=source.Hastherebeenanyclientdetriment,
					target.[Signoff byJennyClose]=source.[Signoff byJennyClose],
					target.ImmediatereferraltoCRG=source.ImmediatereferraltoCRG,
					target.LastUploadedDate=getdate()
when	not matched by target 
then	insert
		(
			UnlicensedSaleID,
			CaseStatus, 
			CustomerName, 
			DateofULS, 
			AdviserName, 
			AdviserUID, 
			BQMSupervisorName, 
			AQM, 
			ProductSold, 
			ReasonforUnlicensedSaleLDComments, 
			DatesenttoAQMBQMforinvestigation, 
			DeadlineforResponse5workingdays, 
			Dateresponsereceived, 
			BQMFeedbackfrominvestigation,
			AQMFeedbackfrominvestigation,
			AdviserBreach, 
			HascasebeencheckedbyAQT, 
			AQTcheckoutcomeHastherebeenanyclientdetriment, 
			WasClientvisitedcontactedbyalicensedadviserNameofadviser, 
			Outcomeofclientvisitcontact, 
			Hastherebeenanyclientdetriment, 
			[Signoff byJennyClose], 
			ImmediatereferraltoCRG, 
			LastUploadedDate
		)
 values
		(
			source.UnlicensedSaleID,
			source.CaseStatus, 
			source.CustomerName, 
			source.DateofULS, 
			source.AdviserName, 
			source.AdviserUID, 
			source.BQMSupervisorName, 
			source.AQM, 
			source.ProductSold, 
			source.ReasonforUnlicensedSaleLDComments, 
			source.DatesenttoAQMBQMforinvestigation, 
			source.DeadlineforResponse5workingdays, 
			source.Dateresponsereceived, 
			source.BQMFeedbackfrominvestigation,
			source.AQMFeedbackfrominvestigation,
			source.AdviserBreach, 
			source.HascasebeencheckedbyAQT, 
			source.AQTcheckoutcomeHastherebeenanyclientdetriment, 
			source.WasClientvisitedcontactedbyalicensedadviserNameofadviser, 
			source.Outcomeofclientvisitcontact, 
			source.Hastherebeenanyclientdetriment, 
			source.[Signoff byJennyClose], 
			source.ImmediatereferraltoCRG, 
			getdate()
		 );
GO
/****** Object:  StoredProcedure [TandC].[Pr_UnlicencedSales_Insert]    Script Date: 7/3/2026 3:44:28 PM ******/
