-- T and C insert statements
-- UnlicencedSales
-- Created By Sara Inglis
-- 30th Dec 2015
 
/******************************************************************************************************
Program:	Pr_UnlicencedSales_Insert
Date:		30th Dec 2015
Author:		Sarah Inglis

AMENDMENT HISTORY
=================
Date		Author			Description
----		------			-----------
13/06/2017	S Campbell		Rewrite proc to use a MERGE to update cases which are closed
							or add new Unlicenced sales
01/10/2017	A Groves		Break-fix: Logic added to handle where the SSIS script has imported blank 
							rows. Previously, this caused the INSERT to fail with null AdviserUID.
*******************************************************************************************************/

CREATE procedure [TandC].[Pr_UnlicencedSales_Insert]

As


/****************************************************************************

	Transform the data into a temporary table with the appropriate data types

****************************************************************************/
select top 0 * into #UnlicSales from [tandc].[UnlicensedSales_Staging]

insert into #UnlicSales

(UnlicensedSaleID,
[Case Status],
[Customer Name],
[Date of ULS],
[Adviser Name],
[Adviser UID],
[BQM/Supervisor Name],
[AQM],
[Product Sold],
[Reason for Unlicensed Sale/L&D Comments],
[Date sent to AQM/BQM for investigation],
[Deadline for response (5 working days)],
[Date response received],
[Adviser Breach?],
[Has case been checked by AQT?],
[AQT check outcome/ Has there been any client detriment?],
[Was Client visited/contacted by a licensed adviser? Name of adviser],
[Outcome of client visit/contact],
[Has there been any client detriment?],
[Sign off by Jenny Close],
[Immediate referral to CRG?] 
)
SELECT    
UnlicensedSaleID,
[Case Status],
[Customer Name],
[Date of ULS],
[Adviser Name],
[Adviser UID],
[BQM/Supervisor Name],
[AQM],
[Product Sold],
[Reason for Unlicensed Sale/L&D Comments],
[Date sent to AQM/BQM for investigation],
[Deadline for response (5 working days)],
[Date response received],
[Adviser Breach?],
[Has case been checked by AQT?],
[AQT check outcome/ Has there been any client detriment?],
[Was Client visited/contacted by a licensed adviser? Name of adviser],
[Outcome of client visit/contact],
[Has there been any client detriment?],
[Sign off by Jenny Close],
[Immediate referral to CRG?]
FROM [tandc].[UnlicensedSales_Staging] ulss
where [Adviser UID] is not null					--AG 01/10/2017

/****************************************************************************

	Merge rows into the destination table

****************************************************************************/

merge	TandC.UnlicensedSales as target
using	#UnlicSales as source
on		target.adviseruid = source.[adviser uid]
and     target.CustomerName = source.[Customer Name]
and     target.ProductSold = source.[Product Sold]
and     target.dateofULS = source.[Date of ULS]

when	matched 
and	   (isnull(target.CaseStatus,'') <> isnull(source.[Case Status],'') 
or	   isnull(target.BQMSupervisorName,'') <> isnull(source.[BQM/Supervisor Name],'') 
or	   isnull(target.AQM,'') <> isnull(source.AQM,'') 
or	   isnull(target.ReasonforUnlicensedSaleLDComments,'') <> isnull(source.[Reason for Unlicensed Sale/L&D Comments],'') 
or	   isnull(target.DatesenttoAQMBQMforinvestigation,'') <> isnull(source.[Date sent to AQM/BQM for investigation],'') 
or	   isnull(target.DeadlineforResponse5workingdays,'') <> isnull(source.[Deadline for response (5 working days)],'') 
or	   isnull(target.Dateresponsereceived,'') <> isnull(source.[Date response received],'') 
or	   isnull(target.AdviserBreach,'') <> isnull(source.[Adviser Breach?],'') 
or	   isnull(target.HascasebeencheckedbyAQT,'') <> isnull(source.[Has case been checked by AQT?],'') 
or	   isnull(target.AQTcheckoutcomeHastherebeenanyclientdetriment,'') <> isnull(source.[AQT check outcome/ Has there been any client detriment?],'') 
or	   isnull(target.WasClientvisitedcontactedbyalicensedadviserNameofadviser,'') <> isnull(source.[Was Client visited/contacted by a licensed adviser? Name of adviser],'') 
or	   isnull(target.Outcomeofclientvisitcontact,'') <> isnull(source.[Outcome of client visit/contact],'') 
or	   isnull(target.Hastherebeenanyclientdetriment,'') <> isnull(source.[Has there been any client detriment?],'') 
or	   isnull(target.[Signoff byJennyClose],'') <> isnull(source.[Sign off by Jenny Close],'') 
or	   isnull(target.ImmediatereferraltoCRG,'') <> isnull(source.[Immediate referral to CRG?],''))

then	update 
set     target.CaseStatus=source.[Case Status],
		target.BQMSupervisorName=source.[BQM/Supervisor Name],
		target.AQM=source.AQM,
		target.ReasonforUnlicensedSaleLDComments=source.[Reason for Unlicensed Sale/L&D Comments],
		target.DatesenttoAQMBQMforinvestigation=source.[Date sent to AQM/BQM for investigation],
		target.DeadlineforResponse5workingdays=source.[Deadline for response (5 working days)],
		target.Dateresponsereceived=source.[Date response received],
		target.AdviserBreach=source.[Adviser Breach?],
		target.HascasebeencheckedbyAQT=source.[Has case been checked by AQT?],
		target.AQTcheckoutcomeHastherebeenanyclientdetriment=source.[AQT check outcome/ Has there been any client detriment?],
		target.WasClientvisitedcontactedbyalicensedadviserNameofadviser=source.[Was Client visited/contacted by a licensed adviser? Name of adviser],
		target.Outcomeofclientvisitcontact=source.[Outcome of client visit/contact],
		target.Hastherebeenanyclientdetriment=source.[Has there been any client detriment?],
		target.[Signoff byJennyClose]=source.[Sign off by Jenny Close],
		target.ImmediatereferraltoCRG=source.[Immediate referral to CRG?],
		target.LastUploadedDate=getdate()

when	not matched by target
then	insert
		(UnlicensedSaleID,
	     CaseStatus, 
	     CustomerName, 
	     DateofULS, 
	     AdviserName, 
	     AdviserUID, 
	     BQMSupervisorName, 
	     AQM, 
	     ProductSold, 
         ReasonforUnlicensedSaleLDComments, 
	     DatesenttoAQMBQMforinvestigation, 
	     DeadlineforResponse5workingdays, 
	     Dateresponsereceived, 
         AdviserBreach, 
         HascasebeencheckedbyAQT, 
         AQTcheckoutcomeHastherebeenanyclientdetriment, 
         WasClientvisitedcontactedbyalicensedadviserNameofadviser, 
         Outcomeofclientvisitcontact, 
         Hastherebeenanyclientdetriment, 
         [Signoff byJennyClose], 
         ImmediatereferraltoCRG, 
         LastUploadedDate)
 values
		(source.[Adviser UID]+ CAST(source.[Date of ULS]as nvarchar(255)),
		source.[Case Status],
		source.[Customer Name],
		source.[Date of ULS],
		source.[Adviser Name],
		source.[Adviser UID],
		source.[BQM/Supervisor Name],
		source.[AQM],
		source.[Product Sold],
		source.[Reason for Unlicensed Sale/L&D Comments],
		source.[Date sent to AQM/BQM for investigation],
		source.[Deadline for response (5 working days)],
		source.[Date response received],
		source.[Adviser Breach?],
		source.[Has case been checked by AQT?],
		source.[AQT check outcome/ Has there been any client detriment?],
		source.[Was Client visited/contacted by a licensed adviser? Name of adviser],
		source.[Outcome of client visit/contact],
		source.[Has there been any client detriment?],
		source.[Sign off by Jenny Close],
		source.[Immediate referral to CRG?],
		getdate()
		);














				
				
				
 
				
 
 
GO
